import { forwardRef, type ButtonHTMLAttributes } from "react";
import { cva, type VariantProps } from "class-variance-authority";
import { cn } from "../../lib/cn";

/* Brand CTA rules: restrained. Solid rectangle or underlined link.
   Never a glowing pill. */
export const buttonVariants = cva(
  "inline-flex items-center justify-center gap-2 font-body font-medium transition-colors duration-200 ease-brand disabled:pointer-events-none disabled:opacity-50 [&_svg]:size-4 [&_svg]:shrink-0",
  {
    variants: {
      variant: {
        solid: "rounded-md bg-accent text-accent-ink hover:bg-accent/90",
        ghost: "rounded-md border border-border bg-transparent text-text-0 hover:border-accent-line hover:bg-accent-soft",
        link: "text-accent underline underline-offset-4 hover:text-text-0",
        destructive: "rounded-md border border-err/40 bg-transparent text-err hover:bg-err/10",
      },
      size: {
        sm: "h-7 px-2.5 text-xs",
        md: "h-8 px-3.5 text-sm",
      },
    },
    defaultVariants: { variant: "solid", size: "md" },
  },
);

export interface ButtonProps
  extends ButtonHTMLAttributes<HTMLButtonElement>,
    VariantProps<typeof buttonVariants> {}

export const Button = forwardRef<HTMLButtonElement, ButtonProps>(
  ({ className, variant, size, type = "button", ...props }, ref) => (
    <button ref={ref} type={type} className={cn(buttonVariants({ variant, size }), className)} {...props} />
  ),
);
Button.displayName = "Button";
