import { useEffect, useRef, useState } from "react";
import { Button, CloudSyncIndicator, PI_HEALTH, PageHeader, cn } from "@sporeprint/design";
import { PiTopBar } from "../components/PiTopBar";
import { apiGet } from "../lib/api";
import { relativeSeen, toneForStatus } from "../lib/chambers";
import { usePiLoad } from "../lib/use-pi-load";
import type { HardwareNode } from "../lib/pi-types";

// `.status-pill` base + tone (classmap §10) — self-sufficient tones per
// Binding Lesson 3, same resolved strings as HardwarePage.
const STATUS_PILL_BASE =
  "inline-flex items-center gap-[7px] rounded-pill border px-3 py-[5px] font-mono text-[12px] font-medium uppercase tracking-widest";
const STATUS_PILL_TONE = {
  signal: "border-signal/40 bg-signal-soft text-signal",
  warn: "border-warn bg-bg-2 text-warn",
  err: "border-err bg-bg-2 text-err",
} as const;
type Tone = keyof typeof STATUS_PILL_TONE;
function statusPill(tone: Tone): string {
  return cn(STATUS_PILL_BASE, STATUS_PILL_TONE[tone]);
}

const NODE_LEFT = {
  signal: "border-l-signal",
  warn: "border-l-warn",
  err: "border-l-err",
} as const;

/** Pi-side espota push status — `GET /api/hardware/nodes/{id}/ota`. */
interface OtaStatus {
  node_id: string;
  state: "idle" | "running" | "ok" | "error";
  message: string | null;
  started_at: number | null;
  finished_at: number | null;
  bytes_sent: number;
  total_bytes: number;
}

export function FirmwarePage() {
  const { data, loading, error: loadError } = usePiLoad(
    () => apiGet<HardwareNode[]>("/api/hardware/nodes"),
    [],
  );
  const nodes = data ?? [];

  return (
    <>
      <PiTopBar
        crumbs={[{ label: "system" }, { label: "firmware", active: true }]}
        right={<CloudSyncIndicator cloud={PI_HEALTH.cloud} />}
      />

      <PageHeader
        eyebrow="Pi-mediated distribution"
        title="Firmware"
        italic={false}
        meta={
          <span>
            {nodes.length} node{nodes.length === 1 ? "" : "s"} · push a signed .bin per node over espota
          </span>
        }
      />

      <div className="grid grid-cols-[1fr] gap-[22px] px-7 pt-[22px] pb-7 max-w-none">
        <main className="flex flex-col gap-3.5">
          {loadError ? (
            <p className="font-mono text-[13px] tracking-[0.05em] text-err">
              Failed to load hardware nodes: {loadError}
            </p>
          ) : loading ? (
            <p className="font-mono text-[13px] tracking-[0.05em] text-text-2">Loading…</p>
          ) : nodes.length === 0 ? (
            <p className="font-mono text-[13px] tracking-[0.05em] text-text-2">
              No hardware nodes have reported to this Pi yet.
            </p>
          ) : (
            <>
              {nodes.map((n) => (
                <NodeCard key={n.node_id} node={n} />
              ))}
            </>
          )}

          <p className="font-mono text-[12px] text-text-2">
            current versions are each node&rsquo;s last-reported firmware. TODO(wire): there is no
            release-manifest endpoint on this Pi — versions are shown as-is, not compared against a
            latest release. The OTA password is the node&rsquo;s ArduinoOTA password (min 12 chars) and
            is sent only with the push; it is never stored.
          </p>
        </main>
      </div>
    </>
  );
}

function NodeCard({ node }: { node: HardwareNode }) {
  const [open, setOpen] = useState(false);
  const [file, setFile] = useState<File | null>(null);
  const [password, setPassword] = useState("");
  const [pushing, setPushing] = useState(false);
  const [pushError, setPushError] = useState<string | null>(null);
  const [status, setStatus] = useState<OtaStatus | null>(null);
  const fileRef = useRef<HTMLInputElement>(null);

  // Resume an in-progress push if one was already running when the page loaded.
  useEffect(() => {
    let alive = true;
    apiGet<OtaStatus>(`/api/hardware/nodes/${node.node_id}/ota`)
      .then((s) => {
        if (alive && s.state !== "idle") setStatus(s);
      })
      .catch(() => {
        /* no prior push / older Pi without the endpoint — ignore */
      });
    return () => {
      alive = false;
    };
  }, [node.node_id]);

  // Poll every ~2s while a push is running.
  useEffect(() => {
    if (status?.state !== "running") return;
    let alive = true;
    const timer = setInterval(() => {
      apiGet<OtaStatus>(`/api/hardware/nodes/${node.node_id}/ota`)
        .then((s) => {
          if (alive) setStatus(s);
        })
        .catch(() => {
          /* transient poll failure — keep the last snapshot, retry next tick */
        });
    }, 2000);
    return () => {
      alive = false;
      clearInterval(timer);
    };
  }, [status?.state, node.node_id]);

  async function push() {
    if (!file || !password || pushing) return;
    setPushError(null);
    setPushing(true);
    try {
      const fd = new FormData();
      fd.append("file", file);
      fd.append("password", password);
      const res = await fetch(`/api/hardware/nodes/${node.node_id}/ota`, {
        method: "POST",
        credentials: "same-origin",
        body: fd,
      });
      if (!res.ok) {
        const detail = await res.text();
        throw new Error(`HTTP ${res.status}: ${detail.slice(0, 200)}`);
      }
      // 202 accepted — flip to running optimistically; the poller then reads
      // real byte progress from the status endpoint.
      setStatus({
        node_id: node.node_id,
        state: "running",
        message: "starting…",
        started_at: null,
        finished_at: null,
        bytes_sent: 0,
        total_bytes: file.size,
      });
      setPassword("");
    } catch (err) {
      setPushError(err instanceof Error ? err.message : "push failed");
    } finally {
      setPushing(false);
    }
  }

  const tone = toneForStatus(node.status);
  const running = status?.state === "running";
  const pct =
    status && status.total_bytes > 0
      ? Math.min(100, (status.bytes_sent / status.total_bytes) * 100)
      : 0;

  return (
    <section
      className={cn(
        "flex flex-col gap-[18px] rounded-md border border-border-soft bg-bg-1 p-[26px] border-l-[3px]",
        NODE_LEFT[tone],
      )}
    >
      <div className="flex flex-wrap items-center justify-between gap-3">
        <div className="flex flex-col gap-1">
          <span className="font-mono text-[12px] font-medium uppercase tracking-[0.14em] text-text-2">
            {node.node_type} · {node.node_id}
          </span>
          <span className="font-mono text-[14px] text-text-1">
            fw {node.firmware_version ?? "—"} · seen {relativeSeen(node.last_seen)}
            {node.ip_address ? ` · ${node.ip_address}` : ""}
          </span>
        </div>
        <div className="flex items-center gap-2">
          <span className={statusPill(tone)}>{node.status ?? "unknown"}</span>
          <Button type="button" variant={open ? "solid" : "ghost"} onClick={() => setOpen((v) => !v)}>
            {open ? "cancel" : "update firmware"}
          </Button>
        </div>
      </div>

      {open && (
        <div className="flex flex-col gap-2.5 rounded-sm border border-border-soft bg-bg-2 p-4">
          {!node.ip_address && (
            <span className={statusPill("warn")}>no known IP for this node — it must be online to push</span>
          )}
          <label className="flex flex-col gap-1.5">
            <span className="font-mono text-[12px] font-medium uppercase tracking-[0.14em] text-text-2">firmware image (.bin)</span>
            <input
              ref={fileRef}
              type="file"
              accept=".bin"
              className="t-input"
              onChange={(e) => setFile(e.target.files?.[0] ?? null)}
            />
          </label>
          <label className="flex flex-col gap-1.5">
            <span className="font-mono text-[12px] font-medium uppercase tracking-[0.14em] text-text-2">OTA password</span>
            <input
              type="password"
              className="t-input"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="node ArduinoOTA password"
              spellCheck={false}
              autoCorrect="off"
            />
          </label>
          <div className="flex flex-wrap items-center gap-2">
            <Button
              type="button"
              variant="solid"
              onClick={() => void push()}
              disabled={!file || !password || pushing || running}
            >
              {pushing ? "starting…" : running ? "pushing…" : "push →"}
            </Button>
            {pushError && <span className={cn(statusPill("err"), "self-center")}>{pushError}</span>}
          </div>
        </div>
      )}

      {status && status.state !== "idle" && (
        <div className="flex flex-col gap-2">
          {running && (
            <>
              <div className="h-[14px] overflow-hidden rounded-pill bg-bg-2">
                <div className="h-full bg-accent" style={{ width: `${pct}%` }} />
              </div>
              <span className="font-mono text-[12px] text-text-2">
                pushing {status.bytes_sent.toLocaleString()} / {status.total_bytes.toLocaleString()} bytes
                {status.message ? ` · ${status.message}` : ""}
              </span>
            </>
          )}
          {status.state === "ok" && (
            <span className={cn(statusPill("signal"), "self-start")}>{status.message ?? "flash confirmed by node"}</span>
          )}
          {status.state === "error" && (
            <span className={cn(statusPill("err"), "self-start")}>{status.message ?? "push failed"}</span>
          )}
        </div>
      )}
    </section>
  );
}
