/* =============================================================
   sporeprint.ai — the mark
   A partial spore-deposit (wedge of stippled dots) whose outer
   edge resolves into a regular polar lattice — biology becoming
   signal. Same generator from favicon to hero.

   Two entry points:

   - makeLogo(size, opts)            → returns a standalone <svg>
   - makeLogoGroup(scale, cx, cy, opts) → returns an <g> to embed
                                          inside an existing svg

   opts:
     latticeBias:  1.0  (higher = more "AI resolve" at the outer edge)
     baseDensity:  1.0  (higher = more organic stipple dots)
     innerBiasPow: 1.6  (higher = dots cluster harder near inner arc)
     color:        "currentColor" | any CSS color

   Tuned defaults for common scales (see SKILL.md):
     14px tile corner:   baseDensity 0.4
     22px nav mark:      baseDensity 1.0  (default)
     64px empty state:   baseDensity 0.9
     220px chamber hero: baseDensity 1.1
   ============================================================= */

const NS = "http://www.w3.org/2000/svg";

// Fixed geometry — do not change. The wedge shape is the mark.
const GEOM = {
  cx: 26,
  cy: 50,
  innerR: 6,
  outerR: 72,
  startA: -Math.PI * 0.36,     // -65°
  endA:    Math.PI * 0.36,     // +65°
};

/**
 * Standalone SVG spore-print mark.
 * @param {number} size - Rendered pixel size (width and height).
 * @param {object} [opts]
 * @returns {SVGSVGElement}
 */
export function makeLogo(size, opts = {}) {
  const {
    latticeBias = 1.0,
    baseDensity = 1.0,
    innerBiasPow = 1.6,
    color = "currentColor",
  } = opts;

  const svg = document.createElementNS(NS, "svg");
  svg.setAttribute("viewBox", "0 0 100 100");
  svg.setAttribute("width", size);
  svg.setAttribute("height", size);
  svg.setAttribute("aria-label", "sporeprint");
  svg.style.color = color;
  svg.style.verticalAlign = "middle";

  const { cx, cy, innerR, outerR, startA, endA } = GEOM;
  const totalA = endA - startA;

  // Count scales with size so small marks stay readable
  const base =
    size >= 64 ? 1400 :
    size >= 36 ? 700  :
    180;
  const baseCount = Math.round(base * baseDensity);

  // --- Organic stipple (inner, dense → outer, faded) -------------
  for (let i = 0; i < baseCount; i++) {
    const t = Math.pow(Math.random(), innerBiasPow);
    const r = innerR + t * (outerR - innerR);
    const a = startA + Math.random() * totalA;
    const rr = r + (Math.random() - 0.5) * 1.6;
    const x = cx + rr * Math.cos(a);
    const y = cy + rr * Math.sin(a);
    const radial = (rr - innerR) / (outerR - innerR);
    const op = Math.max(0.08, 1 - Math.pow(radial, 0.55)) * 0.95;

    const dot = document.createElementNS(NS, "circle");
    dot.setAttribute("cx", x.toFixed(2));
    dot.setAttribute("cy", y.toFixed(2));
    dot.setAttribute("r", (size >= 64 ? 0.45 : 0.5).toFixed(2));
    dot.setAttribute("fill", "currentColor");
    dot.setAttribute("opacity", op.toFixed(3));
    svg.appendChild(dot);
  }

  // --- Lattice (regular polar grid, the "AI resolve") ------------
  const latticeStart = innerR + (outerR - innerR) * (0.55 - 0.1 * (latticeBias - 1));
  const radialStep = size >= 64 ? 3.6 : 4.5;
  const angularStep = (Math.PI / 180) * (size >= 64 ? 3.0 : 4.5);

  for (let r = latticeStart; r <= outerR; r += radialStep) {
    for (let a = startA; a <= endA + 0.0001; a += angularStep) {
      const rNorm = (r - latticeStart) / (outerR - latticeStart);
      const keepThreshold = 0.35 + rNorm * 0.55 - (latticeBias - 1) * 0.25;
      if (Math.random() > keepThreshold) continue;
      const x = cx + r * Math.cos(a);
      const y = cy + r * Math.sin(a);
      const op = Math.min((0.25 + rNorm * 0.55) * latticeBias, 0.95);

      const dot = document.createElementNS(NS, "circle");
      dot.setAttribute("cx", x.toFixed(2));
      dot.setAttribute("cy", y.toFixed(2));
      dot.setAttribute("r", (size >= 64 ? 0.55 : 0.55).toFixed(2));
      dot.setAttribute("fill", "currentColor");
      dot.setAttribute("opacity", op.toFixed(3));
      svg.appendChild(dot);
    }
  }

  return svg;
}

/**
 * Returns a <g> element containing just the dots, positioned to
 * be embedded inside an existing SVG (e.g. centered in a
 * 220×220 viewBox for the chamber hero).
 *
 * @param {number} scale - Scale factor relative to the 100×100
 *                         viewBox coordinate system.
 * @param {number} cx - Center x in the host viewBox.
 * @param {number} cy - Center y in the host viewBox.
 * @param {object} [opts]
 * @returns {SVGGElement}
 */
export function makeLogoGroup(scale, cx, cy, opts = {}) {
  const {
    latticeBias = 1.0,
    baseDensity = 1.0,
    innerBiasPow = 1.6,
    color = "#D4A15E",
  } = opts;

  const g = document.createElementNS(NS, "g");
  const { cx: origCx, cy: origCy, innerR, outerR, startA, endA } = GEOM;
  const totalA = endA - startA;
  const count = Math.round(1200 * baseDensity);

  for (let i = 0; i < count; i++) {
    const t = Math.pow(Math.random(), innerBiasPow);
    const r = innerR + t * (outerR - innerR);
    const a = startA + Math.random() * totalA;
    const rr = r + (Math.random() - 0.5) * 1.6;
    const lx = origCx + rr * Math.cos(a);
    const ly = origCy + rr * Math.sin(a);
    const x = cx + (lx - 50) * scale;
    const y = cy + (ly - 50) * scale;
    const radial = (rr - innerR) / (outerR - innerR);
    const op = Math.max(0.08, 1 - Math.pow(radial, 0.55)) * 0.95;

    const dot = document.createElementNS(NS, "circle");
    dot.setAttribute("cx", x.toFixed(2));
    dot.setAttribute("cy", y.toFixed(2));
    dot.setAttribute("r", (0.55 * scale).toFixed(2));
    dot.setAttribute("fill", color);
    dot.setAttribute("opacity", op.toFixed(3));
    g.appendChild(dot);
  }

  const latticeStart = innerR + (outerR - innerR) * 0.55;
  const radialStep = 3.6;
  const angularStep = (Math.PI / 180) * 3.0;
  for (let r = latticeStart; r <= outerR; r += radialStep) {
    for (let a = startA; a <= endA + 0.0001; a += angularStep) {
      const rNorm = (r - latticeStart) / (outerR - latticeStart);
      const keepThreshold = 0.35 + rNorm * 0.55 - (latticeBias - 1) * 0.25;
      if (Math.random() > keepThreshold) continue;
      const lx = origCx + r * Math.cos(a);
      const ly = origCy + r * Math.sin(a);
      const x = cx + (lx - 50) * scale;
      const y = cy + (ly - 50) * scale;
      const op = Math.min((0.25 + rNorm * 0.55) * latticeBias, 0.95);

      const dot = document.createElementNS(NS, "circle");
      dot.setAttribute("cx", x.toFixed(2));
      dot.setAttribute("cy", y.toFixed(2));
      dot.setAttribute("r", (0.7 * scale).toFixed(2));
      dot.setAttribute("fill", color);
      dot.setAttribute("opacity", op.toFixed(3));
      g.appendChild(dot);
    }
  }

  return g;
}

/* --- Usage examples ------------------------------------------

// 1. Nav bar (22px saffron):
document.querySelector("#nav-mark").appendChild(
  makeLogo(22, { color: "#D4A15E" })
);

// 2. Fleet-tile micro-mark (14px, muted):
const micro = makeLogo(14, { color: "var(--text-3)", baseDensity: 0.4 });
tileEl.appendChild(micro);

// 3. Chamber-view hero (embedded in a 220x220 existing SVG):
const host = document.querySelector("#chamber-svg");
host.appendChild(
  makeLogoGroup(1.6, 110, 110, {
    color: "#D4A15E",
    baseDensity: 1.1,
  })
);

--------------------------------------------------------------- */
