// `.status-pill` base + tone (classmap §10). Full resolved utility strings —
// no shared legacy base class, so no utility emit-order fight (Binding Lesson 3).
const STATUS_PILL_BASE =
  "inline-flex items-center gap-[7px] rounded-pill border px-3 py-[5px] font-mono text-[12px] font-medium uppercase tracking-widest";
const STATUS_PILL_TONE = {
  signal: "border-signal/40 bg-signal-soft text-signal",
  warn: "border-warn bg-bg-2 text-warn",
  err: "border-err bg-bg-2 text-err",
} as const;

// ── Pi FastAPI response shapes (read from server/app/*) ─────────────

/** `GET /api/health/detail/system` (health/service.py get_system_metrics). */
interface SystemHealth {
  cpu_percent: number;
  memory_percent: number;
  memory_used_mb: number;
  memory_total_mb: number;
  disk_percent: number;
  disk_used_gb: number;
  disk_total_gb: number;
  cpu_temp_c: number | null;
  uptime_hours: number;
  reliability?: { uptime_ts_clamps: number; mqtt_supervisor_restarts: number };
}

/** `GET /api/cloud/status` (cloud/service.py get_cloud_status). */
interface CloudStatus {
  configured: boolean;
  connected: boolean;
  queue_depth: number;
  last_forward: number | null;
}

// ── Real-data mapping helpers ────────────────────────────────────────

/** One pass over `GET /api/telemetry/latest`: freshest row per
 *  `node_id|sensor`, so per-chamber lookups don't rescan the full array. */
function latestBySensor(latest: LatestRow[]): Map<string, LatestRow> {
  const map = new Map<string, LatestRow>();
  for (const r of latest) {
    const key = `${r.node_id}|${r.sensor}`;
    const cur = map.get(key);
    if (!cur || r.timestamp > cur.timestamp) map.set(key, r);
  }
  return map;
}

/** Freshest reading per sensor across the chamber's nodes. Missing sensors
 *  stay NaN — the design Telemetry type has no "unknown" slot. */
function chamberTelemetry(nodeIds: string[], freshest: Map<string, LatestRow>): Telemetry {
  const val = (sensor: string): number | undefined => {
    let best: LatestRow | undefined;
    for (const nodeId of nodeIds) {
      const r = freshest.get(`${nodeId}|${sensor}`);
      if (r && (!best || r.timestamp > best.timestamp)) best = r;
    }
    return best?.value;
  };
  const tempF = val("temp_f");
  const humidity = val("humidity");
  const co2 = val("co2_ppm");
  const vpd = tempF != null && humidity != null ? vpdOf(tempF, humidity) : undefined;
  return {
    tempF: tempF ?? Number.NaN,
    humidity: humidity ?? Number.NaN,
    co2: co2 ?? Number.NaN,
    vpdKpa: vpd ?? Number.NaN,
  };
}

/** Project the server's GrowPhase onto the design's 5-value ChamberPhase. */
function mapPhase(p: string): ChamberPhase {
  switch (p) {
    case "primordia_induction":
    case "fruiting":
      return "fruiting";
    case "rest": // between-flush recovery — nearest canonical bucket
      return "harvest";
    case "complete":
      return "idle";
    default: // agar / liquid_culture / grain + substrate colonization / cold_storage
      return "spawn";
  }
}

function stateOf(nodes: HardwareNode[], session: PiSession | null): ChamberState {
  if (nodes.some((n) => n.status === "offline")) return "err";
  if (!session) return "idle";
  if (nodes.length === 0 || nodes.some((n) => n.status !== "online")) return "warn";
  return "active";
}

/** day N (from phase_history entered_at) of M (species expected_duration_days
 *  max). total stays 0 for phases outside the profile (e.g. cold_storage) —
 *  FleetTile then renders the parked "idle" label. */
function dayOf(session: PiSession | null, species: PiSpecies | null): { current: number; total: number } {
  if (!session) return { current: 0, total: 0 };
  const history = session.phase_history ?? [];
  const entry =
    history.find((h) => h.exited_at == null && h.phase === session.current_phase) ??
    [...history].reverse().find((h) => h.phase === session.current_phase);
  const current = entry ? Math.max(1, Math.floor((Date.now() / 1000 - entry.entered_at) / 86400) + 1) : 0;
  const total = species?.phases?.[session.current_phase]?.expected_duration_days?.[1] ?? 0;
  return { current, total };
}

// ── Page data loading ────────────────────────────────────────────────

interface FleetChamberView {
  tile: Chamber;
  name: string;
  targets: ActTargets;
}

interface FleetData {
  views: FleetChamberView[];
  events: FleetEvent[];
  serverVersion: string | null;
  nodesOnline: number;
  nodesTotal: number;
}

async function loadFleet(): Promise<FleetData> {
  const [chambers, nodes, latest, overrides, health, speciesList] = await Promise.all([
    apiGet<PiChamber[]>("/api/chambers"),
    apiGet<HardwareNode[]>("/api/hardware/nodes"),
    apiGet<LatestRow[]>("/api/telemetry/latest"),
    apiGet<OverrideRow[]>("/api/automation/overrides"),
    apiGet<{ version?: string }>("/api/health"),
    // One species list indexed by id replaces the former per-species fan-out.
    apiGet<PiSpecies[]>("/api/species"),
  ]);
  const speciesById = new Map(speciesList.map((s) => [s.id, s]));

  // Per-session detail fetches stay (active chambers only, as before): the
  // `GET /api/sessions` list endpoint omits phase_history — detail-only —
  // which dayOf() needs for the tile's "day N of M".
  const sessionByChamber = new Map<number, PiSession>();
  await Promise.all(
    chambers
      .filter((c) => c.active_session_id != null)
      .map(async (c) => {
        sessionByChamber.set(c.id, await apiGet<PiSession>(`/api/sessions/${c.active_session_id}`));
      }),
  );

  // Live event feed ← session events of every chamber with an active grow.
  const merged: { chamberName: string; row: SessionEventRow }[] = [];
  await Promise.all(
    [...sessionByChamber.entries()].map(async ([chamberId, s]) => {
      const rows = await apiGet<SessionEventRow[]>(`/api/sessions/${s.id}/events`);
      const name = chambers.find((c) => c.id === chamberId)?.name ?? String(chamberId);
      for (const row of rows) merged.push({ chamberName: name, row });
    }),
  );
  merged.sort((a, b) => b.row.timestamp - a.row.timestamp);
  const events = merged.slice(0, 22).map(({ chamberName, row }) => toFleetEvent(row, chamberName));

  const freshest = latestBySensor(latest);
  const nodesById = new Map(nodes.map((n) => [n.node_id, n]));
  const views: FleetChamberView[] = chambers.map((c) => {
    const session = sessionByChamber.get(c.id) ?? null;
    const species = session ? (speciesById.get(session.species_profile_id) ?? null) : null;
    const cNodes = c.node_ids.map((id) => nodesById.get(id)).filter((n): n is HardwareNode => Boolean(n));
    const targets = actuatorTargets(cNodes);
    const day = dayOf(session, species);
    return {
      tile: {
        id: String(c.id),
        display: displayOf(c.id),
        // TODO(wire): chambers have no rack/shelf position server-side (only
        // sessions carry tub/shelf) — tile omits the rack badge below.
        rack: { rack: 0, shelf: 0 },
        serial: "", // TODO(wire): no hardware serial on the chambers table
        firmware: cNodes.find((n) => n.firmware_version)?.firmware_version ?? "",
        lastBoot: "", // TODO(wire): node boot time is not exposed over REST
        species: {
          // Idle chambers have no session → no species; the chamber's real
          // name fills the species line instead of a fake binomial.
          binomial: species?.scientific_name ?? c.name,
          common: species?.common_name ?? c.name,
        },
        phase: session ? mapPhase(session.current_phase) : "idle",
        state: stateOf(cNodes, session),
        day,
        progress: day.total > 0 ? Math.min(100, Math.round((day.current / day.total) * 100)) : 0,
        telemetry: chamberTelemetry(c.node_ids, freshest),
        actuators: buildActuators(targets, overrides),
        events: [],
      } satisfies Chamber,
      name: c.name,
      targets,
    };
  });

  const nodesOnline = nodes.filter((n) => n.status === "online").length;
  return { views, events, serverVersion: health.version ?? null, nodesOnline, nodesTotal: nodes.length };
}

interface SystemView {
  system: SystemHealth;
  cloud: CloudStatus;
  clients: number;
  mqtt: Record<string, string | number>;
}

async function loadSystem(): Promise<SystemView> {
  const [system, cloud, clients, mqtt] = await Promise.all([
    apiGet<SystemHealth>("/api/health/detail/system"),
    apiGet<CloudStatus>("/api/cloud/status"),
    apiGet<unknown[]>("/api/health/detail/clients"),
    apiGet<Record<string, string | number>>("/api/health/detail/mqtt"),
  ]);
  return { system, cloud, clients: clients.length, mqtt };
}

const SYSTEM_POLL_MS = 15_000;
const TRACE_CAP = 240; // 1h of 15s samples

interface Kpi {
  label: string;
  value: string;
  unit?: string;
  delta?: string;
  tone?: "signal" | "accent";
}

function buildKpis(sys: SystemView): Kpi[] {
  const { system, cloud } = sys;
  const kpis: Kpi[] = [
    { label: "cpu", value: String(Math.round(system.cpu_percent)), unit: "%" },
    {
      label: "ram",
      value: String(Math.round(system.memory_percent)),
      unit: "%",
      delta: `${(system.memory_used_mb / 1024).toFixed(1)}GB / ${(system.memory_total_mb / 1024).toFixed(0)}GB`,
    },
    {
      label: "disk",
      value: String(Math.round(system.disk_percent)),
      unit: "%",
      delta: `${system.disk_used_gb}GB / ${system.disk_total_gb}GB`,
    },
  ];
  if (system.cpu_temp_c != null) {
    // psutil reports no temperature on non-Pi dev hosts — omit the KPI then.
    kpis.push({ label: "temp", value: String(Math.round(system.cpu_temp_c)), unit: "°C", tone: "signal" });
  }
  // TODO(wire): the fake strip had an "uplink" KPI — there is no
  // network-interface endpoint on the Pi server, so it is omitted.
  kpis.push({
    label: "cloud",
    value: !cloud.configured ? "unpaired" : cloud.connected ? "synced" : "offline",
    delta:
      cloud.queue_depth > 0
        ? `${cloud.queue_depth} queued`
        : cloud.last_forward != null
          ? `last ${fmtClock(cloud.last_forward)}`
          : undefined,
    tone: cloud.connected ? "signal" : undefined,
  });
  kpis.push({
    label: "uptime",
    value: `${Math.floor(system.uptime_hours / 24)}d`,
    delta: `${Math.round(system.uptime_hours % 24)}h`,
  });
  return kpis;
}

// Threshold tones mirror the design PiHealthPanel (replaced below because its
// PiHealth prop demands an uplink row no Pi endpoint can populate).
function pctTone(pct: number): "ok" | "warn" | "err" {
  if (pct > 90) return "err";
  if (pct >= 70) return "warn";
  return "ok";
}
function tempTone(c: number): "ok" | "warn" | "err" {
  if (c > 75) return "err";
  if (c >= 60) return "warn";
  return "ok";
}

export function FleetPage({ onSelect }: Props) {
  const [fleet, setFleet] = useState<FleetData | null>(null);
  const [fleetLoading, setFleetLoading] = useState(true);
  const [fleetError, setFleetError] = useState<string | null>(null);

  const [sys, setSys] = useState<SystemView | null>(null);
  const [sysError, setSysError] = useState<string | null>(null);
  const [sysTrace, setSysTrace] = useState<{ cpu: number[]; mem: number[]; temp: number[] }>({
    cpu: [],
    mem: [],
    temp: [],
  });

  const [overrideTargetId, setOverrideTargetId] = useState<string>("");
  const [overrides, setOverrides] = useState<Actuators | null>(null);
  const [overrideError, setOverrideError] = useState<string | null>(null);

  // After an override apply/release, re-sync ONLY the override rows and
  // recompute the tile actuator banks from them — the optimistic update
  // already handles the quick-override panel, so no full fleet reload.
  const refreshOverrides = useCallback(async () => {
    const rows = await apiGet<OverrideRow[]>("/api/automation/overrides");
    setFleet((prev) =>
      prev
        ? {
            ...prev,
            views: prev.views.map((v) => ({
              ...v,
              tile: { ...v.tile, actuators: buildActuators(v.targets, rows) },
            })),
          }
        : prev,
    );
  }, []);

  useEffect(() => {
    let cancelled = false;
    setFleetLoading(true);
    setFleetError(null);
    loadFleet()
      .then((data) => {
        if (cancelled) return;
        setFleet(data);
        // Default quick-override target: first warn chamber, else the first.
        const warn = data.views.find((v) => v.tile.state === "warn");
        const first = warn ?? data.views[0];
        if (first) {
          setOverrideTargetId(first.tile.id);
          setOverrides(first.tile.actuators);
        }
      })
      .catch((err: unknown) => {
        if (!cancelled) setFleetError(err instanceof Error ? err.message : "fetch failed");
      })
      .finally(() => {
        if (!cancelled) setFleetLoading(false);
      });
    return () => {
      cancelled = true;
    };
  }, []);

  // Pi system panel — poll every 15s and accumulate the sparkline trace
  // client-side. TODO(wire): the Pi has no system-metrics history endpoint
  // (GET /api/health/detail/system is instantaneous), so the trace builds
  // live from page-open rather than backfilling a full hour.
  useEffect(() => {
    let cancelled = false;
    const tick = async () => {
      try {
        const view = await loadSystem();
        if (cancelled) return;
        setSys(view);
        setSysError(null);
        setSysTrace((prev) => ({
          cpu: [...prev.cpu, view.system.cpu_percent].slice(-TRACE_CAP),
          mem: [...prev.mem, view.system.memory_percent].slice(-TRACE_CAP),
          temp: [...prev.temp, view.system.cpu_temp_c ?? Number.NaN].slice(-TRACE_CAP),
        }));
      } catch (err) {
        if (!cancelled) setSysError(err instanceof Error ? err.message : "fetch failed");
      }
    };
    void tick();
    const timer = setInterval(() => void tick(), SYSTEM_POLL_MS);
    return () => {
      cancelled = true;
      clearInterval(timer);
    };
  }, []);

  const overrideView = useMemo(
    () => fleet?.views.find((v) => v.tile.id === overrideTargetId) ?? null,
    [fleet, overrideTargetId],
  );

  function switchOverrideTarget(id: string) {
    setOverrideTargetId(id);
    setOverrideError(null);
    const next = fleet?.views.find((v) => v.tile.id === id);
    setOverrides(next ? next.tile.actuators : null);
  }

  // Quick 5-minute pin: force the channel via the hardware command endpoint
  // (the actuation primitive) AND register a manual override with expires_at
  // (so the rules engine leaves the pinned state alone for the window).
  async function applyOverride(key: ActuatorKey) {
    if (!overrideView || !overrides) return;
    const target = overrideView.targets[key];
    if (!target) {
      setOverrideError(`no ${key} channel is mapped on this chamber's nodes`);
      return;
    }
    setOverrideError(null);
    const prev = overrides;
    const cur = prev[key];

    if (cur.override) {
      // Release: clear the automation override; the rules engine resumes
      // control of the channel (the Pi has no "restore prior state" concept).
      setOverrides({ ...prev, [key]: { on: false, sub: "state unknown" } });
      try {
        await apiSend<unknown>(
          `/api/automation/overrides/${encodeURIComponent(target.nodeId)}?channel=${encodeURIComponent(target.channel)}`,
          "DELETE",
        );
        void refreshOverrides();
      } catch (err) {
        setOverrides(prev);
        setOverrideError(err instanceof Error ? err.message : "release failed");
      }
      return;
    }

    const next = !cur.on;
    const durationSec = 300;
    setOverrides({
      ...prev,
      [key]: {
        ...cur,
        on: next,
        sub: "override · 5m",
        override: {
          untilIso: new Date(Date.now() + durationSec * 1000).toISOString(),
          durationSec,
        },
      },
    });
    try {
      await apiSend<unknown>(`/api/hardware/nodes/${encodeURIComponent(target.nodeId)}/command`, "POST", {
        channel: target.channel,
        state: next ? "on" : "off",
        ...(next ? { duration_sec: durationSec } : {}),
      });
      await apiSend<unknown>("/api/automation/overrides", "POST", {
        target: target.nodeId,
        channel: target.channel,
        locked: true,
        reason: `pi-ui quick override (${key})`,
        expires_at: Date.now() / 1000 + durationSec,
      });
      void refreshOverrides();
    } catch (err) {
      setOverrides(prev);
      setOverrideError(err instanceof Error ? err.message : "override failed");
    }
  }

  const views = fleet?.views ?? [];
  const onlineCount = views.filter((v) => v.tile.state !== "idle").length;
  const activeCount = views.filter((v) => v.tile.state === "active").length;
  const warnCount = views.filter((v) => v.tile.state === "warn").length;
  const errCount = views.filter((v) => v.tile.state === "err").length;

  const kpis = sys ? buildKpis(sys) : [];
  const mqttEntries = sys ? Object.entries(sys.mqtt) : [];

  return (
    <>
      {/* TODO(wire): the hostname/IP pill needs a Pi endpoint exposing the
          host identity — none exists, so the pill is omitted. The cloud pip
          stays on the fake PI_HEALTH.cloud by design (separate wiring pass). */}
      <PiTopBar
        crumbs={[{ label: "local" }, { label: "chambers", active: true }]}
        right={<CloudSyncIndicator cloud={PI_HEALTH.cloud} />}
      />

      <PageHeader
        eyebrow="On this Pi"
        title="Local chambers"
        italic={false}
        meta={
          fleet ? (
            <span>
              {views.length} attached · {onlineCount} online
              {warnCount > 0 && ` · ${warnCount} warn`}
              {errCount > 0 && ` · ${errCount} err`}
              {fleet.serverVersion && ` · server ${fleet.serverVersion}`}
            </span>
          ) : (
            <span>…</span>
          )
        }
      />

      <div className="grid grid-cols-[1fr_400px] gap-[22px] px-7 pt-[22px] pb-7 max-[1180px]:grid-cols-1">
        <main className="flex flex-col gap-4">
          {/* TODO(wire): the active-alert banner rendered the fake ALERTS
              feed. The Pi has no alerts REST endpoint (alerts fan out via
              ntfy push + the cloud relay), so the banner is omitted. */}

          {fleetError ? (
            <p className="font-mono text-[13px] tracking-[0.05em] text-err">
              Failed to load chambers: {fleetError}
            </p>
          ) : fleetLoading ? (
            <p className="font-mono text-[13px] tracking-[0.05em] text-text-2">Loading…</p>
          ) : (
            <>
              {/* ---------- Status line ---------- */}
              <section
                className="flex flex-wrap items-center gap-2 rounded-md border border-border-soft bg-bg-1 px-[18px] py-3.5"
                aria-label="Right now"
              >
                <span className="font-mono text-[13px] font-medium uppercase tracking-[0.16em] text-text-2">
                  right now
                </span>
                <span className="font-body text-[16px] leading-[1.55] text-text-1">
                  {views.length} chambers attached · {activeCount} running · {fleet!.nodesOnline}/
                  {fleet!.nodesTotal} nodes online
                </span>
                <span className="ml-auto flex items-center gap-2">
                  <span className={cn(STATUS_PILL_BASE, STATUS_PILL_TONE.signal)}>{activeCount} active</span>
                  {warnCount > 0 && (
                    <span className={cn(STATUS_PILL_BASE, STATUS_PILL_TONE.warn)}>{warnCount} warn</span>
                  )}
                  {errCount > 0 && (
                    <span className={cn(STATUS_PILL_BASE, STATUS_PILL_TONE.err)}>{errCount} err</span>
                  )}
                </span>
              </section>

              {/* ---------- KPI strip (GET /api/health/detail/system + /api/cloud/status) ---------- */}
              <section
                className="grid grid-cols-[repeat(auto-fit,minmax(160px,1fr))] gap-3"
                aria-label="Pi system KPIs"
              >
                {sysError && !sys ? (
                  <p className="font-mono text-[13px] tracking-[0.05em] text-err">
                    Failed to load Pi system health: {sysError}
                  </p>
                ) : (
                  kpis.map((kpi) => {
                    const toneColor =
                      kpi.tone === "signal" ? "text-signal" : kpi.tone === "accent" ? "text-accent" : null;
                    return (
                      <div
                        key={kpi.label}
                        className="flex min-h-[140px] flex-col gap-2.5 rounded-md border border-border-soft bg-bg-1 px-7 py-[26px]"
                      >
                        <span
                          className={cn(
                            "font-mono text-[13px] font-medium uppercase tracking-[0.14em]",
                            toneColor ?? "text-text-2",
                          )}
                        >
                          {kpi.label}
                        </span>
                        <span
                          className={cn(
                            "font-mono text-[44px] leading-none tracking-[-0.005em]",
                            toneColor ?? "text-text-0",
                          )}
                        >
                          {kpi.value}
                          {kpi.unit && <span className="ml-1.5 text-[18px] text-text-2">{kpi.unit}</span>}
                        </span>
                        {kpi.delta && (
                          <span className="font-mono text-[14px] tracking-[0.04em] text-text-2">{kpi.delta}</span>
                        )}
                      </div>
                    );
                  })
                )}
              </section>

              {/* ---------- System sparklines (polled, accumulated client-side) ---------- */}
              <section
                className="flex flex-col gap-[18px] rounded-md border border-border-soft bg-bg-1 p-[26px]"
                aria-label="Pi system trace · live"
              >
                <div className="mb-1.5 font-mono text-[15px] font-medium uppercase tracking-[0.16em] text-text-2">
                  Pi system · live
                </div>
                <Sparkline
                  channel="temp"
                  values={sysTrace.cpu}
                  label="cpu %"
                  display={sys ? String(Math.round(sys.system.cpu_percent)) : "—"}
                />
                <Sparkline
                  channel="hum"
                  values={sysTrace.mem}
                  label="ram %"
                  display={sys ? String(Math.round(sys.system.memory_percent)) : "—"}
                />
                <Sparkline
                  channel="co2"
                  values={sysTrace.temp}
                  label="temp °C"
                  display={sys?.system.cpu_temp_c != null ? String(Math.round(sys.system.cpu_temp_c)) : "—"}
                />
              </section>

              {/* ---------- Local fleet grid (GET /api/chambers + telemetry/latest) ---------- */}
              <section aria-label="Local fleet">
                <div className="mb-2.5 font-mono text-[13px] font-medium uppercase tracking-[0.16em] text-text-2">
                  Chambers
                </div>
                {views.length === 0 ? (
                  <p className="font-mono text-[13px] tracking-[0.05em] text-text-2">
                    No chambers configured on this Pi yet.
                  </p>
                ) : (
                  <div className="grid auto-rows-[252px] grid-cols-[repeat(auto-fit,minmax(320px,1fr))] gap-2.5">
                    {views.map((v) => {
                      const c = v.tile;
                      const offset = ((c.id.charCodeAt(c.id.length - 1) * 37) % 300) / 100;
                      return (
                        <div key={c.id} className="block h-full min-w-0">
                          <FleetTile
                            chamber={c}
                            large
                            pulseOffsetSec={offset}
                            onSelect={onSelect}
                            selected={c.id === overrideTargetId}
                          />
                        </div>
                      );
                    })}
                  </div>
                )}
              </section>

              {/* ---------- Quick actuator overrides ---------- */}
              {overrideView && overrides && (
                <section
                  className="flex flex-col gap-[18px] rounded-md border border-border-soft bg-bg-1 p-[26px]"
                  aria-label="Quick overrides"
                >
                  <div className="mb-1.5 flex items-center justify-between gap-3 font-mono text-[15px] font-medium uppercase tracking-[0.16em] text-text-2">
                    <span>Quick overrides · {overrideView.tile.id}</span>
                    <Select value={overrideTargetId} onValueChange={switchOverrideTarget}>
                      <SelectTrigger aria-label="select chamber to override" className="w-[200px] normal-case">
                        <span className="min-w-0 flex-1 truncate text-left">
                          <SelectValue />
                        </span>
                      </SelectTrigger>
                      <SelectContent>
                        {views.map((v) => (
                          <SelectItem key={v.tile.id} value={v.tile.id}>
                            {v.tile.id} · {v.tile.species.common}
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>
                  <p className="-mt-1 font-body text-[16px] leading-[1.55] text-text-1">
                    5-minute manual pin. Rule automation pauses for the override window. Tap a tile above to switch
                    target.
                  </p>
                  {/* The 5-column ActuatorRow (design-owned, repeat(5,1fr) + overflow:hidden)
                      needs ~640px and can't shrink its tracks below content. At ≤1180px the
                      shell collapses to a ~544px column, so instead of overflowing the page
                      (or clipping the 5th actuator) the strip scrolls horizontally within
                      itself — every control stays reachable, page overflow gone. Inert at
                      wide widths where the row already fits. */}
                  <div className="min-w-0 max-[1180px]:overflow-x-auto max-[1180px]:[&>div]:w-max">
                    <ActuatorRow actuators={overrides} editable onOverride={(k) => void applyOverride(k)} />
                  </div>
                  {overrideError && (
                    <p className="font-mono text-[13px] tracking-[0.05em] text-err">{overrideError}</p>
                  )}
                  <div className="flex items-center justify-end gap-3">
                    <Button variant="link" size="sm" onClick={() => onSelect(overrideView.tile.id)}>
                      open {overrideView.tile.id} →
                    </Button>
                  </div>
                </section>
              )}

              {/* ---------- Recent fleet alerts ---------- */}
              <section
                className="flex flex-col gap-[18px] rounded-md border border-border-soft bg-bg-1 p-[26px]"
                aria-label="Recent alerts"
              >
                <div className="mb-1.5 font-mono text-[15px] font-medium uppercase tracking-[0.16em] text-text-2">
                  Recent alerts
                </div>
                {/* TODO(wire): no Pi-side alert-history endpoint — node alerts
                    go out via ntfy push and are forwarded to the cloud relay;
                    metric alert history lives in the cloud app. */}
                <p className="font-mono text-[13px] tracking-[0.05em] text-text-2">
                  No local alert history on this Pi — alerts page via ntfy and the cloud app.
                </p>
              </section>
            </>
          )}
        </main>

        {/* ---------- Right rail ---------- */}
        <aside className="flex flex-col gap-3.5">
          {/* Pi system rows (GET /api/health/detail/system + /api/cloud/status).
              Renders the PiHealthPanel classes directly: the design component's
              PiHealth prop requires an uplink row, and the Pi server has no
              network-interface endpoint to populate it honestly.
              TODO(wire): uplink row omitted for that reason. */}
          {sys ? (
            <div className="pi-health" aria-label="Pi system health">
              <div className="pi-head">Pi system</div>
              <PiRow k="cpu" cls={pctTone(sys.system.cpu_percent)} value={String(Math.round(sys.system.cpu_percent))} unit="%" />
              <PiRow k="mem" cls={pctTone(sys.system.memory_percent)} value={String(Math.round(sys.system.memory_percent))} unit="%" />
              <PiRow k="disk" cls={pctTone(sys.system.disk_percent)} value={String(Math.round(sys.system.disk_percent))} unit="%" />
              {sys.system.cpu_temp_c != null && (
                <PiRow k="temp" cls={tempTone(sys.system.cpu_temp_c)} value={String(Math.round(sys.system.cpu_temp_c))} unit="°C" />
              )}
              {!sys.cloud.configured ? (
                <PiRow k="cloud" cls="warn" value="not configured" dot="warn" />
              ) : sys.cloud.connected && sys.cloud.queue_depth === 0 ? (
                <PiRow k="cloud" cls="ok" value="synced" dot="accent" />
              ) : sys.cloud.connected ? (
                <PiRow k="cloud" cls="warn" value={`syncing · ${sys.cloud.queue_depth} pending`} dot="warn" />
              ) : (
                <PiRow k="cloud" cls="err" value={`offline · ${sys.cloud.queue_depth} pending`} dot="err" />
              )}
            </div>
          ) : (
            <p className="font-mono text-[13px] tracking-[0.05em] text-text-2">
              {sysError ? `Pi system health unavailable: ${sysError}` : "Loading Pi system health…"}
            </p>
          )}

          {/* Network / broker (GET /api/health/detail/mqtt + clients + system.reliability) */}
          <section
            className="flex flex-col gap-[18px] rounded-md border border-border-soft bg-bg-1 p-[26px]"
            aria-label="Network"
          >
            <div className="mb-1.5 font-mono text-[15px] font-medium uppercase tracking-[0.16em] text-text-2">
              Network
            </div>
            {sys && (
              <>
                <NetRow k="connections" v={String(sys.clients)} sub="socket.io" />
                {sys.system.reliability && (
                  <>
                    <NetRow k="mqtt restarts" v={String(sys.system.reliability.mqtt_supervisor_restarts)} />
                    <NetRow k="ts clamps" v={String(sys.system.reliability.uptime_ts_clamps)} />
                  </>
                )}
                {mqttEntries.map(([k, v]) => (
                  <NetRow key={k} k={k} v={String(v)} />
                ))}
                {mqttEntries.length === 0 && (
                  // TODO(wire): GET /api/health/detail/mqtt serves the $SYS
                  // broker-stat cache, but nothing on the server populates it
                  // (health.service.update_mqtt_stat has no caller) — so the
                  // broker host/rtt/packet rows of the old fake panel have no
                  // real source and are omitted.
                  <NetRow k="broker $SYS" v="not reported" />
                )}
              </>
            )}
          </section>

          {/* Live event feed ← GET /api/sessions/{id}/events across active grows */}
          <section
            className="flex flex-col gap-[18px] rounded-md border border-border-soft bg-bg-1 p-0"
            aria-label="Live event feed"
          >
            {fleet && fleet.events.length > 0 ? (
              <EventFeed events={fleet.events} title="Live events" />
            ) : (
              <p className="p-[26px] font-mono text-[13px] tracking-[0.05em] text-text-2">
                No session events yet — the feed fills once a grow is running.
              </p>
            )}
          </section>
        </aside>
      </div>
    </>
  );
}

// ---------- Helpers ----------

function PiRow({
  k,
  cls,
  value,
  unit,
  dot,
}: {
  k: string;
  cls: "ok" | "warn" | "err";
  value: string;
  unit?: string;
  dot?: string;
}) {
  return (
    <div className="pi-row">
      <span className="k">{k}</span>
      <span className={`v ${cls}`}>
        {dot && <span className={`dot ${dot}`} />}
        <span>{value}</span>
        {unit && <span className="u">{unit}</span>}
      </span>
    </div>
  );
}

function NetRow({
  k,
  v,
  sub,
  tone,
}: {
  k: string;
  v: string;
  sub?: string;
  tone?: "ok" | "warn" | "err";
}) {
  const valueColor =
    tone === "err"
      ? "text-err"
      : tone === "warn"
        ? "text-warn"
        : tone === "ok"
          ? "text-signal"
          : "text-text-0";
  return (
    <div className="grid grid-cols-[1fr_auto] items-baseline gap-3 border-t border-border-soft py-2.5">
      <span className="font-mono text-[13px] uppercase tracking-[0.1em] text-text-2">{k}</span>
      <span className="flex items-baseline gap-2">
        <span className={cn("font-mono text-[14px]", valueColor)}>{v}</span>
        {sub && <span className="font-mono text-[13px] tracking-[0.05em] text-text-2">· {sub}</span>}
      </span>
    </div>
  );
}
