"use client";
import type { ReactNode } from "react";
import { cn } from "../lib/cn";

type ChipTone = "accent" | "signal" | "warn" | "err" | "idle" | "default";

// Engine choice: kept the legacy `status-pill`/tone/`idle` classes (already
// button-compatible — see `.status-pill[role="button"], button.status-pill`
// in components.css) rather than switching to `badgeVariants`, so the
// existing appearance is byte-for-byte unchanged. New token utilities
// (transition) are layered on via `cn` alongside them; focus falls back to
// the global `:focus-visible` saffron outline defined in theme.css.
export function Chip({
  active = false,
  count,
  tone = "default",
  onClick,
  type = "button",
  children,
  ariaLabel,
}: {
  active?: boolean;
  count?: number;
  tone?: ChipTone;
  onClick?: () => void;
  type?: "button" | "submit";
  children: ReactNode;
  ariaLabel?: string;
}) {
  const legacyCls = active
    ? `status-pill ${tone === "default" ? "accent" : tone}`
    : "status-pill idle";
  return (
    <button
      type={type}
      className={cn(
        legacyCls,
        "transition-colors duration-200 ease-brand",
      )}
      aria-pressed={active}
      aria-label={ariaLabel}
      onClick={onClick}
      style={{ cursor: "pointer", appearance: "none", padding: "6px 14px" }}
    >
      <span>{children}</span>
      {count !== undefined && (
        <span className="t-mono-sm" style={{ marginLeft: 6 }}>
          {count}
        </span>
      )}
    </button>
  );
}

export function ChipGroup({
  label,
  children,
}: {
  label?: string;
  children: ReactNode;
}) {
  return (
    <div className={cn("row-8")} role="group" aria-label={label}>
      {label && <span className="t-label" style={{ marginBottom: 0 }}>{label}</span>}
      <div className="cluster">{children}</div>
    </div>
  );
}
