import type { ChannelTrace } from "../data/types";

const CHANNEL_LABEL = {
  temp: "Temperature",
  hum: "Humidity",
  co2: "CO₂",
  vpd: "VPD",
} as const;

const CHANNEL_NUM = {
  temp: "01",
  hum: "02",
  co2: "03",
  vpd: "04",
} as const;

const UNITS = {
  temp: "°F",
  hum: "%",
  co2: "ppm",
  vpd: "kPa",
} as const;

interface Props {
  channel: "temp" | "hum" | "co2" | "vpd";
  trace: ChannelTrace;
  /** Now-value displayed on the right rail. */
  nowValue: string;
  /** Sub-text on the right rail (e.g. "mister · 9 cycles"). */
  delta?: string;
  /** Indicates the delta should glow accent (humidity during mister). */
  deltaActive?: boolean;
  /** Optional override of legend range. */
  rangeLabel?: string;
}

/**
 * One channel of the chamber-history scope per components.md §8.
 * SVG is hand-rolled — recharts/chart.js fight the aesthetic.
 */
export function TraceRow({ channel, trace, nowValue, delta, deltaActive, rangeLabel }: Props) {
  const W = 1000;
  const H = 92;
  const PAD_T = 6;
  const PAD_B = 6;
  const inner = H - PAD_T - PAD_B;
  const [lo, hi] = trace.range;
  const span = Math.max(1e-6, hi - lo);
  const n = trace.samples.length;

  const linePoints = trace.samples
    .map((s, i) => {
      const x = (i / Math.max(1, n - 1)) * W;
      const y = PAD_T + inner - ((s.v - lo) / span) * inner;
      return `${i === 0 ? "M" : "L"} ${x.toFixed(1)} ${y.toFixed(1)}`;
    })
    .join(" ");

  // Area path for fill — close down to the baseline
  const areaPoints = `${linePoints} L ${W} ${H - PAD_B} L 0 ${H - PAD_B} Z`;

  // Hairline at "now" = last sample
  const hairX = W - 8;

  return (
    <div className={`t-row ${channel}`}>
      <div className="legend">
        <div className="k">channel · {CHANNEL_NUM[channel]}</div>
        <div className="name">{CHANNEL_LABEL[channel]}</div>
        <div className="range">{rangeLabel ?? `${lo} – ${hi} ${UNITS[channel]}`}</div>
      </div>
      <div className="scope">
        <svg viewBox={`0 0 ${W} ${H}`} preserveAspectRatio="none" aria-hidden>
          {/* horizontal grid */}
          <line className="t-grid" x1={0} y1={PAD_T + inner * 0.25} x2={W} y2={PAD_T + inner * 0.25} />
          <line className="t-grid" x1={0} y1={PAD_T + inner * 0.5} x2={W} y2={PAD_T + inner * 0.5} />
          <line className="t-grid" x1={0} y1={PAD_T + inner * 0.75} x2={W} y2={PAD_T + inner * 0.75} />
          {/* event ticks */}
          {trace.ticks.map((t) => {
            const x = (t / Math.max(1, n - 1)) * W;
            return (
              <line key={`tick-${t}`} className="t-tick" x1={x} y1={PAD_T} x2={x} y2={H - PAD_B} />
            );
          })}
          {/* fill */}
          <path className="t-line-area" d={areaPoints} />
          {/* line */}
          <path className="t-line" d={linePoints} />
          {/* hair at now */}
          <line className="t-hair" x1={hairX} y1={PAD_T} x2={hairX} y2={H - PAD_B} />
        </svg>
      </div>
      <div className="readout">
        <div className="now">
          {nowValue}
          <span className="u">{UNITS[channel]}</span>
        </div>
        {delta && (
          <div className="delta">
            <span className={deltaActive ? "on" : ""}>{delta}</span>
          </div>
        )}
      </div>
    </div>
  );
}
