import type { ReactNode } from "react";
import { Logo } from "./Logo";

export function PublicTopBar({
  brand,
  rightNav,
}: {
  brand?: { word: string; suffix?: string };
  rightNav?: ReactNode;
}) {
  const word = brand?.word ?? "sporeprint";
  const suffix = brand?.suffix ?? ".ai";
  return (
    <header
      className="row-between"
      style={{
        padding: "26px 40px",
        borderBottom: "1px solid var(--border-soft)",
        background: "var(--bg-1)",
      }}
    >
      <a
        href="/"
        className="row-12"
        style={{ textDecoration: "none", color: "inherit" }}
        aria-label={`${word}${suffix} home`}
      >
        <Logo size={32} opts={{ color: "var(--accent)" }} />
        <span className="sidebar-brand-word">{word}</span>
        <span className="t-mono t-muted">{suffix}</span>
      </a>
      {rightNav && <nav className="row-16">{rightNav}</nav>}
    </header>
  );
}
