// Real Pi culture row (GET /api/cultures — see server/app/cultures/service.py
// + the `cultures` table in server/app/db.py). Replaces the former CultureStub
// fixture: the Pi tracks type/source/generation/status, not a cultivar "strain"
// label or a 1–5 vigour rating.
interface PiCulture {
  id: number;
  type: string;
  parent_id: number | null;
  species_profile_id: string;
  source: string;
  vendor_name: string | null;
  lot_number: string | null;
  generation: number;
  status: string;
  notes: string | null;
  spore_print_quality: string | null;
  tissue_source_location: string | null;
  storage_location: string | null;
  created_at: number;
}

interface LineageResponse {
  culture: PiCulture;
  ancestors: PiCulture[];
  descendants: PiCulture[];
  contamination_rate: number;
  total_children: number;
  contaminated_children: number;
}

// Culture `type` values accepted by the server's CultureCreate model.
const CULTURE_TYPES = [
  "spore_syringe",
  "agar",
  "liquid_culture",
  "grain_spawn",
  "sawdust_spawn",
  "spore_print",
  "tissue_clone",
] as const;

const TYPE_LABEL: Record<string, string> = {
  spore_syringe: "spore syringe",
  agar: "agar plate",
  liquid_culture: "liquid culture",
  grain_spawn: "grain spawn",
  sawdust_spawn: "sawdust spawn",
  spore_print: "spore print",
  tissue_clone: "tissue clone",
};
const TYPE_TONE: Record<string, "signal" | "accent" | "warn"> = {
  spore_syringe: "warn",
  agar: "signal",
  liquid_culture: "accent",
  grain_spawn: "warn",
  sawdust_spawn: "warn",
  spore_print: "signal",
  tissue_clone: "accent",
};
function typeLabel(t: string): string {
  return TYPE_LABEL[t] ?? t;
}
function typeTone(t: string): "signal" | "accent" | "warn" {
  return TYPE_TONE[t] ?? "signal";
}

// The transfer form's coarse "new kind" picker maps onto server culture types.
const KIND_TO_TYPE: Record<string, string> = {
  agar: "agar",
  lc: "liquid_culture",
  spawn: "grain_spawn",
};

const CULTURE_SOURCES = ["vendor", "clone", "spore_print", "transfer"] as const;

// `.status-pill` base + tone (classmap §10) — self-sufficient tones per
// Binding Lesson 3. Same resolved strings as FleetPage/SessionsPage.
const STATUS_PILL_BASE =
  "inline-flex items-center gap-[7px] rounded-pill border px-3 py-[5px] font-mono text-[12px] font-medium uppercase tracking-widest";
const STATUS_PILL_TONE = {
  accent: "border-accent-line bg-accent-soft text-accent",
  signal: "border-signal/40 bg-signal-soft text-signal",
  warn: "border-warn bg-bg-2 text-warn",
} as const;
function statusPill(tone: keyof typeof STATUS_PILL_TONE): string {
  return cn(STATUS_PILL_BASE, STATUS_PILL_TONE[tone]);
}

const STATUS_TONE: Record<string, keyof typeof STATUS_PILL_TONE> = {
  active: "signal",
  contaminated: "warn",
  depleted: "warn",
  archived: "accent",
};

// Hand-rolled `.data-table` cascade (classmap §9).
const TH =
  "text-left py-3.5 px-[18px] font-mono text-[12px] font-medium tracking-[0.14em] uppercase text-text-2 border-b border-border-soft bg-bg-1";
const TD = "py-3.5 px-[18px] border-t border-border-soft align-middle";

const REFRESH_AGE_DAYS = 120;

function ageDaysOf(c: PiCulture): number {
  return Math.max(0, Math.floor((Date.now() - c.created_at * 1000) / 86_400_000));
}
function createdOnOf(c: PiCulture): string {
  return new Date(c.created_at * 1000).toISOString().slice(0, 10);
}
function speciesOf(id: string): { binomial: string; common: string } {
  const sp = SPECIES_LIBRARY.find((s) => s.id === id);
  return { binomial: sp?.binomial ?? "", common: sp?.common ?? id };
}
function refreshDue(c: PiCulture): boolean {
  return ageDaysOf(c) >= REFRESH_AGE_DAYS;
}

interface TreeNode {
  culture: PiCulture;
  children: TreeNode[];
}

// Build the selected culture's lineage (ancestors + self + descendants) into a
// tree, rooted at the topmost ancestor. Replaces the former client-side forest
// over every culture — the tree now comes from GET /api/cultures/{id}/lineage.
function buildLineageTree(lin: LineageResponse): TreeNode[] {
  const all = [...lin.ancestors, lin.culture, ...lin.descendants];
  const ids = new Set(all.map((c) => c.id));
  const roots = all.filter((c) => c.parent_id == null || !ids.has(c.parent_id));
  const build = (nodes: PiCulture[]): TreeNode[] =>
    nodes.map((c) => ({
      culture: c,
      children: build(all.filter((x) => x.parent_id === c.id)),
    }));
  return build(roots);
}

export function CulturesPage() {
  const [refreshKey, setRefreshKey] = useState(0);
  const [selectedId, setSelectedId] = useState<number | null>(null);
  const [showNew, setShowNew] = useState(false);

  const { data: cultures, error: loadError } = usePiLoad(async () => {
    const rows = await apiGet<PiCulture[]>("/api/cultures");
    // Seed/repair the selection inside the loader so it lands in the same
    // commit as the rows (batches with the hook's setState).
    setSelectedId((prev) =>
      prev != null && rows.some((c) => c.id === prev) ? prev : rows[0]?.id ?? null,
    );
    return rows;
  }, [refreshKey]);

  const refresh = useCallback(() => setRefreshKey((k) => k + 1), []);

  const list = cultures ?? [];
  // Derived (not the hook's flag) so a refreshKey reload keeps showing the
  // current list instead of flashing "Loading…" — same as before.
  const loading = cultures === null;
  const selected = useMemo(
    () => list.find((c) => c.id === selectedId) ?? null,
    [list, selectedId],
  );
  const refreshCount = useMemo(() => list.filter(refreshDue).length, [list]);

  return (
    <>
      <PiTopBar
        crumbs={[{ label: "track" }, { label: "cultures", active: true }]}
        right={<CloudSyncIndicator cloud={PI_HEALTH.cloud} />}
      />

      <PageHeader
        eyebrow="Track"
        title="Cultures"
        italic={false}
        meta={
          <span>
            {list.length} cultures · {refreshCount} flagged for refresh · ancestry cached for offline browsing
          </span>
        }
        right={
          <Button type="button" variant={showNew ? "ghost" : "solid"} onClick={() => setShowNew((v) => !v)}>
            {showNew ? "cancel" : "+ new culture →"}
          </Button>
        }
      />

      <div className="grid grid-cols-[1fr_400px] gap-[22px] px-7 pt-[22px] pb-7 max-[1180px]:grid-cols-1">
        <main className="flex flex-col gap-3.5 max-[1180px]:min-w-0">
          {showNew && (
            <NewCultureForm
              onClose={() => setShowNew(false)}
              onCreated={() => {
                setShowNew(false);
                refresh();
              }}
            />
          )}

          {loadError ? (
            <p className="font-mono text-[13px] tracking-[0.05em] text-err">
              Failed to load cultures: {loadError}
            </p>
          ) : loading ? (
            <p className="font-mono text-[13px] tracking-[0.05em] text-text-2">Loading…</p>
          ) : list.length === 0 ? (
            <p className="font-mono text-[13px] tracking-[0.05em] text-text-2">
              No cultures yet — start one with “+ new culture”.
            </p>
          ) : (
            <div className="max-[1180px]:min-w-0 max-[1180px]:overflow-x-auto">
              <table className="w-full border-collapse overflow-hidden rounded-md border border-border-soft bg-bg-1 font-body text-[15px] text-text-1">
                <thead>
                  <tr>
                    <th scope="col" className={TH}>ID</th>
                    <th scope="col" className={TH}>Species</th>
                    <th scope="col" className={TH}>Kind</th>
                    <th scope="col" className={`${TH} text-right`}>Age</th>
                    <th scope="col" className={`${TH} text-right`}>Gen</th>
                    <th scope="col" className={TH}>Parent</th>
                    <th scope="col" className={TH}>Status</th>
                  </tr>
                </thead>
                <tbody>
                  {list.map((c) => {
                    const isSel = selectedId === c.id;
                    const sp = speciesOf(c.species_profile_id);
                    const tone = STATUS_TONE[c.status] ?? "signal";
                    return (
                      <tr
                        key={c.id}
                        onClick={() => setSelectedId(c.id)}
                        className={cn("cursor-pointer", isSel ? "bg-bg-2" : "hover:bg-bg-2")}
                      >
                        <td className={cn(TD, "font-mono text-text-0")}>#{c.id}</td>
                        <td className={cn(TD, "font-body text-text-0")}>{sp.common}</td>
                        <td className={TD}><span className={statusPill(typeTone(c.type))}>{typeLabel(c.type)}</span></td>
                        <td className={cn(TD, "text-right font-mono text-text-0")}>{ageDaysOf(c)}d</td>
                        <td className={cn(TD, "text-right font-mono text-text-0")}>G{c.generation}</td>
                        <td className={cn(TD, "font-mono text-text-0")}>{c.parent_id != null ? `#${c.parent_id}` : "—"}</td>
                        <td className={TD}><span className={statusPill(tone)}>{c.status}</span></td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          )}

          {selectedId != null && (
            <LineageSection cultureId={selectedId} selectedId={selectedId} onSelect={setSelectedId} />
          )}
        </main>

        <aside className="flex flex-col gap-3.5">
          {selected && (
            <section className="flex flex-col gap-[18px] rounded-md border border-border-soft bg-bg-1 p-[26px]">
              <div className="mb-1.5 font-mono text-[15px] font-medium tracking-[0.16em] uppercase text-text-2">
                Selected · #{selected.id}
              </div>
              {/* Genuine binomial — serif italic per T7/T8 precedent. */}
              <h2 className="font-serif text-[26px] font-medium italic leading-[1.18] tracking-[-0.005em] text-text-0">
                {speciesOf(selected.species_profile_id).binomial || speciesOf(selected.species_profile_id).common}
              </h2>
              <span className="font-mono text-[12px] text-text-2">{speciesOf(selected.species_profile_id).common}</span>
              <div className="flex flex-col gap-2.5">
                <Row k="kind" v={typeLabel(selected.type)} />
                <Row k="source" v={selected.source} />
                <Row k="age" v={`${ageDaysOf(selected)}d`} />
                <Row k="gen" v={`G${selected.generation}`} />
                <Row k="parent" v={selected.parent_id != null ? `#${selected.parent_id}` : "—"} />
                <Row k="created" v={createdOnOf(selected)} />
                <Row k="status" v={selected.status} />
                <Row k="vendor" v={selected.vendor_name ?? "—"} />
                <Row k="storage" v={selected.storage_location ?? "—"} />
              </div>
              {selected.notes && (
                <p className="font-body text-[14px] leading-[1.55] text-text-2">↳ {selected.notes}</p>
              )}
              {refreshDue(selected) && (
                <div className="flex flex-col gap-1 rounded-sm border border-warn bg-[rgba(200,150,96,0.12)] p-3">
                  <span className="font-mono text-[13px] font-medium uppercase tracking-[0.16em] text-warn">
                    refresh due
                  </span>
                  <span className="font-body text-[14px] leading-[1.55] text-text-1">
                    Age past {REFRESH_AGE_DAYS}d — schedule a transfer to a fresh plate.
                  </span>
                </div>
              )}
            </section>
          )}

          <TransferSection cultures={list} onTransferred={refresh} />
        </aside>
      </div>
    </>
  );
}

// Lineage tree for the selected culture — fetched fresh from the server so it
// reflects real parent/child relationships, not a client-built forest.
function LineageSection({
  cultureId,
  selectedId,
  onSelect,
}: {
  cultureId: number;
  selectedId: number;
  onSelect: (id: number) => void;
}) {
  const [lineage, setLineage] = useState<LineageResponse | null>(null);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    let alive = true;
    setLineage(null);
    setError(null);
    apiGet<LineageResponse>(`/api/cultures/${cultureId}/lineage`)
      .then((res) => {
        if (alive) setLineage(res);
      })
      .catch((err) => {
        if (alive) setError(err instanceof Error ? err.message : "load failed");
      });
    return () => {
      alive = false;
    };
  }, [cultureId]);

  const tree = useMemo(() => (lineage ? buildLineageTree(lineage) : []), [lineage]);

  return (
    <section className="flex flex-col gap-[18px] rounded-md border border-border-soft bg-bg-1 p-[26px]">
      <div className="mb-1.5 font-mono text-[15px] font-medium tracking-[0.16em] uppercase text-text-2">
        Lineage tree
      </div>
      <span className="font-mono text-[12px] text-text-2">
        {lineage
          ? `${lineage.total_children} direct children · ${lineage.contamination_rate}% contaminated`
          : "click a row above to load its ancestry"}
      </span>
      {error ? (
        <span className="font-mono text-[12px] text-err">failed to load lineage: {error}</span>
      ) : !lineage ? (
        <span className="font-mono text-[12px] text-text-2">Loading…</span>
      ) : (
        <div className="font-mono text-[14px] leading-[1.7] text-text-1">
          {tree.map((n) => (
            <TreeBranch key={n.culture.id} node={n} selectedId={selectedId} onSelect={onSelect} />
          ))}
        </div>
      )}
    </section>
  );
}

// Fork off the next generation from an existing culture (POST /api/cultures with
// a parent_id — the server auto-computes generation from the parent chain).
function TransferSection({
  cultures,
  onTransferred,
}: {
  cultures: PiCulture[];
  onTransferred: () => void;
}) {
  const [parentId, setParentId] = useState<string>("");
  const [kind, setKind] = useState<string>("lc");
  const [note, setNote] = useState("");
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const canSubmit = parentId !== "" && !submitting;

  async function commit() {
    const parent = cultures.find((c) => String(c.id) === parentId);
    if (!parent) return;
    setSubmitting(true);
    setError(null);
    try {
      await apiSend<PiCulture>("/api/cultures", "POST", {
        type: KIND_TO_TYPE[kind] ?? "liquid_culture",
        species_profile_id: parent.species_profile_id,
        source: "transfer",
        parent_id: parent.id,
        notes: note.trim() || null,
      });
      setNote("");
      onTransferred();
    } catch (err) {
      setError(err instanceof Error ? err.message : "transfer failed");
    } finally {
      setSubmitting(false);
    }
  }

  return (
    <section className="flex flex-col gap-[18px] rounded-md border border-border-soft bg-bg-1 p-[26px]">
      <div className="mb-1.5 font-mono text-[15px] font-medium tracking-[0.16em] uppercase text-text-2">
        Transfer flow
      </div>
      <p className="font-body text-[14px] leading-[1.55] text-text-1">
        Take an existing plate or LC and fork off the next generation. The new culture inherits the
        parent’s species; pick a kind for the new entry.
      </p>
      <label className="flex flex-col gap-1.5">
        <span className="font-mono text-[12px] font-medium uppercase tracking-[0.14em] text-text-2">
          parent culture
        </span>
        <Select value={parentId} onValueChange={setParentId}>
          <SelectTrigger className="w-full" aria-label="parent culture">
            <span className="min-w-0 flex-1 truncate text-left">
              <SelectValue placeholder="pick a parent…" />
            </span>
          </SelectTrigger>
          <SelectContent>
            {cultures.map((c) => (
              <SelectItem key={c.id} value={String(c.id)}>
                <span className="font-mono text-text-0">#{c.id}</span> · {speciesOf(c.species_profile_id).common} · G{c.generation}
              </SelectItem>
            ))}
          </SelectContent>
        </Select>
      </label>
      <label className="flex flex-col gap-1.5">
        <span className="font-mono text-[12px] font-medium uppercase tracking-[0.14em] text-text-2">
          new kind
        </span>
        <Select value={kind} onValueChange={setKind}>
          <SelectTrigger className="w-full" aria-label="new kind">
            <span className="min-w-0 flex-1 truncate text-left">
              <SelectValue />
            </span>
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="agar">agar plate</SelectItem>
            <SelectItem value="lc">liquid culture</SelectItem>
            <SelectItem value="spawn">grain spawn</SelectItem>
          </SelectContent>
        </Select>
      </label>
      <label className="flex flex-col gap-1.5">
        <span className="font-mono text-[12px] font-medium uppercase tracking-[0.14em] text-text-2">
          note
        </span>
        <Input
          placeholder="e.g. selected fastest sector"
          value={note}
          onChange={(e) => setNote(e.target.value)}
        />
      </label>
      {error && <p className="font-mono text-[12px] text-err">{error}</p>}
      <Button
        type="button"
        variant="solid"
        className="self-start"
        onClick={commit}
        disabled={!canSubmit}
      >
        {submitting ? "recording…" : "record transfer →"}
      </Button>
    </section>
  );
}

function NewCultureForm({
  onClose,
  onCreated,
}: {
  onClose: () => void;
  onCreated: () => void;
}) {
  const [type, setType] = useState<string>("agar");
  const [speciesId, setSpeciesId] = useState(SPECIES_LIBRARY[0]?.id ?? "");
  const [source, setSource] = useState<string>("vendor");
  const [vendor, setVendor] = useState("");
  const [notes, setNotes] = useState("");
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);

  return (
    <form
      className="flex flex-col gap-3 rounded-md border border-border-soft bg-bg-1 p-[26px]"
      onSubmit={async (e) => {
        e.preventDefault();
        if (submitting) return;
        setSubmitting(true);
        setError(null);
        try {
          await apiSend<PiCulture>("/api/cultures", "POST", {
            type,
            species_profile_id: speciesId,
            source,
            vendor_name: vendor.trim() || null,
            notes: notes.trim() || null,
          });
          onCreated();
        } catch (err) {
          setError(err instanceof Error ? err.message : "create failed");
        } finally {
          setSubmitting(false);
        }
      }}
    >
      <div className="mb-1.5 font-mono text-[15px] font-medium tracking-[0.16em] uppercase text-text-2">New culture</div>
      <div className="grid grid-cols-[repeat(auto-fit,minmax(200px,1fr))] gap-3">
        <Field label="Type">
          <Select value={type} onValueChange={setType}>
            <SelectTrigger className="w-full" aria-label="type">
              <span className="min-w-0 flex-1 truncate text-left">
                <SelectValue />
              </span>
            </SelectTrigger>
            <SelectContent>
              {CULTURE_TYPES.map((t) => (
                <SelectItem key={t} value={t}>{typeLabel(t)}</SelectItem>
              ))}
            </SelectContent>
          </Select>
        </Field>
        <Field label="Species">
          <Select value={speciesId} onValueChange={setSpeciesId}>
            <SelectTrigger className="w-full" aria-label="species">
              <span className="min-w-0 flex-1 truncate text-left">
                <SelectValue placeholder="Select species…" />
              </span>
            </SelectTrigger>
            <SelectContent>
              {SPECIES_LIBRARY.map((s) => (
                <SelectItem key={s.id} value={s.id}>{s.common}</SelectItem>
              ))}
            </SelectContent>
          </Select>
        </Field>
        <Field label="Source">
          <Select value={source} onValueChange={setSource}>
            <SelectTrigger className="w-full" aria-label="source">
              <span className="min-w-0 flex-1 truncate text-left">
                <SelectValue />
              </span>
            </SelectTrigger>
            <SelectContent>
              {CULTURE_SOURCES.map((s) => (
                <SelectItem key={s} value={s}>{s.replace(/_/g, " ")}</SelectItem>
              ))}
            </SelectContent>
          </Select>
        </Field>
        <Field label="Vendor (optional)">
          <Input value={vendor} onChange={(e) => setVendor(e.target.value)} placeholder="e.g. North Spore" />
        </Field>
      </div>
      <Field label="Notes (optional)">
        <Input value={notes} onChange={(e) => setNotes(e.target.value)} placeholder="e.g. clean rhizomorphic growth" />
      </Field>
      {error && <p className="font-mono text-[12px] text-err">{error}</p>}
      <div className="flex items-center justify-end gap-2.5">
        <Button type="button" variant="ghost" onClick={onClose}>cancel</Button>
        <Button type="submit" disabled={submitting}>
          {submitting ? "creating…" : "create culture →"}
        </Button>
      </div>
    </form>
  );
}

function Field({ label, children }: { label: string; children: React.ReactNode }) {
  return (
    <label className="flex flex-col gap-1.5">
      <span className="font-mono text-[12px] font-medium tracking-[0.14em] uppercase text-text-2">{label}</span>
      {children}
    </label>
  );
}

function TreeBranch({
  node,
  selectedId,
  onSelect,
}: {
  node: TreeNode;
  selectedId: number;
  onSelect: (id: number) => void;
}) {
  const c = node.culture;
  const due = refreshDue(c);
  return (
    <div className="py-1">
      <button
        type="button"
        onClick={() => onSelect(c.id)}
        className={cn(
          "w-full cursor-pointer appearance-none rounded-sm border-none px-2 py-1 text-left",
          selectedId === c.id ? "bg-accent-soft" : "bg-transparent",
        )}
      >
        <span className="font-medium text-text-0">#{c.id}</span>
        <span className="ml-1.5 font-display italic text-text-0">{speciesOf(c.species_profile_id).common}</span>
        <span className="ml-2 text-text-2">
          · {typeLabel(c.type)} · G{c.generation} · {ageDaysOf(c)}d{due && <span className="ml-1.5 text-warn">refresh</span>}
        </span>
      </button>
      {node.children.length > 0 && (
        <div className="ml-2 border-l border-border-soft pl-6">
          {node.children.map((child) => (
            <TreeBranch key={child.culture.id} node={child} selectedId={selectedId} onSelect={onSelect} />
          ))}
        </div>
      )}
    </div>
  );
}

function Row({ k, v }: { k: string; v: string }) {
  return (
    <div className="flex items-baseline justify-between gap-3">
      <span className="font-mono text-[12px] font-medium tracking-[0.14em] uppercase text-text-2">{k}</span>
      <span className="font-mono text-[14px] text-text-1">{v}</span>
    </div>
  );
}
