"use client";
import type { ReactNode } from "react";
import { Dialog, DialogContent, DialogFooter } from "./ui/dialog";

/**
 * Legacy-API modal, rebuilt on the Dialog primitive (Radix).
 * Public props are frozen — do not add required props here; new
 * call-sites should use Dialog/DialogContent directly.
 */
export function Modal({
  open,
  onClose,
  title,
  children,
  footer,
  ariaDescribedBy,
}: {
  open: boolean;
  onClose: () => void;
  title: string;
  children: ReactNode;
  footer?: ReactNode;
  ariaDescribedBy?: string;
}) {
  return (
    <Dialog open={open} onOpenChange={(next) => { if (!next) onClose(); }}>
      <DialogContent title={title} aria-describedby={ariaDescribedBy} className="modal-card-next">
        {children}
        {footer && <DialogFooter className="justify-between">{footer}</DialogFooter>}
      </DialogContent>
    </Dialog>
  );
}
