import { useEffect, useMemo, useState } from "react";
import { Link } from "react-router-dom";
import {
  Button,
  CloudSyncIndicator,
  DataTable,
  Input,
  KpiCard,
  PageHeader,
  PI_HEALTH,
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
  SearchInput,
  cn,
} from "@sporeprint/design";
import { PiTopBar } from "../components/PiTopBar";
import { apiGet, apiSend } from "../lib/api";
import type { PiChamber, PiSession } from "../lib/pi-types";

// ── Real Pi API shapes ──────────────────────────────────────────
interface ChamberStats {
  chamber_id: number;
  lifetime_grows: number;
  completed_grows: number;
  contaminated_grows: number;
  contamination_rate: number; // 0–1
  contamination_event_count: number;
  total_wet_yield_g: number;
  total_dry_yield_g: number;
}
interface MaintenanceEntry {
  id: number;
  chamber_id: number;
  kind: string; // clean | calibrate | inspect | repair
  due_at: number | null;
  completed_at: number | null;
  notes: string | null;
  created_at: number;
}
interface ChamberPhoto {
  id: number;
  session_id: number | null;
  node_id: string;
  timestamp: number;
  resolution: string | null;
  analysis_claude: string | null;
  created_at: number;
}
const MAINTENANCE_KINDS = ["clean", "calibrate", "inspect", "repair"] as const;

const STATUS_PILL_BASE =
  "inline-flex items-center gap-[7px] font-mono text-[12px] font-medium tracking-widest uppercase rounded-pill py-[5px] px-3 border";
const STATUS_PILL_TONE = {
  accent: "text-accent bg-accent-soft border-accent-line",
  signal: "text-signal bg-signal-soft border-signal/40",
  warn: "text-warn bg-bg-2 border-warn",
  err: "text-err bg-bg-2 border-err",
  idle: "text-text-3 bg-bg-2 border-border",
} as const;
function statusPill(tone: keyof typeof STATUS_PILL_TONE): string {
  return `${STATUS_PILL_BASE} ${STATUS_PILL_TONE[tone]}`;
}

function fmtTs(ts: number | null): string {
  if (!ts) return "—";
  return new Date(ts * 1000).toLocaleString(undefined, {
    month: "short",
    day: "numeric",
    hour: "2-digit",
    minute: "2-digit",
  });
}

export function ChambersInventoryPage() {
  const [chambers, setChambers] = useState<PiChamber[] | null>(null);
  const [loadError, setLoadError] = useState<string | null>(null);
  const [statsById, setStatsById] = useState<Record<number, ChamberStats>>({});
  const [sessionsById, setSessionsById] = useState<Record<number, PiSession>>({});
  const [query, setQuery] = useState("");
  const [selectedId, setSelectedId] = useState<number | null>(null);
  const [showSchedule, setShowSchedule] = useState(false);

  // Two-phase load (chambers paint first, stats/phases fill in after), so
  // this page keeps its custom effect rather than usePiLoad.
  useEffect(() => {
    let alive = true;
    setLoadError(null);
    apiGet<PiChamber[]>("/api/chambers")
      .then(async (rows) => {
        if (!alive) return;
        setChambers(rows);
        setSelectedId((cur) => cur ?? rows[0]?.id ?? null);
        // Lifetime stats per chamber (parallel — no batch /stats endpoint).
        const stats = await Promise.all(
          rows.map((c) =>
            apiGet<ChamberStats>(`/api/chambers/${c.id}/stats`)
              .then((s) => [c.id, s] as const)
              .catch(() => null),
          ),
        );
        // Active-session phases: one sessions list indexed by id replaces the
        // former per-active-chamber GET /api/sessions/{id} loop.
        const sessions = await apiGet<PiSession[]>("/api/sessions").catch(() => [] as PiSession[]);
        if (!alive) return;
        setStatsById(Object.fromEntries(stats.filter((x): x is readonly [number, ChamberStats] => x !== null)));
        setSessionsById(Object.fromEntries(sessions.map((s) => [s.id, s])));
      })
      .catch((err) => {
        if (alive) {
          setChambers([]);
          setLoadError(err instanceof Error ? err.message : "fetch failed");
        }
      });
    return () => {
      alive = false;
    };
  }, []);

  const allLocal = useMemo(() => chambers ?? [], [chambers]);

  const filtered = useMemo(() => {
    const q = query.trim().toLowerCase();
    if (!q) return allLocal;
    return allLocal.filter((c) => [c.name, c.description ?? ""].join(" ").toLowerCase().includes(q));
  }, [allLocal, query]);

  const selected = useMemo(
    () => filtered.find((c) => c.id === selectedId) ?? filtered[0] ?? allLocal[0] ?? null,
    [filtered, selectedId, allLocal],
  );

  const kpis = useMemo(() => {
    const statList = Object.values(statsById);
    const grows = statList.reduce((n, s) => n + s.lifetime_grows, 0);
    const wet = statList.reduce((n, s) => n + s.total_wet_yield_g, 0);
    const contaminated = statList.reduce((n, s) => n + s.contaminated_grows, 0);
    const rate = grows > 0 ? contaminated / grows : 0;
    return { total: allLocal.length, grows, wet, rate };
  }, [statsById, allLocal]);

  function activePhase(c: PiChamber): string {
    if (c.active_session_id == null) return "idle";
    const s = sessionsById[c.active_session_id];
    return s ? s.current_phase.replace(/_/g, " ") : "active";
  }

  return (
    <>
      <PiTopBar
        crumbs={[{ label: "track" }, { label: "chambers", active: true }]}
        right={<CloudSyncIndicator cloud={PI_HEALTH.cloud} />}
      />

      <PageHeader
        eyebrow="Track"
        title="Chambers"
        italic={false}
        meta={
          <span>
            physical asset inventory · maintenance · lifetime stats · {filtered.length} of {allLocal.length} visible
          </span>
        }
        right={
          <Button
            variant={showSchedule ? "solid" : "ghost"}
            onClick={() => setShowSchedule((v) => !v)}
            disabled={selected === null}
          >
            {showSchedule ? "cancel" : "+ schedule maintenance"}
          </Button>
        }
      />

      <div className="grid grid-cols-[1fr_400px] gap-[22px] px-7 pt-[22px] pb-7 max-[1180px]:grid-cols-1">
        <main className="flex flex-col gap-3.5 max-[1180px]:min-w-0">
          <section className="grid grid-cols-[repeat(auto-fit,minmax(220px,1fr))] gap-3">
            <KpiCard label="chambers" value={kpis.total.toString()} />
            <KpiCard label="lifetime grows" value={kpis.grows.toString()} tone="signal" />
            <KpiCard label="wet yield" value={`${kpis.wet.toLocaleString()}g`} tone="accent" />
            <KpiCard label="contam rate" value={`${(kpis.rate * 100).toFixed(1)}%`} />
          </section>

          <section className="flex flex-row flex-wrap items-center gap-2 rounded-md border border-border-soft bg-bg-1 p-[26px]">
            <div className="flex-[1_1_240px] min-w-[200px]">
              <SearchInput
                value={query}
                onChange={setQuery}
                placeholder="search chamber name …"
                ariaLabel="search chambers"
              />
            </div>
          </section>

          {loadError ? (
            <p className="font-mono text-[13px] tracking-[0.05em] text-err">Failed to load chambers: {loadError}</p>
          ) : chambers === null ? (
            <p className="font-mono text-[13px] tracking-[0.05em] text-text-2">Loading…</p>
          ) : allLocal.length === 0 ? (
            <p className="font-mono text-[13px] tracking-[0.05em] text-text-2">
              No chambers configured on this Pi yet.
            </p>
          ) : (
            <div className="max-[1180px]:min-w-0 max-[1180px]:overflow-x-auto">
              <DataTable<PiChamber>
                rowKey={(c) => String(c.id)}
                onRowClick={(c) => setSelectedId(c.id)}
                columns={[
                  {
                    key: "name",
                    header: "Chamber",
                    render: (c) => (
                      <Link
                        to={`/chamber/${c.id}`}
                        className="font-mono text-[14px] tracking-normal text-accent no-underline cursor-pointer hover:text-text-0"
                        onClick={(e) => e.stopPropagation()}
                      >
                        {c.name}
                      </Link>
                    ),
                  },
                  { key: "nodes", header: "Nodes", align: "right", render: (c) => <>{c.node_ids.length}</> },
                  {
                    key: "active",
                    header: "Active",
                    render: (c) => (
                      <span className={statusPill(c.active_session_id != null ? "accent" : "idle")}>{activePhase(c)}</span>
                    ),
                  },
                  {
                    key: "grows",
                    header: "Lifetime grows",
                    align: "right",
                    render: (c) => <>{statsById[c.id]?.lifetime_grows ?? "—"}</>,
                  },
                  {
                    key: "yield",
                    header: "Wet yield",
                    align: "right",
                    render: (c) => {
                      const s = statsById[c.id];
                      return <>{s ? `${s.total_wet_yield_g.toLocaleString()}g` : "—"}</>;
                    },
                  },
                  {
                    key: "contam",
                    header: "Contam",
                    align: "right",
                    render: (c) => {
                      const s = statsById[c.id];
                      return <>{s ? `${(s.contamination_rate * 100).toFixed(1)}%` : "—"}</>;
                    },
                  },
                ]}
                rows={filtered}
              />
            </div>
          )}
        </main>

        {selected && (
          <DetailPanel
            chamber={selected}
            stats={statsById[selected.id] ?? null}
            showSchedule={showSchedule}
            onScheduled={() => setShowSchedule(false)}
          />
        )}
      </div>
    </>
  );
}

function Field({ label, children }: { label: string; children: React.ReactNode }) {
  return (
    <label className="flex flex-col gap-1.5">
      <span className="font-mono text-[12px] font-medium tracking-[0.14em] uppercase text-text-2">{label}</span>
      {children}
    </label>
  );
}

function DetailPanel({
  chamber,
  stats,
  showSchedule,
  onScheduled,
}: {
  chamber: PiChamber;
  stats: ChamberStats | null;
  showSchedule: boolean;
  onScheduled: () => void;
}) {
  const [maintenance, setMaintenance] = useState<MaintenanceEntry[] | null>(null);
  const [maintError, setMaintError] = useState<string | null>(null);
  const [photos, setPhotos] = useState<ChamberPhoto[] | null>(null);
  const [refresh, setRefresh] = useState(0);
  const [busy, setBusy] = useState(false);
  const [actionError, setActionError] = useState<string | null>(null);

  useEffect(() => {
    let alive = true;
    setMaintError(null);
    setMaintenance(null);
    setPhotos(null);
    apiGet<MaintenanceEntry[]>(`/api/chambers/${chamber.id}/maintenance`)
      .then((rows) => {
        if (alive) setMaintenance(rows);
      })
      .catch((err) => {
        if (alive) {
          setMaintenance([]);
          setMaintError(err instanceof Error ? err.message : "load failed");
        }
      });
    apiGet<ChamberPhoto[]>(`/api/chambers/${chamber.id}/photos?limit=6`)
      .then((rows) => {
        if (alive) setPhotos(rows);
      })
      .catch(() => {
        if (alive) setPhotos([]);
      });
    return () => {
      alive = false;
    };
  }, [chamber.id, refresh]);

  async function complete(entryId: number) {
    setBusy(true);
    setActionError(null);
    try {
      await apiSend(`/api/chambers/${chamber.id}/maintenance/${entryId}/complete`, "POST", {});
      setRefresh((k) => k + 1);
    } catch (err) {
      setActionError(err instanceof Error ? err.message : "action failed");
    } finally {
      setBusy(false);
    }
  }

  async function markCleaned() {
    setBusy(true);
    setActionError(null);
    try {
      const open = (maintenance ?? []).find((m) => m.kind === "clean" && m.completed_at == null);
      let entryId = open?.id;
      if (entryId === undefined) {
        // No outstanding clean entry — create one, then complete it.
        const created = await apiSend<MaintenanceEntry>(`/api/chambers/${chamber.id}/maintenance`, "POST", {
          kind: "clean",
          notes: "marked cleaned",
        });
        entryId = created.id;
      }
      await apiSend(`/api/chambers/${chamber.id}/maintenance/${entryId}/complete`, "POST", {});
      setRefresh((k) => k + 1);
    } catch (err) {
      setActionError(err instanceof Error ? err.message : "action failed");
    } finally {
      setBusy(false);
    }
  }

  return (
    <aside className="flex flex-col gap-3.5">
      <section className="flex flex-col gap-[18px] rounded-md border border-border-soft bg-bg-1 p-[26px]">
        <div className="mb-1.5 font-mono text-[15px] font-medium tracking-[0.16em] uppercase text-text-2">{chamber.name}</div>
        <span className="font-mono text-[12px] text-text-2">
          {chamber.description ?? "no description"} · {chamber.node_ids.length} node
          {chamber.node_ids.length === 1 ? "" : "s"} · added {fmtTs(chamber.created_at)}
        </span>

        {stats ? (
          <div className="grid grid-cols-2 gap-3">
            <KpiCard label="lifetime grows" value={stats.lifetime_grows.toString()} />
            <KpiCard label="completed" value={stats.completed_grows.toString()} tone="signal" />
            <KpiCard label="wet yield" value={`${stats.total_wet_yield_g.toLocaleString()}g`} tone="accent" />
            <KpiCard label="dry yield" value={`${stats.total_dry_yield_g.toLocaleString()}g`} />
            <KpiCard label="contam rate" value={`${(stats.contamination_rate * 100).toFixed(1)}%`} />
            <KpiCard label="contam events" value={stats.contamination_event_count.toString()} />
          </div>
        ) : (
          <span className="font-mono text-[12px] text-text-2">Loading stats…</span>
        )}

        <div className="flex items-center gap-2">
          <Button type="button" onClick={() => void markCleaned()} disabled={busy}>
            mark cleaned →
          </Button>
        </div>
        {actionError && <span className={cn(statusPill("err"), "self-start")}>{actionError}</span>}
      </section>

      {showSchedule && (
        <ScheduleForm
          chamber={chamber}
          onDone={() => {
            setRefresh((k) => k + 1);
            onScheduled();
          }}
        />
      )}

      <section className="flex flex-col gap-[18px] rounded-md border border-border-soft bg-bg-1 p-[26px]">
        <div className="mb-1.5 font-mono text-[15px] font-medium tracking-[0.16em] uppercase text-text-2">Maintenance log</div>
        {maintError ? (
          <p className="font-mono text-[13px] tracking-[0.05em] text-err">Failed to load: {maintError}</p>
        ) : maintenance === null ? (
          <p className="font-mono text-[12px] text-text-2">Loading…</p>
        ) : maintenance.length === 0 ? (
          <p className="font-mono text-[12px] text-text-2">No maintenance scheduled or logged for this chamber.</p>
        ) : (
          <ul className="flex flex-col gap-2 list-none p-0 m-0">
            {maintenance.map((m) => {
              const open = m.completed_at == null;
              return (
                <li
                  key={m.id}
                  className="flex items-center gap-3 rounded-sm border border-border-soft bg-bg-2 py-2.5 px-3"
                >
                  <span className={statusPill(open ? "warn" : "signal")}>{m.kind}</span>
                  <div className="min-w-0 flex-1">
                    <div className="font-mono text-[12px] text-text-2">
                      {open ? `due ${fmtTs(m.due_at)}` : `done ${fmtTs(m.completed_at)}`}
                    </div>
                    {m.notes && <div className="font-body text-[14px] leading-[1.4] text-text-1">{m.notes}</div>}
                  </div>
                  {open && (
                    <Button type="button" variant="ghost" size="sm" onClick={() => void complete(m.id)} disabled={busy}>
                      complete →
                    </Button>
                  )}
                </li>
              );
            })}
          </ul>
        )}
      </section>

      <section className="flex flex-col gap-[18px] rounded-md border border-border-soft bg-bg-1 p-[26px]">
        <div className="mb-1.5 font-mono text-[15px] font-medium tracking-[0.16em] uppercase text-text-2">Recent frames</div>
        {/* Photos derive from vision_frames captured by this chamber's nodes.
            The Pi serves no frame-image URL (file_path is a local path), so
            these tiles show real capture metadata, not the pixels — same
            honest treatment as VisionPage's timelapse strip. */}
        {photos === null ? (
          <p className="font-mono text-[12px] text-text-2">Loading…</p>
        ) : photos.length === 0 ? (
          <p className="font-mono text-[12px] text-text-2">
            No camera frames from this chamber&rsquo;s nodes yet.
          </p>
        ) : (
          <div className="grid grid-cols-2 gap-3">
            {photos.map((p) => (
              <div key={p.id} className="flex flex-col overflow-hidden rounded-md border border-border-soft bg-bg-1">
                <div className="flex aspect-[4/3] items-end justify-start border-b border-border-soft bg-[radial-gradient(circle_at_30%_30%,var(--bg-2),var(--bg-0))] p-2 font-mono text-[12px] text-text-3">
                  {p.resolution ?? "frame"}
                </div>
                <div className="flex flex-col gap-1 px-3 py-2.5">
                  <span className="font-mono text-[12px] text-text-1">{fmtTs(p.timestamp)}</span>
                  <span className="font-mono text-[12px] text-text-3">
                    {p.node_id}
                    {p.analysis_claude ? " · analyzed" : ""}
                  </span>
                </div>
              </div>
            ))}
          </div>
        )}
      </section>

      {/* TODO(wire): sensor-calibration history has no Pi backend — the Pi
          exposes no per-sensor calibration/drift log, so that section is
          omitted rather than fabricated. */}
    </aside>
  );
}

function ScheduleForm({ chamber, onDone }: { chamber: PiChamber; onDone: () => void }) {
  const [kind, setKind] = useState<string>("clean");
  const [dueInDays, setDueInDays] = useState("7");
  const [notes, setNotes] = useState("");
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);

  return (
    <form
      className="flex flex-col gap-3 rounded-md border border-border-soft bg-bg-1 p-[26px]"
      onSubmit={async (e) => {
        e.preventDefault();
        if (submitting) return;
        setSubmitting(true);
        setError(null);
        const days = dueInDays.trim() === "" ? null : Number(dueInDays);
        const due_at = days != null && Number.isFinite(days) ? Date.now() / 1000 + days * 86400 : null;
        try {
          await apiSend(`/api/chambers/${chamber.id}/maintenance`, "POST", {
            kind,
            due_at,
            notes: notes.trim() || null,
          });
          onDone();
        } catch (err) {
          setError(err instanceof Error ? err.message : "schedule failed");
        } finally {
          setSubmitting(false);
        }
      }}
    >
      <div className="mb-1.5 font-mono text-[15px] font-medium tracking-[0.16em] uppercase text-text-2">
        Schedule maintenance · {chamber.name}
      </div>
      <div className="grid grid-cols-[repeat(auto-fit,minmax(160px,1fr))] gap-3">
        <Field label="Task">
          <Select value={kind} onValueChange={setKind}>
            <SelectTrigger aria-label="task" className="w-full">
              <span className="min-w-0 flex-1 truncate text-left">
                <SelectValue />
              </span>
            </SelectTrigger>
            <SelectContent>
              {MAINTENANCE_KINDS.map((k) => (
                <SelectItem key={k} value={k}>{k}</SelectItem>
              ))}
            </SelectContent>
          </Select>
        </Field>
        <Field label="Due in (days)">
          <Input type="number" min={0} value={dueInDays} onChange={(e) => setDueInDays(e.target.value)} />
        </Field>
        <Field label="Note">
          <Input value={notes} onChange={(e) => setNotes(e.target.value)} placeholder="optional" />
        </Field>
      </div>
      {error && <p className="font-mono text-[12px] text-err">{error}</p>}
      <div className="flex items-center gap-2.5 justify-end">
        <Button type="submit" disabled={submitting}>
          {submitting ? "scheduling…" : "schedule →"}
        </Button>
      </div>
    </form>
  );
}
