import { useEffect, useState } from "react";

interface PiLoad<T> {
  data: T | null;
  loading: boolean;
  error: string | null;
}

/**
 * Shared terminal-load hook for pages wired to the Pi API — the one
 * useState/useEffect/`let cancelled` pattern, hoisted.
 *
 * On every deps change: loading=true, error=null, run the loader (which may
 * compose Promise.all internally), then set data — unless the effect was
 * cancelled (deps changed again / unmounted) in the meantime. On failure the
 * error message is kept and data resets to null.
 */
export function usePiLoad<T>(loader: () => Promise<T>, deps: unknown[]): PiLoad<T> {
  const [data, setData] = useState<T | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    let cancelled = false;
    setLoading(true);
    setError(null);
    loader()
      .then((result) => {
        if (!cancelled) setData(result);
      })
      .catch((err: unknown) => {
        if (!cancelled) {
          setError(err instanceof Error ? err.message : "fetch failed");
          setData(null);
        }
      })
      .finally(() => {
        if (!cancelled) setLoading(false);
      });
    return () => {
      cancelled = true;
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps -- deps are caller-owned
  }, deps);

  return { data, loading, error };
}
