import { useState } from "react";
import { useParams } from "react-router-dom";
import {
  Button,
  CloudSyncIndicator,
  PI_HEALTH,
  PageHeader,
  RangeSelector,
  TraceRow,
} from "@sporeprint/design";
import type { ChannelTrace, TimeRange } from "@sporeprint/design";
import { PiTopBar } from "../components/PiTopBar";
import { apiGet } from "../lib/api";
import { vpdOf } from "../lib/chambers";
import { usePiLoad } from "../lib/use-pi-load";
import type { HistoryRow, LatestRow, PiChamber, PiSession, PiSpecies } from "../lib/pi-types";

interface Props {
  onBack: (id: string) => void;
}

interface RangeParam {
  seconds: number;
  resolution?: "5min" | "hourly" | "daily";
}

// Map each selectable window to the telemetry endpoint's from/to span and
// server-side rollup resolution. LIVE pulls raw (unbucketed) samples.
const RANGE_PARAMS: Record<TimeRange, RangeParam> = {
  LIVE: { seconds: 3600 },
  "1H": { seconds: 3600, resolution: "5min" },
  "4H": { seconds: 14400, resolution: "5min" },
  "24H": { seconds: 86400, resolution: "hourly" },
  "7D": { seconds: 604800, resolution: "daily" },
  "30D": { seconds: 2592000, resolution: "daily" },
};

const EMPTY_TRACE: ChannelTrace = { samples: [], ticks: [], range: [0, 1] };

interface HistoryView {
  chamberName: string;
  speciesCommon?: string;
  speciesBinomial?: string;
  phase?: string;
  nodeId?: string;
  temp: ChannelTrace;
  hum: ChannelTrace;
  co2: ChannelTrace;
  vpd: ChannelTrace;
  now: { temp?: number; hum?: number; co2?: number; vpd?: number };
  axis: string[];
}

function fetchHistory(
  nodeId: string,
  sensor: string,
  from: number,
  to: number,
  resolution?: string,
): Promise<HistoryRow[]> {
  const p = new URLSearchParams({
    node_id: nodeId,
    sensor,
    from_ts: String(from),
    to_ts: String(to),
  });
  if (resolution) p.set("resolution", resolution);
  return apiGet<HistoryRow[]>(`/api/telemetry/history?${p.toString()}`);
}

// VPD is not a stored sensor, so derive it per-sample from the temp + humidity
// histories. They share node/window/resolution, so buckets align by index.
function deriveVpd(tempF: HistoryRow[], hum: HistoryRow[]): HistoryRow[] {
  const n = Math.min(tempF.length, hum.length);
  const out: HistoryRow[] = [];
  for (let i = 0; i < n; i++) {
    out.push({ timestamp: tempF[i]!.timestamp, value: vpdOf(tempF[i]!.value, hum[i]!.value) });
  }
  return out;
}

function toTrace(rows: HistoryRow[], round: (v: number) => number): ChannelTrace {
  const samples = rows.map((r) => ({ t: r.timestamp, v: r.value }));
  const values = samples.map((s) => s.v);
  const lo = values.length ? Math.min(...values) : 0;
  const hi = values.length ? Math.max(...values) : lo + 1;
  return { samples, ticks: [], range: [round(lo), round(hi)] };
}

const round2 = (v: number): number => Math.round(v * 100) / 100;

function latestValue(latest: LatestRow[], sensor: string): number | undefined {
  return latest.find((r) => r.sensor === sensor)?.value;
}

function fmtTime(ts: number): string {
  const d = new Date(ts * 1000);
  return `${String(d.getHours()).padStart(2, "0")}:${String(d.getMinutes()).padStart(2, "0")}`;
}

function axisLabels(rows: HistoryRow[], count = 9): string[] {
  if (rows.length === 0) return [];
  const labels: string[] = [];
  for (let i = 0; i < count; i++) {
    const idx = Math.round((i / (count - 1)) * (rows.length - 1));
    labels.push(fmtTime(rows[idx]!.timestamp));
  }
  return labels;
}

async function loadHistory(chamberId: string, range: TimeRange): Promise<HistoryView> {
  const chamber = await apiGet<PiChamber>(`/api/chambers/${encodeURIComponent(chamberId)}`);
  const nodeId = chamber.node_ids[0];

  // Header enrichment: species + phase live on the chamber's active session.
  let speciesCommon: string | undefined;
  let speciesBinomial: string | undefined;
  let phase: string | undefined;
  if (chamber.active_session_id != null) {
    const session = await apiGet<PiSession>(`/api/sessions/${chamber.active_session_id}`);
    phase = session.current_phase;
    if (session.species_profile_id) {
      const sp = await apiGet<PiSpecies>(
        `/api/species/${encodeURIComponent(session.species_profile_id)}`,
      );
      speciesCommon = sp.common_name;
      speciesBinomial = sp.scientific_name;
    }
  }

  const base = { chamberName: chamber.name, speciesCommon, speciesBinomial, phase, nodeId };

  if (!nodeId) {
    return {
      ...base,
      temp: EMPTY_TRACE,
      hum: EMPTY_TRACE,
      co2: EMPTY_TRACE,
      vpd: EMPTY_TRACE,
      now: {},
      axis: [],
    };
  }

  const { seconds, resolution } = RANGE_PARAMS[range];
  const to = Math.floor(Date.now() / 1000);
  const from = to - seconds;

  const [tempRows, humRows, co2Rows, latest] = await Promise.all([
    fetchHistory(nodeId, "temp_f", from, to, resolution),
    fetchHistory(nodeId, "humidity", from, to, resolution),
    fetchHistory(nodeId, "co2_ppm", from, to, resolution),
    apiGet<LatestRow[]>(`/api/telemetry/latest?node_id=${encodeURIComponent(nodeId)}`),
  ]);

  const vpdRows = deriveVpd(tempRows, humRows);
  const tempNow = latestValue(latest, "temp_f");
  const humNow = latestValue(latest, "humidity");
  const co2Now = latestValue(latest, "co2_ppm");
  const vpdNow = tempNow != null && humNow != null ? vpdOf(tempNow, humNow) : undefined;

  return {
    ...base,
    temp: toTrace(tempRows, Math.round),
    hum: toTrace(humRows, Math.round),
    co2: toTrace(co2Rows, Math.round),
    vpd: toTrace(vpdRows, round2),
    now: { temp: tempNow, hum: humNow, co2: co2Now, vpd: vpdNow },
    axis: axisLabels(tempRows),
  };
}

const fmtNow = (v: number | undefined, digits: number): string =>
  v == null ? "—" : v.toFixed(digits);

export function ChamberHistoryPage({ onBack }: Props) {
  const { id } = useParams();
  const [range, setRange] = useState<TimeRange>("4H");
  const { data: view, loading, error: loadError } = usePiLoad<HistoryView>(
    // No route id → never resolve: stay on the initial Loading state without
    // issuing a request (mirrors the old `if (!id) return` guard).
    () => (id ? loadHistory(id, range) : new Promise<HistoryView>(() => undefined)),
    [id, range],
  );

  const title = view?.speciesBinomial ?? view?.chamberName ?? id ?? "chamber";
  const italic = Boolean(view?.speciesBinomial);
  // TODO(wire): "day N/M" of the current phase isn't exposed by any Pi
  // endpoint (it would need phase_history timestamps + species durations),
  // so the meta line stops at the phase name.
  const metaParts = [view?.chamberName ?? id, view?.phase, view?.nodeId].filter(Boolean);

  return (
    <>
      <PiTopBar
        crumbs={[
          { label: "chambers", href: "/" },
          { label: (id ?? "").toLowerCase(), href: `/chamber/${id}` },
          { label: "history", active: true },
        ]}
        right={<CloudSyncIndicator cloud={PI_HEALTH.cloud} />}
      />

      <PageHeader
        eyebrow={view?.speciesCommon}
        title={title}
        italic={italic}
        meta={<span>{metaParts.join(" · ")}</span>}
        right={
          <div className="flex flex-col items-end gap-2">
            <RangeSelector
              value={range}
              onChange={setRange}
              options={["LIVE", "1H", "4H", "24H"]}
            />
            <Button variant="link" size="sm" onClick={() => onBack(id ?? "")}>
              ← back to chamber
            </Button>
          </div>
        }
      />

      <div className="grid max-w-none grid-cols-[1fr] gap-[22px] px-7 pt-[22px] pb-7">
        <main className="flex flex-col gap-4">
          {loadError ? (
            <p className="font-mono text-[13px] tracking-[0.05em] text-err">
              Failed to load chamber history: {loadError}
            </p>
          ) : loading || !view ? (
            <p className="font-mono text-[13px] tracking-[0.05em] text-text-2">Loading…</p>
          ) : !view.nodeId ? (
            <p className="font-mono text-[13px] tracking-[0.05em] text-text-2">
              No telemetry node is bound to this chamber yet.
            </p>
          ) : (
            <>
              <section className="overflow-hidden rounded-md border border-border-soft">
                {/* TODO(wire): actuator cycle counts + live actuator state
                    (the old "N cycles" / mister-active glow) aren't in the
                    telemetry history feed, so event ticks are empty and the
                    deltas are plain channel annotations. */}
                <TraceRow
                  channel="temp"
                  trace={view.temp}
                  nowValue={fmtNow(view.now.temp, 1)}
                />
                <TraceRow
                  channel="hum"
                  trace={view.hum}
                  nowValue={fmtNow(view.now.hum, 0)}
                  delta="mister"
                />
                <TraceRow
                  channel="co2"
                  trace={view.co2}
                  nowValue={fmtNow(view.now.co2, 0)}
                  delta="fae"
                />
                <TraceRow
                  channel="vpd"
                  trace={view.vpd}
                  nowValue={fmtNow(view.now.vpd, 2)}
                  delta="derived"
                />
                <div
                  className="flex justify-between border-t border-border-soft bg-bg-1 px-[22px] pt-2.5 pb-3 font-mono text-[12px] tracking-[0.1em] text-text-3"
                  aria-label="time axis"
                >
                  {view.axis.map((label, i) => (
                    <span key={`${label}-${i}`}>{label}</span>
                  ))}
                </div>
              </section>
              <p className="font-mono text-[12px] text-text-2">
                long-range history (&gt; 24h) opens on the cloud app — Pi keeps the last day local.
              </p>
            </>
          )}
        </main>
      </div>
    </>
  );
}
