import { useCallback, useEffect, useMemo, useState } from "react";
import {
  Button,
  CloudSyncIndicator,
  DataTable,
  PI_HEALTH,
  PageHeader,
  cn,
} from "@sporeprint/design";
import { PiTopBar } from "../components/PiTopBar";
import { apiGet, apiSend } from "../lib/api";
import { usePiLoad } from "../lib/use-pi-load";
import type { PiSession } from "../lib/pi-types";

// ── Real Pi API shapes (server/app/transcript router) ──────────────────
interface SessionAnalysis {
  overall_score?: number;
  summary?: string;
  issues_identified?: unknown;
  vision_concerns?: unknown;
  yield_assessment?: unknown;
  phase_timing?: unknown;
  recommendations?: unknown;
  condition_analysis?: unknown;
  error?: string;
}

// `.status-pill` base + tone (classmap §10) — self-sufficient tones.
const STATUS_PILL_BASE =
  "inline-flex items-center gap-[7px] rounded-pill border px-3 py-[5px] font-mono text-[12px] font-medium uppercase tracking-widest";
const STATUS_PILL_TONE = {
  accent: "border-accent-line bg-accent-soft text-accent",
  signal: "border-signal/40 bg-signal-soft text-signal",
  warn: "border-warn bg-bg-2 text-warn",
  err: "border-err bg-bg-2 text-err",
} as const;
function statusPill(tone: keyof typeof STATUS_PILL_TONE): string {
  return cn(STATUS_PILL_BASE, STATUS_PILL_TONE[tone]);
}

function statusTone(status: string): keyof typeof STATUS_PILL_TONE {
  switch (status) {
    case "active":
      return "accent";
    case "complete":
      return "signal";
    case "contaminated":
      return "err";
    default:
      return "signal";
  }
}

const SCORE_TONE = (n: number): keyof typeof STATUS_PILL_TONE => {
  if (n >= 80) return "accent";
  if (n >= 60) return "signal";
  if (n >= 40) return "warn";
  return "err";
};

function durationDays(s: PiSession): number {
  const end = s.completed_at ?? Date.now() / 1000;
  return Math.max(0, Math.round((end - s.created_at) / 86400));
}

async function fetchText(path: string): Promise<string> {
  const res = await fetch(path, { credentials: "same-origin" });
  if (!res.ok) {
    throw new Error(`HTTP ${res.status}`);
  }
  return res.text();
}

function downloadBlob(filename: string, content: string, mime: string) {
  const blob = new Blob([content], { type: mime });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = filename;
  a.click();
  URL.revokeObjectURL(url);
}

function transcriptPath(sessionId: number, format: "json" | "markdown"): string {
  return `/api/transcript/sessions/${sessionId}/transcript?format=${format}`;
}

export function TranscriptsPage() {
  const [selectedId, setSelectedId] = useState<number | null>(null);
  const [view, setView] = useState<"markdown" | "analysis">("markdown");

  const [markdown, setMarkdown] = useState<string>("");
  const [mdLoading, setMdLoading] = useState(false);
  const [mdError, setMdError] = useState<string | null>(null);

  const [analyses, setAnalyses] = useState<Record<number, SessionAnalysis>>({});
  const [analyzing, setAnalyzing] = useState(false);
  const [analyzeError, setAnalyzeError] = useState<string | null>(null);

  const { data: sessionRows, loading, error: loadError } = usePiLoad(async () => {
    const rows = await apiGet<PiSession[]>("/api/sessions");
    // Seed the selection inside the loader so it lands in the same commit as
    // the rows (batches with the hook's setState).
    setSelectedId((prev) => prev ?? rows[0]?.id ?? null);
    return rows;
  }, []);
  const sessions = sessionRows ?? [];

  const selected = useMemo(
    () => sessions.find((s) => s.id === selectedId) ?? null,
    [sessions, selectedId],
  );

  // Load the markdown preview whenever the selected session changes.
  useEffect(() => {
    if (selectedId == null) return;
    let cancelled = false;
    setMdLoading(true);
    setMdError(null);
    setMarkdown("");
    fetchText(transcriptPath(selectedId, "markdown"))
      .then((text) => {
        if (!cancelled) setMarkdown(text);
      })
      .catch((err) => {
        if (!cancelled) setMdError(err instanceof Error ? err.message : "load failed");
      })
      .finally(() => {
        if (!cancelled) setMdLoading(false);
      });
    return () => {
      cancelled = true;
    };
  }, [selectedId]);

  function selectSession(id: number) {
    setSelectedId(id);
    setView("markdown");
  }

  async function runAnalysis() {
    if (selectedId == null) return;
    setAnalyzing(true);
    setAnalyzeError(null);
    try {
      const result = await apiSend<SessionAnalysis>(
        `/api/transcript/sessions/${selectedId}/analyze`,
        "POST",
      );
      if (result.error) {
        setAnalyzeError(result.error);
        return;
      }
      setAnalyses((prev) => ({ ...prev, [selectedId]: result }));
      setView("analysis");
    } catch (err) {
      setAnalyzeError(err instanceof Error ? err.message : "analysis failed");
    } finally {
      setAnalyzing(false);
    }
  }

  async function exportTranscript(sessionId: number, format: "json" | "markdown") {
    try {
      const text = await fetchText(transcriptPath(sessionId, format));
      downloadBlob(`sporeprint-session-${sessionId}.${format === "json" ? "json" : "md"}`, text,
        format === "json" ? "application/json" : "text/markdown");
    } catch {
      /* surfaced by the disabled state on failure — no fake success */
    }
  }

  async function copyMarkdown() {
    if (selectedId == null) return;
    try {
      const text = markdown || (await fetchText(transcriptPath(selectedId, "markdown")));
      await navigator.clipboard.writeText(text);
    } catch {
      /* clipboard denied — no-op */
    }
  }

  const analysis = selectedId != null ? analyses[selectedId] : undefined;

  return (
    <>
      <PiTopBar
        crumbs={[{ label: "track" }, { label: "transcripts", active: true }]}
        right={<CloudSyncIndicator cloud={PI_HEALTH.cloud} />}
      />

      <PageHeader
        eyebrow="Track"
        title="Session transcripts"
        italic={false}
        meta={<span>structured grow logs · export json/markdown · claude analysis on demand</span>}
      />

      <div className="grid grid-cols-[1fr_400px] gap-[22px] px-7 pt-[22px] pb-7 max-[1180px]:grid-cols-1">
        <main className="flex flex-col gap-3.5 max-[1180px]:min-w-0">
          <div className="max-[1180px]:min-w-0 max-[1180px]:overflow-x-auto">
            {loadError ? (
              <p className="font-mono text-[13px] tracking-[0.05em] text-err">
                Failed to load sessions: {loadError}
              </p>
            ) : loading ? (
              <p className="font-mono text-[13px] tracking-[0.05em] text-text-2">Loading sessions…</p>
            ) : sessions.length === 0 ? (
              <p className="font-body text-[14px] leading-[1.55] text-text-2">
                No grow sessions on this Pi yet.
              </p>
            ) : (
              <DataTable<PiSession>
                rowKey={(t) => t.id}
                columns={[
                  {
                    key: "session",
                    header: "Session",
                    render: (t) => (
                      <button
                        type="button"
                        onClick={() => selectSession(t.id)}
                        className="cursor-pointer border-none bg-transparent p-0 font-mono text-[14px] tracking-normal text-accent no-underline hover:text-text-0"
                      >
                        {t.name}
                      </button>
                    ),
                  },
                  {
                    key: "species",
                    header: "Species",
                    render: (t) => (
                      <span className="font-serif text-[18px] font-medium italic tracking-[-0.005em] text-text-0">
                        {t.species_profile_id}
                      </span>
                    ),
                  },
                  {
                    key: "status",
                    header: "Status",
                    render: (t) => <span className={statusPill(statusTone(t.status))}>{t.status}</span>,
                  },
                  { key: "phase", header: "Phase", render: (t) => <>{t.current_phase}</> },
                  { key: "days", header: "Days", align: "right", render: (t) => <>{durationDays(t)}d</> },
                  {
                    key: "yield",
                    header: "Yield",
                    align: "right",
                    render: (t) => <>{t.total_wet_yield_g ? `${t.total_wet_yield_g}g` : "—"}</>,
                  },
                  {
                    key: "export",
                    header: "Export",
                    align: "right",
                    render: (t) => (
                      <Button
                        type="button"
                        variant="link"
                        size="sm"
                        onClick={() => void exportTranscript(t.id, "json")}
                      >
                        json →
                      </Button>
                    ),
                  },
                ]}
                rows={sessions}
              />
            )}
          </div>

          {selected && (
            <section className="flex flex-col gap-[18px] rounded-md border border-border-soft bg-bg-1 p-[26px]">
              <div className="flex flex-wrap items-center justify-between gap-3">
                <div className="mb-1.5 font-mono text-[15px] font-medium tracking-[0.16em] uppercase text-text-2">
                  {view === "markdown" ? "Markdown preview" : "Claude analysis"} · {selected.name}
                </div>
                <div className="flex items-center gap-2">
                  <Button
                    type="button"
                    variant="ghost"
                    size="sm"
                    className={view === "markdown" ? "border-accent-line text-accent" : undefined}
                    onClick={() => setView("markdown")}
                  >
                    preview
                  </Button>
                  <Button
                    type="button"
                    variant="ghost"
                    size="sm"
                    className={view === "analysis" ? "border-accent-line text-accent" : undefined}
                    onClick={() => setView("analysis")}
                    disabled={!analysis}
                  >
                    analysis
                  </Button>
                </div>
              </div>
              {view === "markdown" ? (
                mdLoading ? (
                  <p className="font-mono text-[13px] tracking-[0.05em] text-text-2">Loading transcript…</p>
                ) : mdError ? (
                  <p className="font-mono text-[13px] tracking-[0.05em] text-err">Failed: {mdError}</p>
                ) : (
                  <article className="flex flex-col gap-2 px-1 py-3">
                    {markdown.split("\n").map((line, i) => (
                      <MarkdownLine key={i} line={line} />
                    ))}
                  </article>
                )
              ) : analysis ? (
                <AnalysisView analysis={analysis} />
              ) : (
                <p className="font-body text-[14px] leading-[1.55] text-text-2">Run analysis to view.</p>
              )}
            </section>
          )}
        </main>

        <aside className="flex flex-col gap-3.5">
          {selected && (
            <section className="flex flex-col gap-[18px] rounded-md border border-border-soft bg-bg-1 p-[26px]">
              <div className="mb-1.5 font-mono text-[15px] font-medium tracking-[0.16em] uppercase text-text-2">
                Selected · {selected.name}
              </div>
              <h2 className="font-serif text-[26px] font-medium italic leading-[1.18] tracking-[-0.005em] text-text-0">
                {selected.species_profile_id}
              </h2>
              <div className="flex flex-col gap-2.5">
                <Row k="status" v={selected.status} />
                <Row k="phase" v={selected.current_phase} />
                <Row k="duration" v={`${durationDays(selected)}d`} />
                <Row k="wet yield" v={selected.total_wet_yield_g ? `${selected.total_wet_yield_g}g` : "—"} />
                <Row k="dry yield" v={selected.total_dry_yield_g ? `${selected.total_dry_yield_g}g` : "—"} />
              </div>
              <div className="mt-2 flex flex-col gap-2.5">
                <Button type="button" variant="ghost" size="sm" onClick={() => void exportTranscript(selected.id, "json")}>
                  export json
                </Button>
                <Button type="button" variant="ghost" size="sm" onClick={() => void exportTranscript(selected.id, "markdown")}>
                  export markdown
                </Button>
                <Button type="button" variant="ghost" size="sm" onClick={() => void copyMarkdown()}>
                  copy to clipboard
                </Button>
              </div>
            </section>
          )}

          {selected && (
            <section className="flex flex-col gap-[18px] rounded-md border border-border-soft bg-bg-1 p-[26px]">
              <div className="mb-1.5 font-mono text-[15px] font-medium tracking-[0.16em] uppercase text-text-2">
                Claude analysis
              </div>
              <p className="font-body text-[14px] leading-[1.55] text-text-1">
                Runs against captured telemetry, actuator log, harvest metadata. Analysis is BYOK on the
                Pi (rate limit applies).
              </p>
              {analyzeError && <span className="font-mono text-[12px] text-err">{analyzeError}</span>}
              <Button type="button" variant="solid" onClick={() => void runAnalysis()} disabled={analyzing}>
                {analyzing ? "analyzing…" : analysis ? "re-run analysis →" : "analyze →"}
              </Button>
              {analysis && typeof analysis.overall_score === "number" && (
                <div className="flex flex-col gap-1.5 rounded-sm border border-border-soft bg-bg-2 p-3">
                  <span className="font-mono text-[13px] font-medium tracking-[0.16em] uppercase text-text-2">
                    overall
                  </span>
                  <div className="flex items-baseline gap-2">
                    <span
                      className={cn(
                        "font-mono text-[28px] leading-none tracking-normal",
                        SCORE_TONE(analysis.overall_score) === "accent" ? "text-accent" : "text-text-0",
                      )}
                    >
                      {analysis.overall_score}
                    </span>
                    <span className="font-mono text-[12px] text-text-2">/ 100</span>
                  </div>
                  <span className={statusPill(SCORE_TONE(analysis.overall_score))}>
                    {verdictFromScore(analysis.overall_score)}
                  </span>
                </div>
              )}
            </section>
          )}
        </aside>
      </div>
    </>
  );
}

function AnalysisView({ analysis }: { analysis: SessionAnalysis }) {
  const score = typeof analysis.overall_score === "number" ? analysis.overall_score : null;
  return (
    <div className="flex flex-col gap-4">
      {score !== null && (
        <div className="flex items-baseline gap-3.5">
          <span
            className={cn(
              "font-mono text-[40px] leading-none",
              SCORE_TONE(score) === "accent" ? "text-accent" : "text-text-0",
            )}
          >
            {score}
          </span>
          <span className="font-mono text-[14px] text-text-1">/ 100 · {verdictFromScore(score)}</span>
        </div>
      )}
      {typeof analysis.summary === "string" && (
        <p className="font-body text-[16px] leading-[1.55] text-text-1">{analysis.summary}</p>
      )}
      <Field label="issues identified" value={analysis.issues_identified} tone="warn" />
      <Field label="vision concerns" value={analysis.vision_concerns} tone="warn" />
      <Field label="yield assessment" value={analysis.yield_assessment} />
      <Field label="phase timing" value={analysis.phase_timing} />
      <Field label="condition analysis" value={analysis.condition_analysis} />
      <Field label="recommendations" value={analysis.recommendations} />
    </div>
  );
}

function Field({ label, value, tone }: { label: string; value: unknown; tone?: "warn" }) {
  if (value == null || (Array.isArray(value) && value.length === 0)) return null;
  const textCls = tone === "warn" ? "text-warn" : "text-text-1";
  const headCls = tone === "warn" ? "text-warn" : "text-text-2";
  const items: string[] = Array.isArray(value)
    ? value.map((v) => (typeof v === "string" ? v : JSON.stringify(v)))
    : typeof value === "string"
      ? [value]
      : [JSON.stringify(value, null, 2)];
  return (
    <div>
      <span className={cn("font-mono text-[13px] font-medium uppercase tracking-[0.16em]", headCls)}>
        {label}
      </span>
      <ul className="my-1.5 flex flex-col gap-1 pl-[18px]">
        {items.map((it, i) => (
          <li key={i} className={cn("font-body text-[14px] leading-[1.55]", textCls)}>
            {it}
          </li>
        ))}
      </ul>
    </div>
  );
}

// Light-touch markdown line renderer — headings, list items, and paragraphs.
// The server's export_markdown is genuine markdown; this preserves the
// "markdown preview" visual structure without a heavyweight parser.
function MarkdownLine({ line }: { line: string }) {
  if (line.startsWith("### ")) {
    return <h3 className="font-mono text-[13px] font-medium uppercase tracking-[0.16em] text-text-2">{line.slice(4)}</h3>;
  }
  if (line.startsWith("## ")) {
    return <h2 className="mt-1 font-body text-[18px] font-medium leading-[1.25] text-text-0">{line.slice(3)}</h2>;
  }
  if (line.startsWith("# ")) {
    return <h1 className="font-display text-[26px] font-medium leading-[1.18] tracking-[-0.005em] text-text-0">{line.slice(2)}</h1>;
  }
  if (line.startsWith("- ") || line.startsWith("* ")) {
    return <div className="pl-[18px] font-body text-[16px] leading-[1.55] text-text-1">• {line.slice(2)}</div>;
  }
  if (line.trim() === "") return <span className="h-1" />;
  return <p className="font-body text-[16px] leading-[1.55] text-text-1">{line}</p>;
}

function verdictFromScore(score: number): string {
  if (score >= 85) return "excellent";
  if (score >= 70) return "good";
  if (score >= 50) return "fair";
  if (score >= 30) return "poor";
  return "lost";
}

function Row({ k, v }: { k: string; v: string }) {
  return (
    <div className="flex items-center justify-between gap-3">
      <span className="font-mono text-[12px] font-medium tracking-[0.14em] uppercase text-text-2">{k}</span>
      <span className="font-mono text-[14px] text-text-1">{v}</span>
    </div>
  );
}
