"use client";

import { cn } from "../lib/cn";

export type TimeRange = "LIVE" | "1H" | "4H" | "24H" | "7D" | "30D";

const ALL: TimeRange[] = ["LIVE", "1H", "4H", "24H", "7D", "30D"];

// Engine choice: same plain anchor-based tablist as SegmentedControl, not
// ToggleGroup. `.v-time-ranges a.active` and `.v-time-ranges a` are both
// asserted on directly by pre-existing suites (see SegmentedControl.tsx for
// the two call sites) — Radix ToggleGroup's role="group" root + <button
// data-state="on"> items would regress both without touching those tests,
// which is out of scope here. Token utilities (transition) are layered onto
// the legacy `v-time-ranges`/`active` classes instead; focus falls back to
// the global `:focus-visible` saffron outline defined in theme.css.
export function RangeSelector({
  value,
  onChange,
  /** Pi UI only exposes short-range windows — long history lives on cloud. */
  options = ALL,
}: {
  value: TimeRange;
  onChange?: (next: TimeRange) => void;
  options?: TimeRange[];
}) {
  return (
    <div className={cn("v-time-ranges")} role="tablist" aria-label="time range">
      {options.map((r) => {
        const active = r === value;
        return (
          <a
            key={r}
            href={`#${r.toLowerCase()}`}
            className={cn(
              active && "active",
              "transition-colors duration-200 ease-brand",
            )}
            role="tab"
            aria-selected={active}
            onClick={(e) => {
              e.preventDefault();
              onChange?.(r);
            }}
          >
            {r}
          </a>
        );
      })}
    </div>
  );
}
