import { Fragment, type ReactNode } from "react";
import { Link } from "react-router-dom";
import type { BreadcrumbCrumb } from "@sporeprint/design";

interface Props {
  /** Breadcrumb trail, left → right. The terminal (`active`) crumb
   *  renders in the saffron accent; any crumb with an `href` renders as
   *  a router `Link`, everything else as plain text. */
  crumbs: BreadcrumbCrumb[];
  /** Mono hostname/IP pill in the right zone (FleetPage, SettingsPage
   *  render one; most pages omit it). */
  host?: { hostname: string; ip: string };
  /** Right-zone content — every page passes a `<CloudSyncIndicator>`. */
  right?: ReactNode;
}

/**
 * Shared shop-floor top bar. Pi-ui-local (NOT `@sporeprint/design`'s
 * `<AppTopBar>`) because every pi-ui page renders the brand-less
 * `.app-top.no-brand` variant — the Pi's brand lives in the Sidebar, not
 * the top bar — and the design package always emits a brand block with
 * no `hideBrand` escape hatch. Adding one is a design-pkg change and the
 * package is frozen this phase (Substrate II Phase 3 plan, T2); this
 * local component is the sanctioned alternative. Every non-setup page
 * (19 sites) replaces its hand-rolled `.app-top no-brand` block with
 * this component in T3–T11.
 *
 * Reproduces `.app-top.no-brand` / `.bc` / `.sep` / `.accent` / `.right`
 * / `.host-pill` / `.mut` from `components.css` exactly — see
 * `docs/superpowers/plans/2026-07-03-substrate-ii-classmap-pi-delta.md`
 * §1–5. Breadcrumb items are flat siblings (not nested per-item
 * wrappers) so the nav's flex `gap` produces even spacing on both sides
 * of each separator, matching the pre-migration markup's layout.
 */
export function PiTopBar({ crumbs, host, right }: Props) {
  return (
    <header className="sticky top-0 z-30 grid min-h-[68px] grid-cols-[1fr_minmax(220px,auto)] items-center gap-[18px] border-b border-border-soft bg-bg-1 px-8 py-[18px]">
      <nav
        className="inline-flex items-center justify-start gap-2.5 font-mono text-[14px] font-medium tracking-[0.1em] text-text-1 uppercase"
        aria-label="breadcrumb"
      >
        {crumbs.map((c, i) => (
          <Fragment key={`${c.label}-${i}`}>
            {i > 0 && <span className="text-text-3">/</span>}
            {c.active ? (
              <b className="font-medium tracking-[0.08em] text-accent">{c.label}</b>
            ) : c.href ? (
              <Link to={c.href} className="text-inherit no-underline">
                {c.label}
              </Link>
            ) : (
              <span>{c.label}</span>
            )}
          </Fragment>
        ))}
      </nav>
      <div className="inline-flex items-center justify-end gap-4 font-mono text-[14px] tracking-[0.05em] text-text-2 uppercase">
        {host && (
          <span className="inline-flex items-center gap-2 rounded-pill border border-border-soft bg-bg-1 px-3 py-[7px] font-mono text-[13px] text-text-2">
            {host.hostname}
            <span className="text-text-2">· {host.ip}</span>
          </span>
        )}
        {right}
      </div>
    </header>
  );
}
