import { useEffect, useMemo, useState } from "react";
import {
  Button,
  Chip,
  ChipGroup,
  CloudSyncIndicator,
  DataTable,
  EmptyState,
  Input,
  PageHeader,
  PI_HEALTH,
  RESTOCK_SUGGESTIONS,
  SearchInput,
  SHOPPING_LIST,
  cn,
  toast,
  type ShoppingItem,
} from "@sporeprint/design";
import { PiTopBar } from "../components/PiTopBar";

function Field({ label, children }: { label: string; children: React.ReactNode }) {
  return (
    <label className="flex flex-col gap-1.5">
      <span className="font-mono text-[12px] font-medium tracking-[0.14em] uppercase text-text-2">{label}</span>
      {children}
    </label>
  );
}

type FilterMode = "all" | "unpurchased" | "purchased";

interface CustomItem extends ShoppingItem {
  custom: true;
}

const STORAGE_PURCHASED = "pi:shopping:purchased";
const STORAGE_NOTES = "pi:shopping:notes";
const STORAGE_CUSTOM = "pi:shopping:custom";

function loadStored<T>(key: string, fallback: T): T {
  if (typeof window === "undefined") return fallback;
  try {
    const raw = window.localStorage.getItem(key);
    return raw ? (JSON.parse(raw) as T) : fallback;
  } catch {
    return fallback;
  }
}

// `.status-pill` base + tone (classmap §10) — every tone fully
// self-sufficient (own text + bg + border) per Binding Lesson 3, same
// convention as FleetPage/SessionsPage/SpeciesPage.
const STATUS_PILL_BASE =
  "inline-flex items-center gap-[7px] font-mono text-[12px] font-medium tracking-widest uppercase rounded-pill py-[5px] px-3 border";
const STATUS_PILL_TONE = {
  err: "text-err bg-bg-2 border-err",
  warn: "text-warn bg-bg-2 border-warn",
  idle: "text-text-3 bg-bg-2 border-border",
} as const;
function statusPill(tone: keyof typeof STATUS_PILL_TONE): string {
  return `${STATUS_PILL_BASE} ${STATUS_PILL_TONE[tone]}`;
}

export function ShoppingPage() {
  const [purchased, setPurchased] = useState<Record<string, boolean>>(() =>
    loadStored<Record<string, boolean>>(STORAGE_PURCHASED, {}),
  );
  const [notes, setNotes] = useState<Record<string, string>>(() =>
    loadStored<Record<string, string>>(STORAGE_NOTES, {}),
  );
  const [custom, setCustom] = useState<CustomItem[]>(() =>
    loadStored<CustomItem[]>(STORAGE_CUSTOM, []),
  );
  const [showAdd, setShowAdd] = useState(false);
  const [filter, setFilter] = useState<FilterMode>("all");
  const [categoryFilter, setCategoryFilter] = useState<string>("all");
  const [query, setQuery] = useState("");

  useEffect(() => {
    if (typeof window === "undefined") return;
    try {
      window.localStorage.setItem(STORAGE_PURCHASED, JSON.stringify(purchased));
    } catch {}
  }, [purchased]);

  useEffect(() => {
    if (typeof window === "undefined") return;
    try {
      window.localStorage.setItem(STORAGE_NOTES, JSON.stringify(notes));
    } catch {}
  }, [notes]);

  useEffect(() => {
    if (typeof window === "undefined") return;
    try {
      window.localStorage.setItem(STORAGE_CUSTOM, JSON.stringify(custom));
    } catch {}
  }, [custom]);

  const allItems = useMemo<ShoppingItem[]>(
    () => [...SHOPPING_LIST, ...custom],
    [custom],
  );

  const categories = useMemo(() => {
    const cats = new Set<string>(allItems.map((i) => i.category));
    return Array.from(cats);
  }, [allItems]);

  const filtered = useMemo(() => {
    const q = query.trim().toLowerCase();
    return allItems.filter((it) => {
      const isP = !!purchased[it.id];
      if (filter === "unpurchased" && isP) return false;
      if (filter === "purchased" && !isP) return false;
      if (categoryFilter !== "all" && it.category !== categoryFilter) return false;
      if (!q) return true;
      return [it.item, it.supplier, it.category].join(" ").toLowerCase().includes(q);
    });
  }, [allItems, filter, categoryFilter, query, purchased]);

  const grouped = useMemo(() => {
    return filtered.reduce<Record<string, ShoppingItem[]>>((acc, item) => {
      const supplier = item.supplier;
      if (!acc[supplier]) acc[supplier] = [];
      acc[supplier].push(item);
      return acc;
    }, {});
  }, [filtered]);

  function togglePurchased(id: string) {
    setPurchased((prev) => ({ ...prev, [id]: !prev[id] }));
  }

  function setNote(id: string, value: string) {
    setNotes((prev) => ({ ...prev, [id]: value }));
  }

  function addCustom(item: CustomItem) {
    setCustom((prev) => [...prev, item]);
  }

  function removeCustom(id: string) {
    setCustom((prev) => prev.filter((c) => c.id !== id));
    setPurchased((prev) => {
      const next = { ...prev };
      delete next[id];
      return next;
    });
  }

  function exportCsv() {
    const header = ["category", "item", "qty", "unit", "supplier", "url", "estCost", "purchased", "notes"];
    const rows = allItems.map((it) =>
      [
        it.category,
        it.item,
        it.qty.toString(),
        it.unit,
        it.supplier,
        it.url,
        it.estCost.toString(),
        purchased[it.id] ? "yes" : "no",
        (notes[it.id] ?? "").replace(/[\r\n,]+/g, " "),
      ]
        .map((c) => `"${c.replace(/"/g, '""')}"`)
        .join(","),
    );
    const csv = [header.join(","), ...rows].join("\n");
    const blob = new Blob([csv], { type: "text/csv;charset=utf-8" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = "sporeprint-shopping-list.csv";
    a.click();
    URL.revokeObjectURL(url);
    toast.success("downloaded · CSV saved to your downloads folder");
  }

  function printList() {
    if (typeof window !== "undefined") window.print();
  }

  const totalCost = filtered.reduce((sum, it) => sum + it.estCost, 0);
  const purchasedCount = filtered.filter((i) => purchased[i.id]).length;
  const unpurchasedCount = filtered.length - purchasedCount;

  return (
    <>
      <PiTopBar
        crumbs={[{ label: "plan" }, { label: "shopping", active: true }]}
        right={<CloudSyncIndicator cloud={PI_HEALTH.cloud} />}
      />

      <PageHeader
        eyebrow="Plan"
        title="Shopping list"
        italic={false}
        meta={
          <span>
            {filtered.length} items shown · {unpurchasedCount} to buy · est ${totalCost} · every row links to a real product
          </span>
        }
        right={
          <div className="flex items-center gap-2">
            <Button variant="ghost" onClick={printList}>
              print →
            </Button>
            <Button variant="solid" onClick={exportCsv}>
              export csv →
            </Button>
          </div>
        }
      />

      <div className="grid grid-cols-[1fr] gap-[22px] px-7 pt-[22px] pb-7 max-w-none">
        <main className="flex flex-col gap-[18px]">
          <Toolbar
            filter={filter}
            onFilter={setFilter}
            category={categoryFilter}
            onCategory={setCategoryFilter}
            categories={categories}
            query={query}
            onQuery={setQuery}
            onAddCustom={() => setShowAdd((v) => !v)}
            showAdd={showAdd}
          />

          {showAdd && <CustomItemForm onAdd={(item) => { addCustom(item); setShowAdd(false); }} />}

          <RestockBanner />

          {Object.entries(grouped).map(([supplier, items]) => (
            <SupplierSection
              key={supplier}
              supplier={supplier}
              items={items}
              purchased={purchased}
              notes={notes}
              onTogglePurchased={togglePurchased}
              onSetNote={setNote}
              onRemove={(id) => {
                if (id.startsWith("custom:")) removeCustom(id);
              }}
            />
          ))}

          {filtered.length === 0 && (
            <EmptyState
              title="No matches"
              body="Adjust filters or clear the search to see the full list."
            />
          )}
        </main>
      </div>
    </>
  );
}

function Toolbar({
  filter,
  onFilter,
  category,
  onCategory,
  categories,
  query,
  onQuery,
  onAddCustom,
  showAdd,
}: {
  filter: FilterMode;
  onFilter: (f: FilterMode) => void;
  category: string;
  onCategory: (c: string) => void;
  categories: string[];
  query: string;
  onQuery: (q: string) => void;
  onAddCustom: () => void;
  showAdd: boolean;
}) {
  return (
    // `.side-panel.cluster` + the source's `style={{flexDirection:"row"}}`
    // override — `.cluster` (declared after `.side-panel` in components.css)
    // already wins the `gap` property (8px, not side-panel's 18px); the row
    // direction was always a forced override since `.cluster` never sets
    // `flex-direction` (verified live: gap 8px / row / wrap / center at
    // clean HEAD). Resolved directly rather than re-adding an inline style.
    <section className="flex flex-row flex-wrap items-center gap-2 rounded-md border border-border-soft bg-bg-1 p-[26px]">
      <div className="flex-[1_1_280px] min-w-[220px]">
        <SearchInput
          value={query}
          onChange={onQuery}
          placeholder="search items, suppliers, categories …"
          ariaLabel="search shopping list"
        />
      </div>
      <ChipGroup label="status">
        <Chip active={filter === "all"} onClick={() => onFilter("all")}>all</Chip>
        <Chip active={filter === "unpurchased"} onClick={() => onFilter("unpurchased")}>to buy</Chip>
        <Chip active={filter === "purchased"} onClick={() => onFilter("purchased")}>bought</Chip>
      </ChipGroup>
      <ChipGroup label="category">
        <Chip active={category === "all"} onClick={() => onCategory("all")}>all</Chip>
        {categories.map((c) => (
          <Chip key={c} active={category === c} onClick={() => onCategory(c)}>
            {c.toLowerCase()}
          </Chip>
        ))}
      </ChipGroup>
      <Button variant={showAdd ? "solid" : "ghost"} onClick={onAddCustom} className="ml-auto">
        {showAdd ? "cancel" : "+ custom"}
      </Button>
      {/* Internal route, but the source rendered a plain `<a>` (not a
          router `Link`) — preserved as-is (full-page nav is the pre-existing
          behavior; upgrading to `Link` would be a behavior change, not a
          style migration). */}
      <a
        className="font-mono text-[12px] font-medium tracking-[0.16em] uppercase text-text-2 bg-transparent border border-border rounded-sm py-[9px] px-4 cursor-pointer transition-all duration-[var(--dur-fast)] ease-brand hover:text-text-0 hover:bg-bg-2"
        href="/builder"
      >
        ← from builder
      </a>
    </section>
  );
}

function CustomItemForm({ onAdd }: { onAdd: (item: CustomItem) => void }) {
  const [item, setItem] = useState("");
  const [qty, setQty] = useState("1");
  const [unit, setUnit] = useState("ea");
  const [supplier, setSupplier] = useState("Amazon");
  const [url, setUrl] = useState("");
  const [estCost, setEstCost] = useState("0");
  const [category, setCategory] = useState("Custom");

  function submit(e: React.FormEvent) {
    e.preventDefault();
    if (!item.trim()) return;
    if (!url.trim()) return;
    const id = `custom:${Date.now().toString(36)}`;
    onAdd({
      id,
      category,
      item: item.trim(),
      qty: Math.max(1, parseInt(qty, 10) || 1),
      unit,
      supplier,
      url,
      estCost: Math.max(0, parseFloat(estCost) || 0),
      custom: true,
    });
    setItem("");
    setUrl("");
    setEstCost("0");
  }

  return (
    // `.side-panel.stack-14` — `.stack-14` (declared after `.side-panel`)
    // wins `gap` (14px, not side-panel's 18px) — verified live at clean HEAD.
    <form className="flex flex-col gap-3.5 rounded-md border border-border-soft bg-bg-1 p-[26px]" onSubmit={submit}>
      <div className="mb-1.5 font-mono text-[15px] font-medium tracking-[0.16em] uppercase text-text-2">Add custom item</div>
      <div className="grid grid-cols-[repeat(auto-fit,minmax(180px,1fr))] gap-3">
        <Field label="Item">
          <Input value={item} onChange={(e) => setItem(e.target.value)} placeholder="e.g. Carbon filter pad" required />
        </Field>
        <Field label="Category">
          <Input value={category} onChange={(e) => setCategory(e.target.value)} />
        </Field>
        <Field label="Qty">
          <Input type="number" min={1} value={qty} onChange={(e) => setQty(e.target.value)} />
        </Field>
        <Field label="Unit">
          <Input value={unit} onChange={(e) => setUnit(e.target.value)} placeholder="ea / lb / box" />
        </Field>
        <Field label="Supplier">
          <Input value={supplier} onChange={(e) => setSupplier(e.target.value)} />
        </Field>
        <Field label="Est. cost ($)">
          <Input type="number" min={0} step="0.01" value={estCost} onChange={(e) => setEstCost(e.target.value)} />
        </Field>
        <Field label="Product URL (required)">
          <Input type="url" value={url} onChange={(e) => setUrl(e.target.value)} placeholder="https://…" required />
        </Field>
      </div>
      <div className="flex items-center gap-2 justify-end">
        <Button type="submit">add to list →</Button>
      </div>
    </form>
  );
}

function RestockBanner() {
  return (
    <section className="flex flex-col gap-[18px] rounded-md border border-border-soft bg-bg-1 p-[26px]">
      <div className="mb-1.5 font-mono text-[15px] font-medium tracking-[0.16em] uppercase text-text-2">Restock suggestions</div>
      <p className="-mt-1.5 font-mono text-[12px] text-text-2">
        low stock + expiring inventory · click to add to a builder shopping list row
      </p>
      <DataTable
        rowKey={(r) => r.id}
        columns={[
          { key: "item", header: "Item", render: (r) => <>{r.item}</> },
          { key: "reason", header: "Reason", render: (r) => <>{r.reason}</> },
          { key: "sev", header: "Severity", render: (r) => (
            <span className={statusPill(
              r.severity === "err" ? "err" : r.severity === "warn" ? "warn" : "idle"
            )}>{r.severity}</span>
          ) },
          { key: "act", header: "Action", align: "right", render: (r) => r.shoppingId
            ? <a className="font-mono text-[14px] font-medium tracking-[0.16em] uppercase text-accent no-underline cursor-pointer bg-transparent border-none p-0 self-start hover:text-text-0" href={`#${r.shoppingId}`}>jump →</a>
            : <span className="font-mono text-[12px] text-text-2">—</span> },
        ]}
        rows={RESTOCK_SUGGESTIONS}
      />
    </section>
  );
}

function SupplierSection({
  supplier,
  items,
  purchased,
  notes,
  onTogglePurchased,
  onSetNote,
  onRemove,
}: {
  supplier: string;
  items: ShoppingItem[];
  purchased: Record<string, boolean>;
  notes: Record<string, string>;
  onTogglePurchased: (id: string) => void;
  onSetNote: (id: string, v: string) => void;
  onRemove: (id: string) => void;
}) {
  const subtotal = items.reduce((sum, it) => sum + it.estCost, 0);
  const purchasedSubtotal = items
    .filter((it) => purchased[it.id])
    .reduce((sum, it) => sum + it.estCost, 0);

  return (
    <section className="flex flex-col gap-2.5">
      <div className="flex flex-wrap items-baseline justify-between gap-3">
        <span className="font-mono text-[13px] font-medium tracking-[0.16em] uppercase text-text-2">{supplier}</span>
        <span className="font-mono text-[12px] text-text-2">
          {items.length} items · est ${subtotal} · {purchasedSubtotal > 0 ? `bought $${purchasedSubtotal}` : "none bought"}
        </span>
      </div>
      <DataTable<ShoppingItem>
        rowKey={(it) => it.id}
        columns={[
          { key: "check", header: "", render: (it) => (
            <input
              type="checkbox"
              checked={!!purchased[it.id]}
              onChange={() => onTogglePurchased(it.id)}
              aria-label={`mark ${it.item} purchased`}
              className="h-[18px] w-[18px] accent-accent"
            />
          ) },
          { key: "item", header: "Item", render: (it) => {
            const isP = !!purchased[it.id];
            return (
              <>
                <a
                  href={it.url}
                  target="_blank"
                  rel="noopener noreferrer"
                  className={cn(
                    "font-body text-[16px] text-text-0 no-underline cursor-pointer bg-transparent border-none p-0 hover:text-accent",
                    isP && "line-through",
                  )}
                >
                  {it.item}
                </a>
                <div className="mt-0.5 font-mono text-[12px] text-text-3">
                  {it.category}
                  {(it as CustomItem).custom && (
                    <>
                      {" · "}
                      <button
                        type="button"
                        className="inline font-mono text-[14px] tracking-normal text-accent no-underline cursor-pointer bg-transparent border-none p-0 hover:text-text-0"
                        onClick={() => onRemove(it.id)}
                      >
                        remove
                      </button>
                    </>
                  )}
                </div>
              </>
            );
          } },
          { key: "qty", header: "Qty", align: "right", render: (it) => <>{it.qty} {it.unit}</> },
          { key: "note", header: "Note", render: (it) => (
            <Input
              type="text"
              value={notes[it.id] ?? ""}
              onChange={(e) => onSetNote(it.id, e.target.value)}
              placeholder="…"
            />
          ) },
          { key: "cost", header: "Est. cost", align: "right", render: (it) => <>${it.estCost}</> },
          { key: "buy", header: "Buy", align: "right", render: (it) => (
            <a href={it.url} target="_blank" rel="noopener noreferrer" className="font-mono text-[14px] font-medium tracking-[0.16em] uppercase text-accent no-underline cursor-pointer bg-transparent border-none p-0 self-start hover:text-text-0">buy →</a>
          ) },
        ]}
        rows={items}
      />
    </section>
  );
}
