import type { ReactNode } from "react";

type KpiTone = "default" | "accent" | "signal" | "warn" | "err";

export function KpiCard({
  label,
  value,
  unit,
  delta,
  trend,
  tone = "default",
  spark,
  children,
}: {
  label: string;
  value: string | number;
  unit?: string;
  delta?: string;
  trend?: "up" | "down" | "flat";
  tone?: KpiTone;
  spark?: ReactNode;
  children?: ReactNode;
}) {
  const cls = `kpi-card ${tone === "default" ? "" : tone}`.trim();
  const deltaCls = `kpi-delta ${trend === "up" ? "up" : trend === "down" ? "down" : ""}`.trim();
  return (
    <div className={cls}>
      <span className="kpi-label">{label}</span>
      <div className="kpi-value">
        {value}
        {unit && <span className="u">{unit}</span>}
      </div>
      {delta && <span className={deltaCls}>{delta}</span>}
      {spark && <div style={{ marginTop: 6 }}>{spark}</div>}
      {children}
    </div>
  );
}
