"use client";

import type { ReactNode } from "react";
import { Logo } from "./Logo";
import { LiveDot } from "./LiveDot";

/**
 * Left-rail navigation. Surfaces (cloud-web, pi-ui) compose section
 * arrays + render their own framework-specific link components inside
 * <SidebarLink>. The Sidebar component owns the chrome (brand,
 * separators, footer) and the styled link class.
 *
 * Each surface bridges its router into the link wrapper:
 *   <Link href="/fleet" className={`sidebar-link ${active ? "active" : ""}`}>
 *     Fleet
 *   </Link>
 */

export interface SidebarSection {
  label?: string;
  items: ReactNode[];
}

interface Props {
  brand: { word: string; suffix?: string };
  sections: SidebarSection[];
  /** Bottom-of-rail metadata: version + status. */
  footer?: {
    version: string;
    /** "synced", "syncing", "offline", or any short string. */
    statusLabel?: string;
    statusKind?: "accent" | "signal" | "warn" | "err";
    extra?: ReactNode;
  };
}

export function Sidebar({ brand, sections, footer }: Props) {
  return (
    <aside className="sidebar" aria-label="primary navigation">
      <div className="sidebar-brand">
        <Logo size={26} opts={{ color: "var(--accent)" }} />
        <span className="word">{brand.word}</span>
        {brand.suffix && <span className="tld">{brand.suffix}</span>}
      </div>
      <nav className="sidebar-body">
        {sections.map((s, i) => (
          <div key={`section-${i}`} className="sidebar-section">
            {s.label && <div className="section-title">{s.label}</div>}
            {s.items.map((item, j) => (
              <span key={`item-${i}-${j}`}>{item}</span>
            ))}
          </div>
        ))}
      </nav>
      {footer && (
        <div className="sidebar-foot">
          <span className="ver">{footer.version}</span>
          {footer.statusLabel && (
            <span className="row">
              <LiveDot kind={footer.statusKind ?? "signal"} />
              {footer.statusLabel}
            </span>
          )}
          {footer.extra}
        </div>
      )}
    </aside>
  );
}
