import { useEffect, useMemo, useState } from "react";
import { Link } from "react-router-dom";
import {
  BUILDER_3D_MODELS,
  BUILDER_ALTERNATES,
  BUILDER_FIRMWARE,
  Chip,
  CloudSyncIndicator,
  DataTable,
  HARDWARE_TIERS,
  KpiCard,
  PageHeader,
  PI_HEALTH,
  SegmentedControl,
  WiringDiagram,
  cn,
  type BuilderTier,
} from "@sporeprint/design";
import { PiTopBar } from "../components/PiTopBar";

type Tab = "overview" | "shopping" | "models" | "wiring" | "firmware" | "setup";

const TIER_TABS: Tab[] = ["overview", "shopping", "models", "wiring", "firmware", "setup"];
const STORAGE_KEY = "pi:builder:setupProgress";

// `.status-pill` base + tone (classmap §10 / Phase-2 map). Full resolved
// utility strings — no shared legacy base class, so no utility emit-order
// fight (Binding Lesson 3). `idle` reproduces the base pill's own
// bg-bg-2/border-border plus the `.idle` color override (bare-vs-idle,
// Lesson 3) — Substitutions is the one place on this page that renders it.
const STATUS_PILL_BASE =
  "inline-flex items-center gap-[7px] rounded-pill border px-3 py-[5px] font-mono text-[12px] font-medium uppercase tracking-widest";
const STATUS_PILL_TONE = {
  accent: "border-accent-line bg-accent-soft text-accent",
  warn: "border-warn bg-bg-2 text-warn",
  idle: "border-border bg-bg-2 text-text-3",
} as const;

// `.t-link-cta` / `.t-link-mono` / `.t-link-body` / `.t-btn-primary`
// (Phase-2 classmap §2). Every CTA in this file lives on an `<a>` (external
// product/repo/doc links) or the one internal `<Link>` (send BOM to
// /shopping) — never a real `<button>` — so `Button` (renders `<button>`,
// no `asChild`/Slot) can't stand in for any of them. Same "Button can't
// render this element" exception T3/T4/T5 documented for anchor-based CTAs;
// kept as the mapped classmap-literal utility strings instead.
const T_LINK_CTA =
  "self-start font-mono text-[14px] font-medium uppercase tracking-[0.16em] text-accent no-underline cursor-pointer bg-transparent border-none p-0 hover:text-text-0";
const T_LINK_MONO =
  "font-mono text-[14px] tracking-normal text-accent no-underline cursor-pointer bg-transparent border-none p-0 hover:text-text-0";
const T_LINK_BODY =
  "font-body text-[16px] text-text-0 no-underline cursor-pointer bg-transparent border-none p-0 hover:text-accent";
const T_BTN_PRIMARY =
  "font-mono text-[13px] font-medium uppercase tracking-[0.16em] text-accent bg-accent-soft border border-accent-line rounded-sm py-[11px] px-[18px] cursor-pointer transition-all duration-[var(--dur-fast)] ease-brand hover:bg-accent-line disabled:cursor-not-allowed disabled:opacity-50 disabled:bg-bg-2 disabled:border-border disabled:text-text-3";

export function BuilderPage() {
  const [tierId, setTierId] = useState<BuilderTier["id"]>("recommended");
  const [tab, setTab] = useState<Tab>("overview");
  const [chambers, setChambers] = useState(1);
  const [completedSteps, setCompletedSteps] = useState<Record<string, boolean>>(() => {
    if (typeof window === "undefined") return {};
    try {
      const raw = window.localStorage.getItem(STORAGE_KEY);
      return raw ? (JSON.parse(raw) as Record<string, boolean>) : {};
    } catch {
      return {};
    }
  });

  const tier = HARDWARE_TIERS.find((t) => t.id === tierId)!;

  useEffect(() => {
    if (typeof window === "undefined") return;
    try {
      window.localStorage.setItem(STORAGE_KEY, JSON.stringify(completedSteps));
    } catch {
      // ignore quota / private mode
    }
  }, [completedSteps]);

  function toggleStep(key: string) {
    setCompletedSteps((prev) => ({ ...prev, [key]: !prev[key] }));
  }

  return (
    <>
      <PiTopBar
        crumbs={[{ label: "system" }, { label: "builder", active: true }]}
        right={<CloudSyncIndicator cloud={PI_HEALTH.cloud} />}
      />

      <PageHeader
        eyebrow="Hardware"
        title="Builder"
        italic={false}
        meta={
          <span>
            3 reference builds · pre-wired BOMs · 8 printable enclosures · firmware tree · setup tracker
          </span>
        }
      />

      <div className="grid grid-cols-[1fr] gap-[22px] px-7 pt-[22px] pb-7 max-w-none">
        <main className="flex flex-col gap-[22px]">
          <TierPicker tierId={tierId} onSelect={setTierId} />

          <ChamberMultiplier chambers={chambers} onChange={setChambers} />

          <SegmentedControl
            ariaLabel="builder section"
            value={tab}
            onChange={(t) => setTab(t)}
            options={TIER_TABS.map((t) => ({ value: t, label: t }))}
          />

          {tab === "overview" && <Overview tier={tier} />}
          {tab === "shopping" && <Shopping tier={tier} chambers={chambers} />}
          {tab === "models" && <Models />}
          {tab === "wiring" && <Wiring tier={tier} />}
          {tab === "firmware" && <Firmware tier={tier} />}
          {tab === "setup" && (
            <Setup
              tier={tier}
              completed={completedSteps}
              onToggle={toggleStep}
            />
          )}

          <Resources />
        </main>
      </div>
    </>
  );
}

function TierPicker({
  tierId,
  onSelect,
}: {
  tierId: BuilderTier["id"];
  onSelect: (id: BuilderTier["id"]) => void;
}) {
  return (
    <section
      className="grid min-w-0 auto-rows-fr grid-cols-[repeat(auto-fit,minmax(min(320px,100%),1fr))] gap-3"
      aria-label="tier picker"
    >
      {HARDWARE_TIERS.map((t) => {
        const active = t.id === tierId;
        return (
          <button
            key={t.id}
            type="button"
            onClick={() => onSelect(t.id)}
            className={cn(
              "flex min-h-[200px] cursor-pointer flex-col gap-3 rounded-md border px-6 py-[22px] text-left text-inherit appearance-none",
              active ? "border-accent-line bg-accent-soft" : "border-border-soft bg-bg-1",
            )}
          >
            <div className="flex items-baseline justify-between gap-3">
              <div className="flex min-w-0 flex-col gap-1">
                <span className="font-mono text-[13px] font-medium uppercase tracking-[0.16em] text-text-2">
                  {t.tagline}
                </span>
                <h2 className="font-body text-[18px] font-medium leading-[1.25] text-text-0">{t.name}</h2>
                <span className="font-mono text-[12px] text-text-2">
                  {t.componentCount} components · {t.estimatedCost}
                </span>
              </div>
              {active && <span className={cn(STATUS_PILL_BASE, STATUS_PILL_TONE.accent)}>selected</span>}
            </div>
            <p className="mt-auto font-body text-[14px] leading-[1.55] text-text-1">{t.bestFor}</p>
          </button>
        );
      })}
    </section>
  );
}

function ChamberMultiplier({
  chambers,
  onChange,
}: {
  chambers: number;
  onChange: (n: number) => void;
}) {
  const presets = [1, 2, 4, 6, 12];
  return (
    <section className="flex flex-row flex-wrap items-center gap-2 rounded-md border border-border-soft bg-bg-1 p-[26px]">
      <span className="font-mono text-[13px] font-medium uppercase tracking-[0.16em] text-text-2">
        Chambers to build
      </span>
      <div className="flex flex-wrap items-center gap-2" role="group" aria-label="chambers">
        {presets.map((n) => (
          <Chip key={n} active={chambers === n} onClick={() => onChange(n)}>
            ×{n}
          </Chip>
        ))}
      </div>
      <span className="ml-auto font-mono text-[12px] text-text-2">
        cost calculator multiplies the BOM · <span className="text-text-1">shared parts (Pi, PSU)</span> are not
        duplicated
      </span>
    </section>
  );
}

