function multiplyComponentQty(qty: number, chambers: number, isShared: boolean): number {
  if (isShared) return qty;
  return qty * chambers;
}

const SHARED_NAMES = new Set([
  "Raspberry Pi 5 (4GB)",
  "12V 5A Power Supply",
]);

function Shopping({ tier, chambers }: { tier: BuilderTier; chambers: number }) {
  const grouped = tier.components.reduce<Record<string, BuilderTier["components"]>>(
    (acc, c) => {
      if (!acc[c.category]) acc[c.category] = [];
      acc[c.category]!.push(c);
      return acc;
    },
    {},
  );

  const total = useMemo(() => {
    return tier.components.reduce((sum, c) => {
      const n = parseFloat(c.priceApprox.replace(/[^\d.]/g, ""));
      const qty = multiplyComponentQty(c.quantity, chambers, SHARED_NAMES.has(c.name));
      return sum + (Number.isFinite(n) ? n * qty : 0);
    }, 0);
  }, [tier, chambers]);

  return (
    <section className="flex flex-col gap-[18px]">
      <div className="flex flex-col flex-wrap items-center justify-between gap-3 rounded-md border border-border-soft bg-bg-1 p-[26px]">
        <div>
          <span className="font-mono text-[13px] font-medium uppercase tracking-[0.16em] text-text-2">
            Bill of materials · ×{chambers} chamber{chambers > 1 ? "s" : ""}
          </span>
          <p className="mt-1 font-mono text-[12px] text-text-2">
            shared infrastructure (Pi, PSU) does not duplicate · <span className="text-text-1">per-chamber</span>{" "}
            parts scale linearly
          </p>
        </div>
        {/* Internal SPA route — `<Link>`, not a plain `<a>`, so navigating
            here doesn't force a full page reload (same reasoning PiTopBar's
            `href` crumbs use). Every other CTA in this file is a genuine
            external anchor and stays `<a>`. */}
        <Link to="/shopping" className={T_BTN_PRIMARY}>
          send BOM to /shopping →
        </Link>
      </div>

      {Object.entries(grouped).map(([cat, items]) => {
        // DataTable's `R extends { id?: string | number }` constraint rejects
        // `BuilderComponent` outright (TS2559 — zero properties in common
        // with an all-optional bound counts as a "weak type" mismatch, not
        // just a missing-optional-field case). Same fix T4 used for Setup's
        // discovered-chamber rows: map in a synthetic `id` before handing
        // rows to DataTable, rather than fighting the generic.
        const rows = items.map((c) => ({ ...c, id: c.name }));
        return (
        <div key={cat} className="flex flex-col gap-2.5">
          <span className="font-mono text-[13px] font-medium uppercase tracking-[0.16em] text-text-2">{cat}</span>
          <DataTable<(typeof rows)[number]>
            rowKey={(c) => c.id}
            columns={[
              {
                key: "component",
                header: "Component",
                render: (c) => (
                  <div className="flex flex-col gap-1">
                    <a href={c.url} target="_blank" rel="noopener noreferrer" className={T_LINK_BODY}>
                      {c.name}
                    </a>
                    <div className="mt-1 font-mono text-[12px] text-text-2">{c.notes}</div>
                  </div>
                ),
              },
              { key: "role", header: "Role", render: (c) => c.role },
              {
                key: "qty",
                header: "Qty",
                align: "right",
                render: (c) => {
                  const isShared = SHARED_NAMES.has(c.name);
                  const qty = multiplyComponentQty(c.quantity, chambers, isShared);
                  return (
                    <>
                      <span className="font-mono text-text-0">×{qty}</span>
                      {isShared && chambers > 1 && (
                        <div className="mt-0.5 font-mono text-[12px] text-text-3">(shared)</div>
                      )}
                    </>
                  );
                },
              },
              {
                key: "price",
                header: "~Price",
                align: "right",
                render: (c) => <span className="font-mono text-text-0">{c.priceApprox}</span>,
              },
              {
                key: "buy",
                header: "Buy",
                align: "right",
                render: (c) => (
                  <a href={c.url} target="_blank" rel="noopener noreferrer" className={T_LINK_CTA}>
                    buy →
                  </a>
                ),
              },
            ]}
            rows={rows}
          />
        </div>
        );
      })}

      <Substitutions tier={tier} />

      <div className="flex flex-col items-baseline justify-between gap-3 rounded-md border border-border-soft bg-bg-1 p-[26px]">
        <span className="font-mono text-[13px] font-medium uppercase tracking-[0.16em] text-text-2">
          Estimated total · {chambers} chamber{chambers > 1 ? "s" : ""}
        </span>
        <span className="font-mono text-[28px] leading-none tracking-normal text-text-0">${total.toFixed(0)}</span>
      </div>
    </section>
  );
}

function Substitutions({ tier }: { tier: BuilderTier }) {
  const tierComponentNames = new Set(tier.components.map((c) => c.name));
  const relevant = BUILDER_ALTERNATES.filter((a) => tierComponentNames.has(a.forComponent));
  if (relevant.length === 0) return null;
  const grouped = relevant.reduce<Record<string, typeof BUILDER_ALTERNATES>>((acc, a) => {
    if (!acc[a.forComponent]) acc[a.forComponent] = [];
    acc[a.forComponent]!.push(a);
    return acc;
  }, {});

  return (
    <div className="flex flex-col gap-[18px] rounded-md border border-border-soft bg-bg-1 p-[26px]">
      <div className="mb-1.5 font-mono text-[15px] font-medium uppercase tracking-[0.16em] text-text-2">
        Substitutions
      </div>
      <p className="-mt-1.5 font-mono text-[12px] text-text-2">
        cheaper or beefier alternatives · price/availability tradeoffs
      </p>
      <div className="flex flex-col gap-3.5">
        {Object.entries(grouped).map(([forComponent, alts]) => {
          // Same DataTable `id` workaround as the BOM table above.
          const rows = alts.map((a) => ({ ...a, id: `${a.forComponent}|${a.name}` }));
          return (
          <div key={forComponent} className="flex flex-col gap-2">
            <span className="font-mono text-[13px] font-medium uppercase tracking-[0.16em] text-text-2">
              in place of · {forComponent}
            </span>
            {/* `.data-table.compact` (13px / tighter padding) has no
                equivalent prop on the frozen `DataTable` primitive — adopted
                it anyway per "primitives over hand-rolling"; the resulting
                rows render at DataTable's own (larger) default density. A
                disclosed difference, not a hand-rolled `<table>` reproduction
                — see report. */}
            <DataTable<(typeof rows)[number]>
              rowKey={(a) => a.id}
              columns={[
                {
                  key: "alternate",
                  header: "Alternate",
                  render: (a) => (
                    <a href={a.url} target="_blank" rel="noopener noreferrer" className={T_LINK_BODY}>
                      {a.name}
                    </a>
                  ),
                },
                {
                  key: "price",
                  header: "Price",
                  render: (a) => <span className="font-mono text-text-0">{a.priceApprox}</span>,
                },
                { key: "tradeoff", header: "Tradeoff", render: (a) => a.tradeoff },
                {
                  key: "stock",
                  header: "Stock",
                  render: (a) => (
                    <span
                      className={cn(
                        STATUS_PILL_BASE,
                        STATUS_PILL_TONE[
                          a.availability === "in-stock" ? "accent" : a.availability === "backorder" ? "warn" : "idle"
                        ],
                      )}
                    >
                      {a.availability}
                    </span>
                  ),
                },
                {
                  key: "buy",
                  header: "Buy",
                  align: "right",
                  render: (a) => (
                    <a href={a.url} target="_blank" rel="noopener noreferrer" className={T_LINK_CTA}>
                      buy →
                    </a>
                  ),
                },
              ]}
              rows={rows}
            />
          </div>
          );
        })}
      </div>
    </div>
  );
}

