const WIRING_VARIANTS: Array<{ id: BuilderTier["id"]; label: string; href: string }> = [
  { id: "bare_bones", label: "bare-bones", href: "https://github.com/59psi/SporePrint/blob/main/hardware/wiring/wiring-bare-bones.svg" },
  { id: "recommended", label: "recommended", href: "https://github.com/59psi/SporePrint/blob/main/hardware/wiring/wiring-recommended.svg" },
  { id: "all_the_things", label: "all-the-things", href: "https://github.com/59psi/SporePrint/blob/main/hardware/wiring/wiring-all-the-things.svg" },
];

