"use client";
import type { ReactNode } from "react";
import { useState } from "react";
import { Chip } from "./Chip";

// ────────────────────────────────────────────────────────────────────────
// Types — match the Pi server's GET /api/integrations response shape.
// ────────────────────────────────────────────────────────────────────────

export type IntegrationTier = "free" | "premium";
export type IntegrationState = "ok" | "degraded" | "disabled" | "error";

export interface IntegrationHealth {
  state: IntegrationState | null;
  last_error: string | null;
  last_checked_at: number | null;
}

export interface IntegrationDriverState {
  slug: string;
  tier_required: IntegrationTier;
  enabled: boolean;
  /** Config map. Secret fields are already redacted to ••••last4. */
  config: Record<string, unknown>;
  health: IntegrationHealth;
}

export interface IntegrationFieldDescriptor {
  name: string;
  label: string;
  type: "text" | "password" | "number" | "boolean" | "json" | "url";
  placeholder?: string;
  description?: string;
}

/** Per-vendor field schema. The Pi exposes a JSON schema from pydantic at
 *  GET /api/integrations/{slug}/config but rendering raw JSON Schema is a
 *  rabbit hole; for v4.1.0 we ship hand-curated schemas keyed by slug.
 *  Future: auto-generate from the Pi's response.
 */
export interface IntegrationVendorSchema {
  slug: string;
  label: string;
  blurb: string;
  fields: IntegrationFieldDescriptor[];
  /** v4.1.2 — list of writable actions surfaced as buttons-with-form. */
  actions?: VendorActionDescriptor[];
  /** Optional helper rendered above the form. */
  helper?: ReactNode;
}

/** Per-action input shape so the UI can render a focused control
 *  (e.g. percent slider for set_dim) instead of a generic JSON blob.
 */
export interface VendorActionDescriptor {
  name: string;
  label: string;
  fields: IntegrationFieldDescriptor[];
}

// ────────────────────────────────────────────────────────────────────────
// Status pill
// ────────────────────────────────────────────────────────────────────────

function stateTone(state: IntegrationState | null): "signal" | "accent" | "warn" | "err" | "idle" {
  switch (state) {
    case "ok":
      return "signal";
    case "degraded":
      return "warn";
    case "error":
      return "err";
    case "disabled":
    default:
      return "idle";
  }
}

function stateLabel(state: IntegrationState | null): string {
  switch (state) {
    case "ok":
      return "ok";
    case "degraded":
      return "degraded";
    case "error":
      return "error";
    case "disabled":
    default:
      return "disabled";
  }
}

export function IntegrationStatusPill({ state }: { state: IntegrationState | null }) {
  return (
    <Chip active tone={stateTone(state)}>
      {stateLabel(state)}
    </Chip>
  );
}

// ────────────────────────────────────────────────────────────────────────
// Single driver card
// ────────────────────────────────────────────────────────────────────────

export interface IntegrationCardCallbacks {
  onSave: (slug: string, enabled: boolean, config: Record<string, unknown>) => Promise<void>;
  onTest: (slug: string) => Promise<{ state: IntegrationState; last_error?: string | null } | null>;
  /** v4.1.2 — invoke a vendor write action. Returns the Pi's response
   *  body verbatim so the UI can show success/error feedback.
   */
  onAction?: (
    slug: string,
    action: string,
    payload: Record<string, unknown>,
  ) => Promise<unknown>;
}

interface IntegrationCardProps {
  driver: IntegrationDriverState;
  schema: IntegrationVendorSchema;
  /** When true, the card is read-only — used in the cloud-web mirror to
   *  surface state without offering a config form (Pi LAN UI is the
   *  primary surface). */
  readOnly?: boolean;
  callbacks?: IntegrationCardCallbacks;
}

export function IntegrationCard({
  driver,
  schema,
  readOnly = false,
  callbacks,
}: IntegrationCardProps) {
  const [enabled, setEnabled] = useState(driver.enabled);
  const [draft, setDraft] = useState<Record<string, unknown>>(() => ({ ...driver.config }));
  const [saving, setSaving] = useState(false);
  const [testing, setTesting] = useState(false);
  const [testResult, setTestResult] = useState<string | null>(null);
  const [saveError, setSaveError] = useState<string | null>(null);

  function setField(name: string, value: unknown) {
    setDraft((d) => ({ ...d, [name]: value }));
  }

  async function handleSave() {
    if (!callbacks) return;
    setSaving(true);
    setSaveError(null);
    try {
      await callbacks.onSave(driver.slug, enabled, draft);
    } catch (err) {
      setSaveError(err instanceof Error ? err.message : "save failed");
    } finally {
      setSaving(false);
    }
  }

  async function handleTest() {
    if (!callbacks) return;
    setTesting(true);
    setTestResult(null);
    try {
      const result = await callbacks.onTest(driver.slug);
      if (result == null) {
        setTestResult("test failed (no response)");
      } else if (result.state === "ok") {
        setTestResult("✓ connection ok");
      } else {
        setTestResult(`✗ ${result.state}${result.last_error ? `: ${result.last_error}` : ""}`);
      }
    } catch (err) {
      setTestResult(err instanceof Error ? `✗ ${err.message}` : "✗ test failed");
    } finally {
      setTesting(false);
    }
  }

  const tierTone = driver.tier_required === "premium" ? "accent" : "idle";

  return (
    <section
      className="card"
      style={{ display: "flex", flexDirection: "column", gap: 12, padding: 16 }}
    >
      <header
        style={{
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          gap: 12,
        }}
      >
        <div style={{ display: "flex", flexDirection: "column", gap: 4 }}>
          <h3 className="t-display" style={{ margin: 0, fontSize: 18 }}>
            {schema.label}
          </h3>
          <p className="t-meta" style={{ margin: 0, opacity: 0.7 }}>
            {schema.blurb}
          </p>
        </div>
        <div style={{ display: "flex", gap: 8 }}>
          <Chip active tone={tierTone}>
            {driver.tier_required}
          </Chip>
          <IntegrationStatusPill state={driver.health.state} />
        </div>
      </header>

      {driver.health.last_error && (
        <p className="t-meta" style={{ margin: 0, color: "var(--err, #d97757)" }}>
          {driver.health.last_error}
        </p>
      )}

      {schema.helper && <div className="t-meta">{schema.helper}</div>}

      {!readOnly && (
        <>
          <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
            {schema.fields.map((field) => (
              <FieldInput
                key={field.name}
                field={field}
                value={draft[field.name]}
                onChange={(v) => setField(field.name, v)}
              />
            ))}
          </div>

          <label
            style={{
              display: "flex",
              gap: 8,
              alignItems: "center",
              cursor: "pointer",
            }}
          >
            <input
              type="checkbox"
              checked={enabled}
              onChange={(e) => setEnabled(e.target.checked)}
            />
            <span>enabled</span>
          </label>

          <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
            <button
              type="button"
              className="btn-primary"
              disabled={saving}
              onClick={handleSave}
            >
              {saving ? "saving…" : "save"}
            </button>
            <button
              type="button"
              className="btn-secondary"
              disabled={testing}
              onClick={handleTest}
            >
              {testing ? "testing…" : "test connection"}
            </button>
            {testResult && (
              <span className="t-meta" style={{ alignSelf: "center" }}>
                {testResult}
              </span>
            )}
            {saveError && (
              <span className="t-meta" style={{ color: "var(--err, #d97757)", alignSelf: "center" }}>
                {saveError}
              </span>
            )}
          </div>

          {schema.actions && schema.actions.length > 0 && callbacks?.onAction && (
            <VendorActionsBlock
              slug={driver.slug}
              actions={schema.actions}
              onAction={callbacks.onAction}
            />
          )}
        </>
      )}
    </section>
  );
}

function VendorActionsBlock({
  slug,
  actions,
  onAction,
}: {
  slug: string;
  actions: VendorActionDescriptor[];
  onAction: (slug: string, action: string, payload: Record<string, unknown>) => Promise<unknown>;
}) {
  return (
    <fieldset
      style={{
        border: "1px solid var(--border-soft)",
        borderRadius: 6,
        padding: 12,
        display: "flex",
        flexDirection: "column",
        gap: 12,
      }}
    >
      <legend className="t-meta" style={{ padding: "0 6px", opacity: 0.8 }}>
        Vendor actions
      </legend>
      {actions.map((action) => (
        <VendorActionRow
          key={action.name}
          slug={slug}
          action={action}
          onAction={onAction}
        />
      ))}
    </fieldset>
  );
}

function VendorActionRow({
  slug,
  action,
  onAction,
}: {
  slug: string;
  action: VendorActionDescriptor;
  onAction: (slug: string, action: string, payload: Record<string, unknown>) => Promise<unknown>;
}) {
  const [draft, setDraft] = useState<Record<string, unknown>>({});
  const [busy, setBusy] = useState(false);
  const [result, setResult] = useState<string | null>(null);

  async function handleSubmit() {
    setBusy(true);
    setResult(null);
    try {
      const body = await onAction(slug, action.name, draft);
      setResult(`✓ ${action.name} ok${body ? ` — ${JSON.stringify(body).slice(0, 120)}` : ""}`);
    } catch (err) {
      setResult(`✗ ${err instanceof Error ? err.message : String(err)}`);
    } finally {
      setBusy(false);
    }
  }

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
      <strong className="t-meta" style={{ fontSize: 13 }}>{action.label}</strong>
      <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
        {action.fields.map((field) => (
          <FieldInput
            key={field.name}
            field={field}
            value={draft[field.name]}
            onChange={(v) => setDraft((d) => ({ ...d, [field.name]: v }))}
          />
        ))}
      </div>
      <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
        <button
          type="button"
          className="btn-secondary"
          disabled={busy}
          onClick={handleSubmit}
        >
          {busy ? "sending…" : `send ${action.name}`}
        </button>
        {result && <span className="t-meta">{result}</span>}
      </div>
    </div>
  );
}

// ────────────────────────────────────────────────────────────────────────
// Field input
// ────────────────────────────────────────────────────────────────────────

function FieldInput({
  field,
  value,
  onChange,
}: {
  field: IntegrationFieldDescriptor;
  value: unknown;
  onChange: (v: unknown) => void;
}) {
  const labelEl = (
    <label className="t-meta" style={{ display: "flex", flexDirection: "column", gap: 4 }}>
      <span>{field.label}</span>
      {field.description && (
        <span style={{ opacity: 0.6, fontSize: 12 }}>{field.description}</span>
      )}
      {renderControl()}
    </label>
  );

  function renderControl() {
    if (field.type === "boolean") {
      return (
        <input
          type="checkbox"
          checked={Boolean(value)}
          onChange={(e) => onChange(e.target.checked)}
        />
      );
    }
    if (field.type === "number") {
      return (
        <input
          type="number"
          value={typeof value === "number" ? value : ""}
          placeholder={field.placeholder}
          onChange={(e) => onChange(e.target.value === "" ? "" : Number(e.target.value))}
        />
      );
    }
    if (field.type === "json") {
      const text = typeof value === "string" ? value : JSON.stringify(value ?? {}, null, 2);
      return (
        <textarea
          rows={4}
          value={text}
          placeholder={field.placeholder ?? "{}"}
          onChange={(e) => {
            const raw = e.target.value;
            try {
              onChange(JSON.parse(raw));
            } catch {
              // Keep raw text in flight; commit on parse-success only.
              onChange(raw);
            }
          }}
        />
      );
    }
    return (
      <input
        type={field.type === "password" ? "password" : field.type === "url" ? "url" : "text"}
        value={typeof value === "string" || typeof value === "number" ? String(value) : ""}
        placeholder={field.placeholder}
        onChange={(e) => onChange(e.target.value)}
      />
    );
  }

  return labelEl;
}

