// ────────────────────────────────────────────────────────────────────────
// Top-level panel — list of cards
// ────────────────────────────────────────────────────────────────────────

export interface IntegrationsPanelProps {
  drivers: IntegrationDriverState[];
  /** Slug → schema lookup. Defaults to the bundled INTEGRATION_SCHEMAS. */
  schemas?: Record<string, IntegrationVendorSchema>;
  readOnly?: boolean;
  callbacks?: IntegrationCardCallbacks;
  /** Optional banner above the list. */
  intro?: ReactNode;
}

export function IntegrationsPanel({
  drivers,
  schemas = INTEGRATION_SCHEMAS,
  readOnly = false,
  callbacks,
  intro,
}: IntegrationsPanelProps) {
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
      {intro && <div className="t-meta">{intro}</div>}
      {drivers.length === 0 ? (
        <p className="t-meta">No integrations registered. Update the Pi to v4.1+.</p>
      ) : (
        drivers.map((driver) => {
          const schema =
            schemas[driver.slug] ?? {
              slug: driver.slug,
              label: driver.slug,
              blurb: "Unrecognised vendor — schema fallback.",
              fields: [],
            };
          return (
            <IntegrationCard
              key={driver.slug}
              driver={driver}
              schema={schema}
              readOnly={readOnly}
              callbacks={callbacks}
            />
          );
        })
      )}
    </div>
  );
}
