import type { ReactNode } from "react";

export function EmptyState({
  title,
  body,
  action,
}: {
  title: string;
  body?: ReactNode;
  action?: ReactNode;
}) {
  return (
    <div className="empty-state" role="status">
      <span className="t-eyebrow" style={{ marginBottom: 0 }}>nothing here</span>
      <h3 className="t-h3">{title}</h3>
      {body && <p className="t-body-sm" style={{ maxWidth: 420 }}>{body}</p>}
      {action && <div style={{ marginTop: 8 }}>{action}</div>}
    </div>
  );
}
