import type { Telemetry } from "../data/types";

/**
 * 2×2 telemetry grid per components.md §4. The `accent` arg picks one
 * cell to highlight in saffron — semantic, used for "currently
 * adjusting" e.g. humidity while the mister is engaged.
 */
export function KvCluster({
  t,
  accent,
}: {
  t: Telemetry;
  accent?: "temp" | "humidity" | "co2" | "vpd";
}) {
  return (
    <div className="f-kv" role="list">
      <Cell label="Temp" value={t.tempF.toFixed(1)} unit="°F" accent={accent === "temp"} />
      <Cell label="Humidity" value={Math.round(t.humidity).toString()} unit="%" accent={accent === "humidity"} />
      <Cell label="CO₂" value={Math.round(t.co2).toString()} unit="ppm" accent={accent === "co2"} />
      <Cell label="VPD" value={t.vpdKpa.toFixed(2)} unit="kPa" accent={accent === "vpd"} />
    </div>
  );
}

function Cell({ label, value, unit, accent }: { label: string; value: string; unit: string; accent?: boolean }) {
  return (
    <div className={accent ? "accent" : ""} role="listitem">
      <div className="k">{label}</div>
      <div className="v">
        {value}
        <span className="u">{unit}</span>
      </div>
    </div>
  );
}
