// ---------- helpers ----------

/**
 * Deterministic pseudo-random in [0,1) seeded from a string.
 * Mulberry32 hash. Stable across surfaces — required for parity tests.
 */
export function seedRand(seed: string): () => number {
  let h = 1779033703 ^ seed.length;
  for (let i = 0; i < seed.length; i++) {
    h = Math.imul(h ^ seed.charCodeAt(i), 3432918353);
    h = (h << 13) | (h >>> 19);
  }
  return () => {
    h = Math.imul(h ^ (h >>> 16), 2246822507);
    h = Math.imul(h ^ (h >>> 13), 3266489909);
    h ^= h >>> 16;
    return ((h >>> 0) % 100000) / 100000;
  };
}

function makeTrace(opts: {
  seed: string;
  count: number;
  base: number;
  amplitude: number;
  frequency: number;
  range: [number, number];
  tickEvery?: number;
}): ChannelTrace {
  const r = seedRand(opts.seed);
  const samples = Array.from({ length: opts.count }, (_, i) => {
    const t = i;
    const phase = (i / opts.count) * Math.PI * 2 * opts.frequency;
    const noise = (r() - 0.5) * opts.amplitude * 0.4;
    const v = opts.base + Math.sin(phase) * opts.amplitude + noise;
    return { t, v };
  });
  const ticks: number[] = [];
  if (opts.tickEvery) {
    for (let i = opts.tickEvery; i < opts.count; i += opts.tickEvery) {
      ticks.push(i);
    }
  }
  return { samples, ticks, range: opts.range };
}

