// ---------- fleet (24 chambers; CH-007 is the canonical) ----------

const SPECIES_POOL: Array<Chamber["species"]> = [
  { binomial: "Hericium erinaceus", common: "Lion's Mane" },
  { binomial: "Pleurotus ostreatus", common: "Pearl Oyster" },
  { binomial: "Pleurotus eryngii", common: "King Trumpet" },
  { binomial: "Pleurotus citrinopileatus", common: "Golden Oyster" },
  { binomial: "Lentinula edodes", common: "Shiitake" },
  { binomial: "Flammulina velutipes", common: "Enoki" },
  { binomial: "Grifola frondosa", common: "Maitake" },
  { binomial: "Hypsizygus tessulatus", common: "Beech" },
];

const PHASES: Array<Chamber["phase"]> = ["spawn", "fruiting", "harvest", "idle"];
const STATES: Array<Chamber["state"]> = ["active", "active", "active", "active", "warn", "idle"];

export function buildFleet(): Chamber[] {
  const chambers: Chamber[] = [];
  for (let i = 1; i <= 24; i++) {
    const idStr = i.toString().padStart(3, "0");
    const id = `CH-${idStr}`;
    if (id === "CH-007") {
      chambers.push(CANONICAL_CHAMBER);
      continue;
    }
    const r = seedRand(id);
    const speciesIdx = Math.floor(r() * SPECIES_POOL.length);
    const species = SPECIES_POOL[speciesIdx]!;
    const phaseIdx = Math.floor(r() * PHASES.length);
    const phase = PHASES[phaseIdx]!;
    const stateIdx = Math.floor(r() * STATES.length);
    const state = STATES[stateIdx]!;
    const day = phase === "idle" ? 0 : Math.floor(r() * 16) + 1;
    const total = phase === "fruiting" ? 18 : phase === "spawn" ? 14 : phase === "harvest" ? 5 : 0;
    const left = idStr[1] ?? "0";
    const right = idStr[2] ?? "0";
    chambers.push({
      id,
      display: { left, right },
      rack: { rack: Math.ceil(i / 6), shelf: ((i - 1) % 6) + 1 },
      serial: `esp32:7c-9e-bd:00:${(i + 0x40).toString(16)}`,
      firmware: "2.14.1",
      lastBoot: "2026-04-12T11:02:00Z",
      species,
      phase,
      state,
      day: { current: day, total },
      progress: total > 0 ? Math.round((day / total) * 100) : 0,
      telemetry: {
        tempF: 60 + r() * 12,
        humidity: 80 + r() * 18,
        co2: 600 + r() * 600,
        vpdKpa: 0.04 + r() * 0.4,
      },
      actuators: {
        mister: { on: r() > 0.7, sub: "—" },
        fan: { on: r() > 0.5, sub: "—" },
        heater: { on: false, sub: "—" },
        pump: { on: false, sub: "—" },
        light: { on: r() > 0.4, sub: "12:12" },
      },
      events: [],
    });
  }
  return chambers;
}

