// ---------- history ----------

export function chamberHistory(chamberId: string, hours: number = 4): ChamberHistory {
  // 240 samples = 4h at 1m granularity. The shape is stable for any
  // chamberId, but the seed differs so chambers don't all look identical.
  const sampleCount = hours * 60;
  const seed = chamberId;
  const axis = Array.from({ length: 9 }, (_, i) => {
    const minutesAgo = hours * 60 - (i * (hours * 60)) / 8;
    const totalMinutes = 14 * 60 + 30 - minutesAgo;
    const hh = Math.floor(totalMinutes / 60).toString().padStart(2, "0");
    const mm = Math.floor(totalMinutes % 60).toString().padStart(2, "0");
    return `${hh}:${mm}`;
  });

  return {
    hours,
    axis,
    temp: makeTrace({
      seed: `${seed}:temp`,
      count: sampleCount,
      base: 64,
      amplitude: 0.6,
      frequency: 1.5,
      range: [62, 66],
    }),
    hum: makeTrace({
      seed: `${seed}:hum`,
      count: sampleCount,
      base: 93,
      amplitude: 2.6,
      frequency: 8,
      range: [88, 98],
      tickEvery: 22,
    }),
    co2: makeTrace({
      seed: `${seed}:co2`,
      count: sampleCount,
      base: 820,
      amplitude: 110,
      frequency: 5,
      range: [600, 1000],
      tickEvery: 38,
    }),
    vpd: makeTrace({
      seed: `${seed}:vpd`,
      count: sampleCount,
      base: 0.1,
      amplitude: 0.05,
      frequency: 3,
      range: [0.04, 0.18],
    }),
  };
}

