export type RuleScopeKind = "global" | "chamber" | "species" | "phase";
export type RuleMetric =
  | "humidity"
  | "co2"
  | "temp"
  | "vpd"
  | "reservoir"
  | "time"
  | "vision"
  | "phase";
export type RuleOperator = "gt" | "lt" | "gte" | "lte" | "eq";
export type RuleAction =
  | "mister"
  | "fan"
  | "heater"
  | "pump"
  | "light"
  | "alert"
  | "suspend";

export interface RuleFire {
  /** HH:MM:SS local time of fire. Stable per-rule for screenshots. */
  ts: string;
  chamberId: string;
  /** Human-readable measurement that tripped the rule. */
  value: string;
  /** Outcome — "fired", "skipped (cooldown)", "suspended", etc. */
  outcome: "fired" | "skipped" | "suspended";
}

export interface RuleStub {
  id: string;
  name: string;
  scope: string;
  scopeKind: RuleScopeKind;
  /** Target — chamber id, species binomial, phase name, or "all". */
  scopeTarget: string;
  metric: RuleMetric;
  operator: RuleOperator;
  /** Threshold value rendered into the input as a string so units stay
   *  intact (e.g., "850" ppm, "60" °F, "07:00" for time). */
  threshold: string;
  /** Free-form human summary used in the list view. */
  condition: string;
  action: RuleAction;
  /** Action duration in seconds. 0 means "until condition clears". */
  actionDurationSec: number;
  /** Cooldown so the rule cannot re-fire faster than this. */
  cooldownSec: number;
  active: boolean;
  lastFired: string;
  fires7d: number;
  /** What this rule WOULD have fired in the last 24h. Used for the
   *  dry-run preview panel. Includes both real and skipped fires. */
  recentFires: RuleFire[];
  /** Free-form description shown in the editor — explains the why. */
  description: string;
}

function makeFires(seed: string, count: number, chambers: string[]): RuleFire[] {
  const r = seedRand(seed);
  const fires: RuleFire[] = [];
  let mins = 0;
  for (let i = 0; i < count; i++) {
    mins += Math.floor(r() * 90) + 10; // 10–100 min between fires
    const total = 24 * 60;
    const fromNow = Math.min(mins, total - 1);
    const hours = Math.floor((total - fromNow) / 60);
    const minutes = (total - fromNow) % 60;
    const ts = `${hours.toString().padStart(2, "0")}:${minutes.toString().padStart(2, "0")}:${Math.floor(r() * 60).toString().padStart(2, "0")}`;
    const chamberId = chambers[Math.floor(r() * chambers.length)] ?? chambers[0]!;
    const variance = (r() - 0.5) * 4;
    fires.push({
      ts,
      chamberId,
      value: variance.toFixed(1),
      outcome: r() > 0.92 ? "skipped" : "fired",
    });
  }
  return fires.reverse();
}

