/** Per-flush yield observation. Used for n-per-arm in stat-sig calc. */
export interface ExperimentObservation {
  flush: number;
  yieldGrams: number;
}

export interface ExperimentArm {
  label: string;
  chamber: string;
  /** Aggregate yield across all observations. */
  yieldGrams: number;
  flushes: number;
  /** Per-flush observations — used to compute mean, variance, n. */
  observations?: ExperimentObservation[];
}

export interface ExperimentMilestone {
  /** ISO date or short label like "day 4" / "2026-03-12". */
  on: string;
  label: string;
  /** "" default = sage, "a" = accent (positive), "w" = warn, "e" = err. */
  tone?: "" | "a" | "w" | "e";
}

export interface ExperimentVariable {
  name: string;
  controlValue: string;
  treatmentValue: string;
}

export interface ExperimentStub {
  id: string;
  name: string;
  species: string;
  /** Primary variable — kept singular for backwards compatibility with
   *  pi-ui + mobile cards. New surfaces should also read
   *  `additionalVariables` for multi-variable runs. */
  variable: string;
  armA: ExperimentArm;
  armB: ExperimentArm;
  status: "running" | "complete";
  /** Optional fields — present on v3.4-extended entries, absent on
   *  legacy ones. The cloud-web Experiments page degrades gracefully. */
  hypothesis?: string;
  /** "higher" = expect armB > armA on yield; "lower" = expect armB < armA;
   *  "none" = exploratory, no a priori direction. */
  expectedDirection?: "higher" | "lower" | "none";
  /** Operator's pre-experiment confidence in the hypothesis, 0–100. */
  confidencePre?: number;
  startedOn?: string;
  endedOn?: string;
  /** Additional variables co-varied with the primary one (multi-var). */
  additionalVariables?: ExperimentVariable[];
  milestones?: ExperimentMilestone[];
  /** Markdown-ish paragraphs (split on blank lines) for the write-up. */
  writeUp?: string;
}

