  id: string;
  kind: PlannerEventKind;
  label: string;
  /** chamber id ("CH-007") or null for non-chamber tasks (cleanings, orders). */
  chamberId: string | null;
  /** species binomial when applicable. */
  species?: string;
  /** species common name. */
  speciesCommon?: string;
  /** substrate description. */
  substrate?: string;
  /** estimated duration in days for this stage. */
