// ---------- Hardware health (v3.4 HardwareWeb parity) -------
//
// The cloud /hardware page mirrors the Pi `component_health`
// telemetry stream: each chamber publishes 4 nodes (climate /
// relay / lighting / camera) that report uptime, free heap, RSSI,
// and per-component counters (sensor reads/fails, relay channel
// state + on-time, lighting PWM + dwell, camera frame rate).

export type NodeKind = "climate" | "relay" | "lighting" | "camera";
export type NodeStatus = "ok" | "warn" | "err" | "offline";

export interface SensorCounters {
  /** I2C address chip identifier — sht31, scd41, bh1750, etc. */
  chip: string;
  reads: number;
  fails: number;
  /** Most recent reading (already formatted for display). */
  lastValue: string;
  ok: boolean;
}

export interface RelayChannel {
  /** "ch1", "ch2", … */
  id: string;
  label: string;
  /** True = energised. */
  on: boolean;
  /** PWM duty 0..100 (or null for binary channels). */
  pwmPct: number | null;
  /** Total seconds the channel has been energised since boot. */
  onTimeSec: number;
  /** Minutes since last state change (used to flag stuck channels). */
  minutesSinceChange: number;
  /** True = the channel was commanded but the GPIO state did not flip. */
  stuck: boolean;
}

export interface LightingChannel {
  id: string;
  label: string;
  /** PWM duty 0..100. */
  pwmPct: number;
  /** Hours on this 24h period. */
  onHours: number;
  /** Driver temp °C (warn at 65, err at 80). */
  driverTempC: number;
}

export interface CameraStats {
  /** Captures per second (sub-1 is normal for the ESP32-CAM). */
  fps: number;
  captureSuccess: number;
  captureFail: number;
  /** Average ms from shutter to upload. */
  avgLatencyMs: number;
  /** PSRAM free bytes. */
  psramFree: number;
  flash: boolean;
}

export interface NodeHealthFull {
  nodeId: string;
  chamberId: string;
  kind: NodeKind;
  status: NodeStatus;
  firmware: string;
  uptimeSec: number;
  /** Free heap bytes — ESP32 reference is 160KB. */
  freeHeap: number;
  /** Wifi RSSI (dBm). Stronger is closer to 0. Below -80 is bad. */
  rssi: number;
  /** Per-kind sub-payload. Only one is populated. */
  sensors?: SensorCounters[];
  relayChannels?: RelayChannel[];
  lightingChannels?: LightingChannel[];
  camera?: CameraStats;
  /** Free-form note explaining warn/err state. */
  note?: string;
}

/**
 * Build a deterministic but varied fleet of node-health records, four
 * nodes per chamber. Status quirks are seeded by chamber ID so the
 * same chambers always show the same problems across renders.
 */
export function buildHardwareNodeHealth(): NodeHealthFull[] {
  const out: NodeHealthFull[] = [];
  const fleetIdx = (id: string) => parseInt(id.replace("CH-", ""), 10);

  for (const chamber of FLEET) {
    const idx = fleetIdx(chamber.id);
    const r = seedRand(`${chamber.id}:hw`);
    const baseUptime = 14 * 86400 + Math.floor(r() * 86400);

    // ---- climate node ----------------------------------------
    const climateWarn = idx % 7 === 6;
    const climateOffline = idx === 21;
    const sht31Fails = climateWarn ? 4 : Math.floor(r() * 2);
    const scd41Fails = Math.floor(r() * 2);
    out.push({
      nodeId: `${chamber.id}-climate`,
      chamberId: chamber.id,
      kind: "climate",
      status: climateOffline ? "offline" : climateWarn ? "warn" : "ok",
      firmware: chamber.firmware,
      uptimeSec: climateOffline ? 0 : baseUptime,
      freeHeap: 96 * 1024 + Math.floor(r() * 28 * 1024),
      rssi: -52 - Math.floor(r() * 22),
      sensors: [
        {
          chip: "sht31",
          reads: 21420 + Math.floor(r() * 3000),
          fails: sht31Fails,
          lastValue: `${chamber.telemetry.tempF.toFixed(1)}°F · ${Math.round(chamber.telemetry.humidity)}%`,
          ok: sht31Fails < 3,
        },
        {
          chip: "scd41",
          reads: 7140 + Math.floor(r() * 800),
          fails: scd41Fails,
          lastValue: `${Math.round(chamber.telemetry.co2)}ppm`,
          ok: scd41Fails < 3,
        },
        {
          chip: "bh1750",
          reads: 14280 + Math.floor(r() * 1200),
          fails: 0,
          lastValue: chamber.actuators.light.on ? "412 lx" : "1 lx",
          ok: true,
        },
      ],
      note: climateOffline
        ? "node unreachable since 09:14 — last RTT 9 hours ago"
        : climateWarn
          ? "SHT31 temperature drift +0.6°F vs SCD41 reference — recalibration recommended"
          : undefined,
    });

    // ---- relay node ------------------------------------------
    const relayErr = idx % 11 === 0 && idx > 0;
    const stuckCh = relayErr ? 2 : -1;
    const relayChannels: RelayChannel[] = ["fae", "exhaust", "circulation", "mister"].map((label, ci) => {
      const isStuck = ci === stuckCh;
      const baseOn = ci === 0 ? !!chamber.actuators.fan.on : ci === 3 ? !!chamber.actuators.mister.on : ci === 1;
      return {
        id: `ch${ci + 1}`,
        label,
        on: isStuck ? true : baseOn,
        pwmPct: ci === 0 ? Math.floor(40 + r() * 50) : null,
        onTimeSec: Math.floor(800 + r() * 14000),
        minutesSinceChange: isStuck ? 47 + Math.floor(r() * 30) : Math.floor(r() * 12),
        stuck: isStuck,
      };
    });
    out.push({
      nodeId: `${chamber.id}-relay`,
      chamberId: chamber.id,
      kind: "relay",
      status: relayErr ? "err" : "ok",
      firmware: chamber.firmware,
      uptimeSec: baseUptime,
      freeHeap: 124 * 1024 + Math.floor(r() * 16 * 1024),
      rssi: -58 - Math.floor(r() * 18),
      relayChannels,
      note: relayErr
        ? "channel 3 (circulation) commanded off at 13:42 but GPIO still reads HIGH — auto-suspended"
        : undefined,
    });

    // ---- lighting node --------------------------------------
    const lightingChannels: LightingChannel[] = ["6500K white", "450nm blue", "660nm red", "730nm far-red"].map((label, ci) => ({
      id: `lt${ci + 1}`,
      label,
      pwmPct: chamber.actuators.light.on ? Math.floor(15 + r() * 38) : 0,
      onHours: chamber.actuators.light.on ? 6.4 + r() * 4 : 0,
      driverTempC: 38 + Math.floor(r() * 8),
    }));
    out.push({
      nodeId: `${chamber.id}-lighting`,
      chamberId: chamber.id,
      kind: "lighting",
      status: "ok",
      firmware: chamber.firmware,
      uptimeSec: baseUptime,
      freeHeap: 132 * 1024 + Math.floor(r() * 12 * 1024),
      rssi: -56 - Math.floor(r() * 20),
      lightingChannels,
    });

    // ---- camera node ----------------------------------------
    const cameraWarn = idx % 13 === 5;
    const fps = cameraWarn ? 0.4 : 0.95 + r() * 0.1;
    out.push({
      nodeId: `${chamber.id}-camera`,
      chamberId: chamber.id,
      kind: "camera",
      status: cameraWarn ? "warn" : "ok",
      firmware: chamber.firmware,
      uptimeSec: baseUptime,
      freeHeap: 84 * 1024 + Math.floor(r() * 12 * 1024),
      rssi: -64 - Math.floor(r() * 14),
      camera: {
        fps,
        captureSuccess: 8124 + Math.floor(r() * 200),
        captureFail: cameraWarn ? 312 : Math.floor(r() * 4),
        avgLatencyMs: cameraWarn ? 1820 : 380 + Math.floor(r() * 120),
        psramFree: 1_400_000 + Math.floor(r() * 400_000),
        flash: false,
      },
      note: cameraWarn ? "frame rate dropped below 0.5fps — USB cable check recommended" : undefined,
    });
  }
  return out;
}

export const HARDWARE_NODE_HEALTH: NodeHealthFull[] = buildHardwareNodeHealth();

