// Aggregate counts used by KPIs at the top of /hardware.
export interface HardwareKpis {
  totalNodes: number;
  onlineNodes: number;
  offlineNodes: number;
  warnNodes: number;
  errNodes: number;
  /** Sensor reads per second across the fleet (last minute average). */
  sensorRateHz: number;
  /** Camera fps averaged across all camera nodes. */
  avgFps: number;
  /** Total stuck relay channels right now. */
  stuckRelayCount: number;
  /** Sensor calibration entries past their next-due date. */
  calibrationOverdueCount: number;
}

export function computeHardwareKpis(): HardwareKpis {
  const totalNodes = HARDWARE_NODE_HEALTH.length;
  const onlineNodes = HARDWARE_NODE_HEALTH.filter((n) => n.status !== "offline").length;
  const offlineNodes = totalNodes - onlineNodes;
  const warnNodes = HARDWARE_NODE_HEALTH.filter((n) => n.status === "warn").length;
  const errNodes = HARDWARE_NODE_HEALTH.filter((n) => n.status === "err").length;
  // Stub-rate: each climate node has 3 sensors and reads at ~0.2Hz.
  const sensorRateHz = Math.round(
    HARDWARE_NODE_HEALTH.flatMap((n) => n.sensors ?? []).length * 0.2,
  );
  const cams = HARDWARE_NODE_HEALTH.filter((n) => n.kind === "camera" && n.camera);
  const avgFps =
    cams.length > 0
      ? Math.round(
          (cams.reduce((s, n) => s + (n.camera?.fps ?? 0), 0) / cams.length) * 100,
        ) / 100
      : 0;
  const stuckRelayCount = HARDWARE_NODE_HEALTH.filter((n) => n.kind === "relay").reduce(
    (sum, n) => sum + (n.relayChannels?.filter((c) => c.stuck).length ?? 0),
    0,
  );
  const calibrationOverdueCount = SENSOR_CALIBRATION_HISTORY.filter(
    (c) => c.daysUntilDue < 0,
  ).length;
  return {
    totalNodes,
    onlineNodes,
    offlineNodes,
    warnNodes,
    errNodes,
    sensorRateHz,
    avgFps,
    stuckRelayCount,
    calibrationOverdueCount,
  };
}

