// Per-chamber operational metadata that lives on the cloud Chambers
// asset page. Distinct from the live Fleet view: this is the
// physical inventory + lifetime stats + maintenance schedule.

export type ChamberEnclosure = "MartelliBox v2" | "MartelliBox v3" | "ShoeboxXL" | "Custom · 32qt";
export type ChamberActivity = "in-rotation" | "idle" | "retired";
export type MaintenanceKind =
  | "pco-clean"
  | "gasket-replace"
  | "sensor-recal"
  | "filter-swap"
  | "leak-test";
export type MaintenanceStatus = "overdue" | "due-soon" | "current";

export interface MaintenanceLogEntry {
  id: string;
  chamberId: string;
  /** Display date — "Apr 12" / "Mar 28". */
  date: string;
  daysAgo: number;
  kind: MaintenanceKind;
  /** Operator-facing description. */
  note: string;
  /** Tech who logged it (initials). */
  by: string;
}

export interface ChamberPhoto {
  id: string;
  chamberId: string;
  /** Display caption. */
  label: string;
  /** "Apr 14 · 14:22". */
  ts: string;
  /** What stage of the chamber's life the photo captures. */
  kind: "build" | "fruiting" | "harvest" | "issue" | "ref";
}

export interface ChamberAsset {
  id: string;
  rack: string; // "R2·S3"
  enclosure: ChamberEnclosure;
  installed: string; // "2024-08"
  installedDaysAgo: number;
  activity: ChamberActivity;
  /** Lifetime grow sessions completed in this chamber. */
  lifetimeSessions: number;
  /** Lifetime wet-yield grams. */
  lifetimeYieldG: number;
  /** Average days-from-inoculation to first pin. */
  avgTimeToFruit: number;
  /** Longest single run in days. */
  longestRunDays: number;
  /** Lifetime contamination rate (0..1). */
  contamRate: number;
  /** Days until next scheduled maintenance. Negative = overdue. */
  nextMaintDays: number;
  /** Free-form description of the next maintenance task. */
  nextMaintLabel: string;
  /** Maintenance log entries for this chamber, newest first. */
  log: MaintenanceLogEntry[];
  /** Photo gallery placeholders. */
  photos: ChamberPhoto[];
}

const ENCLOSURE_POOL: ChamberEnclosure[] = [
  "MartelliBox v2",
  "ShoeboxXL",
  "MartelliBox v3",
  "Custom · 32qt",
];

const INSTALL_POOL = ["2024-04", "2024-08", "2024-11", "2025-02", "2025-06", "2025-09"];

const MAINT_KIND_POOL: Array<{ kind: MaintenanceKind; label: string }> = [
  { kind: "pco-clean", label: "PCO clean · panel + diffuser" },
  { kind: "gasket-replace", label: "lid gasket replacement" },
  { kind: "sensor-recal", label: "SHT31 recalibration" },
  { kind: "filter-swap", label: "intake hepa filter swap" },
  { kind: "leak-test", label: "static-pressure leak test" },
];

function buildChamberAssets(): ChamberAsset[] {
  // Mirror the 24-chamber FLEET so chamber ids line up across pages.
  return FLEET.map((chamber, idx) => {
    const r = seedRand(`asset:${chamber.id}`);
    const enclosure = ENCLOSURE_POOL[idx % ENCLOSURE_POOL.length]!;
    const installed = INSTALL_POOL[idx % INSTALL_POOL.length]!;
    // Days since the install month — rough but stable.
    const installedDaysAgo = 60 + idx * 27 + Math.floor(r() * 30);
    const lifetimeSessions = 6 + (idx % 14);
    const lifetimeYieldG = 1800 + idx * 412 + Math.floor(r() * 240);
    const avgTimeToFruit = 9 + Math.floor(r() * 6);
    const longestRunDays = 22 + Math.floor(r() * 12);
    const contamRate = ((idx * 13) % 9) / 100;

    // Next-maintenance task: rotate through the kind pool deterministically.
    const nextKind = MAINT_KIND_POOL[idx % MAINT_KIND_POOL.length]!;
    // Spread due dates across overdue / due-soon / current windows.
    const dueOffset = ((idx * 7) % 41) - 14; // -14..26 days
    const nextMaintDays = dueOffset;
    const nextMaintLabel = nextKind.label;

    // Activity flag — a few idle, one retired, rest in-rotation.
    const activity: ChamberActivity =
      idx === 9 ? "retired" : chamber.phase === "idle" ? "idle" : "in-rotation";

    // Maintenance log — last 4 entries, newest first.
    const log: MaintenanceLogEntry[] = [];
    let elapsed = 6 + Math.floor(r() * 8);
    for (let i = 0; i < 4; i++) {
      const k = MAINT_KIND_POOL[(idx + i + 2) % MAINT_KIND_POOL.length]!;
      const month = ["Apr", "Mar", "Feb", "Jan"][i] ?? "Jan";
      const day = 28 - i * 6 - (idx % 4) || 4;
      const noteSuffix =
        i === 0
          ? "post-harvest reset"
          : i === 1
            ? "routine"
            : i === 2
              ? "drift > threshold"
              : "annual";
      log.push({
        id: `mlog:${chamber.id}:${i}`,
        chamberId: chamber.id,
        date: `${month} ${day}`,
        daysAgo: elapsed,
        kind: k.kind,
        note: `${k.label} · ${noteSuffix}`,
        by: ["BB", "RT", "AK", "BB"][i] ?? "BB",
      });
      elapsed += 18 + Math.floor(r() * 14);
    }

    // Photo gallery placeholders — 4 slots per chamber.
    const photos: ChamberPhoto[] = [
      { id: `ph:${chamber.id}:1`, chamberId: chamber.id, label: "build · empty", ts: `${installed} · day 1`, kind: "build" },
      { id: `ph:${chamber.id}:2`, chamberId: chamber.id, label: "primordia",     ts: "Apr 9 · 11:18",        kind: "fruiting" },
      { id: `ph:${chamber.id}:3`, chamberId: chamber.id, label: "first flush",   ts: "Apr 14 · 14:22",       kind: "harvest" },
      { id: `ph:${chamber.id}:4`, chamberId: chamber.id, label: "ref · clean",   ts: "Apr 16 · 09:01",       kind: "ref" },
    ];

    return {
      id: chamber.id,
      rack: `R${chamber.rack.rack}·S${chamber.rack.shelf}`,
      enclosure,
      installed,
      installedDaysAgo,
      activity,
      lifetimeSessions,
      lifetimeYieldG,
      avgTimeToFruit,
      longestRunDays,
      contamRate,
      nextMaintDays,
      nextMaintLabel,
      log,
      photos,
    };
  });
}

export const CHAMBER_ASSETS: ChamberAsset[] = buildChamberAssets();

export function maintenanceStatusFor(daysUntil: number): MaintenanceStatus {
  if (daysUntil < 0) return "overdue";
  if (daysUntil <= 7) return "due-soon";
  return "current";
}

