// ---------- Vision page stubs (v3.4 parity → v4 expansion) -------

export type VisionCamState = "online" | "offline" | "stale";
export type VisionContamFlag = "clean" | "suspect" | "confirmed";

export interface VisionCameraStub {
  /** Mirrors the chamber id — every fleet chamber owns one camera node. */
  chamberId: string;
  rack: string;
  speciesCommon: string;
  speciesBinomial: string;
  state: VisionCamState;
  /** Frame rate (fps) — typically 1 fps but a couple of nodes run at 0.5 fps. */
  fps: number;
  /** "1280x960" — short label for the meta strip. */
  resolution: string;
  /** Seconds since last successful capture. */
  lastCaptureSec: number;
  /** Frames stored on the Pi for this chamber's camera (rolling 24h). */
  framesStored: number;
  /** 0..1 latest contam classifier confidence — 0 means clean / not flagged. */
  contamConfidence: number;
  /** What the latest classifier returned (display label). */
  contamFlag: VisionContamFlag;
  /** Latest detection note for the side panel. */
  lastNote: string;
  /** 4 thumbnail labels — most-recent → 4 captures back. */
  timeLapse: Array<{ label: string; ts: string }>;
}

export const VISION_CAMERAS: VisionCameraStub[] = (() => {
  const TIMELAPSE_LABELS = ["t-0s", "t-60s", "t-120s", "t-180s"];
  return FLEET.map((chamber, idx) => {
    const r = seedRand(`vision:${chamber.id}`);
    const offline = chamber.state === "idle" && idx % 7 === 3;
    const stale = !offline && idx % 11 === 5;
    const state: VisionCamState = offline ? "offline" : stale ? "stale" : "online";
    const fps = idx % 6 === 0 ? 0.5 : 1;
    const resolution = idx % 4 === 0 ? "1600x1200" : "1280x960";
    const lastCaptureSec =
      state === "offline" ? 1840 + idx * 13 : state === "stale" ? 90 + idx * 4 : 4 + ((idx * 3) % 14);
    const framesStored = 1180 + idx * 47 + Math.floor(r() * 80);
    const suspect = idx % 9 === 4;
    const confirmed = idx === 13;
    const contamFlag: VisionContamFlag = confirmed ? "confirmed" : suspect ? "suspect" : "clean";
    const contamConfidence = confirmed ? 0.94 : suspect ? 0.62 + r() * 0.22 : 0;
    const lastNote = confirmed
      ? "trichoderma · green-mould pattern on substrate corner · confidence 0.94"
      : suspect
        ? "low-confidence contam ping · monitoring · spore-print classifier"
        : state === "offline"
          ? "camera offline · last frame 30+ minutes ago"
          : "frame ok · no contam markers detected";
    const timeLapse = TIMELAPSE_LABELS.map((l, i) => ({
      label: l,
      ts: state === "offline" ? "—" : `t-${i * 60 + 4}s`,
    }));
    return {
      chamberId: chamber.id,
      rack: `R${chamber.rack.rack}·S${chamber.rack.shelf}`,
      speciesCommon: chamber.species.common,
      speciesBinomial: chamber.species.binomial,
      state,
      fps,
      resolution,
      lastCaptureSec,
      framesStored,
      contamConfidence,
      contamFlag,
      lastNote,
      timeLapse,
    };
  });
})();

