"use client";

import { useEffect, useRef } from "react";
import { makeLogo, makeLogoGroup } from "../logo";

export interface LogoOpts {
  baseDensity?: number;
  latticeBias?: number;
  innerBiasPow?: number;
  color?: string;
}

/**
 * The spore-print mark. Renders a fresh stipple every mount — randomness
 * is intentional (real spore prints differ each impression). For
 * deterministic snapshot testing, the data-snapshot fallback below
 * emits a single representative dot count instead of the live SVG.
 */
export function Logo({ size = 22, opts }: { size?: number; opts?: LogoOpts }) {
  const ref = useRef<HTMLSpanElement | null>(null);

  useEffect(() => {
    const host = ref.current;
    if (!host) return;
    host.replaceChildren();
    try {
      const svg = makeLogo(size, opts ?? {});
      host.appendChild(svg);
    } catch {
      // makeLogo requires a DOM. Skip in non-DOM environments.
    }
  }, [size, opts]);

  return (
    <span
      ref={ref}
      className="logo-mount"
      data-logo-size={size}
      style={{ display: "inline-flex", width: size, height: size, alignItems: "center", justifyContent: "center" }}
      aria-label="sporeprint"
    />
  );
}

/**
 * Hero-mark variant for the chamber view. Renders into a 220×220 SVG
 * with a saffron breathing gradient behind the dots. Per components.md §6.
 */
export function ChamberHeroMark({
  display,
  ringLabel = "— Chamber —",
}: {
  display: { left: string; right: string };
  ringLabel?: string;
}) {
  const hostRef = useRef<SVGGElement | null>(null);

  useEffect(() => {
    const host = hostRef.current;
    if (!host) return;
    while (host.firstChild) host.removeChild(host.firstChild);
    try {
      const g = makeLogoGroup(1.6, 110, 110, { color: "#D4A15E", baseDensity: 1.1 });
      host.appendChild(g);
    } catch {
      // makeLogoGroup requires a DOM. Skip in non-DOM environments.
    }
  }, [display.left, display.right]);

  return (
    <div className="c-mark">
      <svg className="host" viewBox="0 0 220 220">
        <defs>
          <radialGradient id="gradA" cx="50%" cy="50%" r="50%">
            <stop offset="0%" stopColor="#D4A15E" stopOpacity="0.22" />
            <stop offset="60%" stopColor="#D4A15E" stopOpacity="0.04" />
            <stop offset="100%" stopColor="#D4A15E" stopOpacity="0" />
          </radialGradient>
        </defs>
        <circle className="breath" cx={110} cy={110} r={80} fill="url(#gradA)" />
        <circle cx={110} cy={110} r={92} fill="none" stroke="var(--border)" strokeWidth="1" />
        <g ref={hostRef} />
      </svg>
      <div className="inside">
        <div className="ring">{ringLabel}</div>
        <div className="n">
          <span>{display.left}</span>
          <span className="sep">·</span>
          <span>{display.right}</span>
        </div>
      </div>
    </div>
  );
}
