import { CloudSyncIndicator, PI_HEALTH, PageHeader, cn } from "@sporeprint/design";
import { PiTopBar } from "../components/PiTopBar";
import { apiGet } from "../lib/api";
import { relativeSeen, toneForStatus } from "../lib/chambers";
import { usePiLoad } from "../lib/use-pi-load";
import type { HardwareNode } from "../lib/pi-types";

// `.status-pill` base + tone (classmap §10). Full resolved utility strings —
// no shared legacy base class, so no utility emit-order fight (Binding Lesson 3).
const STATUS_PILL_BASE =
  "inline-flex items-center gap-[7px] rounded-pill border px-3 py-[5px] font-mono text-[12px] font-medium uppercase tracking-widest";
const STATUS_PILL_TONE = {
  signal: "border-signal/40 bg-signal-soft text-signal",
  warn: "border-warn bg-bg-2 text-warn",
  err: "border-err bg-bg-2 text-err",
} as const;

// `.side-panel.left-<tone>` accent border (components.css) → 3px left border in tone.
const NODE_LEFT = {
  signal: "border-l-signal",
  warn: "border-l-warn",
  err: "border-l-err",
} as const;

type Tone = keyof typeof STATUS_PILL_TONE;

function nodeDetail(node: HardwareNode): string {
  const parts = [`fw ${node.firmware_version ?? "—"}`, `seen ${relativeSeen(node.last_seen)}`];
  if (node.ip_address) parts.push(node.ip_address);
  if (typeof node.mqtt_reconnects === "number" && node.mqtt_reconnects > 0) {
    parts.push(`${node.mqtt_reconnects} reconnects`);
  }
  return parts.join(" · ");
}

export function HardwarePage() {
  const { data, loading, error: loadError } = usePiLoad(
    () => apiGet<HardwareNode[]>("/api/hardware/nodes"),
    [],
  );
  const nodes = data ?? [];

  const onlineCount = nodes.filter((n) => n.status === "online").length;
  const worst: Tone = nodes.some((n) => n.status === "offline")
    ? "err"
    : nodes.some((n) => n.status !== "online")
      ? "warn"
      : "signal";

  return (
    <>
      <PiTopBar
        crumbs={[{ label: "monitor" }, { label: "hardware", active: true }]}
        right={<CloudSyncIndicator cloud={PI_HEALTH.cloud} />}
      />

      <PageHeader
        eyebrow="On this Pi"
        title="Hardware health"
        italic={false}
        meta={<span>per-chamber sensor + relay + lighting + camera nodes</span>}
      />

      <div className="grid grid-cols-[1fr] gap-[22px] px-7 pt-[22px] pb-7 max-w-none">
        <main className="flex flex-col gap-3.5">
          {loadError ? (
            <p className="font-mono text-[13px] tracking-[0.05em] text-err">
              Failed to load hardware nodes: {loadError}
            </p>
          ) : loading ? (
            <p className="font-mono text-[13px] tracking-[0.05em] text-text-2">Loading…</p>
          ) : nodes.length === 0 ? (
            <p className="font-mono text-[13px] tracking-[0.05em] text-text-2">
              No hardware nodes have reported to this Pi yet.
            </p>
          ) : (
            <section className="flex flex-col gap-[18px] rounded-md border border-border-soft bg-bg-1 p-[26px]">
              <div className="flex items-baseline justify-between gap-3">
                <span className="font-mono text-[13px] font-medium uppercase tracking-[0.16em] text-text-2">
                  {onlineCount}/{nodes.length} nodes online
                </span>
                <span className={cn(STATUS_PILL_BASE, STATUS_PILL_TONE[worst])}>
                  {worst === "signal" ? "all nominal" : worst === "warn" ? "needs attention" : "fault"}
                </span>
              </div>
              <div className="grid grid-cols-[repeat(auto-fit,minmax(240px,1fr))] gap-2.5">
                {nodes.map((n) => {
                  const tone = toneForStatus(n.status);
                  return (
                    <div
                      key={n.node_id}
                      className={cn(
                        "flex flex-col gap-[18px] rounded-md border border-border-soft bg-bg-1 p-3.5 border-l-[3px]",
                        NODE_LEFT[tone],
                      )}
                    >
                      <span className="font-mono text-[12px] font-medium uppercase tracking-[0.14em] text-text-2">
                        {n.node_type} · {n.node_id}
                      </span>
                      <span className="font-mono text-[14px] text-text-1">{nodeDetail(n)}</span>
                    </div>
                  );
                })}
              </div>
            </section>
          )}
        </main>
      </div>
    </>
  );
}
