"use client";
import { useMemo, useState, type ReactNode } from "react";
import {
  flexRender,
  getCoreRowModel,
  getSortedRowModel,
  useReactTable,
  type ColumnDef,
  type SortingState,
} from "@tanstack/react-table";
import { ChevronDown, ChevronUp } from "lucide-react";
import { cn } from "../lib/cn";

export interface Column<R> {
  key: string;
  header: string;
  align?: "left" | "right";
  render: (row: R) => ReactNode;
  /** Provide to make the column sortable. */
  sortValue?: (row: R) => string | number;
}

export function DataTable<R extends { id?: string | number }>({
  columns,
  rows,
  caption,
  rowKey,
  onRowClick,
  empty,
  stickyHeader = false,
  initialSort,
}: {
  columns: Column<R>[];
  rows: R[];
  caption?: string;
  rowKey?: (row: R) => string | number;
  onRowClick?: (row: R) => void;
  empty?: ReactNode;
  stickyHeader?: boolean;
  initialSort?: { key: string; desc?: boolean };
}) {
  const getKey = rowKey ?? ((r: R) => (r.id ?? "") as string | number);
  const [sorting, setSorting] = useState<SortingState>(
    initialSort ? [{ id: initialSort.key, desc: initialSort.desc ?? false }] : [],
  );

  const columnDefs = useMemo<ColumnDef<R>[]>(
    () =>
      columns.map((c) => ({
        id: c.key,
        header: c.header,
        cell: ({ row }) => c.render(row.original),
        enableSorting: Boolean(c.sortValue),
        accessorFn: c.sortValue ?? (() => ""),
        sortingFn: "basic",
        sortDescFirst: false,
      })),
    [columns],
  );

  const table = useReactTable({
    data: rows,
    columns: columnDefs,
    state: { sorting },
    onSortingChange: setSorting,
    getCoreRowModel: getCoreRowModel(),
    getSortedRowModel: getSortedRowModel(),
    getRowId: (row, index) => String(getKey(row) || index),
  });

  if (rows.length === 0 && empty !== undefined) {
    return <>{empty}</>;
  }

  const alignFor = (key: string) => columns.find((c) => c.key === key)?.align;

  return (
    <table className="data-table w-full">
      {caption && (
        <caption className="t-eyebrow mb-2 text-left">{caption}</caption>
      )}
      <thead className={cn(stickyHeader && "sticky top-0 z-10 bg-bg-1")}>
        {table.getHeaderGroups().map((hg) => (
          <tr key={hg.id}>
            {hg.headers.map((h) => {
              const align = alignFor(h.column.id);
              const sortable = h.column.getCanSort();
              const dir = h.column.getIsSorted();
              const ariaSort = sortable
                ? dir === "asc"
                  ? "ascending"
                  : dir === "desc"
                    ? "descending"
                    : "none"
                : undefined;
              return (
                <th
                  key={h.id}
                  scope="col"
                  className={align === "right" ? "num" : ""}
                  aria-sort={ariaSort}
                >
                  {sortable ? (
                    <button
                      type="button"
                      onClick={h.column.getToggleSortingHandler()}
                      className={cn(
                        "inline-flex items-center gap-1 transition-colors duration-200 ease-brand hover:text-text-0",
                        align === "right" && "flex-row-reverse",
                      )}
                      aria-label={`sort by ${String(h.column.columnDef.header)}`}
                    >
                      {flexRender(h.column.columnDef.header, h.getContext())}
                      {dir === "asc" && <ChevronUp className="size-3" aria-hidden />}
                      {dir === "desc" && <ChevronDown className="size-3" aria-hidden />}
                    </button>
                  ) : (
                    flexRender(h.column.columnDef.header, h.getContext())
                  )}
                </th>
              );
            })}
          </tr>
        ))}
      </thead>
      <tbody>
        {table.getRowModel().rows.map((row) => (
          <tr
            key={row.id}
            onClick={onRowClick ? () => onRowClick(row.original) : undefined}
            onKeyDown={
              onRowClick
                ? (e) => {
                    if (e.key === "Enter" || e.key === " ") {
                      e.preventDefault();
                      onRowClick(row.original);
                    }
                  }
                : undefined
            }
            tabIndex={onRowClick ? 0 : undefined}
            role={onRowClick ? "button" : undefined}
            className={cn(onRowClick && "cursor-pointer")}
          >
            {row.getVisibleCells().map((cell) => (
              <td key={cell.id} className={alignFor(cell.column.id) === "right" ? "num" : ""}>
                {flexRender(cell.column.columnDef.cell, cell.getContext())}
              </td>
            ))}
          </tr>
        ))}
      </tbody>
    </table>
  );
}
