import { useState } from "react";
import { Button, DataTable, Input, PublicTopBar, cn } from "@sporeprint/design";

const SETUP_COMPLETE_KEY = "sporeprint:setup_complete";

// `.status-pill` base + tone (classmap §10). Full resolved utility strings —
// no shared legacy base class, so no utility emit-order fight (Binding Lesson 3).
const STATUS_PILL_BASE =
  "inline-flex items-center gap-[7px] rounded-pill border px-3 py-[5px] font-mono text-[12px] font-medium uppercase tracking-widest";
const STATUS_PILL_SIGNAL = "border-signal/40 bg-signal-soft text-signal";

/**
 * Mark first-run setup as complete on the Pi server, then mirror the
 * flag in localStorage. Best-effort — if the server call fails we
 * still set localStorage so the operator isn't stuck in a redirect
 * loop on an offline Pi.
 */
async function markSetupComplete(): Promise<void> {
  try {
    await fetch("/api/settings/setup-status", {
      method: "POST",
      credentials: "same-origin",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ setup_complete: true }),
    });
  } catch {
    // ignore — localStorage is the fallback
  }
  if (typeof window !== "undefined") {
    window.localStorage.setItem(SETUP_COMPLETE_KEY, "1");
  }
}

type Step = 1 | 2 | 3 | 4 | 5;

const STEPS: Record<Step, { roman: string; title: string; sub: string }> = {
  1: { roman: "§ I", title: "Welcome", sub: "Let's get your chambers online. This wizard takes about 5 minutes." },
  2: { roman: "§ II", title: "Network", sub: "Wired ethernet works without setup. WiFi networks ask once." },
  3: { roman: "§ III", title: "Cloud link", sub: "Pair this Pi to a paid sporeprint.ai account, or run locally only." },
  4: { roman: "§ IV", title: "First chamber", sub: "Scan the LAN for an unclaimed ESP32 chamber and add it to the rack." },
  5: { roman: "§ V", title: "Done", sub: "Your fleet is live at chambers.local. Everything else happens in flight." },
};

export function SetupPage() {
  const [step, setStep] = useState<Step>(1);
  const meta = STEPS[step];

  return (
    <div className="flex min-h-screen flex-col bg-bg-0">
      <PublicTopBar
        brand={{ word: "sporeprint", suffix: " · local" }}
        rightNav={
          <span className="font-mono text-[13px] font-medium uppercase tracking-[0.16em] text-text-2">
            First-run setup
          </span>
        }
      />

      {/* Step indicator strip */}
      <nav
        aria-label="setup progress"
        className="grid grid-cols-[repeat(5,1fr)] border-b border-border-soft bg-bg-1 px-10"
      >
        {([1, 2, 3, 4, 5] as Step[]).map((s) => {
          const past = s < step;
          const current = s === step;
          return (
            <button
              key={s}
              type="button"
              onClick={() => setStep(s)}
              className={cn(
                "flex cursor-pointer flex-col items-start gap-1 border-b-[3px] bg-transparent px-4 py-5 text-left",
                current
                  ? "border-b-accent text-accent"
                  : past
                    ? "border-b-accent-line text-text-1"
                    : "border-b-transparent text-text-3",
              )}
            >
              <span className="font-mono text-[13px] font-medium uppercase tracking-[0.16em] text-inherit">
                {STEPS[s].roman}
              </span>
              <span className="font-body text-[18px] font-medium leading-[1.25] text-inherit">
                {STEPS[s].title}
              </span>
            </button>
          );
        })}
      </nav>

      {/* Step body — generous, full-width */}
      <main className="mx-auto flex w-full max-w-[960px] flex-1 flex-col gap-6 px-10 pt-12 pb-16">
        <section className="flex flex-col gap-3">
          <span className="font-mono text-[13px] font-medium uppercase tracking-[0.16em] text-text-2">{meta.roman}</span>
          <h1 className="font-display text-[clamp(36px,4.4vw,56px)] font-semibold italic leading-[1.05] tracking-[-0.015em] text-text-0">
            {meta.title}
          </h1>
          <p className="max-w-[720px] font-body text-[18px] leading-[1.5] text-text-1">{meta.sub}</p>
        </section>

        {step === 1 && <StepOne />}
        {step === 2 && <StepTwo />}
        {step === 3 && <StepThree />}
        {step === 4 && <StepFour />}
        {step === 5 && <StepFive />}

        {/* Bottom nav */}
        <nav className="flex items-center justify-between gap-3 border-t border-border-soft pt-6">
          <Button
            variant="ghost"
            disabled={step === 1}
            onClick={() => setStep((s) => (s > 1 ? ((s - 1) as Step) : s))}
          >
            ← back
          </Button>
          <Button
            onClick={async () => {
              if (step === 5) {
                await markSetupComplete();
                window.location.href = "/";
              } else {
                setStep((s) => ((s + 1) as Step));
              }
            }}
          >
            {step === 5 ? "open fleet →" : "continue →"}
          </Button>
        </nav>
      </main>
    </div>
  );
}

