"use client";

import { Input } from "./ui/input";

// Wraps the Input primitive (Task 4). `t-input` is kept alongside Input's
// own utility classes for legacy-CSS coexistence; `aria-label` preserves the
// current fallback-to-placeholder behavior exactly (not just `ariaLabel`).
export function SearchInput({
  value,
  onChange,
  placeholder = "search…",
  ariaLabel,
}: {
  value: string;
  onChange: (v: string) => void;
  placeholder?: string;
  ariaLabel?: string;
}) {
  return (
    <Input
      type="search"
      role="searchbox"
      className="t-input"
      placeholder={placeholder}
      aria-label={ariaLabel ?? placeholder}
      value={value}
      onChange={(e) => onChange(e.currentTarget.value)}
    />
  );
}
