// Tiny same-origin fetch helpers for the Pi LAN UI — dependency-free.

async function errorFor(res: Response): Promise<Error> {
  let text = "";
  try {
    text = await res.text();
  } catch {
    text = "";
  }
  return new Error(text ? `HTTP ${res.status}: ${text.slice(0, 200)}` : `HTTP ${res.status}`);
}

export async function apiGet<T>(path: string): Promise<T> {
  const res = await fetch(path, { credentials: "same-origin" });
  if (!res.ok) {
    throw await errorFor(res);
  }
  return (await res.json()) as T;
}

export async function apiSend<T>(
  path: string,
  method: "POST" | "PUT" | "DELETE",
  body?: unknown,
): Promise<T> {
  const init: RequestInit = { method, credentials: "same-origin" };
  if (body !== undefined) {
    init.headers = { "Content-Type": "application/json" };
    init.body = JSON.stringify(body);
  }
  const res = await fetch(path, init);
  if (!res.ok) {
    throw await errorFor(res);
  }
  return (await res.json()) as T;
}
