"use client";

import { cn } from "../lib/cn";

interface Opt<T extends string> { value: T; label: string }

// Engine choice: plain anchor-based tablist (not ToggleGroup/Radix).
// Two pre-existing suites assert on this exact markup — `.v-time-ranges a.active`
// (src/__tests__/components.test.tsx) and `.v-time-ranges a` with a 4-item
// textContent match (pi-ui src/__tests__/pages.test.tsx) — which a Radix
// ToggleGroupItem (renders a <button data-state="on">, root role="group")
// cannot satisfy without editing those suites. Token utilities are layered
// on top of the legacy classes instead of swapping the engine; focus falls
// back to the global `:focus-visible` saffron outline defined in theme.css.
export function SegmentedControl<T extends string>({
  options,
  value,
  onChange,
  ariaLabel,
}: {
  options: Opt<T>[];
  value: T;
  onChange: (v: T) => void;
  ariaLabel?: string;
}) {
  return (
    <div className={cn("v-time-ranges")} role="tablist" aria-label={ariaLabel}>
      {options.map((opt) => {
        const active = opt.value === value;
        return (
          <a
            key={opt.value}
            href={`#${opt.value}`}
            role="tab"
            aria-selected={active}
            className={cn(
              active && "active",
              "transition-colors duration-200 ease-brand",
            )}
            onClick={(e) => { e.preventDefault(); onChange(opt.value); }}
          >
            {opt.label}
          </a>
        );
      })}
    </div>
  );
}
