type MetricVariant = "default" | "accent" | "signal";

const VARIANT_CLASS: Record<MetricVariant, string> = {
  default: "",
  accent: "accent",
  signal: "signal",
};

interface Props {
  label: string;
  /** Number-as-string so callers control formatting. Always mono. */
  value: string;
  unit?: string;
  /** Sub-line: state context, e.g. "mister on · 0.4s burst". */
  sub?: string;
  variant?: MetricVariant;
}

export function MetricReadout({ label, value, unit, sub, variant = "default" }: Props) {
  const cls = ["c-m", VARIANT_CLASS[variant]].filter(Boolean).join(" ");
  return (
    <div className={cls}>
      <div className="lbl">{label}</div>
      <div className="val">
        {value}
        {unit && <span className="u">{unit}</span>}
      </div>
      {sub && <div className="sub">{sub}</div>}
    </div>
  );
}
