// Shared chamber/actuator/format helpers hoisted from the wired pages
// (FleetPage, ChamberDetailPage, ChamberHistoryPage, FirmwarePage,
// HardwarePage) — one copy each, identical semantics.

import type { ActuatorKey, ActuatorState, Actuators, FleetEvent } from "@sporeprint/design";
import type { HardwareNode, OverrideRow, SessionEventRow } from "./pi-types";

// ── Actuator channel mapping ─────────────────────────────────────────
//
// WIRE CONTRACT — this map mirrors the firmware personality channel names
// (firmware/lib/sp_core/personality.h): a relay bank owns
// fae/exhaust/circulation/aux, a lighting bank owns white/blue/red/far_red.
//   mister ← "aux"   (the misting pump — see automation/templates.py
//                     "Mist (no humidifier)": relay aux, GPIO 14)
//   fan    ← "fae"   (fresh-air exchange fan)
//   light  ← "white" (lighting bank's primary channel)
// TODO(wire): heater + pump have no native relay channel — heaters/cool pumps
// are smart plugs (`/api/automation/plugs`); those keys render unmapped ("—").
// TODO(wire): exhaust/circulation exist on the wire but have no ActuatorKey in
// the design bank, so they are not controllable from this strip.
export const ACTUATOR_CHANNELS: Record<ActuatorKey, readonly string[]> = {
  mister: ["aux"],
  fan: ["fae"],
  heater: [],
  pump: [],
  light: ["white"],
};

export const ACTUATOR_KEYS: readonly ActuatorKey[] = ["mister", "fan", "heater", "pump", "light"];

export type ActTargets = Partial<Record<ActuatorKey, { nodeId: string; channel: string }>>;

/** Parse a node's persisted JSON `channels` column into channel names. */
export function nodeChannels(n: HardwareNode): string[] {
  if (!n.channels) return [];
  try {
    const parsed: unknown = JSON.parse(n.channels);
    return Array.isArray(parsed) ? parsed.filter((c): c is string => typeof c === "string") : [];
  } catch {
    return [];
  }
}

/** First node that carries each actuator's wire channel. Each node's
 *  `channels` JSON is parsed once per call, not once per actuator key. */
export function actuatorTargets(nodes: HardwareNode[]): ActTargets {
  const parsed = nodes.map((n) => ({ nodeId: n.node_id, chans: nodeChannels(n) }));
  const out: ActTargets = {};
  for (const key of ACTUATOR_KEYS) {
    for (const { nodeId, chans } of parsed) {
      const match = ACTUATOR_CHANNELS[key].find((c) => chans.includes(c));
      if (match) {
        out[key] = { nodeId, channel: match };
        break;
      }
    }
  }
  return out;
}

export function buildActuators(targets: ActTargets, rows: OverrideRow[]): Actuators {
  const build = (key: ActuatorKey): ActuatorState => {
    const t = targets[key];
    if (!t) return { on: false, sub: "—" };
    const ov = rows.find(
      (o) => o.locked && o.target === t.nodeId && (o.channel === t.channel || o.channel == null),
    );
    if (!ov) {
      // TODO(wire): live relay switch state only flows over MQTT/Socket.IO
      // ("actuator_state" events → actuator_events table, which has no REST
      // route) — so on-state is unknowable here and the LED rests off.
      return { on: false, sub: "state unknown" };
    }
    return {
      on: false,
      sub: ov.expires_at != null ? `override · until ${fmtClock(ov.expires_at)}` : "override · manual",
      override: {
        untilIso: ov.expires_at != null ? new Date(ov.expires_at * 1000).toISOString() : "",
        durationSec: ov.expires_at != null ? Math.max(0, Math.round(ov.expires_at - Date.now() / 1000)) : 0,
      },
    };
  };
  return {
    mister: build("mister"),
    fan: build("fan"),
    heater: build("heater"),
    pump: build("pump"),
    light: build("light"),
  };
}

// ── Real-data mapping helpers ────────────────────────────────────────

/** VPD (kPa) from °F + %RH — the standard saturation-deficit formula. */
// Magnus/Tetens (17.27, 237.3). NOTE: server weather/providers.py uses 237.7 —
// when a source reports vpd_kpa directly, prefer that reading (TODO(wire)).
export function vpdOf(tempF: number, humidity: number): number {
  const tc = ((tempF - 32) * 5) / 9;
  const svp = 0.61078 * Math.exp((17.27 * tc) / (tc + 237.3));
  return Math.max(0, svp * (1 - humidity / 100));
}

export function fmtClock(ts: number): string {
  const d = new Date(ts * 1000);
  const p = (n: number) => String(n).padStart(2, "0");
  return `${p(d.getHours())}:${p(d.getMinutes())}:${p(d.getSeconds())}`;
}

/** Hero-mark digits from the integer chamber PK ("7" → 0·7). */
export function displayOf(id: number): { left: string; right: string } {
  const s = String(id).padStart(2, "0");
  return { left: s.slice(0, -1), right: s.slice(-1) };
}

/** Session-event row → design FleetEvent. `prefix` (the chamber name) is
 *  prepended to the message on fleet-wide feeds. */
export function toFleetEvent(row: SessionEventRow, prefix?: string): FleetEvent {
  const tag = (row.type || "event").replace(/[^a-zA-Z0-9]/g, "").slice(0, 5).toUpperCase() || "EVENT";
  const cls: FleetEvent["cls"] = /contam|abort|fail|error/i.test(row.type)
    ? "e"
    : /alert|warn/i.test(row.type)
      ? "w"
      : /phase|harvest|override/i.test(row.type)
        ? "a"
        : "";
  const msg = row.description ?? row.type;
  return { ts: fmtClock(row.timestamp), tag, msg: prefix ? `${prefix} · ${msg}` : msg, cls };
}

// ── Node status helpers (FirmwarePage + HardwarePage) ────────────────

export type NodeStatusTone = "signal" | "warn" | "err";

export function toneForStatus(status: string | null): NodeStatusTone {
  if (status === "online") return "signal";
  if (status === "offline") return "err";
  return "warn";
}

export function relativeSeen(lastSeen: number | null): string {
  if (!lastSeen) return "never seen";
  const secs = Math.max(0, Math.floor(Date.now() / 1000 - lastSeen));
  if (secs < 60) return `${secs}s ago`;
  if (secs < 3600) return `${Math.floor(secs / 60)}m ago`;
  if (secs < 86400) return `${Math.floor(secs / 3600)}h ago`;
  return `${Math.floor(secs / 86400)}d ago`;
}
