import { useCallback, useEffect, useMemo, useState } from "react";
import {
  Button,
  CloudSyncIndicator,
  DataTable,
  Input,
  PI_HEALTH,
  PageHeader,
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
  cn,
} from "@sporeprint/design";
import { PiTopBar } from "../components/PiTopBar";
import { apiGet, apiSend } from "../lib/api";
import { usePiLoad } from "../lib/use-pi-load";
import type { PiSession } from "../lib/pi-types";

// Real Pi experiment row (GET /api/experiments — see
// server/app/experiments/service.py + the `experiments` table). An experiment
// references two grow sessions (control + variant) and one independent
// variable; per-metric comparison + significance come from dedicated endpoints.
interface Experiment {
  id: number;
  title: string;
  hypothesis: string;
  control_session_id: number;
  variant_session_id: number;
  independent_variable: string;
  control_value: string;
  variant_value: string;
  dependent_variables: string[];
  status: string;
  conclusion: string | null;
  created_at: number;
  completed_at: number | null;
}

interface ComparisonMetric {
  metric: string;
  control_value: number | null;
  variant_value: number | null;
  pct_difference: number | null;
  winner: "control" | "variant" | "tie" | null;
}
interface Comparison {
  experiment: Experiment;
  metrics: ComparisonMetric[];
}

interface Analysis {
  analysis?: {
    summary?: string;
    hypothesis_supported?: boolean;
    confidence?: string;
    recommendations?: string[];
    raw?: string;
  };
  error?: string;
}

// `.status-pill` base + tone (classmap §10) — self-sufficient tones per
// Binding Lesson 3. Same resolved strings as FleetPage/SessionsPage/CulturesPage.
const STATUS_PILL_BASE =
  "inline-flex items-center gap-[7px] rounded-pill border px-3 py-[5px] font-mono text-[12px] font-medium uppercase tracking-widest";
const STATUS_PILL_TONE = {
  accent: "border-accent-line bg-accent-soft text-accent",
  signal: "border-signal/40 bg-signal-soft text-signal",
  warn: "border-warn bg-bg-2 text-warn",
  idle: "border-border bg-bg-2 text-text-3",
} as const;
function statusPill(tone: keyof typeof STATUS_PILL_TONE): string {
  return cn(STATUS_PILL_BASE, STATUS_PILL_TONE[tone]);
}

function statusTone(status: string): keyof typeof STATUS_PILL_TONE {
  if (status === "active") return "accent";
  if (status === "completed") return "signal";
  return "idle";
}
function winnerTone(winner: ComparisonMetric["winner"]): keyof typeof STATUS_PILL_TONE {
  if (winner === "variant") return "accent";
  if (winner === "control") return "signal";
  return "idle";
}

export function ExperimentsPage() {
  const [refreshKey, setRefreshKey] = useState(0);
  const [selectedId, setSelectedId] = useState<number | null>(null);
  const [showNew, setShowNew] = useState(false);

  const { data: experiments, error: loadError } = usePiLoad(async () => {
    const rows = await apiGet<Experiment[]>("/api/experiments");
    // Seed/repair the selection inside the loader so it lands in the same
    // commit as the rows (batches with the hook's setState).
    setSelectedId((prev) =>
      prev != null && rows.some((e) => e.id === prev) ? prev : rows[0]?.id ?? null,
    );
    return rows;
  }, [refreshKey]);

  const refresh = useCallback(() => setRefreshKey((k) => k + 1), []);

  const list = experiments ?? [];
  // Derived (not the hook's flag) so a refreshKey reload keeps showing the
  // current list instead of flashing "Loading…" — same as before.
  const loading = experiments === null;
  const selected = useMemo(
    () => list.find((e) => e.id === selectedId) ?? null,
    [list, selectedId],
  );

  return (
    <>
      <PiTopBar
        crumbs={[{ label: "track" }, { label: "experiments", active: true }]}
        right={<CloudSyncIndicator cloud={PI_HEALTH.cloud} />}
      />

      <PageHeader
        eyebrow="Track"
        title="Experiments"
        italic={false}
        meta={
          <span>
            {list.length} runs · A/B comparisons · pair two sessions · vary one parameter
          </span>
        }
        right={
          <Button type="button" variant={showNew ? "ghost" : "solid"} onClick={() => setShowNew((v) => !v)}>
            {showNew ? "cancel" : "+ new experiment →"}
          </Button>
        }
      />

      <div className="grid grid-cols-[1fr_400px] gap-[22px] px-7 pt-[22px] pb-7 max-[1180px]:grid-cols-1">
        <main className="flex flex-col gap-3.5">
          {showNew && (
            <NewExperimentForm
              onClose={() => setShowNew(false)}
              onCreated={() => {
                setShowNew(false);
                refresh();
              }}
            />
          )}

          {loadError ? (
            <p className="font-mono text-[13px] tracking-[0.05em] text-err">
              Failed to load experiments: {loadError}
            </p>
          ) : loading ? (
            <p className="font-mono text-[13px] tracking-[0.05em] text-text-2">Loading…</p>
          ) : list.length === 0 ? (
            <p className="font-mono text-[13px] tracking-[0.05em] text-text-2">
              No experiments yet — start one with “+ new experiment”.
            </p>
          ) : (
            <div className="grid grid-cols-[repeat(auto-fit,minmax(min(440px,100%),1fr))] auto-rows-fr gap-3 min-w-0">
              {list.map((ex) => {
                const isSelected = ex.id === selectedId;
                return (
                  <article
                    key={ex.id}
                    onClick={() => setSelectedId(ex.id)}
                    className={cn(
                      "flex min-h-[200px] cursor-pointer flex-col gap-3 rounded-md border bg-bg-1 px-6 py-[22px]",
                      isSelected ? "border-accent-line" : "border-border-soft",
                    )}
                  >
                    <div className="flex items-baseline justify-between gap-3">
                      <div className="flex min-w-0 flex-col gap-1">
                        <span className="mb-0 font-mono text-[13px] font-medium uppercase tracking-[0.16em] text-text-2">variable: {ex.independent_variable}</span>
                        <h2 className="font-body font-medium text-[18px] leading-[1.25] text-text-0">{ex.title}</h2>
                      </div>
                      <span className={statusPill(statusTone(ex.status))}>{ex.status}</span>
                    </div>
                    <div className="grid grid-cols-[1fr_auto_1fr] items-stretch gap-3.5">
                      <ValueArm label="control" value={ex.control_value} />
                      <div className="flex items-center justify-center px-2 py-0">
                        <span className="mb-0 font-mono text-[13px] font-medium uppercase tracking-[0.16em] text-text-2">vs</span>
                      </div>
                      <ValueArm label="variant" value={ex.variant_value} accent />
                    </div>
                    <div className="mt-auto font-mono text-[12px] text-text-2">
                      {isSelected ? "comparison in panel →" : "select to compare →"}
                    </div>
                  </article>
                );
              })}
            </div>
          )}
        </main>

        <aside className="flex flex-col gap-3.5">
          {selected ? (
            <DetailPanel experiment={selected} />
          ) : (
            <section className="flex flex-col gap-[18px] rounded-md border border-border-soft bg-bg-1 p-[26px]">
              <span className="font-mono text-[12px] text-text-2">select an experiment to see its comparison</span>
            </section>
          )}
        </aside>
      </div>
    </>
  );
}

function DetailPanel({ experiment: ex }: { experiment: Experiment }) {
  const [comparison, setComparison] = useState<Comparison | null>(null);
  const [compError, setCompError] = useState<string | null>(null);
  const [analysis, setAnalysis] = useState<Analysis | null>(null);
  const [analysisError, setAnalysisError] = useState<string | null>(null);
  const [analyzing, setAnalyzing] = useState(false);

  useEffect(() => {
    let alive = true;
    setComparison(null);
    setCompError(null);
    setAnalysis(null);
    setAnalysisError(null);
    apiGet<Comparison>(`/api/experiments/${ex.id}/comparison`)
      .then((res) => {
        if (alive) setComparison(res);
      })
      .catch((err) => {
        if (alive) setCompError(err instanceof Error ? err.message : "load failed");
      });
    return () => {
      alive = false;
    };
  }, [ex.id]);

  // On-demand only — GET /{id}/analyze may call Claude, so it fires from this
  // button rather than automatically for every card. Errors (e.g. "Claude API
  // not configured") surface inline instead of blocking the panel.
  async function runAnalysis() {
    setAnalyzing(true);
    setAnalysisError(null);
    try {
      const res = await apiGet<Analysis>(`/api/experiments/${ex.id}/analyze`);
      setAnalysis(res);
    } catch (err) {
      setAnalysisError(err instanceof Error ? err.message : "analysis failed");
    } finally {
      setAnalyzing(false);
    }
  }

  return (
    <>
      <section className="flex flex-col gap-[18px] rounded-md border border-border-soft bg-bg-1 p-[26px]">
        <div className="mb-1.5 font-mono text-[15px] font-medium uppercase tracking-[0.16em] text-text-2">Detail · #{ex.id}</div>
        <h2 className="font-body font-medium text-[22px] leading-[1.25] text-text-0">{ex.title}</h2>
        {ex.hypothesis && (
          <div className="flex flex-col gap-1">
            <span className="mb-0 font-mono text-[13px] font-medium uppercase tracking-[0.16em] text-text-2">hypothesis</span>
            <p className="font-body text-[16px] leading-[1.55] text-text-1">{ex.hypothesis}</p>
          </div>
        )}
        <div className="grid grid-cols-2 gap-2.5">
          <Stat label="variable" value={ex.independent_variable} />
          <Stat label="status" value={ex.status} />
          <Stat label="control" value={ex.control_value} />
          <Stat label="variant" value={ex.variant_value} />
        </div>
        {ex.conclusion && (
          <div className="flex flex-col gap-1">
            <span className="mb-0 font-mono text-[13px] font-medium uppercase tracking-[0.16em] text-text-2">conclusion</span>
            <p className="font-body text-[15px] leading-[1.55] text-text-1">{ex.conclusion}</p>
          </div>
        )}
      </section>

      <section className="flex flex-col gap-[18px] rounded-md border border-border-soft bg-bg-1 p-[26px]">
        <div className="mb-1.5 font-mono text-[15px] font-medium uppercase tracking-[0.16em] text-text-2">Comparison</div>
        {compError ? (
          <span className="font-mono text-[12px] text-err">failed to load comparison: {compError}</span>
        ) : !comparison ? (
          <span className="font-mono text-[12px] text-text-2">Loading…</span>
        ) : comparison.metrics.length === 0 ? (
          <span className="font-mono text-[12px] text-text-2">no shared metrics yet</span>
        ) : (
          <DataTable<ComparisonMetric & { id: string }>
            rows={comparison.metrics.map((m) => ({ ...m, id: m.metric }))}
            columns={[
              { key: "metric", header: "Metric", render: (m) => m.metric.replace(/_/g, " ") },
              { key: "control", header: "Control", align: "right", render: (m) => (m.control_value ?? "—") },
              { key: "variant", header: "Variant", align: "right", render: (m) => (m.variant_value ?? "—") },
              {
                key: "delta",
                header: "Δ%",
                align: "right",
                render: (m) => (m.pct_difference != null ? `${m.pct_difference > 0 ? "+" : ""}${m.pct_difference}%` : "—"),
              },
              {
                key: "winner",
                header: "Winner",
                render: (m) => <span className={statusPill(winnerTone(m.winner))}>{m.winner ?? "—"}</span>,
              },
            ]}
          />
        )}
      </section>

      <section className="flex flex-col gap-[18px] rounded-md border border-border-soft bg-bg-1 p-[26px]">
        <div className="mb-1.5 font-mono text-[15px] font-medium uppercase tracking-[0.16em] text-text-2">Significance</div>
        <p className="font-body text-[14px] leading-[1.55] text-text-1">
          Run a Claude-backed analysis of the control-vs-variant results. Uses the Pi’s configured
          Claude key; may take a few seconds.
        </p>
        <Button type="button" variant="solid" className="self-start" onClick={runAnalysis} disabled={analyzing}>
          {analyzing ? "analyzing…" : "run significance analysis →"}
        </Button>
        {analysisError && <p className="font-mono text-[12px] text-err">{analysisError}</p>}
        {analysis?.error && (
          <p className="font-mono text-[12px] text-warn">{analysis.error}</p>
        )}
        {analysis?.analysis && (
          <div className="flex flex-col gap-2.5">
            {analysis.analysis.summary && (
              <p className="font-body text-[15px] leading-[1.55] text-text-1">{analysis.analysis.summary}</p>
            )}
            <div className="flex flex-wrap gap-2">
              {typeof analysis.analysis.hypothesis_supported === "boolean" && (
                <span className={statusPill(analysis.analysis.hypothesis_supported ? "accent" : "warn")}>
                  {analysis.analysis.hypothesis_supported ? "hypothesis supported" : "not supported"}
                </span>
              )}
              {analysis.analysis.confidence && (
                <span className={statusPill("signal")}>confidence · {analysis.analysis.confidence}</span>
              )}
            </div>
            {analysis.analysis.recommendations && analysis.analysis.recommendations.length > 0 && (
              <ul className="flex flex-col gap-1.5">
                {analysis.analysis.recommendations.map((r, i) => (
                  <li key={i} className="font-body text-[14px] leading-[1.55] text-text-1">↳ {r}</li>
                ))}
              </ul>
            )}
            {analysis.analysis.raw && (
              <p className="font-mono text-[12px] text-text-2">{analysis.analysis.raw}</p>
            )}
          </div>
        )}
      </section>

      {/* TODO(wire): side-by-side chamber telemetry sparklines were driven by
          the fake chamberHistory() generator. Wiring them for real needs a
          session → chamber → node_id mapping (GET /api/chambers/{id}.node_ids
          → GET /api/telemetry/history) that the experiment/comparison payloads
          don't expose. Omitted until that mapping is available.
          TODO(wire): experiment milestones have no server model either. */}
    </>
  );
}

// The control-session and variant-session pickers are the same control with
// a different label — one component used twice.
function SessionSelect({
  sessions,
  value,
  onChange,
  ariaLabel,
}: {
  sessions: PiSession[];
  value: string;
  onChange: (v: string) => void;
  ariaLabel: string;
}) {
  return (
    <Select value={value} onValueChange={onChange}>
      <SelectTrigger className="w-full" aria-label={ariaLabel}>
        <span className="min-w-0 flex-1 truncate text-left">
          <SelectValue placeholder="pick a session…" />
        </span>
      </SelectTrigger>
      <SelectContent>
        {sessions.map((s) => (
          <SelectItem key={s.id} value={String(s.id)}>
            <span className="font-mono text-text-0">#{s.id}</span> · {s.name}
          </SelectItem>
        ))}
      </SelectContent>
    </Select>
  );
}

function NewExperimentForm({
  onClose,
  onCreated,
}: {
  onClose: () => void;
  onCreated: () => void;
}) {
  const { data: sessionRows } = usePiLoad(() => apiGet<PiSession[]>("/api/sessions"), []);
  const sessions = sessionRows ?? [];
  const [title, setTitle] = useState("");
  const [hypothesis, setHypothesis] = useState("");
  const [variable, setVariable] = useState("");
  const [controlId, setControlId] = useState("");
  const [controlValue, setControlValue] = useState("");
  const [variantId, setVariantId] = useState("");
  const [variantValue, setVariantValue] = useState("");
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const valid =
    title.trim() !== "" &&
    hypothesis.trim() !== "" &&
    variable.trim() !== "" &&
    controlId !== "" &&
    variantId !== "" &&
    controlValue.trim() !== "" &&
    variantValue.trim() !== "";

  return (
    <form
      className="flex flex-col gap-3 rounded-md border border-border-soft bg-bg-1 p-[26px]"
      onSubmit={async (e) => {
        e.preventDefault();
        if (submitting || !valid) return;
        setSubmitting(true);
        setError(null);
        try {
          await apiSend<Experiment>("/api/experiments", "POST", {
            title: title.trim(),
            hypothesis: hypothesis.trim(),
            control_session_id: Number.parseInt(controlId, 10),
            variant_session_id: Number.parseInt(variantId, 10),
            independent_variable: variable.trim(),
            control_value: controlValue.trim(),
            variant_value: variantValue.trim(),
          });
          onCreated();
        } catch (err) {
          setError(err instanceof Error ? err.message : "create failed");
        } finally {
          setSubmitting(false);
        }
      }}
    >
      <div className="mb-1.5 font-mono text-[15px] font-medium tracking-[0.16em] uppercase text-text-2">New experiment</div>
      <Field label="Title">
        <Input value={title} onChange={(e) => setTitle(e.target.value)} placeholder="e.g. Lion's Mane · pinning RH" />
      </Field>
      <Field label="Hypothesis">
        <Input value={hypothesis} onChange={(e) => setHypothesis(e.target.value)} placeholder="e.g. higher pinning RH lifts first-flush yield" />
      </Field>
      <Field label="Independent variable">
        <Input value={variable} onChange={(e) => setVariable(e.target.value)} placeholder="e.g. humidity setpoint at pinning" />
      </Field>
      <div className="grid grid-cols-[repeat(auto-fit,minmax(200px,1fr))] gap-3">
        <Field label="Control session">
          <SessionSelect sessions={sessions} value={controlId} onChange={setControlId} ariaLabel="control session" />
        </Field>
        <Field label="Control value">
          <Input value={controlValue} onChange={(e) => setControlValue(e.target.value)} placeholder="e.g. 92% RH" />
        </Field>
        <Field label="Variant session">
          <SessionSelect sessions={sessions} value={variantId} onChange={setVariantId} ariaLabel="variant session" />
        </Field>
        <Field label="Variant value">
          <Input value={variantValue} onChange={(e) => setVariantValue(e.target.value)} placeholder="e.g. 96% RH" />
        </Field>
      </div>
      {error && <p className="font-mono text-[12px] text-err">{error}</p>}
      <div className="flex items-center justify-end gap-2.5">
        <Button type="button" variant="ghost" onClick={onClose}>cancel</Button>
        <Button type="submit" disabled={submitting || !valid}>
          {submitting ? "creating…" : "create experiment →"}
        </Button>
      </div>
    </form>
  );
}

function ValueArm({ label, value, accent }: { label: string; value: string; accent?: boolean }) {
  return (
    <div
      className={cn(
        "flex flex-col gap-1.5 rounded-sm border bg-bg-2 p-4",
        accent ? "border-accent-line" : "border-border-soft",
      )}
    >
      <span className="mb-0 font-mono text-[13px] font-medium uppercase tracking-[0.16em] text-text-2">{label}</span>
      <div className={cn("font-mono text-[20px] leading-tight tracking-normal", accent ? "text-accent" : "text-text-0")}>
        {value || "—"}
      </div>
    </div>
  );
}

function Field({ label, children }: { label: string; children: React.ReactNode }) {
  return (
    <label className="flex flex-col gap-1.5">
      <span className="font-mono text-[12px] font-medium tracking-[0.14em] uppercase text-text-2">{label}</span>
      {children}
    </label>
  );
}

function Stat({ label, value }: { label: string; value: string }) {
  return (
    <div className="flex flex-col gap-1 rounded-sm border border-border-soft bg-bg-2 p-3">
      <span className="font-mono text-[12px] font-medium tracking-[0.14em] uppercase text-text-2">{label}</span>
      <span className="font-mono text-[14px] text-text-1">{value}</span>
    </div>
  );
}
