const PHASE_TONE: Record<GrowSessionStub["phase"], "accent" | "signal" | "warn" | "err" | "idle"> = {
  spawn: "signal",
  fruiting: "accent",
  harvest: "signal",
  complete: "idle",
  contam: "err",
};

// statusPill tones — every tone fully self-sufficient (own text + bg +
// border, no shared base color) per Binding Lesson 3: a shared base color
// would lose to whichever tone utility Tailwind happens to emit last,
// corrupting tones invisibly. Same resolved strings as T3/T5/T7 and
// cloud-web's own _SessionsView (Phase-2 T9).
const STATUS_PILL_BASE =
  "inline-flex items-center gap-[7px] font-mono text-[12px] font-medium tracking-widest uppercase rounded-pill py-[5px] px-3 border";
const STATUS_PILL_TONE = {
  accent: "text-accent bg-accent-soft border-accent-line",
  signal: "text-signal bg-signal-soft border-[rgba(125,184,168,0.4)]",
  warn: "text-warn bg-bg-2 border-warn",
  err: "text-err bg-bg-2 border-err",
  idle: "text-text-3 bg-bg-2 border-border",
} as const;
function statusPill(tone: keyof typeof STATUS_PILL_TONE): string {
  return `${STATUS_PILL_BASE} ${STATUS_PILL_TONE[tone]}`;
}

// No first-class `warn` Button variant exists in the frozen design
// package — T5's SettingsPage precedent, reused verbatim for the
// "mark contaminated" action below.
const WARN_GHOST = "border-warn/40 text-warn hover:border-warn/40 hover:bg-warn/10";

// Hand-rolled `.data-table` cascade (classmap §9), reproduced as utilities
// since this table is kept hand-rolled rather than adopted as <DataTable>
// (see the comment above the <table> below for why).
const TH =
  "text-left py-3.5 px-[18px] font-mono text-[12px] font-medium tracking-[0.14em] uppercase text-text-2 border-b border-border-soft bg-bg-1";
const TD = "py-3.5 px-[18px] border-t border-border-soft align-middle";

type StatusFilter = "all" | "active" | "complete" | "contam";
type PhaseFilter = "all" | GrowSessionStub["phase"];
type SortMode = "newest" | "oldest" | "yield" | "duration";

// Map a raw Pi `sessions` row (GET /api/sessions) onto the display stub the
// table renders. The list endpoint gives base fields; the rich fields
// (harvests, phase segments) are fetched per-session by the detail panel.
const REAL_PHASE_TO_STUB: Record<string, GrowSessionStub["phase"]> = {
  agar: "spawn",
  liquid_culture: "spawn",
  grain_colonization: "spawn",
  substrate_colonization: "spawn",
  cold_storage: "spawn",
  primordia_induction: "fruiting",
  fruiting: "fruiting",
  rest: "harvest",
  complete: "complete",
};

function realSessionToStub(row: Record<string, unknown>): GrowSessionStub {
  const sp = SPECIES_LIBRARY.find((s) => s.id === row.species_profile_id);
  const startedAt = (row.started_at as string) || (row.created_at as string) || "";
  const startedMs = startedAt ? new Date(startedAt).getTime() : Date.now();
  const startedDaysAgo = Math.max(0, Math.floor((Date.now() - startedMs) / 86_400_000));
  const status = String(row.status ?? "");
  const phase =
    status === "contaminated" || status === "aborted"
      ? "contam"
      : (REAL_PHASE_TO_STUB[String(row.current_phase ?? "")] ?? "spawn");
  return {
    id: String(row.id),
    chamberId: row.chamber_id != null ? `CH-${row.chamber_id}` : "—",
    species: {
      binomial: sp?.binomial ?? "",
      common: sp?.common ?? String(row.name ?? "session"),
    },
    substrate: (row.substrate as string) ?? "—",
    startedDaysAgo,
    phase,
    yieldGrams: (row.total_wet_yield_g as number) ?? null,
    flushes: (row.flush_count as number) ?? 0,
  };
}

export function SessionsPage() {
  // Fetch real sessions from the Pi (same-origin /api/sessions). This is the
  // Pi's own local truth — there is no fake fallback: a failed fetch surfaces
  // an error banner rather than demo data. Re-fetches after any mutation
  // (create / harvest / complete / abort) via the refreshKey bump. Kept on a
  // raw fetch (not apiGet) so the error banner stays a bare `HTTP <status>`.
  const [refreshKey, setRefreshKey] = useState(0);
  const { data: realSessions, error: listError } = usePiLoad<GrowSessionStub[]>(
    () =>
      fetch("/api/sessions", { credentials: "same-origin" })
        .then((r) => (r.ok ? r.json() : Promise.reject(new Error(`HTTP ${r.status}`))))
        .then((rows: Record<string, unknown>[]) => (Array.isArray(rows) ? rows.map(realSessionToStub) : [])),
    [refreshKey],
  );
  // Derived (not the hook's flag) so a refreshKey reload keeps showing the
  // current table instead of flashing "Loading…" — same as before.
  const loading = realSessions === null;
  const allLocal = useMemo(() => realSessions ?? [], [realSessions]);

  const [status, setStatus] = useState<StatusFilter>("all");
  const [phaseFilter, setPhaseFilter] = useState<PhaseFilter>("all");
  const [sort, setSort] = useState<SortMode>("newest");
  const [query, setQuery] = useState("");
  const [showNew, setShowNew] = useState(false);
  const [selectedId, setSelectedId] = useState<string>("");

  const filtered = useMemo(() => {
    const q = query.trim().toLowerCase();
    let list = allLocal.filter((s) => {
      if (status === "active" && (s.phase === "complete" || s.phase === "contam")) return false;
      if (status === "complete" && s.phase !== "complete") return false;
      if (status === "contam" && s.phase !== "contam") return false;
      if (phaseFilter !== "all" && s.phase !== phaseFilter) return false;
      if (!q) return true;
      return [s.id, s.chamberId, s.species.binomial, s.species.common, s.substrate]
        .join(" ")
        .toLowerCase()
        .includes(q);
    });
    list = [...list];
    list.sort((a, b) => {
      switch (sort) {
        case "newest":
          return a.startedDaysAgo - b.startedDaysAgo;
        case "oldest":
          return b.startedDaysAgo - a.startedDaysAgo;
        case "yield":
          return (b.yieldGrams ?? 0) - (a.yieldGrams ?? 0);
        case "duration":
          return b.startedDaysAgo - a.startedDaysAgo;
      }
    });
    return list;
  }, [allLocal, status, phaseFilter, sort, query]);

  const selected = useMemo(
    () => filtered.find((s) => s.id === selectedId) ?? filtered[0] ?? allLocal[0],
    [filtered, selectedId, allLocal],
  );

  const kpis = useMemo(() => {
    const total = allLocal.length;
    const active = allLocal.filter((s) => s.phase !== "complete" && s.phase !== "contam").length;
    const completed = allLocal.filter((s) => s.phase === "complete").length;
    const contam = allLocal.filter((s) => s.phase === "contam").length;
    const contamRate = total > 0 ? contam / total : 0;
    const yieldRecent = allLocal
      .filter((s) => (s.yieldGrams ?? 0) > 0 && s.startedDaysAgo <= 30)
      .reduce((sum, s) => sum + (s.yieldGrams ?? 0), 0);
    return { total, active, completed, contam, contamRate, yieldRecent };
  }, [allLocal]);

  return (
    <>
      <PiTopBar
        crumbs={[{ label: "monitor" }, { label: "grows", active: true }]}
        right={<CloudSyncIndicator cloud={PI_HEALTH.cloud} />}
      />

      <PageHeader
        eyebrow="On this Pi"
        title="Grow sessions"
        italic={false}
        meta={
          <span>
            {filtered.length} of {allLocal.length} sessions on local chambers · last 30d yield {kpis.yieldRecent.toLocaleString()}g
          </span>
        }
        right={
          <Button type="button" variant={showNew ? "solid" : "ghost"} onClick={() => setShowNew((v) => !v)}>
            {showNew ? "cancel" : "+ new session"}
          </Button>
        }
      />

      <div className="grid grid-cols-[1fr_400px] gap-[22px] px-7 pt-[22px] pb-7 max-[1180px]:grid-cols-1">
        <main className="flex flex-col gap-3.5 max-[1180px]:min-w-0">
          <section className="grid grid-cols-[repeat(auto-fit,minmax(220px,1fr))] gap-3">
            <KpiCard label="active" value={kpis.active.toString()} tone="accent" />
            <KpiCard label="completed" value={kpis.completed.toString()} tone="signal" />
            <KpiCard label="contam rate" value={`${(kpis.contamRate * 100).toFixed(1)}%`} />
            <KpiCard label="yield · 30d" value={`${kpis.yieldRecent.toLocaleString()}g`} tone="accent" />
          </section>

          <Toolbar
            query={query}
            onQuery={setQuery}
            status={status}
            onStatus={setStatus}
            phaseFilter={phaseFilter}
            onPhaseFilter={setPhaseFilter}
            sort={sort}
            onSort={setSort}
          />

          {showNew && (
            <NewSessionForm
              onClose={() => {
                setShowNew(false);
                setRefreshKey((k) => k + 1);
              }}
            />
          )}

          {listError ? (
            <p className="font-mono text-[13px] tracking-[0.05em] text-err">
              Failed to load sessions: {listError}
            </p>
          ) : loading ? (
            <p className="font-mono text-[13px] tracking-[0.05em] text-text-2">Loading…</p>
          ) : allLocal.length === 0 ? (
            <p className="font-mono text-[13px] tracking-[0.05em] text-text-2">
              No grow sessions on this Pi yet — start one with “+ new session”.
            </p>
          ) : (
          /* Kept hand-rolled (not <DataTable>): this is a master-detail
              list where the selected row's accent-soft background is the
              user's only visual anchor for which session the aside detail
              panel refers to. DataTable's <tr> className is a fixed
              `cn(onRowClick && "cursor-pointer")` with no per-row override
              slot (same "render returns cell content, not the <td>/<tr>
              itself" limitation T6/T7 already documented) — forcing this
              table into DataTable would silently drop the selection
              highlight, a real behavioral affordance, not just density. */
          <div className="max-[1180px]:min-w-0 max-[1180px]:overflow-x-auto">
          <table className="w-full border-collapse bg-bg-1 border border-border-soft rounded-md overflow-hidden font-body text-[15px] text-text-1">
            <thead>
              <tr>
                <th scope="col" className={TH}>Session</th>
                <th scope="col" className={TH}>Chamber</th>
                <th scope="col" className={TH}>Species</th>
                <th scope="col" className={TH}>Substrate</th>
                <th scope="col" className={TH}>Phase</th>
                <th scope="col" className={`${TH} text-right`}>Day</th>
                <th scope="col" className={`${TH} text-right`}>Yield</th>
                <th scope="col" className={TH} />
              </tr>
            </thead>
            <tbody>
              {filtered.map((s) => {
                const isSel = s.id === selectedId;
                return (
                  <tr
                    key={s.id}
                    onClick={() => setSelectedId(s.id)}
                    className={cn("cursor-pointer", isSel ? "bg-accent-soft" : "hover:bg-bg-2")}
                  >
                    <td className={`${TD} font-mono text-text-0`}>{s.id}</td>
                    <td className={TD}>
                      <Link
                        to={`/chamber/${s.chamberId}`}
                        className="font-mono text-[14px] tracking-normal text-accent no-underline cursor-pointer hover:text-text-0"
                      >
                        {s.chamberId}
                      </Link>
                    </td>
                    {/* `.data-table .binomial-cell` resolves to `--f-serif`
                        in components.css — this cell already rendered serif
                        at clean HEAD. */}
                    <td className={`${TD} font-serif italic font-medium text-[18px] tracking-[-0.005em] text-text-0`}>
                      {s.species.binomial || s.species.common}
                    </td>
                    <td className={TD}>{s.substrate}</td>
                    <td className={TD}>
                      <span className={statusPill(PHASE_TONE[s.phase])}>{s.phase}</span>
                    </td>
                    <td className={`${TD} text-right font-mono text-text-0`}>{s.startedDaysAgo}d</td>
                    <td className={`${TD} text-right font-mono text-text-0`}>
                      {s.yieldGrams !== null ? `${s.yieldGrams}g` : "—"}
                    </td>
                    <td className={`${TD} text-right`}>
                      <Link
                        to={`/chamber/${s.chamberId}`}
                        className="font-mono text-[14px] font-medium tracking-[0.16em] uppercase text-accent no-underline cursor-pointer bg-transparent border-none p-0 self-start hover:text-text-0"
                      >
                        open →
                      </Link>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
          </div>
          )}

          <p className="font-mono text-[12px] text-text-2">
            long-range session history opens on the cloud · Pi keeps the last 24h locally
          </p>
        </main>

        {selected && (
          <DetailPanel
            session={selected}
            refreshToken={refreshKey}
            onChanged={() => setRefreshKey((k) => k + 1)}
          />
        )}
      </div>
    </>
  );
}

function Toolbar({
  query,
  onQuery,
  status,
  onStatus,
  phaseFilter,
  onPhaseFilter,
  sort,
  onSort,
}: {
  query: string;
  onQuery: (v: string) => void;
  status: StatusFilter;
  onStatus: (s: StatusFilter) => void;
  phaseFilter: PhaseFilter;
  onPhaseFilter: (p: PhaseFilter) => void;
  sort: SortMode;
  onSort: (s: SortMode) => void;
}) {
  return (
    <section className="flex flex-row flex-wrap items-center gap-2 rounded-md border border-border-soft bg-bg-1 p-[26px]">
      <div className="flex-[1_1_240px] min-w-[200px]">
        <SearchInput
          value={query}
          onChange={onQuery}
          placeholder="search id, chamber, species …"
          ariaLabel="search sessions"
        />
      </div>
      <ChipGroup label="status">
        {(["all", "active", "complete", "contam"] as const).map((s) => (
          <Chip key={s} active={status === s} onClick={() => onStatus(s)}>{s}</Chip>
        ))}
      </ChipGroup>
      <ChipGroup label="phase">
        {(["all", "spawn", "fruiting", "harvest", "complete", "contam"] as const).map((p) => (
          <Chip
            key={p}
            active={phaseFilter === p}
            onClick={() => onPhaseFilter(p as PhaseFilter)}
          >
            {p}
          </Chip>
        ))}
      </ChipGroup>
      <label className="flex items-center gap-2 ml-auto">
        <span className="font-mono text-[12px] font-medium tracking-[0.14em] uppercase text-text-2">sort</span>
        <Select value={sort} onValueChange={(v) => onSort(v as SortMode)}>
          <SelectTrigger className="w-[160px]" aria-label="sort sessions">
            <span className="min-w-0 flex-1 truncate text-left">
              <SelectValue />
            </span>
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="newest">newest</SelectItem>
            <SelectItem value="oldest">oldest</SelectItem>
            <SelectItem value="yield">yield (high → low)</SelectItem>
            <SelectItem value="duration">duration</SelectItem>
          </SelectContent>
        </Select>
      </label>
    </section>
  );
}

function Field({ label, children }: { label: string; children: React.ReactNode }) {
  return (
    <label className="flex flex-col gap-1.5">
      <span className="font-mono text-[12px] font-medium tracking-[0.14em] uppercase text-text-2">{label}</span>
      {children}
    </label>
  );
}

function NewSessionForm({ onClose }: { onClose: () => void }) {
  // Real chambers from the Pi — this select was the page's last fake-fleet
  // holdout. chamber_id is optional server-side, so an unreachable chambers
  // API just means the session is created unassigned.
  const [chambers, setChambers] = useState<{ id: number; name: string }[]>([]);
  const [chamber, setChamber] = useState("");
  const [speciesId, setSpeciesId] = useState(SPECIES_LIBRARY[0]?.id ?? "");
  useEffect(() => {
    let cancelled = false;
    apiGet<{ id: number; name: string }[]>("/api/chambers")
      .then((rows) => {
        if (cancelled) return;
        setChambers(rows);
        setChamber((cur) => cur || (rows[0] ? String(rows[0].id) : ""));
      })
      .catch(() => {
        /* select stays empty; session created unassigned */
      });
    return () => {
      cancelled = true;
    };
  }, []);
  const [substrate, setSubstrate] = useState("MasterMix · 4lb");
  const [culture, setCulture] = useState("");
  const [containerType, setContainerType] = useState("");
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);
  return (
    <form
      className="bg-bg-1 border border-border-soft rounded-md p-[26px] flex flex-col gap-3"
      onSubmit={async (e) => {
        e.preventDefault();
        if (submitting) return;
        const sp = SPECIES_LIBRARY.find((s) => s.id === speciesId);
        setSubmitting(true);
        setError(null);
        try {
          // Same-origin: pi-ui is served by the Pi, which mounts sessions at
          // /api/sessions. Creates a real grow session on the Pi.
          const res = await fetch("/api/sessions", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
              name: sp?.common ?? "New session",
              species_profile_id: speciesId,
              substrate: substrate || null,
              spawn_source: culture || null,
              container_type: containerType || "monotub",
              current_phase: "substrate_colonization",
              chamber_id: chamber ? Number(chamber) : null,
            }),
          });
          if (!res.ok) throw new Error(`create failed (${res.status})`);
          onClose();
        } catch (err) {
          setError(err instanceof Error ? err.message : "create failed");
        } finally {
          setSubmitting(false);
        }
      }}
    >
      <div className="mb-1.5 font-mono text-[15px] font-medium tracking-[0.16em] uppercase text-text-2">New session</div>
      <div className="grid grid-cols-[repeat(auto-fit,minmax(200px,1fr))] gap-3">
        <Field label="Chamber">
          <Select value={chamber} onValueChange={setChamber}>
            <SelectTrigger className="w-full" aria-label="chamber">
              <span className="min-w-0 flex-1 truncate text-left">
                <SelectValue />
              </span>
            </SelectTrigger>
            <SelectContent>
              {chambers.map((c) => (
                <SelectItem key={c.id} value={String(c.id)}>
                  {c.name}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
        </Field>
        <Field label="Species">
          <Select value={speciesId} onValueChange={setSpeciesId}>
            <SelectTrigger className="w-full" aria-label="species">
              <span className="min-w-0 flex-1 truncate text-left">
                <SelectValue placeholder="Select species…" />
              </span>
            </SelectTrigger>
            <SelectContent>
              {SPECIES_LIBRARY.map((s) => (
                <SelectItem key={s.id} value={s.id}>
                  {s.common}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
        </Field>
        <Field label="Substrate">
          <Input value={substrate} onChange={(e) => setSubstrate(e.target.value)} />
        </Field>
        <Field label="Culture (optional)">
          <Input value={culture} onChange={(e) => setCulture(e.target.value)} placeholder="e.g. C-001.1.a.s2" />
        </Field>
        <Field label="Container">
          <Select value={containerType} onValueChange={setContainerType}>
            <SelectTrigger className="w-full" aria-label="container">
              <span className="min-w-0 flex-1 truncate text-left">
                <SelectValue placeholder="Select container…" />
              </span>
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="agar_plate">Agar plate</SelectItem>
              <SelectItem value="liquid_culture">Liquid culture</SelectItem>
              <SelectItem value="grain_jar">Grain jar</SelectItem>
              <SelectItem value="grow_bag">Grow bag</SelectItem>
              <SelectItem value="monotub">Monotub</SelectItem>
              <SelectItem value="tray">Tray</SelectItem>
            </SelectContent>
          </Select>
        </Field>
      </div>
      {["agar_plate", "liquid_culture", "grain_jar"].includes(containerType) && (
        <p className="text-xs text-text-2">
          Sealed vessel: once fully colonized this goes to <strong>cold storage</strong> (the
          fridge), not fruiting — the chamber CO₂ sensor reads room air, not the vessel&rsquo;s.
        </p>
      )}
      {["grow_bag", "monotub", "tray"].includes(containerType) && (
        <p className="text-xs text-text-2">
          Bulk substrate: colonizes sealed (CO₂ control inactive), then opens for{" "}
          <strong>fruiting</strong>, where CO₂ control becomes active.
        </p>
      )}
      {error && <p className="text-xs text-err">{error}</p>}
      <div className="flex items-center gap-2.5 justify-end">
        <Button type="button" variant="ghost" onClick={onClose}>
          cancel
        </Button>
        <Button type="submit" disabled={submitting}>
          {submitting ? "starting…" : "start session →"}
        </Button>
      </div>
    </form>
  );
}

// ── Rich session detail (fetched per selected session) ───────────────

interface RawPhase {
  phase: string;
  entered_at: number;
  exited_at: number | null;
  trigger: string | null;
}
interface RawSession {
  id: number;
  name: string;
  species_profile_id: string;
  substrate: string | null;
  status: string;
  current_phase: string;
  container_type: string | null;
  spawn_source: string | null;
  created_at: number;
  completed_at: number | null;
  total_wet_yield_g: number | null;
  total_dry_yield_g: number | null;
  biological_efficiency: number | null;
  chamber_id: number | null;
  phase_history: RawPhase[];
}
interface FlushYield {
  flush_number: number;
  wet_weight_g: number;
  dry_weight_g: number;
}
interface SessionStats {
  flush_yields: FlushYield[];
  total_wet_yield_g: number;
  total_dry_yield_g: number;
  biological_efficiency: number | null;
  flush_count: number;
  species_avg_yield_g: number | null;
  species_best_yield_g: number | null;
}
interface RawEvent {
  id: number;
  timestamp: number;
  type: string;
  source: string;
  description: string | null;
}

interface PhaseSeg {
  phase: string;
  days: number;
  active: boolean;
}

interface SessionDetail {
  status: string;
  startedOn: string;
  endedOn: string | null;
  cultureId: string | null;
  segments: PhaseSeg[];
  totalWetG: number;
  totalDryG: number;
  bioEfficiency: number | null;
  flushCount: number;
  speciesAvgG: number | null;
  speciesBestG: number | null;
  harvests: FlushYield[];
  timeline: FleetEvent[];
}

function fmtDate(ts: number | null): string {
  if (!ts) return "—";
  return new Date(ts * 1000).toLocaleDateString(undefined, { month: "short", day: "numeric" });
}
function fmtDateTime(ts: number): string {
  return new Date(ts * 1000).toLocaleString(undefined, {
    month: "short",
    day: "numeric",
    hour: "2-digit",
    minute: "2-digit",
  });
}
function eventToFleet(e: RawEvent): FleetEvent {
  const t = e.type.toLowerCase();
  const cls: FleetEvent["cls"] =
    t.includes("contam") || t.includes("abort")
      ? "e"
      : t.includes("harvest") || t.includes("phase") || t.includes("complete")
        ? "a"
        : "";
  return { ts: fmtDateTime(e.timestamp), tag: e.type.slice(0, 5).toUpperCase(), msg: e.description ?? e.type, cls };
}

function buildDetail(s: RawSession, stats: SessionStats, events: RawEvent[]): SessionDetail {
  const now = Date.now() / 1000;
  const segments: PhaseSeg[] = s.phase_history.map((p) => ({
    phase: p.phase,
    days: Math.max(0, Math.round(((p.exited_at ?? now) - p.entered_at) / 86_400)),
    active: p.exited_at == null,
  }));
  return {
    status: s.status,
    startedOn: fmtDate(s.created_at),
    endedOn: s.completed_at ? fmtDate(s.completed_at) : null,
    cultureId: s.spawn_source,
    segments,
    totalWetG: stats.total_wet_yield_g,
    totalDryG: stats.total_dry_yield_g,
    bioEfficiency: stats.biological_efficiency,
    flushCount: stats.flush_count,
    speciesAvgG: stats.species_avg_yield_g,
    speciesBestG: stats.species_best_yield_g,
    harvests: stats.flush_yields,
    timeline: events.map(eventToFleet),
  };
}

function DetailPanel({
  session,
  refreshToken,
  onChanged,
}: {
  session: GrowSessionStub;
  refreshToken: number;
  onChanged: () => void;
}) {
  const [detail, setDetail] = useState<SessionDetail | null>(null);
  const [detailErr, setDetailErr] = useState<string | null>(null);

  useEffect(() => {
    let alive = true;
    setDetail(null);
    setDetailErr(null);
    Promise.all([
      apiGet<RawSession>(`/api/sessions/${session.id}`),
      apiGet<SessionStats>(`/api/sessions/${session.id}/stats`),
      apiGet<RawEvent[]>(`/api/sessions/${session.id}/events`),
    ])
      .then(([s, stats, events]) => {
        if (alive) setDetail(buildDetail(s, stats, events));
      })
      .catch((err) => {
        if (alive) setDetailErr(err instanceof Error ? err.message : "load failed");
      });
    return () => {
      alive = false;
    };
  }, [session.id, refreshToken]);

  const isActive = detail ? detail.status === "active" : session.phase !== "complete" && session.phase !== "contam";

  return (
    <aside className="flex flex-col gap-3.5">
      <section className="bg-bg-1 border border-border-soft rounded-md p-[26px] flex flex-col gap-[18px]">
        <div className="mb-1.5 font-mono text-[15px] font-medium tracking-[0.16em] uppercase text-text-2">
          {session.id} · {session.chamberId}
        </div>
        <span className="font-mono text-[12px] text-text-2">
          started {detail?.startedOn ?? `${session.startedDaysAgo}d ago`}
          {detail?.cultureId && ` · culture ${detail.cultureId}`}
          {detail?.endedOn && ` · ended ${detail.endedOn}`}
        </span>

        {/* `.t-display-sm binomial` — `.binomial` wins font-family at clean
            HEAD (T7 precedent). */}
        <h2 className="font-serif italic font-medium text-[26px] leading-[1.18] tracking-[-0.005em] text-text-0">
          {session.species.binomial || session.species.common}
        </h2>
        <span className="font-body text-[14px] leading-[1.55] text-text-1">
          {session.species.common} · {session.substrate}
        </span>

        {detailErr ? (
          <span className="font-mono text-[12px] text-err">detail failed to load: {detailErr}</span>
        ) : !detail ? (
          <span className="font-mono text-[12px] text-text-2">Loading…</span>
        ) : (
          <PhaseProgress segments={detail.segments} />
        )}
      </section>

      {detail && (
        <section className="bg-bg-1 border border-border-soft rounded-md p-[26px] flex flex-col gap-[18px]">
          <div className="mb-1.5 font-mono text-[15px] font-medium tracking-[0.16em] uppercase text-text-2">Run summary</div>
          <div className="grid grid-cols-2 gap-3">
            <KpiCard label="wet yield" value={`${detail.totalWetG.toLocaleString()}g`} />
            <KpiCard label="dry yield" value={`${detail.totalDryG.toLocaleString()}g`} tone="accent" />
            <KpiCard label="flushes" value={detail.flushCount.toString()} />
            <KpiCard
              label="bio-efficiency"
              value={detail.bioEfficiency != null ? `${detail.bioEfficiency}%` : "—"}
              tone="signal"
            />
          </div>
          {(detail.speciesAvgG != null || detail.speciesBestG != null) && (
            <span className="font-mono text-[12px] text-text-2">
              species avg · {detail.speciesAvgG != null ? `${detail.speciesAvgG}g` : "—"} · best {detail.speciesBestG != null ? `${detail.speciesBestG}g` : "—"}
            </span>
          )}
        </section>
      )}

      {detail && detail.harvests.length > 0 && (
        <section className="bg-bg-1 border border-border-soft rounded-md p-[26px] flex flex-col gap-[18px]">
          <div className="mb-1.5 font-mono text-[15px] font-medium tracking-[0.16em] uppercase text-text-2">Harvest log</div>
          {/* Per-flush wet/dry from GET /{id}/stats (flush_yields). The Pi
              exposes no per-harvest GET returning individual date/quality
              rows, so those columns are omitted here.
              TODO(wire): surface harvest date/quality if the server adds a
              raw-harvest list endpoint. */}
          <DataTable<FlushYield & { id: number }>
            rows={detail.harvests.map((h) => ({ ...h, id: h.flush_number }))}
            columns={[
              { key: "flush", header: "#", align: "right", render: (h) => h.flush_number },
              { key: "wet", header: "Wet", align: "right", render: (h) => `${h.wet_weight_g}g` },
              { key: "dry", header: "Dry", align: "right", render: (h) => (h.dry_weight_g ? `${h.dry_weight_g}g` : "—") },
            ]}
          />
        </section>
      )}

      {/* TODO(wire): the Pi has no structured per-session contamination
          records (confidence/classification/resolved). Contamination shows
          up in the event timeline below instead. */}

      {detail && detail.timeline.length > 0 && (
        <EventFeed events={detail.timeline} title="Session timeline" />
      )}

      <SessionActions session={session} isActive={isActive} onChanged={onChanged} />
    </aside>
  );
}

function SessionActions({
  session,
  isActive,
  onChanged,
}: {
  session: GrowSessionStub;
  isActive: boolean;
  onChanged: () => void;
}) {
  const [showHarvest, setShowHarvest] = useState(false);
  const [confirmEnd, setConfirmEnd] = useState(false);
  const [confirmContam, setConfirmContam] = useState(false);
  const [busy, setBusy] = useState(false);
  const [error, setError] = useState<string | null>(null);

  async function run(path: string) {
    setBusy(true);
    setError(null);
    try {
      await apiSend<RawSession>(`/api/sessions/${session.id}${path}`, "POST", {});
      onChanged();
    } catch (err) {
      setError(err instanceof Error ? err.message : "action failed");
    } finally {
      setBusy(false);
      setConfirmEnd(false);
      setConfirmContam(false);
    }
  }

  return (
    <section className="bg-bg-1 border border-border-soft rounded-md p-[26px] flex flex-col gap-[18px]">
      <div className="mb-1.5 font-mono text-[15px] font-medium tracking-[0.16em] uppercase text-text-2">Actions</div>
      {error && <p className="font-mono text-[12px] text-err">{error}</p>}
      <div className="flex flex-wrap gap-2 items-center">
        {isActive && (
          <>
            <Button type="button" onClick={() => setShowHarvest((v) => !v)}>
              {showHarvest ? "cancel harvest" : "log harvest →"}
            </Button>
            {/* TODO(wire): no endpoint extends a phase's expected window —
                POST /{id}/phase advances to the NEXT phase, the opposite of
                extending. Disabled until the server exposes a window edit. */}
            <Button type="button" variant="ghost" disabled>
              extend window
            </Button>
            <Button
              type="button"
              variant="ghost"
              className={WARN_GHOST}
              disabled={busy}
              onClick={() => (confirmContam ? run("/abort") : setConfirmContam(true))}
            >
              {/* TODO(wire): the Pi has no contaminated-status/reason
                  endpoint. POST /{id}/abort is the closest terminal action —
                  it records status='aborted' (a failed grow), not a
                  contamination classification. */}
              {confirmContam ? "confirm — abort grow?" : "mark contaminated"}
            </Button>
            <Button
              type="button"
              variant="destructive"
              disabled={busy}
              onClick={() => (confirmEnd ? run("/complete") : setConfirmEnd(true))}
            >
              {confirmEnd ? "confirm end?" : "end session"}
            </Button>
          </>
        )}
        {!isActive && (
          <a
            href={`/api/sessions/${session.id}/report.md`}
            className="font-mono text-[14px] font-medium tracking-[0.16em] uppercase text-accent no-underline cursor-pointer hover:text-text-0"
          >
            view archived data →
          </a>
        )}
      </div>
      {showHarvest && isActive && (
        <HarvestForm
          sessionId={session.id}
          onDone={() => {
            setShowHarvest(false);
            onChanged();
          }}
        />
      )}
    </section>
  );
}

function HarvestForm({ sessionId, onDone }: { sessionId: string; onDone: () => void }) {
  const [flush, setFlush] = useState("1");
  const [wet, setWet] = useState("");
  const [notes, setNotes] = useState("");
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const flushNum = Number.parseInt(flush, 10);
  const wetNum = wet.trim() === "" ? null : Number.parseFloat(wet);
  const valid = Number.isFinite(flushNum) && flushNum > 0 && (wetNum === null || Number.isFinite(wetNum));

  return (
    <form
      className="flex flex-col gap-3 rounded-sm border border-border-soft bg-bg-2 p-4"
      onSubmit={async (e) => {
        e.preventDefault();
        if (submitting || !valid) return;
        setSubmitting(true);
        setError(null);
        try {
          await apiSend(`/api/sessions/${sessionId}/harvest`, "POST", {
            flush_number: flushNum,
            wet_weight_g: wetNum,
            notes: notes.trim() || null,
          });
          onDone();
        } catch (err) {
          setError(err instanceof Error ? err.message : "harvest failed");
        } finally {
          setSubmitting(false);
        }
      }}
    >
      <div className="grid grid-cols-2 gap-3">
        <Field label="Flush #">
          <Input type="number" min={1} value={flush} onChange={(e) => setFlush(e.target.value)} />
        </Field>
        <Field label="Wet grams">
          <Input type="number" min={0} step="0.1" value={wet} onChange={(e) => setWet(e.target.value)} placeholder="e.g. 412" />
        </Field>
      </div>
      <Field label="Notes (optional)">
        <Input value={notes} onChange={(e) => setNotes(e.target.value)} placeholder="e.g. first veil break" />
      </Field>
      {error && <p className="font-mono text-[12px] text-err">{error}</p>}
      <Button type="submit" className="self-start" disabled={submitting || !valid}>
        {submitting ? "logging…" : "save harvest →"}
      </Button>
    </form>
  );
}

function segmentTone(seg: PhaseSeg, i: number): string {
  if (seg.active) return "bg-accent";
  return i % 2 === 0 ? "bg-bg-2" : "bg-signal-soft";
}

function PhaseProgress({ segments }: { segments: PhaseSeg[] }) {
  if (segments.length === 0) return null;
  const totalDays = segments.reduce((sum, s) => sum + s.days, 0);
  const active = segments.find((s) => s.active);
  return (
    <div className="flex flex-col gap-1.5">
      <span className="font-mono text-[13px] font-medium tracking-[0.16em] uppercase text-text-2">
        Phase progress · {active ? `${active.phase.replace(/_/g, " ")} · day ${active.days}` : `${totalDays}d total`}
      </span>
      <div className="flex h-4 rounded-pill overflow-hidden border border-border-soft">
        {segments.map((seg, i) => (
          <div
            key={i}
            title={`${seg.phase.replace(/_/g, " ")} · ${seg.days}d`}
            className={segmentTone(seg, i)}
            style={{ flex: Math.max(seg.days, 0.5) }}
          />
        ))}
      </div>
    </div>
  );
}
