import { useCallback, useEffect, useMemo, useState } from "react";
import {
  Button,
  CloudSyncIndicator,
  DataTable,
  PI_HEALTH,
  PageHeader,
  cn,
} from "@sporeprint/design";
import { PiTopBar } from "../components/PiTopBar";
import { apiGet, apiSend } from "../lib/api";
import { fmtClock } from "../lib/chambers";
import type { OverrideRow } from "../lib/pi-types";

// ── Real Pi API shapes (server/app/automation router + models) ─────────
interface RuleThreshold {
  sensor?: string;
  operator?: string;
  value?: number | null;
  profile_ref?: string | null;
}
interface RuleCondition {
  type: string;
  threshold?: RuleThreshold | null;
}
interface RuleAction {
  target: string;
  channel?: string | null;
  state?: string;
}
interface AutoRule {
  id: number;
  name: string;
  description: string;
  enabled: boolean;
  priority: number;
  cooldown_seconds: number;
  applies_to_phases?: string[] | null;
  condition: RuleCondition;
  action: RuleAction;
}
interface Firing {
  id: number;
  rule_id: number | null;
  rule_name: string;
  timestamp: number; // epoch seconds
  condition_met: string | null;
  action_taken: string | null;
  status: string; // pending | sent | failed
  error: string | null;
}
const STATUS_PILL_BASE =
  "inline-flex items-center gap-[7px] rounded-pill border px-3 py-[5px] font-mono text-[12px] font-medium uppercase tracking-widest";
const STATUS_PILL_TONE = {
  accent: "border-accent-line bg-accent-soft text-accent",
  signal: "border-signal/40 bg-signal-soft text-signal",
  warn: "border-warn bg-bg-2 text-warn",
  err: "border-err bg-bg-2 text-err",
  idle: "border-border bg-bg-2 text-text-3",
} as const;
function statusPill(tone: keyof typeof STATUS_PILL_TONE): string {
  return cn(STATUS_PILL_BASE, STATUS_PILL_TONE[tone]);
}

const SEVEN_DAYS_S = 7 * 24 * 3600;

function overrideKey(target: string, channel: string | null | undefined): string {
  return `${target}::${channel ?? ""}`;
}

function conditionSummary(rule: AutoRule): { metric: string; condition: string } {
  const c = rule.condition;
  if (c.type === "threshold" && c.threshold) {
    const t = c.threshold;
    const rhs = t.value != null ? String(t.value) : (t.profile_ref ?? "—");
    return { metric: t.sensor ?? "—", condition: `${t.operator ?? "?"} ${rhs}` };
  }
  return { metric: c.type, condition: c.type };
}

function fmtLastFired(epochSec: number | null): string {
  if (epochSec == null) return "never";
  return fmtClock(epochSec);
}

function truncate(s: string | null, n: number): string {
  if (!s) return "—";
  return s.length > n ? `${s.slice(0, n)}…` : s;
}

export function AutomationPage() {
  const [rules, setRules] = useState<AutoRule[]>([]);
  const [firings, setFirings] = useState<Firing[]>([]);
  const [overrides, setOverrides] = useState<Record<string, OverrideRow>>({});
  const [loading, setLoading] = useState(true);
  const [loadError, setLoadError] = useState<string | null>(null);
  const [selectedId, setSelectedId] = useState<number | null>(null);
  const [nowMs, setNowMs] = useState(() => Date.now());
  const [busyTarget, setBusyTarget] = useState<string | null>(null);

  // Tick so suspend countdowns update and expired overrides fall away.
  useEffect(() => {
    const t = setInterval(() => setNowMs(Date.now()), 1000);
    return () => clearInterval(t);
  }, []);

  const loadOverrides = useCallback(async () => {
    const list = await apiGet<OverrideRow[]>("/api/automation/overrides").catch(() => [] as OverrideRow[]);
    const map: Record<string, OverrideRow> = {};
    for (const o of list) map[overrideKey(o.target, o.channel)] = o;
    setOverrides(map);
  }, []);

  useEffect(() => {
    let cancelled = false;
    (async () => {
      setLoading(true);
      setLoadError(null);
      try {
        const [ruleList, firingList] = await Promise.all([
          apiGet<AutoRule[]>("/api/automation/rules"),
          apiGet<Firing[]>("/api/automation/firings?limit=500").catch(() => [] as Firing[]),
        ]);
        if (cancelled) return;
        setRules(ruleList);
        setFirings(firingList);
        setSelectedId((prev) => prev ?? ruleList[0]?.id ?? null);
        await loadOverrides();
      } catch (err) {
        if (!cancelled) setLoadError(err instanceof Error ? err.message : "fetch failed");
      } finally {
        if (!cancelled) setLoading(false);
      }
    })();
    return () => {
      cancelled = true;
    };
  }, [loadOverrides]);

  const selected = useMemo(
    () => rules.find((r) => r.id === selectedId) ?? null,
    [rules, selectedId],
  );

  const nowSec = nowMs / 1000;

  const lastFiredByRule = useMemo(() => {
    const map: Record<number, number> = {};
    for (const f of firings) {
      if (f.rule_id == null) continue;
      if (!(f.rule_id in map) || f.timestamp > map[f.rule_id]!) map[f.rule_id] = f.timestamp;
    }
    return map;
  }, [firings]);

  const fires7dByRule = useMemo(() => {
    const map: Record<number, number> = {};
    for (const f of firings) {
      if (f.rule_id == null || f.timestamp < nowSec - SEVEN_DAYS_S) continue;
      map[f.rule_id] = (map[f.rule_id] ?? 0) + 1;
    }
    return map;
  }, [firings, nowSec]);

  const activeCount = rules.filter((r) => r.enabled).length;
  const totalFires7d = Object.values(fires7dByRule).reduce((a, b) => a + b, 0);
  const failedRecent = firings.filter(
    (f) => f.status === "failed" && f.timestamp >= nowSec - SEVEN_DAYS_S,
  ).length;

  const selectedFirings = useMemo(
    () =>
      selectedId == null
        ? []
        : firings.filter((f) => f.rule_id === selectedId).sort((a, b) => b.timestamp - a.timestamp).slice(0, 20),
    [firings, selectedId],
  );

  function isSuspended(rule: AutoRule): OverrideRow | null {
    const ov = overrides[overrideKey(rule.action.target, rule.action.channel)];
    if (!ov || !ov.locked) return null;
    if (ov.expires_at != null && ov.expires_at <= nowSec) return null;
    return ov;
  }

  async function toggleRule(rule: AutoRule) {
    const prev = rule.enabled;
    setRules((rs) => rs.map((r) => (r.id === rule.id ? { ...r, enabled: !prev } : r)));
    try {
      // PATCH — not covered by apiSend's POST/PUT/DELETE union.
      const res = await fetch(`/api/automation/rules/${rule.id}/toggle`, {
        method: "PATCH",
        credentials: "same-origin",
      });
      if (!res.ok) throw new Error(`HTTP ${res.status}`);
      const body = (await res.json()) as { id: number; enabled: boolean };
      setRules((rs) => rs.map((r) => (r.id === rule.id ? { ...r, enabled: body.enabled } : r)));
    } catch {
      setRules((rs) => rs.map((r) => (r.id === rule.id ? { ...r, enabled: prev } : r)));
    }
  }

  async function suspendRule(rule: AutoRule) {
    setBusyTarget(rule.action.target);
    const override: OverrideRow = {
      target: rule.action.target,
      channel: rule.action.channel ?? null,
      locked: true,
      reason: "suspended 5m via Pi UI",
      expires_at: nowSec + 5 * 60,
    };
    try {
      await apiSend("/api/automation/overrides", "POST", override);
      setOverrides((prev) => ({ ...prev, [overrideKey(override.target, override.channel)]: override }));
    } catch {
      /* leave state unchanged on failure — no fake success */
    } finally {
      setBusyTarget(null);
    }
  }

  async function cancelSuspend(rule: AutoRule) {
    setBusyTarget(rule.action.target);
    const channel = rule.action.channel ?? null;
    const qs = channel ? `?channel=${encodeURIComponent(channel)}` : "";
    try {
      await apiSend(`/api/automation/overrides/${encodeURIComponent(rule.action.target)}${qs}`, "DELETE");
      setOverrides((prev) => {
        const next = { ...prev };
        delete next[overrideKey(rule.action.target, channel)];
        return next;
      });
    } catch {
      /* leave state unchanged on failure */
    } finally {
      setBusyTarget(null);
    }
  }

  return (
    <>
      <PiTopBar
        crumbs={[{ label: "control" }, { label: "automation", active: true }]}
        right={<CloudSyncIndicator cloud={PI_HEALTH.cloud} />}
      />

      <PageHeader
        eyebrow="Control"
        title="Automation rules"
        italic={false}
        meta={
          <span>
            {activeCount} of {rules.length} active · {totalFires7d.toLocaleString()} fires · 7d ·{" "}
            {failedRecent} failed recently
          </span>
        }
        right={<Button type="button" variant="ghost">authoring → cloud</Button>}
      />

      <div className="grid grid-cols-[1fr_400px] gap-[22px] px-7 pt-[22px] pb-7 max-[1180px]:grid-cols-1">
        <main className="flex flex-col gap-3.5">
          {loadError ? (
            <p className="font-mono text-[13px] tracking-[0.05em] text-err">Failed to load rules: {loadError}</p>
          ) : loading ? (
            <p className="font-mono text-[13px] tracking-[0.05em] text-text-2">Loading rules…</p>
          ) : rules.length === 0 ? (
            <p className="font-body text-[14px] leading-[1.55] text-text-2">No automation rules on this Pi yet.</p>
          ) : (
            rules.map((r) => {
              const ov = isSuspended(r);
              const { metric, condition } = conditionSummary(r);
              return (
                <RuleCard
                  key={r.id}
                  rule={r}
                  metric={metric}
                  condition={condition}
                  lastFired={fmtLastFired(lastFiredByRule[r.id] ?? null)}
                  fires7d={fires7dByRule[r.id] ?? 0}
                  selected={selectedId === r.id}
                  suspendedUntil={ov?.expires_at ?? null}
                  nowSec={nowSec}
                  busy={busyTarget === r.action.target}
                  onSelect={() => setSelectedId(r.id)}
                  onToggle={() => void toggleRule(r)}
                  onSuspend={() => void suspendRule(r)}
                  onCancelSuspend={() => void cancelSuspend(r)}
                />
              );
            })
          )}
          <p className="font-mono text-[12px] text-text-2">
            to author or change a rule, open{" "}
            <a
              href="https://sporeprint.ai/automation"
              className="font-mono text-[14px] font-medium tracking-[0.16em] uppercase text-accent no-underline cursor-pointer hover:text-text-0"
            >
              sporeprint.ai/automation
            </a>
            . Pi can suspend per-chamber from this view, but rule edits sync from the cloud.
          </p>
        </main>

        <aside className="flex flex-col gap-3.5">
          <section className="flex flex-col gap-[18px] rounded-md border border-border-soft bg-bg-1 p-[26px]">
            <div className="mb-1.5 font-mono text-[15px] font-medium uppercase tracking-[0.16em] text-text-2">
              Recent firings{selected ? ` · ${selected.name}` : ""}
            </div>
            <span className="font-mono text-[12px] text-text-2">{selectedFirings.length} firings tracked for this rule</span>
            {selectedFirings.length > 0 ? (
              <DataTable<Firing>
                rowKey={(f) => f.id}
                rows={selectedFirings}
                columns={[
                  { key: "ts", header: "Time", render: (f) => <span className="font-mono text-text-0">{fmtClock(f.timestamp)}</span> },
                  { key: "condition", header: "Condition", render: (f) => <span className="font-mono text-text-1">{truncate(f.condition_met, 40)}</span> },
                  {
                    key: "status",
                    header: "Status",
                    render: (f) => (
                      <span className={statusPill(f.status === "sent" ? "accent" : f.status === "pending" ? "idle" : "warn")}>
                        {f.status}
                      </span>
                    ),
                  },
                ]}
              />
            ) : (
              <p className="font-body text-[14px] leading-[1.55] text-text-1">No firings tracked for this rule.</p>
            )}
          </section>

          {/* Audit log — TODO(wire): the Pi exposes automation_firings (engine
              actions, shown above) but no operator-action audit trail; there
              is no endpoint to source an enabled/suspended/edited-by-operator
              log, so it is omitted rather than fabricated. */}
        </aside>
      </div>
    </>
  );
}

function RuleCard({
  rule,
  metric,
  condition,
  lastFired,
  fires7d,
  selected,
  suspendedUntil,
  nowSec,
  busy,
  onSelect,
  onToggle,
  onSuspend,
  onCancelSuspend,
}: {
  rule: AutoRule;
  metric: string;
  condition: string;
  lastFired: string;
  fires7d: number;
  selected: boolean;
  suspendedUntil: number | null;
  nowSec: number;
  busy: boolean;
  onSelect: () => void;
  onToggle: () => void;
  onSuspend: () => void;
  onCancelSuspend: () => void;
}) {
  const isSuspended = suspendedUntil != null;
  const remainingS = suspendedUntil != null ? Math.max(0, Math.ceil(suspendedUntil - nowSec)) : 0;
  const scope = rule.applies_to_phases?.length ? rule.applies_to_phases.join(", ") : "all phases";
  return (
    <section
      onClick={onSelect}
      className={cn(
        "flex cursor-pointer flex-col gap-[18px] rounded-md border bg-bg-1 p-[26px]",
        selected ? "border-accent-line" : "border-border-soft",
      )}
    >
      <div className="flex items-baseline justify-between gap-3">
        <div className="flex min-w-0 flex-col gap-1">
          <span className="mb-0 font-mono text-[13px] font-medium uppercase tracking-[0.16em] text-text-2">{scope}</span>
          <h2 className="font-display font-medium text-[26px] leading-[1.18] tracking-[-0.005em] text-text-0">{rule.name}</h2>
        </div>
        <div className="flex items-center gap-2.5">
          <span className={statusPill(rule.enabled && !isSuspended ? "accent" : isSuspended ? "warn" : "idle")}>
            {isSuspended ? `suspend ${remainingS}s` : rule.enabled ? "active" : "disabled"}
          </span>
          <input
            type="checkbox"
            className="toggle"
            checked={rule.enabled}
            onClick={(e) => e.stopPropagation()}
            onChange={onToggle}
          />
        </div>
      </div>
      <p className="font-body text-[14px] leading-[1.55] text-text-1">{rule.description}</p>
      <div className="grid grid-cols-[repeat(auto-fit,minmax(150px,1fr))] gap-2.5">
        <Stat label="metric" value={metric} />
        <Stat label="condition" value={condition} />
        <Stat label="last fired" value={lastFired} />
        <Stat label="fires · 7d" value={fires7d.toLocaleString()} />
        <Stat label="cooldown" value={`${rule.cooldown_seconds}s`} />
      </div>
      <div className="mt-1 flex items-center gap-2.5">
        {isSuspended ? (
          <Button
            type="button"
            variant="ghost"
            size="sm"
            onClick={(e) => { e.stopPropagation(); onCancelSuspend(); }}
            disabled={busy}
          >
            {busy ? "…" : `cancel suspend · ${remainingS}s`}
          </Button>
        ) : (
          <Button
            type="button"
            variant="ghost"
            size="sm"
            onClick={(e) => { e.stopPropagation(); onSuspend(); }}
            disabled={busy}
          >
            {busy ? "…" : "suspend 5m"}
          </Button>
        )}
        <Button
          type="button"
          variant="ghost"
          size="sm"
          onClick={(e) => { e.stopPropagation(); onSelect(); }}
        >
          view fires →
        </Button>
      </div>
    </section>
  );
}

function Stat({ label, value }: { label: string; value: string }) {
  return (
    <div className="flex flex-col gap-1 rounded-sm border border-border-soft bg-bg-2 p-3">
      <span className="font-mono text-[12px] font-medium tracking-[0.14em] uppercase text-text-2">{label}</span>
      <span className="font-mono text-[14px] text-text-1">{value}</span>
    </div>
  );
}
