import { useEffect, useState } from "react";
import { Button, CloudSyncIndicator, PageHeader, PI_HEALTH } from "@sporeprint/design";
import { PiTopBar } from "../components/PiTopBar";
import { apiGet } from "../lib/api";

type AnswerKey = "experience" | "substrate" | "climate" | "goal" | "commitment";

interface Step {
  key: AnswerKey;
  roman: string;
  title: string;
  question: string;
  options: { value: string; label: string }[];
}

