import { useMemo, useState } from "react";
import {
  Button,
  CloudSyncIndicator,
  DataTable,
  Input,
  PI_HEALTH,
  PageHeader,
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
  cn,
} from "@sporeprint/design";
import { PiTopBar } from "../components/PiTopBar";
import { apiGet, apiSend } from "../lib/api";
import { usePiLoad } from "../lib/use-pi-load";
import type { PiChamber, PiSession } from "../lib/pi-types";

const DOW = ["mon", "tue", "wed", "thu", "fri", "sat", "sun"];
const MONTHS = ["January", "February", "March", "April", "May", "June", "July", "August", "September", "October", "November", "December"];

// `.event.<tone>` accents (components.css) keyed by the real planner-event kinds.
const EVENT_CLASS: Record<string, string> = {
  inoculate: "signal",
  transfer: "",
  "harvest-window": "warn",
  maintenance: "",
  custom: "",
};
const EVENT_KINDS = ["inoculate", "transfer", "harvest-window", "maintenance", "custom"] as const;

const STATUS_PILL_BASE =
  "inline-flex items-center gap-[7px] rounded-pill border px-3 py-[5px] font-mono text-[12px] font-medium uppercase tracking-widest";
const STATUS_PILL_TONE = {
  warn: "border-warn bg-bg-2 text-warn",
  err: "border-err bg-bg-2 text-err",
} as const;
function statusPill(tone: keyof typeof STATUS_PILL_TONE): string {
  return cn(STATUS_PILL_BASE, STATUS_PILL_TONE[tone]);
}

// ── Real Pi API shapes ──────────────────────────────────────────
interface PlannedEvent {
  id: number;
  title: string;
  kind: string;
  date: string; // YYYY-MM-DD
  chamber_id: number | null;
  session_id: number | null;
  notes: string | null;
  created_at: number;
  updated_at: number;
}
interface ChamberSlot {
  id: number;
  name: string;
  nodes: number;
  phase: string;
}
interface DerivedConflict {
  date: string;
  chamberId: number;
  chamberName: string;
  titles: string[];
}

function pad(n: number): string {
  return String(n).padStart(2, "0");
}
function dateStr(y: number, m0: number, day: number): string {
  return `${y}-${pad(m0 + 1)}-${pad(day)}`;
}

export function PlannerPage() {
  const today = useMemo(() => new Date(), []);
  const [year, setYear] = useState(today.getFullYear());
  const [monthIdx, setMonthIdx] = useState(today.getMonth());
  const [refreshKey, setRefreshKey] = useState(0);

  const [actionError, setActionError] = useState<string | null>(null);
  const [showAdd, setShowAdd] = useState(false);
  const [draggingId, setDraggingId] = useState<number | null>(null);
  const [hoverDay, setHoverDay] = useState<number | null>(null);

  const total = useMemo(() => new Date(year, monthIdx + 1, 0).getDate(), [year, monthIdx]);
  const lead = useMemo(() => (new Date(year, monthIdx, 1).getDay() + 6) % 7, [year, monthIdx]);

  // Month events for the visible month.
  const { data: events, error: eventsError } = usePiLoad(
    () =>
      apiGet<PlannedEvent[]>(
        `/api/planner/events?from=${dateStr(year, monthIdx, 1)}&to=${dateStr(year, monthIdx, total)}`,
      ),
    [year, monthIdx, total, refreshKey],
  );

  // Chambers + sessions (for the add form + the chamber-slots table).
  // Failures degrade to empty lists — the calendar itself still works.
  const { data: refRows } = usePiLoad(
    () =>
      Promise.all([
        apiGet<PiChamber[]>("/api/chambers").catch(() => [] as PiChamber[]),
        apiGet<PiSession[]>("/api/sessions").catch(() => [] as PiSession[]),
      ]),
    [refreshKey],
  );
  const [chambers, sessions] = refRows ?? [[], []];

  const eventsByDay = useMemo(() => {
    const map = new Map<number, PlannedEvent[]>();
    for (const ev of events ?? []) {
      const parts = ev.date.split("-");
      const ey = Number(parts[0]);
      const em = Number(parts[1]);
      const ed = Number(parts[2]);
      if (ey === year && em === monthIdx + 1) {
        const list = map.get(ed) ?? [];
        list.push(ev);
        map.set(ed, list);
      }
    }
    return map;
  }, [events, year, monthIdx]);

  // Same-day + same-chamber collisions (client-derived).
  const conflicts = useMemo<DerivedConflict[]>(() => {
    const groups = new Map<string, PlannedEvent[]>();
    for (const ev of events ?? []) {
      if (ev.chamber_id == null) continue;
      const key = `${ev.date}::${ev.chamber_id}`;
      const list = groups.get(key) ?? [];
      list.push(ev);
      groups.set(key, list);
    }
    const out: DerivedConflict[] = [];
    for (const [, list] of groups) {
      const first = list[0];
      if (list.length < 2 || !first || first.chamber_id == null) continue;
      const cid = first.chamber_id;
      out.push({
        date: first.date,
        chamberId: cid,
        chamberName: chambers.find((c) => c.id === cid)?.name ?? `chamber ${cid}`,
        titles: list.map((e) => e.title),
      });
    }
    return out.sort((a, b) => a.date.localeCompare(b.date));
  }, [events, chambers]);

  const slots = useMemo<ChamberSlot[]>(
    () =>
      chambers.map((c) => {
        const active = c.active_session_id != null ? sessions.find((s) => s.id === c.active_session_id) : undefined;
        return {
          id: c.id,
          name: c.name,
          nodes: c.node_ids.length,
          phase: active ? active.current_phase.replace(/_/g, " ") : "idle",
        };
      }),
    [chambers, sessions],
  );

  const cells: Array<{ day: number; events: PlannedEvent[] } | null> = [];
  for (let i = 0; i < lead; i++) cells.push(null);
  for (let day = 1; day <= total; day++) cells.push({ day, events: eventsByDay.get(day) ?? [] });
  while (cells.length < 42) cells.push(null);

  function shift(delta: number) {
    let m = monthIdx + delta;
    let y = year;
    while (m < 0) {
      m += 12;
      y -= 1;
    }
    while (m > 11) {
      m -= 12;
      y += 1;
    }
    setMonthIdx(m);
    setYear(y);
  }

  async function reschedule(eventId: number, day: number) {
    setActionError(null);
    try {
      await apiSend(`/api/planner/events/${eventId}`, "PUT", { date: dateStr(year, monthIdx, day) });
      setRefreshKey((k) => k + 1);
    } catch (err) {
      setActionError(err instanceof Error ? err.message : "reschedule failed");
    }
  }

  async function remove(eventId: number) {
    setActionError(null);
    try {
      await apiSend(`/api/planner/events/${eventId}`, "DELETE");
      setRefreshKey((k) => k + 1);
    } catch (err) {
      setActionError(err instanceof Error ? err.message : "delete failed");
    }
  }

  function handleDrop(targetDay: number) {
    const id = draggingId;
    setDraggingId(null);
    setHoverDay(null);
    if (id !== null) void reschedule(id, targetDay);
  }

  const monthLabel = `${MONTHS[monthIdx]} ${year}`;
  const eventCount = events?.length ?? 0;

  return (
    <>
      <PiTopBar
        crumbs={[{ label: "plan" }, { label: "planner", active: true }]}
        right={<CloudSyncIndicator cloud={PI_HEALTH.cloud} />}
      />

      <PageHeader
        eyebrow="Plan"
        title={monthLabel}
        italic={false}
        meta={
          <span>
            {eventCount} event{eventCount === 1 ? "" : "s"} · {conflicts.length} conflict
            {conflicts.length === 1 ? "" : "s"} · drag an event to reschedule
          </span>
        }
        right={
          <div className="flex items-center gap-2">
            <Button type="button" variant="ghost" size="sm" onClick={() => shift(-1)} aria-label="previous month">←</Button>
            <Button
              type="button"
              variant="ghost"
              size="sm"
              onClick={() => {
                setYear(today.getFullYear());
                setMonthIdx(today.getMonth());
              }}
            >
              today
            </Button>
            <Button type="button" variant="ghost" size="sm" onClick={() => shift(1)} aria-label="next month">→</Button>
            <Button type="button" variant={showAdd ? "solid" : "ghost"} onClick={() => setShowAdd((v) => !v)}>
              {showAdd ? "cancel" : "add event →"}
            </Button>
          </div>
        }
      />

      <div className="grid grid-cols-[1fr_400px] gap-[22px] px-7 pt-[22px] pb-7 max-[1180px]:grid-cols-1">
        <main className="flex flex-col gap-3.5">
          {showAdd && (
            <AddEventForm
              chambers={chambers}
              defaultDate={dateStr(year, monthIdx, 1)}
              onClose={() => setShowAdd(false)}
              onCreated={() => {
                setShowAdd(false);
                setRefreshKey((k) => k + 1);
              }}
            />
          )}

          {eventsError && (
            <p className="font-mono text-[13px] tracking-[0.05em] text-err">Failed to load events: {eventsError}</p>
          )}
          {actionError && (
            <p className="font-mono text-[13px] tracking-[0.05em] text-err">{actionError}</p>
          )}

          {/* `.calendar`/`.dow`/`.day`/`.dnum`/`.event` — self-contained
              calendar-grid family (kept legacy, same as cloud-web's planner). */}
          <div className="calendar">
            {DOW.map((d) => (
              <div key={d} className="dow">{d}</div>
            ))}
            {cells.map((c, i) => {
              if (!c) return <div key={`pad-${i}`} className="day dim" />;
              const isHover = hoverDay === c.day && draggingId !== null;
              return (
                <div
                  key={`d-${c.day}`}
                  className={cn("day cursor-default", isHover && "border-accent-line bg-accent-soft")}
                  onDragOver={(e) => {
                    e.preventDefault();
                    setHoverDay(c.day);
                  }}
                  onDragLeave={() => setHoverDay((d) => (d === c.day ? null : d))}
                  onDrop={() => handleDrop(c.day)}
                >
                  <span className="dnum">{c.day}</span>
                  {c.events.map((ev) => (
                    <span
                      key={ev.id}
                      draggable
                      onDragStart={() => setDraggingId(ev.id)}
                      onDragEnd={() => {
                        setDraggingId(null);
                        setHoverDay(null);
                      }}
                      title={ev.notes ?? ev.title}
                      className={cn(
                        `event ${EVENT_CLASS[ev.kind] ?? ""}`.trim(),
                        "flex items-center justify-between gap-1 cursor-grab",
                        draggingId === ev.id && "opacity-40",
                      )}
                    >
                      <span className="truncate">{ev.title}</span>
                      <button
                        type="button"
                        aria-label={`delete ${ev.title}`}
                        onClick={(e) => {
                          e.stopPropagation();
                          void remove(ev.id);
                        }}
                        className="shrink-0 px-1 text-text-3 hover:text-err"
                      >
                        ×
                      </button>
                    </span>
                  ))}
                </div>
              );
            })}
          </div>
        </main>

        <aside className="flex flex-col gap-3.5">
          <section className="flex flex-col gap-[18px] rounded-md border border-border-soft bg-bg-1 p-[26px]">
            <div className="mb-1.5 font-mono text-[15px] font-medium tracking-[0.16em] uppercase text-text-2">
              Conflicts · {conflicts.length}
            </div>
            {conflicts.length === 0 ? (
              <p className="font-body text-[14px] leading-[1.55] text-text-1">
                No same-day, same-chamber collisions for {monthLabel}.
              </p>
            ) : (
              <ul className="flex flex-col gap-2.5">
                {conflicts.map((c, i) => (
                  <li
                    key={`cf-${i}`}
                    className="flex flex-col gap-1.5 rounded-sm border border-warn bg-bg-2 px-3.5 py-3"
                  >
                    <div className="flex items-center justify-between gap-3">
                      <span className="font-mono text-[14px] text-text-1">{c.date}</span>
                      <span className={statusPill("warn")}>double-booked</span>
                    </div>
                    <span className="font-body text-[14px] leading-[1.55] text-text-1">
                      {c.chamberName}: {c.titles.join(" · ")}
                    </span>
                  </li>
                ))}
              </ul>
            )}
          </section>

          <section className="flex flex-col gap-[18px] rounded-md border border-border-soft bg-bg-1 p-[26px]">
            <div className="mb-1.5 font-mono text-[15px] font-medium tracking-[0.16em] uppercase text-text-2">
              Chamber slots
            </div>
            {slots.length === 0 ? (
              <p className="font-mono text-[12px] text-text-2">No chambers configured on this Pi.</p>
            ) : (
              <DataTable<ChamberSlot>
                rowKey={(s) => String(s.id)}
                columns={[
                  { key: "name", header: "Chamber", render: (s) => <span className="font-mono text-text-0">{s.name}</span> },
                  { key: "nodes", header: "Nodes", align: "right", render: (s) => <>{s.nodes}</> },
                  { key: "phase", header: "Active phase", render: (s) => <>{s.phase}</> },
                ]}
                rows={slots}
              />
            )}
          </section>
        </aside>
      </div>
    </>
  );
}

function Field({ label, children }: { label: string; children: React.ReactNode }) {
  return (
    <label className="flex flex-col gap-1.5">
      <span className="font-mono text-[12px] font-medium tracking-[0.14em] uppercase text-text-2">{label}</span>
      {children}
    </label>
  );
}

function AddEventForm({
  chambers,
  defaultDate,
  onClose,
  onCreated,
}: {
  chambers: PiChamber[];
  defaultDate: string;
  onClose: () => void;
  onCreated: () => void;
}) {
  const [title, setTitle] = useState("");
  const [kind, setKind] = useState<string>("inoculate");
  const [date, setDate] = useState(defaultDate);
  const [chamber, setChamber] = useState("none");
  const [notes, setNotes] = useState("");
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);

  return (
    <form
      className="flex flex-col gap-3 rounded-md border border-border-soft bg-bg-1 p-[26px]"
      onSubmit={async (e) => {
        e.preventDefault();
        if (submitting || !title.trim()) return;
        setSubmitting(true);
        setError(null);
        try {
          await apiSend("/api/planner/events", "POST", {
            title: title.trim(),
            kind,
            date,
            chamber_id: chamber === "none" ? null : Number(chamber),
            notes: notes.trim() || null,
          });
          onCreated();
        } catch (err) {
          setError(err instanceof Error ? err.message : "create failed");
        } finally {
          setSubmitting(false);
        }
      }}
    >
      <div className="mb-1.5 font-mono text-[15px] font-medium tracking-[0.16em] uppercase text-text-2">New planned event</div>
      <div className="grid grid-cols-[repeat(auto-fit,minmax(180px,1fr))] gap-3">
        <Field label="Title">
          <Input value={title} onChange={(e) => setTitle(e.target.value)} placeholder="e.g. inoculate grain jars" />
        </Field>
        <Field label="Kind">
          <Select value={kind} onValueChange={setKind}>
            <SelectTrigger aria-label="kind" className="w-full">
              <span className="min-w-0 flex-1 truncate text-left">
                <SelectValue />
              </span>
            </SelectTrigger>
            <SelectContent>
              {EVENT_KINDS.map((k) => (
                <SelectItem key={k} value={k}>{k}</SelectItem>
              ))}
            </SelectContent>
          </Select>
        </Field>
        <Field label="Date">
          <Input type="date" value={date} onChange={(e) => setDate(e.target.value)} />
        </Field>
        <Field label="Chamber (optional)">
          <Select value={chamber} onValueChange={setChamber}>
            <SelectTrigger aria-label="chamber" className="w-full">
              <span className="min-w-0 flex-1 truncate text-left">
                <SelectValue />
              </span>
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="none">unassigned</SelectItem>
              {chambers.map((c) => (
                <SelectItem key={c.id} value={String(c.id)}>{c.name}</SelectItem>
              ))}
            </SelectContent>
          </Select>
        </Field>
        <Field label="Notes (optional)">
          <Input value={notes} onChange={(e) => setNotes(e.target.value)} placeholder="optional" />
        </Field>
      </div>
      {error && <p className="font-mono text-[12px] text-err">{error}</p>}
      <div className="flex items-center gap-2.5 justify-end">
        <Button type="button" variant="ghost" onClick={onClose}>cancel</Button>
        <Button type="submit" disabled={submitting || !title.trim()}>
          {submitting ? "adding…" : "add event →"}
        </Button>
      </div>
    </form>
  );
}
