import type { ReactNode } from "react";

/**
 * Display title bar that lives at the top of a content area, below
 * the .app-top breadcrumb strip. Cormorant italic title + optional
 * eyebrow + meta line + right-side controls slot. Uses the t-* scale
 * — no inline font sizes.
 */
interface Props {
  eyebrow?: string;
  title: string;
  /** Renders italic. Pass a binomial as just the text. */
  italic?: boolean;
  meta?: ReactNode;
  right?: ReactNode;
}

export function PageHeader({ eyebrow, title, italic = true, meta, right }: Props) {
  return (
    <header className="page-header">
      <div className="title-block">
        {eyebrow && <span className="eyebrow">{eyebrow}</span>}
        {italic ? (
          /* The italic variant carries species binomials (every italic
             call-site passes one — audited across all surfaces). The
             `.binomial` span renders them Cormorant serif italic per the
             design system's binomial rule. */
          <h1 className="h-display">
            <span className="binomial">{title}</span>
          </h1>
        ) : (
          <h1 className="h-display-sans">{title}</h1>
        )}
        {meta && <div className="meta">{meta}</div>}
      </div>
      {right && <div>{right}</div>}
    </header>
  );
}
