import { useEffect, useState } from "react";
import {
  Button,
  CloudSyncIndicator,
  PageHeader,
  PI_HEALTH,
  cn,
} from "@sporeprint/design";
import { PiTopBar } from "../components/PiTopBar";
import { apiGet, apiSend } from "../lib/api";
import type { SettingsMap } from "../lib/pi-types";

// ── Real Pi API shapes (server/app health router) ───────────────────────
interface SystemMetrics {
  cpu_percent: number;
  memory_percent: number;
  memory_used_mb: number;
  memory_total_mb: number;
  disk_percent: number;
  disk_used_gb: number;
  disk_total_gb: number;
  cpu_temp_c: number | null;
  uptime_hours: number;
  db_size_mb: number;
}

const ROW = "flex items-center justify-between gap-[18px] border-t border-border-soft px-[22px] py-[18px]";
const ROW_LABEL = "flex flex-col gap-1 min-w-0";
const ROW_NAME = "font-body text-[16px] font-medium text-text-0";
const ROW_DESC = "font-body text-[14px] leading-[1.4] text-text-2";
const ROW_VALUE = "font-mono text-[14px] whitespace-nowrap text-text-1";

const STATUS_PILL_BASE =
  "inline-flex items-center gap-[7px] rounded-pill border px-3 py-[5px] font-mono text-[12px] font-medium uppercase tracking-widest";
const STATUS_PILL_TONE = {
  signal: "border-signal/40 bg-signal-soft text-signal",
  warn: "border-warn bg-bg-2 text-warn",
  err: "border-err bg-bg-2 text-err",
} as const;
function statusPill(tone: keyof typeof STATUS_PILL_TONE): string {
  return cn(STATUS_PILL_BASE, STATUS_PILL_TONE[tone]);
}

// Controls with no Pi backend get a consistent inline "not yet supported"
// marker instead of a fake save path.
function Unsupported() {
  return <span className="font-mono text-[12px] tracking-[0.05em] text-text-3">not yet supported on this Pi</span>;
}

// FastAPI raises HTTPException(400, detail) → apiSend throws
// `HTTP 400: {"detail":"…"}`. Pull the clean message back out.
function extractDetail(err: unknown): string {
  const msg = err instanceof Error ? err.message : String(err);
  const brace = msg.indexOf("{");
  if (brace >= 0) {
    try {
      const parsed = JSON.parse(msg.slice(brace)) as { detail?: string };
      if (parsed.detail) return parsed.detail;
    } catch {
      /* fall through */
    }
  }
  return msg;
}

function uptimeHuman(hours: number): string {
  if (hours < 24) return `${hours.toFixed(1)}h`;
  const d = Math.floor(hours / 24);
  const h = Math.round(hours - d * 24);
  return `${d}d ${h}h`;
}

export function SettingsPage() {
  const [settings, setSettings] = useState<SettingsMap | null>(null);
  const [system, setSystem] = useState<SystemMetrics | null>(null);
  const [version, setVersion] = useState<string | null>(null);
  const [loadError, setLoadError] = useState<string | null>(null);

  // BYOK
  const [byokDraft, setByokDraft] = useState("");
  const [byokBusy, setByokBusy] = useState(false);
  const [byokError, setByokError] = useState<string | null>(null);

  // OTA verify key
  const [otaDraft, setOtaDraft] = useState("");
  const [otaBusy, setOtaBusy] = useState(false);
  const [otaError, setOtaError] = useState<string | null>(null);

  // ntfy topic
  const [ntfyDraft, setNtfyDraft] = useState("");
  const [ntfyBusy, setNtfyBusy] = useState(false);
  const [ntfyError, setNtfyError] = useState<string | null>(null);

  // Hostname (GET /api/settings/system/hostname · PUT /api/settings/hostname)
  const [hostname, setHostname] = useState<string | null>(null);
  const [hostnameDraft, setHostnameDraft] = useState("");
  const [hostnameBusy, setHostnameBusy] = useState(false);
  const [hostnameError, setHostnameError] = useState<string | null>(null);
  const [hostnameNote, setHostnameNote] = useState<string | null>(null);

  // System actions (broker restart · reboot)
  const [brokerBusy, setBrokerBusy] = useState(false);
  const [brokerMsg, setBrokerMsg] = useState<{ tone: "signal" | "err"; text: string } | null>(null);
  const [confirmReboot, setConfirmReboot] = useState(false);
  const [rebootBusy, setRebootBusy] = useState(false);
  const [rebootScheduled, setRebootScheduled] = useState(false);
  const [rebootMsg, setRebootMsg] = useState<{ tone: "signal" | "err"; text: string } | null>(null);

  useEffect(() => {
    let cancelled = false;
    (async () => {
      try {
        const [s, sys, health, host] = await Promise.all([
          apiGet<SettingsMap>("/api/settings"),
          apiGet<SystemMetrics>("/api/health/detail/system").catch(() => null),
          apiGet<{ version: string }>("/api/health").catch(() => null),
          apiGet<{ hostname: string }>("/api/settings/system/hostname").catch(() => null),
        ]);
        if (cancelled) return;
        setSettings(s);
        setSystem(sys);
        setVersion(health?.version ?? null);
        setNtfyDraft(s.ntfy_topic?.value ?? "");
        setHostname(host?.hostname ?? null);
        setHostnameDraft(host?.hostname ?? "");
      } catch (err) {
        if (!cancelled) setLoadError(err instanceof Error ? err.message : "fetch failed");
      }
    })();
    return () => {
      cancelled = true;
    };
  }, []);

  const byokSavedValue = settings?.claude_api_key?.value ?? "";
  const byokDisplay = byokSavedValue ? settings?.claude_api_key?.display_value ?? "" : "";
  const otaSavedValue = settings?.ota_pubkey_b64?.value ?? "";
  const ntfyCurrent = settings?.ntfy_topic?.value ?? "";
  const ntfyDirty = ntfyDraft.trim() !== ntfyCurrent;
  const hostnameDirty = hostname !== null && hostnameDraft.trim() !== "" && hostnameDraft.trim() !== hostname;

  // One shared mutation path for the settings_service keys: PUT the value
  // when given a string, DELETE the key when given null, driving the caller's
  // busy/error pair either way. Server errors surface via extractDetail.
  async function mutateSetting(
    key: string,
    value: string | null,
    setBusy: (busy: boolean) => void,
    setError: (error: string | null) => void,
    onSuccess?: () => void,
  ) {
    setBusy(true);
    setError(null);
    try {
      const updated =
        value !== null
          ? await apiSend<SettingsMap>(`/api/settings/${key}`, "PUT", { value })
          : await apiSend<SettingsMap>(`/api/settings/${key}`, "DELETE");
      setSettings(updated);
      onSuccess?.();
    } catch (err) {
      setError(extractDetail(err));
    } finally {
      setBusy(false);
    }
  }

  async function saveByok() {
    if (!byokDraft.trim()) return;
    await mutateSetting("claude_api_key", byokDraft.trim(), setByokBusy, setByokError, () =>
      setByokDraft(""),
    );
  }

  async function clearByok() {
    await mutateSetting("claude_api_key", null, setByokBusy, setByokError);
  }

  async function saveOtaKey() {
    setOtaError(null);
    const trimmed = otaDraft.trim();
    if (!trimmed) {
      setOtaError("paste the base64 public key first");
      return;
    }
    // Client-side pre-validation (server re-validates Ed25519 authoritatively;
    // its validation error surfaces verbatim via the shared call).
    let decodedLen: number;
    try {
      const bin = atob(trimmed);
      decodedLen = bin.length;
    } catch {
      setOtaError("not valid base64");
      return;
    }
    if (decodedLen !== 32) {
      setOtaError(`must decode to 32 bytes (got ${decodedLen})`);
      return;
    }
    await mutateSetting("ota_pubkey_b64", trimmed, setOtaBusy, setOtaError, () => setOtaDraft(""));
  }

  async function clearOtaKey() {
    await mutateSetting("ota_pubkey_b64", null, setOtaBusy, setOtaError);
  }

  async function saveNtfy() {
    await mutateSetting("ntfy_topic", ntfyDraft.trim(), setNtfyBusy, setNtfyError);
  }

  async function saveHostname() {
    const name = hostnameDraft.trim();
    if (!name || hostnameBusy) return;
    setHostnameBusy(true);
    setHostnameError(null);
    setHostnameNote(null);
    try {
      const res = await apiSend<{ hostname: string; avahi_restarted: boolean }>(
        "/api/settings/hostname",
        "PUT",
        { hostname: name },
      );
      setHostname(res.hostname);
      setHostnameDraft(res.hostname);
      setHostnameNote(
        res.avahi_restarted
          ? `saved · mDNS now advertises ${res.hostname}.local`
          : "saved · mDNS restart failed — reboot to re-advertise",
      );
    } catch (err) {
      // 422 → RFC-1123 validation detail; surfaced verbatim.
      setHostnameError(extractDetail(err));
    } finally {
      setHostnameBusy(false);
    }
  }

  async function restartBroker() {
    setBrokerBusy(true);
    setBrokerMsg(null);
    try {
      await apiSend<{ status: string }>("/api/settings/system/restart-broker", "POST");
      setBrokerMsg({ tone: "signal", text: "broker restarted" });
    } catch (err) {
      // 500 → captured mosquitto stderr.
      setBrokerMsg({ tone: "err", text: extractDetail(err) });
    } finally {
      setBrokerBusy(false);
    }
  }

  async function rebootPi() {
    setRebootBusy(true);
    setRebootMsg(null);
    try {
      const res = await apiSend<{ status: string; grace_seconds: number }>(
        "/api/settings/system/reboot",
        "POST",
      );
      setRebootScheduled(true);
      setRebootMsg({
        tone: "signal",
        text: `rebooting in ${res.grace_seconds}s — the Pi will be unreachable for a minute`,
      });
    } catch (err) {
      setConfirmReboot(false);
      setRebootMsg({ tone: "err", text: extractDetail(err) });
    } finally {
      setRebootBusy(false);
    }
  }

  return (
    <>
      <PiTopBar
        crumbs={[{ label: "system" }, { label: "settings", active: true }]}
        right={<CloudSyncIndicator cloud={PI_HEALTH.cloud} />}
      />

      <PageHeader
        eyebrow="System"
        title="Settings"
        italic={false}
        meta={
          <span>
            local Pi-only preferences{version ? ` · Pi ${version}` : ""}
            {system ? ` · uptime ${uptimeHuman(system.uptime_hours)}` : ""}
          </span>
        }
      />

      {loadError && (
        <p className="px-7 pt-4 font-mono text-[13px] tracking-[0.05em] text-err">
          Failed to load settings: {loadError}
        </p>
      )}

      <div className="grid grid-cols-[1fr] gap-[22px] px-7 pt-[22px] pb-7 max-w-none">
        <main className="flex flex-col gap-[22px]">
          {/* ---------- Network ---------- */}
          <section className="settings-group" aria-label="Network">
            <div className="group-head">Network</div>

            <div className={ROW}>
              <span className={ROW_LABEL}>
                <span className={ROW_NAME}>Hostname</span>
                <span className={ROW_DESC}>advertised over mDNS as &lt;hostname&gt;.local</span>
              </span>
              <div className="flex items-center gap-2">
                <input
                  className="t-input w-[220px]"
                  value={hostnameDraft}
                  onChange={(e) => setHostnameDraft(e.target.value)}
                  placeholder="chambers"
                  spellCheck={false}
                  autoCorrect="off"
                  autoCapitalize="off"
                  disabled={hostname === null}
                />
                <Button
                  type="button"
                  onClick={() => void saveHostname()}
                  disabled={!hostnameDirty || hostnameBusy}
                >
                  {hostnameBusy ? "saving…" : "save"}
                </Button>
              </div>
            </div>
            {(hostnameError || hostnameNote) && (
              <div className="px-[22px] pb-2">
                <span className={statusPill(hostnameError ? "err" : "signal")}>
                  {hostnameError ?? hostnameNote}
                </span>
              </div>
            )}

            {/* TODO(wire): no WiFi scan/join endpoint on the Pi backend. */}
            <div className={ROW}>
              <span className={ROW_LABEL}>
                <span className={ROW_NAME}>WiFi networks</span>
                <span className={ROW_DESC}>scan + join is managed at the OS level, not via this UI</span>
              </span>
              <Unsupported />
            </div>

            <div className={ROW}>
              <span className={ROW_LABEL}>
                <span className={ROW_NAME}>Cloud pairing</span>
                <span className={ROW_DESC}>manage pairing + subscription in the cloud app</span>
              </span>
              <span className={ROW_VALUE}>sporeprint.ai</span>
            </div>
          </section>

          {/* ---------- Display ---------- */}
          {/* TODO(wire): timezone + unit preferences have no Pi backend
              (not in settings_service CONFIGURABLE_SETTINGS). */}
          <section className="settings-group" aria-label="Display and units">
            <div className="group-head">Display</div>
            <div className={ROW}>
              <span className={ROW_LABEL}>
                <span className={ROW_NAME}>Time zone</span>
                <span className={ROW_DESC}>used for cycle scheduling + event timestamps</span>
              </span>
              <Unsupported />
            </div>
            <div className={ROW}>
              <span className={ROW_LABEL}>
                <span className={ROW_NAME}>Temperature · weight · clock</span>
                <span className={ROW_DESC}>display unit preferences</span>
              </span>
              <Unsupported />
            </div>
          </section>

          {/* ---------- Local AI ---------- */}
          <section className="settings-group" aria-label="Local AI keys">
            <div className="group-head">Local AI · BYOK</div>

            <div className={ROW}>
              <span className={ROW_LABEL}>
                <span className={ROW_NAME}>Anthropic API key</span>
                <span className={ROW_DESC}>
                  unlimited Vision + Advisor calls without round-tripping cloud · key stays on this Pi
                </span>
              </span>
              <span className={ROW_VALUE}>{byokDisplay || "—"}</span>
            </div>

            <div className="flex flex-col gap-2.5 px-[22px] pb-[18px]">
              <input
                className="t-input"
                type="password"
                placeholder="sk-ant-……"
                value={byokDraft}
                onChange={(e) => setByokDraft(e.target.value)}
                spellCheck={false}
              />
              <div className="flex flex-wrap items-center gap-2">
                <Button type="button" onClick={() => void saveByok()} disabled={!byokDraft.trim() || byokBusy}>
                  {byokBusy ? "saving…" : "save key"}
                </Button>
                {/* TODO(wire): no key-test endpoint on the Pi settings/AI
                    routers — disabled rather than faking an "ok · 220ms". */}
                <Button type="button" variant="ghost" disabled title="No key-test endpoint on this Pi">
                  test connection
                </Button>
                <Button type="button" variant="ghost" onClick={() => void clearByok()} disabled={!byokSavedValue || byokBusy}>
                  remove
                </Button>
                {byokError && <span className={cn(statusPill("err"), "self-center")}>{byokError}</span>}
              </div>
            </div>
          </section>

          {/* ---------- OTA verify key ---------- */}
          <section className="settings-group" aria-label="OTA verify key">
            <div className="group-head">OTA Updates</div>

            <div className={ROW}>
              <span className={ROW_LABEL}>
                <span className={ROW_NAME}>OTA verify key</span>
                <span className={ROW_DESC}>
                  base64-encoded raw 32-byte Ed25519 public key · empty = OTA
                  disabled (fail-closed) · generate with{" "}
                  <span className="font-mono text-[14px] text-text-1">scripts/generate-ota-keypair.py</span>
                </span>
              </span>
              <span className="font-mono text-[12px] text-text-1 whitespace-nowrap break-all max-w-[300px]">
                {otaSavedValue || "—"}
              </span>
            </div>

            <div className="flex flex-col gap-2.5 px-[22px] pb-[18px]">
              <input
                className="t-input font-mono text-[12px]"
                type="text"
                placeholder="paste base64 public key (44 chars)"
                value={otaDraft}
                onChange={(e) => setOtaDraft(e.target.value)}
                spellCheck={false}
                autoCorrect="off"
              />
              <div className="flex flex-wrap items-center gap-2">
                <Button type="button" onClick={() => void saveOtaKey()} disabled={!otaDraft.trim() || otaBusy}>
                  {otaBusy ? "saving…" : "save key"}
                </Button>
                <Button type="button" variant="ghost" onClick={() => void clearOtaKey()} disabled={!otaSavedValue || otaBusy}>
                  remove
                </Button>
                {otaError && <span className={cn(statusPill("err"), "self-center")}>{otaError}</span>}
                {!otaError && otaSavedValue && (
                  <span className={cn(statusPill("signal"), "self-center")}>OTA enabled</span>
                )}
                {!otaError && !otaSavedValue && (
                  <span className={cn(statusPill("warn"), "self-center")}>OTA disabled</span>
                )}
              </div>
              <p className="font-mono text-[12px] text-text-2">
                Public keys are not secrets — paste the value generated by the
                signing-host ceremony. The matching private key signs every
                release bundle and must stay offline.
              </p>
            </div>
          </section>

          {/* ---------- Notifications ---------- */}
          <section className="settings-group" aria-label="Notifications">
            <div className="group-head">Notifications</div>

            <div className={ROW}>
              <span className={ROW_LABEL}>
                <span className={ROW_NAME}>ntfy topic</span>
                <span className={ROW_DESC}>
                  the Pi publishes to ntfy.sh/&lt;topic&gt; when cloud is offline — this is the topic
                  string, not a full URL
                </span>
              </span>
              <div className="flex items-center gap-2">
                <input
                  className="t-input w-[320px]"
                  value={ntfyDraft}
                  onChange={(e) => setNtfyDraft(e.target.value)}
                  placeholder="sporeprint"
                  spellCheck={false}
                />
                <Button type="button" disabled={!ntfyDirty || ntfyBusy} onClick={() => void saveNtfy()}>
                  {ntfyBusy ? "saving…" : "save"}
                </Button>
              </div>
            </div>
            {ntfyError && (
              <div className="px-[22px] pb-2">
                <span className={statusPill("err")}>{ntfyError}</span>
              </div>
            )}

            {/* TODO(wire): quiet hours + per-type notification toggles have no
                Pi backend (not in CONFIGURABLE_SETTINGS) — omitted, not faked. */}
            <div className={ROW}>
              <span className={ROW_LABEL}>
                <span className={ROW_NAME}>Quiet hours · per-type toggles</span>
                <span className={ROW_DESC}>notification preferences are managed in the cloud app</span>
              </span>
              <Unsupported />
            </div>
          </section>

          {/* ---------- Backup / Restore ---------- */}
          {/* TODO(wire): no config snapshot/restore endpoint on the Pi. */}
          <section className="settings-group" aria-label="Backup and restore">
            <div className="group-head">Backup · Restore</div>
            <div className={ROW}>
              <span className={ROW_LABEL}>
                <span className={ROW_NAME}>Config snapshot</span>
                <span className={ROW_DESC}>download / restore of Pi-local settings</span>
              </span>
              <div className="flex items-center gap-2">
                <Button type="button" disabled>download .json</Button>
                <Unsupported />
              </div>
            </div>
          </section>

          {/* ---------- System ---------- */}
          {/* Factory reset has no Pi backend endpoint (by design) — it stays
              disabled. Broker restart + reboot are live. */}
          <section className="settings-group" aria-label="System">
            <div className="group-head">System</div>
            <div className={ROW}>
              <span className={ROW_LABEL}>
                <span className={ROW_NAME}>Restart MQTT broker</span>
                <span className={ROW_DESC}>useful after gateway changes · does not interrupt this UI</span>
              </span>
              <div className="flex items-center gap-2">
                {brokerMsg && (
                  <span className={cn(statusPill(brokerMsg.tone), "self-center")}>{brokerMsg.text}</span>
                )}
                <Button type="button" variant="ghost" onClick={() => void restartBroker()} disabled={brokerBusy}>
                  {brokerBusy ? "restarting…" : "restart broker"}
                </Button>
              </div>
            </div>
            <div className={ROW}>
              <span className={ROW_LABEL}>
                <span className={ROW_NAME}>Restart Pi</span>
                <span className={ROW_DESC}>reboots the device — the UI drops for ~a minute</span>
              </span>
              <div className="flex items-center gap-2">
                {rebootMsg && (
                  <span className={cn(statusPill(rebootMsg.tone), "self-center")}>{rebootMsg.text}</span>
                )}
                {confirmReboot && !rebootScheduled && (
                  <Button type="button" variant="ghost" onClick={() => setConfirmReboot(false)} disabled={rebootBusy}>
                    cancel
                  </Button>
                )}
                <Button
                  type="button"
                  variant="destructive"
                  disabled={rebootBusy || rebootScheduled}
                  onClick={() => (confirmReboot ? void rebootPi() : setConfirmReboot(true))}
                >
                  {rebootScheduled
                    ? "reboot scheduled"
                    : rebootBusy
                      ? "scheduling…"
                      : confirmReboot
                        ? "confirm — reboot now?"
                        : "reboot Pi"}
                </Button>
              </div>
            </div>
            <div className={ROW}>
              <span className={ROW_LABEL}>
                <span className={ROW_NAME}>Factory reset</span>
                <span className={ROW_DESC}>erases all Pi-local config</span>
              </span>
              <div className="flex items-center gap-2">
                <Button type="button" variant="destructive" disabled>factory reset</Button>
                <Unsupported />
              </div>
            </div>
          </section>

          {/* ---------- About ---------- */}
          <section className="settings-group" aria-label="About">
            <div className="group-head">About</div>
            {version && <KvRow name="Pi service version" value={version} desc="reported by /api/health" />}
            {system ? (
              <>
                <KvRow name="Uptime" value={uptimeHuman(system.uptime_hours)} />
                <KvRow
                  name="CPU"
                  value={`${system.cpu_percent.toFixed(0)}%`}
                  desc={system.cpu_temp_c != null ? `${system.cpu_temp_c.toFixed(1)}°C` : undefined}
                />
                <KvRow
                  name="Memory"
                  value={`${system.memory_used_mb} / ${system.memory_total_mb} MB`}
                  desc={`${system.memory_percent.toFixed(0)}% used`}
                />
                <KvRow
                  name="Disk"
                  value={`${system.disk_used_gb.toFixed(1)} / ${system.disk_total_gb.toFixed(1)} GB`}
                  desc={`${system.disk_percent.toFixed(0)}% used`}
                />
                <KvRow name="Database" value={`${system.db_size_mb.toFixed(2)} MB`} />
              </>
            ) : (
              <div className={ROW}>
                <span className={ROW_LABEL}>
                  <span className={ROW_NAME}>System metrics</span>
                  <span className={ROW_DESC}>from /api/health/detail/system</span>
                </span>
                <span className={ROW_VALUE}>—</span>
              </div>
            )}
            {/* TODO(wire): OS / kernel / hardware / serial / firmware / Python
                / Docker / boot timestamps are not exposed by
                /api/health/detail/system — omitted rather than fabricated. */}
          </section>
        </main>
      </div>
    </>
  );
}

function KvRow({ name, value, desc }: { name: string; value: string; desc?: string }) {
  return (
    <div className={ROW}>
      <span className={ROW_LABEL}>
        <span className={ROW_NAME}>{name}</span>
        {desc && <span className={ROW_DESC}>{desc}</span>}
      </span>
      <span className={ROW_VALUE}>{value}</span>
    </div>
  );
}
