import { useRef, useState } from "react";
import {
  Button,
  CloudSyncIndicator,
  DataTable,
  PI_HEALTH,
  PageHeader,
  cn,
} from "@sporeprint/design";
import { PiTopBar } from "../components/PiTopBar";
import { apiGet, apiSend } from "../lib/api";
import { usePiLoad } from "../lib/use-pi-load";

// ── Real Pi API shapes (server/app/contamination router + library) ─────
interface Contaminant {
  classification: string;
  confidence: number;
  stage?: string;
  location?: string;
  action?: string;
  reasoning?: string;
}
interface IdentifyResult {
  contamination_detected?: boolean;
  contaminants?: Contaminant[];
  health_assessment?: string;
  recommendations?: string[];
  parse_error?: boolean;
  raw_response?: string;
}
interface LibraryEntry {
  id: string;
  common_name: string;
  scientific_name: string;
  appearance: string;
  growth_speed: string;
  smell: string;
  danger_level: string; // high | medium | low
  action: string;
}
// Persisted contamination_events row (identify auto-persist + manual marks).
interface ContaminationEvent {
  id: number;
  session_id: number | null;
  chamber_id: number | null;
  detected_at: number; // unix seconds
  source: string; // identify | manual
  contamination_type: string | null;
  confidence: number | null; // 0–1
  frame_id: number | null;
  notes: string | null;
  root_cause: string | null;
  root_cause_recorded_at: number | null;
  created_at: number;
}

function fmtDetected(ts: number): string {
  return new Date(ts * 1000).toLocaleString(undefined, {
    month: "short",
    day: "numeric",
    hour: "2-digit",
    minute: "2-digit",
  });
}

// `.status-pill` base + tone (classmap §10) — self-sufficient tones.
const STATUS_PILL_BASE =
  "inline-flex items-center gap-[7px] rounded-pill border px-3 py-[5px] font-mono text-[12px] font-medium uppercase tracking-widest";
const STATUS_PILL_TONE = {
  accent: "border-accent-line bg-accent-soft text-accent",
  signal: "border-signal/40 bg-signal-soft text-signal",
  warn: "border-warn bg-bg-2 text-warn",
  err: "border-err bg-bg-2 text-err",
} as const;
function statusPill(tone: keyof typeof STATUS_PILL_TONE): string {
  return cn(STATUS_PILL_BASE, STATUS_PILL_TONE[tone]);
}

function dangerTone(level: string): keyof typeof STATUS_PILL_TONE {
  switch (level) {
    case "high":
      return "err";
    case "medium":
      return "warn";
    default:
      return "signal";
  }
}

interface CheckEntry {
  id: string;
  ts: string;
  origin: "drop" | "manual";
  fileLabel: string;
  status: "pending" | "complete" | "failed";
  verdict?: string;
  confidence?: number;
  note?: string;
}

// Reduce the identify response into a single readable verdict for the log.
function summarize(result: IdentifyResult): { verdict: string; confidence?: number } {
  if (result.parse_error) return { verdict: "unparseable response" };
  const top = result.contaminants?.[0];
  if (result.contamination_detected && top) {
    return { verdict: top.classification, confidence: top.confidence };
  }
  return { verdict: result.health_assessment ?? "no contamination detected" };
}

export function ContaminationPage() {
  const [dragging, setDragging] = useState(false);
  const [checks, setChecks] = useState<CheckEntry[]>([]);
  const fileRef = useRef<HTMLInputElement>(null);

  const { data: libraryRows, error: libError } = usePiLoad(
    () => apiGet<LibraryEntry[]>("/api/contamination/library"),
    [],
  );
  const library = libraryRows ?? [];

  // Persisted event feed + RCA state.
  const [eventsRefresh, setEventsRefresh] = useState(0);
  const { data: events, error: eventsError } = usePiLoad(
    () => apiGet<ContaminationEvent[]>("/api/contamination/events"),
    [eventsRefresh],
  );
  const [selectedEventId, setSelectedEventId] = useState<number | null>(null);
  const [rca, setRca] = useState("");
  const [rcaBusy, setRcaBusy] = useState(false);
  const [rcaError, setRcaError] = useState<string | null>(null);

  const running = checks.filter((c) => c.status === "pending").length;

  const selectedEvent = events?.find((e) => e.id === selectedEventId) ?? null;

  async function identify(file: File, origin: CheckEntry["origin"]) {
    const ts = new Date().toLocaleTimeString("en-GB", { hour12: false });
    const id = `${ts}-${file.name}`;
    const entry: CheckEntry = { id, ts, origin, fileLabel: file.name, status: "pending" };
    setChecks((prev) => [entry, ...prev].slice(0, 12));
    try {
      const fd = new FormData();
      fd.append("file", file);
      const res = await fetch("/api/contamination/identify", {
        method: "POST",
        credentials: "same-origin",
        body: fd,
      });
      if (!res.ok) {
        const detail = await res.text();
        setChecks((prev) =>
          prev.map((c) =>
            c.id === id ? { ...c, status: "failed", note: `HTTP ${res.status}: ${detail.slice(0, 120)}` } : c,
          ),
        );
        return;
      }
      const result = (await res.json()) as IdentifyResult;
      const { verdict, confidence } = summarize(result);
      setChecks((prev) =>
        prev.map((c) => (c.id === id ? { ...c, status: "complete", verdict, confidence } : c)),
      );
      // A positive detection is auto-persisted server-side — pull the feed
      // again so it shows in the gallery.
      setEventsRefresh((k) => k + 1);
    } catch (err) {
      setChecks((prev) =>
        prev.map((c) =>
          c.id === id ? { ...c, status: "failed", note: err instanceof Error ? err.message : "identify failed" } : c,
        ),
      );
    }
  }

  function handleDrop(e: React.DragEvent) {
    e.preventDefault();
    setDragging(false);
    const file = e.dataTransfer.files?.[0];
    if (file) void identify(file, "drop");
  }

  function handlePick(e: React.ChangeEvent<HTMLInputElement>) {
    const file = e.target.files?.[0];
    if (file) void identify(file, "manual");
    if (fileRef.current) fileRef.current.value = "";
  }

  function selectEvent(ev: ContaminationEvent) {
    setSelectedEventId(ev.id);
    setRca(ev.root_cause ?? "");
    setRcaError(null);
  }

  async function submitRca() {
    if (selectedEventId === null || !rca.trim() || rcaBusy) return;
    setRcaBusy(true);
    setRcaError(null);
    try {
      await apiSend(`/api/contamination/events/${selectedEventId}/root-cause`, "POST", {
        root_cause: rca.trim(),
      });
      setEventsRefresh((k) => k + 1);
    } catch (err) {
      setRcaError(err instanceof Error ? err.message : "save failed");
    } finally {
      setRcaBusy(false);
    }
  }

  return (
    <>
      <PiTopBar
        crumbs={[{ label: "track" }, { label: "contamination", active: true }]}
        right={<CloudSyncIndicator cloud={PI_HEALTH.cloud} />}
      />

      <PageHeader
        eyebrow="Track"
        title="Contamination"
        italic={false}
        meta={
          <span>
            BYOK Claude Vision identify · {running} check{running === 1 ? "" : "s"} in flight
          </span>
        }
        right={
          <Button type="button" variant="solid" onClick={() => fileRef.current?.click()}>
            capture + identify →
          </Button>
        }
      />

      <div className="grid grid-cols-[1fr_400px] gap-[22px] px-7 pt-[22px] pb-7 max-[1180px]:grid-cols-1">
        <main className="flex flex-col gap-3.5 max-[1180px]:min-w-0">
          <section
            className={cn(
              "flex flex-col gap-[18px] rounded-md border p-[26px]",
              dragging ? "border-accent-line bg-accent-soft" : "border-border-soft bg-bg-1",
            )}
            onDragOver={(e) => { e.preventDefault(); setDragging(true); }}
            onDragLeave={() => setDragging(false)}
            onDrop={handleDrop}
          >
            <div className="mb-1.5 font-mono text-[15px] font-medium uppercase tracking-[0.16em] text-text-2">Drag-drop · BYOK Claude check</div>
            <div className="flex flex-col gap-2 rounded-md border border-dashed border-border p-7 text-center">
              <span className="font-display font-medium text-[26px] leading-[1.18] tracking-[-0.005em] text-text-0">
                {dragging ? "release to upload" : "drop a frame to identify"}
              </span>
              <span className="font-mono text-[12px] text-text-2">
                runs against the on-Pi BYOK Claude key · returns 503 if no key is set
              </span>
              <input
                ref={fileRef}
                type="file"
                accept="image/*"
                onChange={handlePick}
                className="hidden"
              />
              <div className="mt-1 flex items-center justify-center gap-2.5">
                <Button type="button" variant="ghost" onClick={() => fileRef.current?.click()}>browse files</Button>
                {/* TODO(wire): no camera-grab endpoint — /api/contamination/identify
                    requires an uploaded file; the Pi cannot pull a live frame from a
                    camera node into an identify request. */}
                <Button
                  type="button"
                  variant="ghost"
                  disabled
                  title="No camera-grab endpoint on this Pi — upload a frame instead"
                >
                  grab from camera
                </Button>
              </div>
            </div>
          </section>

          <section className="flex flex-col gap-[18px] rounded-md border border-border-soft bg-bg-1 p-[26px]">
            <div className="mb-1.5 font-mono text-[15px] font-medium uppercase tracking-[0.16em] text-text-2">Response log · last {checks.length}</div>
            <div className="max-[1180px]:min-w-0 max-[1180px]:overflow-x-auto">
              {checks.length === 0 ? (
                <p className="font-body text-[14px] leading-[1.55] text-text-2">
                  Drop or browse a frame to run a Claude Vision contamination check.
                </p>
              ) : (
                <DataTable<CheckEntry>
                  rows={checks}
                  columns={[
                    { key: "ts", header: "Time", render: (c) => <span className="font-mono text-text-0">{c.ts}</span> },
                    { key: "origin", header: "Source", render: (c) => <span className={statusPill(c.origin === "drop" ? "signal" : "accent")}>{c.origin}</span> },
                    { key: "file", header: "File", render: (c) => <span className="font-mono text-text-0">{c.fileLabel}</span> },
                    { key: "result", header: "Result", render: (c) => (c.status === "complete" ? (c.verdict ?? "—") : c.status === "failed" ? <span className="text-err">{c.note ?? "failed"}</span> : "—") },
                    {
                      key: "confidence",
                      header: "Confidence",
                      align: "right",
                      render: (c) => (typeof c.confidence === "number" ? `${(c.confidence * 100).toFixed(0)}%` : "—"),
                    },
                    {
                      key: "status",
                      header: "Status",
                      render: (c) => (
                        <span className={statusPill(c.status === "complete" ? "accent" : c.status === "pending" ? "warn" : "err")}>
                          {c.status}
                        </span>
                      ),
                    },
                  ]}
                />
              )}
            </div>
          </section>

          {/* Persisted contamination-event feed (identify auto-persist +
              manual marks). Click an event to load it into the RCA form. */}
          <section className="flex flex-col gap-[18px] rounded-md border border-border-soft bg-bg-1 p-[26px]">
            <div className="mb-1.5 font-mono text-[15px] font-medium uppercase tracking-[0.16em] text-text-2">
              Event gallery{events ? ` · ${events.length}` : ""}
            </div>
            {eventsError ? (
              <p className="font-mono text-[13px] tracking-[0.05em] text-err">Failed to load events: {eventsError}</p>
            ) : events === null ? (
              <p className="font-mono text-[13px] tracking-[0.05em] text-text-2">Loading…</p>
            ) : events.length === 0 ? (
              <p className="font-body text-[14px] leading-[1.55] text-text-2">
                No contamination events recorded on this Pi yet. Positive identify results are logged
                here automatically.
              </p>
            ) : (
              <ul className="flex flex-col gap-2.5">
                {events.map((ev) => {
                  const isSel = ev.id === selectedEventId;
                  return (
                    <li key={ev.id}>
                      <button
                        type="button"
                        onClick={() => selectEvent(ev)}
                        className={cn(
                          "flex w-full flex-col gap-1.5 rounded-sm border bg-bg-2 px-3.5 py-3 text-left",
                          isSel ? "border-accent-line bg-accent-soft" : "border-border-soft hover:border-border",
                        )}
                      >
                        <div className="flex items-center justify-between gap-3">
                          <span className="font-mono text-[14px] text-text-1">
                            {ev.contamination_type ?? "unclassified"}
                          </span>
                          <span className={statusPill(ev.source === "identify" ? "signal" : "accent")}>{ev.source}</span>
                        </div>
                        <div className="flex flex-wrap items-center gap-3 font-mono text-[12px] text-text-2">
                          <span>{fmtDetected(ev.detected_at)}</span>
                          {typeof ev.confidence === "number" && <span>{(ev.confidence * 100).toFixed(0)}%</span>}
                          {ev.chamber_id != null && <span>CH-{ev.chamber_id}</span>}
                          {ev.session_id != null && <span>session {ev.session_id}</span>}
                        </div>
                        {ev.notes && (
                          <span className="font-body text-[14px] leading-[1.5] text-text-1">{ev.notes}</span>
                        )}
                        <span className={cn("self-start", ev.root_cause ? "text-signal" : "text-text-3", "font-mono text-[12px]")}>
                          {ev.root_cause ? "root-cause recorded" : "no root-cause yet"}
                        </span>
                      </button>
                    </li>
                  );
                })}
              </ul>
            )}
          </section>
        </main>

        <aside className="flex flex-col gap-3.5">
          <section className="flex flex-col gap-[18px] rounded-md border border-border-soft bg-bg-1 p-[26px]">
            <div className="mb-1.5 font-mono text-[15px] font-medium uppercase tracking-[0.16em] text-text-2">Root-cause analysis</div>
            <p className="font-body text-[14px] leading-[1.55] text-text-1">
              Capture the likely cause — substrate, sterilisation, env window — so the next batch has a
              hypothesis to push back against. Select an event from the gallery, then record its cause.
            </p>
            {selectedEvent === null ? (
              <span className={cn(statusPill("warn"), "self-start")}>select an event to analyse</span>
            ) : (
              <>
                <div className="flex flex-col gap-1 rounded-sm border border-border-soft bg-bg-2 p-3">
                  <div className="flex items-center justify-between gap-3">
                    <span className="font-mono text-[14px] text-text-1">
                      {selectedEvent.contamination_type ?? "unclassified"}
                    </span>
                    <span className={statusPill(selectedEvent.source === "identify" ? "signal" : "accent")}>
                      {selectedEvent.source}
                    </span>
                  </div>
                  <span className="font-mono text-[12px] text-text-2">
                    {fmtDetected(selectedEvent.detected_at)}
                    {selectedEvent.chamber_id != null && ` · CH-${selectedEvent.chamber_id}`}
                  </span>
                </div>
                <label className="flex flex-col gap-1.5">
                  <span className="font-mono text-[12px] font-medium uppercase tracking-[0.14em] text-text-2">root cause</span>
                  <textarea
                    className="t-input resize-y"
                    rows={4}
                    value={rca}
                    onChange={(e) => setRca(e.target.value)}
                    placeholder="Likely under-sterilised batch (psi sag) + high RH gave the foothold."
                  />
                </label>
                {rcaError && <span className={cn(statusPill("err"), "self-start")}>{rcaError}</span>}
                <Button
                  type="button"
                  variant="solid"
                  className="self-start"
                  onClick={() => void submitRca()}
                  disabled={!rca.trim() || rcaBusy}
                >
                  {rcaBusy ? "recording…" : selectedEvent.root_cause ? "update analysis →" : "record analysis →"}
                </Button>
              </>
            )}
          </section>

          <section className="flex flex-col gap-[18px] rounded-md border border-border-soft bg-bg-1 p-[26px]">
            <div className="mb-1.5 font-mono text-[15px] font-medium uppercase tracking-[0.16em] text-text-2">Reference library</div>
            {libError ? (
              <p className="font-mono text-[13px] tracking-[0.05em] text-err">Failed to load: {libError}</p>
            ) : library.length === 0 ? (
              <p className="font-mono text-[13px] tracking-[0.05em] text-text-2">Loading…</p>
            ) : (
              library.slice(0, 3).map((r) => (
                <div
                  key={r.id}
                  className="flex flex-col gap-1 rounded-sm border border-border-soft bg-bg-2 p-3"
                >
                  <div className="flex items-baseline justify-between gap-3">
                    <span className="font-mono text-[14px] text-text-1">{r.common_name}</span>
                    <span className={statusPill(dangerTone(r.danger_level))}>
                      {r.danger_level === "high" ? "critical" : r.danger_level}
                    </span>
                  </div>
                  <span className="font-mono text-[12px] text-text-2">{r.growth_speed}</span>
                  <span className="font-body text-[14px] leading-[1.55] text-text-1">{r.appearance}</span>
                </div>
              ))
            )}
          </section>
        </aside>
      </div>
    </>
  );
}
