import type { ReactNode } from "react";
import { NavLink, useLocation } from "react-router-dom";
import { Sidebar, Toaster, cn } from "@sporeprint/design";
import { PI_HEALTH } from "@sporeprint/design";

// `.sidebar-link`/`.sidebar-link.active` utilities (see
// classmap-pi-delta.md §10). `.active` is SAFFRON at base — reproduced
// exactly per the Phase-3 controller ruling (parity default; grammar
// unification deferred to a coordinated all-surface sidebar-link
// retirement, same standing flag as Phase 2's tabs-neutral thread).
const SIDEBAR_LINK =
  "flex items-center gap-2.5 border-l-[3px] border-l-transparent px-[26px] py-[13px] font-body text-[16px] font-normal text-text-1 no-underline transition-all duration-[var(--dur-fast)] ease-brand hover:bg-bg-2 hover:text-text-0";
const SIDEBAR_LINK_ACTIVE = "border-l-border bg-bg-3 font-medium text-text-0";

// v3.4.x Pi UI sidebar parity: full nav, organized by section.
const SECTIONS: Array<{ label: string; items: Array<{ to: string; label: string }> }> = [
  {
    label: "Monitor",
    items: [
      { to: "/", label: "Chambers" },
      { to: "/sessions", label: "Sessions" },
      { to: "/hardware", label: "Hardware" },
      { to: "/vision", label: "Vision" },
    ],
  },
  {
    label: "Control",
    items: [
      { to: "/automation", label: "Automation" },
      { to: "/species", label: "Species" },
    ],
  },
  {
    label: "Plan",
    items: [
      { to: "/planner", label: "Planner" },
      { to: "/wizard", label: "Species Wizard" },
      { to: "/shopping", label: "Shopping List" },
    ],
  },
  {
    label: "Track",
    items: [
      { to: "/cultures", label: "Cultures" },
      { to: "/inventory", label: "Chambers" },
      { to: "/experiments", label: "Experiments" },
      { to: "/contamination", label: "Contamination" },
      { to: "/transcripts", label: "Transcripts" },
    ],
  },
  {
    label: "System",
    items: [
      { to: "/builder", label: "Builder" },
      { to: "/firmware", label: "Firmware" },
      { to: "/integrations", label: "Integrations" },
      { to: "/setup", label: "Setup" },
      { to: "/settings", label: "Settings" },
    ],
  },
];

function uptimeShort(sec: number) {
  const days = Math.floor(sec / 86400);
  const hours = Math.floor((sec % 86400) / 3600);
  return `up ${days}d ${hours}h`;
}

export function AppShell({ children }: { children: ReactNode }) {
  const { pathname } = useLocation();
  return (
    <div className="grid min-h-screen grid-cols-[280px_1fr] bg-bg-0 max-[1180px]:grid-cols-[220px_1fr]">
      <Sidebar
        brand={{ word: "sporeprint", suffix: " · local" }}
        sections={SECTIONS.map((s) => ({
          label: s.label,
          items: s.items.map((item) => {
            const active =
              item.to === "/"
                ? pathname === "/" || pathname.startsWith("/chamber/")
                : pathname === item.to || pathname.startsWith(`${item.to}/`);
            return (
              <NavLink
                key={item.to}
                to={item.to}
                end={item.to === "/"}
                className={cn(SIDEBAR_LINK, active && SIDEBAR_LINK_ACTIVE)}
              >
                <span>{item.label}</span>
              </NavLink>
            );
          }),
        }))}
        footer={{
          version: `v${PI_HEALTH.firmwareVersion}`,
          statusLabel: PI_HEALTH.cloud.state === "synced" ? "synced" : PI_HEALTH.cloud.state,
          statusKind: PI_HEALTH.cloud.state === "synced" ? "signal" : PI_HEALTH.cloud.state === "syncing" ? "warn" : "err",
          extra: <span className="text-text-3">{uptimeShort(PI_HEALTH.uptimeSec)}</span>,
        }}
      />
      <div className="flex min-w-0 flex-col">{children}</div>
      <Toaster />
    </div>
  );
}
