// Full 74-entry catalog (gourmet + medicinal + active + novelty),
// ported from sporeprint/server/app/species/profiles.py.
const PI_SPECIES_LIBRARY: SpeciesEntry[] = SPECIES_LIBRARY;

function Section({ label, children }: { label: string; children: ReactNode }) {
  return (
    <section className="flex flex-col gap-2">
      <span className="font-mono text-[13px] font-medium tracking-[0.16em] uppercase text-text-2">{label}</span>
      {children}
    </section>
  );
}

// `.status-pill` base + tone (classmap §10). Full resolved utility strings —
// no shared legacy base class, so no utility emit-order fight (Binding Lesson 3).
const STATUS_PILL_BASE =
  "inline-flex items-center gap-[7px] rounded-pill border px-3 py-[5px] font-mono text-[12px] font-medium uppercase tracking-widest";
const STATUS_PILL_TONE = {
  accent: "border-accent-line bg-accent-soft text-accent",
  signal: "border-signal/40 bg-signal-soft text-signal",
  warn: "border-warn bg-bg-2 text-warn",
  err: "border-err bg-bg-2 text-err",
} as const;

const TONE: Record<SpeciesEntry["difficulty"], "signal" | "warn" | "err"> = {
  beginner: "signal",
  intermediate: "warn",
  advanced: "err",
};

type Cat = "all" | "gourmet" | "medicinal" | "active";
type Diff = "all" | "beginner" | "intermediate" | "advanced";

const RECENT_KEY = "pi:species:recent";

function loadRecent(): string[] {
  if (typeof window === "undefined") return [];
  try {
    const raw = window.localStorage.getItem(RECENT_KEY);
    return raw ? (JSON.parse(raw) as string[]) : [];
  } catch {
    return [];
  }
}

function pushRecent(id: string): string[] {
  const current = loadRecent().filter((x) => x !== id);
  const next = [id, ...current].slice(0, 6);
  if (typeof window !== "undefined") {
    try {
      window.localStorage.setItem(RECENT_KEY, JSON.stringify(next));
    } catch {}
  }
  return next;
}

function allTags(): string[] {
  const set = new Set<string>();
  for (const s of PI_SPECIES_LIBRARY) for (const t of s.tags) set.add(t);
  return Array.from(set).sort();
}

export function SpeciesPage() {
  const [query, setQuery] = useState("");
  const [cat, setCat] = useState<Cat>("all");
  const [diff, setDiff] = useState<Diff>("all");
  const [tagFilter, setTagFilter] = useState<Set<string>>(new Set());
  const [expanded, setExpanded] = useState<string | null>(null);
  const [recent, setRecent] = useState<string[]>(() => loadRecent());
  const [grams, setGrams] = useState("2270");

  const tags = useMemo(allTags, []);

  const filtered = useMemo(() => {
    const q = query.trim().toLowerCase();
    return PI_SPECIES_LIBRARY.filter((s) => {
      if (cat !== "all" && s.category !== cat) return false;
      if (diff !== "all" && s.difficulty !== diff) return false;
      if (tagFilter.size > 0 && !s.tags.some((t) => tagFilter.has(t))) return false;
      if (!q) return true;
      return [s.common, s.binomial, s.tldr, ...s.tags].join(" ").toLowerCase().includes(q);
    });
  }, [query, cat, diff, tagFilter]);

  const recentEntries = useMemo(
    () => recent.map((id) => PI_SPECIES_LIBRARY.find((s) => s.id === id)).filter(Boolean) as SpeciesEntry[],
    [recent],
  );

  function toggleTag(t: string) {
    setTagFilter((prev) => {
      const next = new Set(prev);
      if (next.has(t)) next.delete(t);
      else next.add(t);
      return next;
    });
  }

  function handleExpand(id: string) {
    if (expanded === id) {
      setExpanded(null);
    } else {
      setExpanded(id);
      setRecent(pushRecent(id));
    }
  }

  return (
    <>
      <PiTopBar
        crumbs={[{ label: "control" }, { label: "species", active: true }]}
        right={<CloudSyncIndicator cloud={PI_HEALTH.cloud} />}
      />

      <PageHeader
        eyebrow="Control"
        title="Species library"
        italic={false}
        meta={
          <span>
            {filtered.length} of {PI_SPECIES_LIBRARY.length} cached locally · works offline · TEK guides + substrate recipes per species
          </span>
        }
      />

      <div className="grid grid-cols-[1fr] gap-[22px] px-7 pt-[22px] pb-7 max-w-none">
        <main className="flex flex-col gap-[18px]">
          <Kpis filtered={filtered} />

          <Toolbar
            query={query}
            onQuery={setQuery}
            cat={cat}
            onCat={setCat}
            diff={diff}
            onDiff={setDiff}
          />

          <TagFilter tags={tags} active={tagFilter} onToggle={toggleTag} />

          {recentEntries.length > 0 && (
            <RecentStrip entries={recentEntries} onPick={handleExpand} />
          )}

          <div className="grid grid-cols-[repeat(auto-fit,minmax(min(320px,100%),1fr))] gap-3 auto-rows-fr min-w-0">
            {filtered.map((s) => (
              <SpeciesCard
                key={s.id}
                s={s}
                expanded={expanded === s.id}
                onExpand={() => handleExpand(s.id)}
                grams={grams}
                onGrams={setGrams}
              />
            ))}
          </div>

          {filtered.length === 0 && (
            <EmptyState
              title="No matches"
              body="Clear tags or broaden the search to see the full library."
            />
          )}
        </main>
      </div>
    </>
  );
}

function Kpis({ filtered }: { filtered: SpeciesEntry[] }) {
  const beginner = filtered.filter((s) => s.difficulty === "beginner").length;
  const gourmet = filtered.filter((s) => s.category === "gourmet").length;
  const medicinal = filtered.filter((s) => s.category === "medicinal").length;
  const active = filtered.filter((s) => s.category === "active").length;
  const avgTtf = filtered.length
    ? Math.round(filtered.reduce((sum, s) => sum + s.ttf, 0) / filtered.length)
    : 0;
  return (
    <section className="grid grid-cols-[repeat(auto-fit,minmax(220px,1fr))] gap-3">
      <KpiCard label="visible" value={filtered.length.toString()} />
      <KpiCard label="beginner-friendly" value={beginner.toString()} tone="signal" />
      <KpiCard
        label="gourmet · medicinal · active"
        value={`${gourmet} · ${medicinal} · ${active}`}
      />
      <KpiCard label="avg ttf" value={`${avgTtf}d`} tone="accent" />
    </section>
  );
}

function Toolbar({
  query,
  onQuery,
  cat,
  onCat,
  diff,
  onDiff,
}: {
  query: string;
  onQuery: (v: string) => void;
  cat: Cat;
  onCat: (c: Cat) => void;
  diff: Diff;
  onDiff: (d: Diff) => void;
}) {
  return (
    <section className="flex flex-row flex-wrap items-center gap-2 rounded-md border border-border-soft bg-bg-1 p-[26px]">
      <div className="min-w-[240px] flex-[1_1_280px]">
        <SearchInput
          value={query}
          onChange={onQuery}
          placeholder="search by name, binomial, tag …"
          ariaLabel="search species"
        />
      </div>
      <ChipGroup label="category">
        <Chip active={cat === "all"} onClick={() => onCat("all")}>all</Chip>
        <Chip active={cat === "gourmet"} onClick={() => onCat("gourmet")}>gourmet</Chip>
        <Chip active={cat === "medicinal"} onClick={() => onCat("medicinal")}>medicinal</Chip>
        <Chip active={cat === "active"} onClick={() => onCat("active")}>active</Chip>
      </ChipGroup>
      <ChipGroup label="difficulty">
        <Chip active={diff === "all"} onClick={() => onDiff("all")}>all</Chip>
        <Chip active={diff === "beginner"} onClick={() => onDiff("beginner")}>beginner</Chip>
        <Chip active={diff === "intermediate"} onClick={() => onDiff("intermediate")}>intermediate</Chip>
        <Chip active={diff === "advanced"} onClick={() => onDiff("advanced")}>advanced</Chip>
      </ChipGroup>
    </section>
  );
}

function TagFilter({
  tags,
  active,
  onToggle,
}: {
  tags: string[];
  active: Set<string>;
  onToggle: (t: string) => void;
}) {
  return (
    <section className="flex flex-wrap items-center gap-1.5">
      <span className="mr-2 font-mono text-[13px] font-medium tracking-[0.16em] uppercase text-text-2">
        tags · multi-select
      </span>
      {tags.map((t) => (
        <Chip key={t} active={active.has(t)} onClick={() => onToggle(t)}>
          {t}
        </Chip>
      ))}
    </section>
  );
}

function RecentStrip({
  entries,
  onPick,
}: {
  entries: SpeciesEntry[];
  onPick: (id: string) => void;
}) {
  return (
    <section className="flex flex-wrap items-center gap-2.5">
      <span className="mr-1.5 font-mono text-[13px] font-medium tracking-[0.16em] uppercase text-text-2">
        recently viewed
      </span>
      {entries.map((e) => (
        <Chip key={e.id} active={false} onClick={() => onPick(e.id)}>
          {e.common}
        </Chip>
      ))}
    </section>
  );
}

const CARD_CELL_BASE = "flex min-h-[280px] cursor-pointer flex-col gap-3 rounded-md border bg-bg-1 px-6 py-[22px]";

