function YieldEstimator({
  s,
  grams,
  onGrams,
}: {
  s: SpeciesEntry;
  grams: string;
  onGrams: (v: string) => void;
}) {
  const blockGrams = Math.max(0, parseInt(grams, 10) || 0);
  // Use cultivationNotes + difficulty to derive a yield range.
  const beRange: [number, number] =
    s.difficulty === "beginner" ? [0.9, 1.2] :
    s.difficulty === "intermediate" ? [0.6, 0.9] :
    [0.4, 0.7];
  const lo = Math.round(blockGrams * beRange[0]);
  const hi = Math.round(blockGrams * beRange[1]);

  return (
    <Section label="Yield estimator">
      <div className="flex flex-wrap items-center gap-3.5">
        <label className="flex flex-col gap-1">
          <span className="font-mono text-[12px] font-medium tracking-[0.14em] uppercase text-text-2">Block size (g)</span>
          <Input
            type="number"
            min={0}
            value={grams}
            onChange={(e) => onGrams(e.target.value)}
            onClick={(e) => e.stopPropagation()}
            className="w-[140px]"
          />
        </label>
        <span className="font-mono text-[12px] text-text-2">×</span>
        <span className="font-mono text-[12px] text-text-2">
          BE {Math.round(beRange[0] * 100)}–{Math.round(beRange[1] * 100)}%
        </span>
        <span className="font-mono text-[12px] text-text-2">=</span>
        <span className="font-mono text-[28px] leading-none tracking-normal text-text-0">
          {lo.toLocaleString()}–{hi.toLocaleString()} g
        </span>
        <span className="font-mono text-[12px] text-text-3">
          (~{(lo / 454).toFixed(1)}–{(hi / 454).toFixed(1)} lb wet)
        </span>
      </div>
    </Section>
  );
}

function TekGuide({ s }: { s: SpeciesEntry }) {
  const steps = deriveTekSteps(s);
  return (
    <Section label="TEK guide">
      <ol className="flex list-none flex-col gap-2.5 p-0">
        {steps.map((step) => (
          <li
            key={step.step}
            className="flex gap-3.5 rounded-sm border border-border-soft bg-bg-2 p-3.5"
          >
            <span className="flex h-[30px] w-[30px] shrink-0 items-center justify-center rounded-full border border-accent-line bg-accent-soft font-mono text-[14px] font-medium text-accent">
              {step.step}
            </span>
            <div className="flex min-w-0 flex-col gap-1">
              <div className="flex justify-between gap-2.5">
                <span className="font-body text-[18px] font-medium leading-[1.25] text-text-0">{step.title}</span>
                <span className="font-mono text-[12px] text-text-2">{step.duration}</span>
              </div>
              <p className="font-body text-[14px] leading-[1.55] text-text-1">{step.description}</p>
              {step.tips.length > 0 && (
                <div className="font-mono text-[12px] text-accent">
                  ✓ {step.tips.join(" · ")}
                </div>
              )}
              {step.mistakes.length > 0 && (
                <div className="font-mono text-[12px] text-err">
                  ✗ {step.mistakes.join(" · ")}
                </div>
              )}
            </div>
          </li>
        ))}
      </ol>
    </Section>
  );
}

function Recipes({ s }: { s: SpeciesEntry }) {
  const recipes = deriveRecipes(s);
  return (
    <Section label="Substrate recipes">
      <div className="flex flex-col gap-2.5">
        {recipes.map((r, i) => {
          // DataTable's `R extends { id?: string | number }` constraint rejects
          // the fixture's ingredient type outright (zero shared props with an
          // all-optional target) — map a synthetic `id` per row, same
          // workaround BuilderPage/FirmwarePage/SetupPage already use.
          const rows = r.ingredients.map((it, j) => ({ ...it, id: j }));
          const suitabilityTone =
            r.suitability === "optimal" ? "accent" : r.suitability === "good" ? "signal" : "warn";
          return (
            <article
              key={i}
              className="flex flex-col gap-2 rounded-sm border border-border-soft bg-bg-2 p-3.5"
            >
              <div className="flex items-baseline justify-between gap-2.5">
                <span className="font-body text-[18px] font-medium leading-[1.25] text-text-0">{r.name}</span>
                <span className={cn(STATUS_PILL_BASE, STATUS_PILL_TONE[suitabilityTone])}>
                  {r.suitability}
                </span>
              </div>
              {/* DataTable has no `.compact` density equivalent (no prop for
                  it, and `render` only returns cell content, not the `<td>`
                  itself) — adopted anyway per "primitives over hand-rolling";
                  rows render at DataTable's own (larger) default density, a
                  disclosed difference, not a fix. Same finding as
                  BuilderPage's Substitutions/FirmwareNodeCard tables (T6). */}
              <DataTable<(typeof rows)[number]>
                columns={[
                  { key: "ingredient", header: "Ingredient", render: (row) => row.ingredient },
                  { key: "amount", header: "Amount", align: "right", render: (row) => row.amount },
                ]}
                rows={rows}
              />
              <div className="font-mono text-[12px] text-text-2">
                hydration {r.hydrationPct}% · spawn {r.spawnRatePct}% · {r.sterilization}
              </div>
              {r.notes && <p className="font-body text-[14px] leading-[1.55] text-text-1">{r.notes}</p>}
            </article>
          );
        })}
      </div>
    </Section>
  );
}

function PhotoGallery({ s }: { s: SpeciesEntry }) {
  const photos = derivePhotos(s);
  return (
    <Section label="Photo references">
      <div className="grid grid-cols-[repeat(auto-fit,minmax(280px,1fr))] gap-3">
        {photos.map((p, i) => (
          <div key={i} className="flex flex-col overflow-hidden rounded-md border border-border-soft bg-bg-1">
            <div className="relative flex aspect-[4/3] shrink-0 items-center justify-center border-b border-border-soft bg-[radial-gradient(circle_at_30%_30%,var(--bg-2),var(--bg-0))] font-mono text-[13px] font-medium tracking-[0.12em] uppercase text-text-3 after:pointer-events-none after:absolute after:inset-0 after:bg-gradient-to-b after:from-transparent after:to-black/40 after:content-['']">
              {p.phase}
            </div>
            <div className="flex h-[116px] flex-col gap-1.5 overflow-hidden px-[18px] pt-4 pb-[18px]">
              <span className="overflow-hidden text-ellipsis whitespace-nowrap font-mono text-[13px] font-medium tracking-[0.05em] text-text-1">{p.phase}</span>
              <span className="font-mono text-[12px] text-text-2">{p.caption}</span>
            </div>
          </div>
        ))}
      </div>
    </Section>
  );
}

// ---- Helpers — derive content from existing fields -----------

interface DerivedTekStep {
  step: number;
  title: string;
  description: string;
  duration: string;
  tips: string[];
  mistakes: string[];
}

function deriveTekSteps(s: SpeciesEntry): DerivedTekStep[] {
  const steps: DerivedTekStep[] = [
    {
      step: 1,
      title: "Inoculate substrate",
      description: `Mix ${s.substrateRanking[0] ?? s.substrates[0]} at the recommended hydration. Sterilise (or pasteurise as noted), cool to <80°F, then add 5–10% grain spawn under sterile conditions.`,
      duration: "1 day",
      tips: ["work near a still-air box or laminar flow", "knead spawn through the bag thoroughly"],
      mistakes: ["adding spawn while substrate is still hot", "skipping sterile gloves"],
    },
    {
      step: 2,
      title: "Spawn run",
      description: `Hold ${s.phases[0]?.tempF ?? "65–75°F"} at low FAE. Mycelium will fully colonise the substrate. Keep CO₂ elevated to encourage hyphal growth.`,
      duration: s.phases[0]?.duration ?? "10–14d",
      tips: ["leave the chamber alone", "darkness is fine for spawn run"],
      mistakes: ["opening the bag prematurely", "introducing FAE before full colonisation"],
    },
    {
      step: 3,
      title: "Pin induction",
      description: s.pinningTrigger,
      duration: s.phases[1]?.duration ?? "3–5d",
      tips: ["temp drop overnight is the strongest single trigger", "watch for primordia within 48–72h"],
      mistakes: ["skipping cold shock when species needs it", "blasting the surface with mist"],
    },
    {
      step: 4,
      title: "Fruit",
      description: `Hold ${s.phases[s.phases.length - 1]?.tempF ?? "60–70°F"} with continuous FAE per phase setpoints. Mist 2–3× per day to keep RH at the upper bound.`,
      duration: s.phases[s.phases.length - 1]?.duration ?? "5–7d / flush",
      tips: ["don't over-mist — substrate slime invites bacteria", "aim mist at walls, not fruits"],
      mistakes: ["letting CO₂ climb above the species ceiling", "skipping FAE because misting was 'wet'"],
    },
    {
      step: 5,
      title: "Harvest + reset",
      description: `Cut at first veil break (or at peak shape for non-oysters). Re-soak the block, lower temperature briefly, and prepare for the next flush. Expect ${s.flushCount}.`,
      duration: "1 day per flush",
      tips: ["weigh wet + dry to track BE over flushes", "rotate the block 180° between flushes"],
      mistakes: ["leaving fruits past spore drop", "not resetting RH after harvest"],
    },
  ];

  return steps;
}

interface DerivedRecipe {
  name: string;
  ingredients: Array<{ ingredient: string; amount: string }>;
  hydrationPct: number;
  spawnRatePct: number;
  sterilization: string;
  suitability: "optimal" | "good" | "marginal";
  notes: string;
}

const RECIPE_BANK: Array<{ key: string; match: (s: SpeciesEntry) => boolean; recipe: DerivedRecipe }> = [
  {
    key: "mastermix",
    match: (s) => (s.substrateRanking[0] ?? "").toLowerCase().includes("mastermix"),
    recipe: {
      name: "MasterMix · 50/50 hardwood/soy",
      ingredients: [
        { ingredient: "Hardwood pellets · oak", amount: "1.0 kg" },
        { ingredient: "Soy hull pellets", amount: "1.0 kg" },
        { ingredient: "Filtered water", amount: "2.5 L" },
        { ingredient: "Gypsum (CaSO₄)", amount: "30 g" },
      ],
      hydrationPct: 65, spawnRatePct: 7, sterilization: "autoclave · 90 min @ 250°F", suitability: "optimal",
      notes: "Standard 4–5 lb fruiting blocks, sterilised in 0.2µm filter-patch bags.",
    },
  },
  {
    key: "hardwood",
    match: (s) => s.substrateRanking.slice(0, 2).some((r) => r.toLowerCase().includes("hardwood")),
    recipe: {
      name: "Supplemented hardwood block",
      ingredients: [
        { ingredient: "Hardwood pellets · oak", amount: "2.0 kg" },
        { ingredient: "Wheat bran (or rice bran)", amount: "200 g" },
        { ingredient: "Filtered water", amount: "2.4 L" },
        { ingredient: "Gypsum", amount: "20 g" },
      ],
      hydrationPct: 62, spawnRatePct: 5, sterilization: "autoclave · 90 min @ 250°F", suitability: "good",
      notes: "Cheaper than MasterMix but lower yields on demanding species.",
    },
  },
  {
    key: "straw",
    match: (s) => s.substrates.some((sb) => sb.toLowerCase().includes("straw")),
    recipe: {
      name: "Pasteurised straw",
      ingredients: [
        { ingredient: "Wheat or oat straw, chopped", amount: "5 kg" },
        { ingredient: "Hot water · 165°F", amount: "to cover" },
        { ingredient: "Hydrated lime (optional)", amount: "20 g per 10 L" },
      ],
      hydrationPct: 70, spawnRatePct: 10, sterilization: "lime-bath pasteurisation · 1 hr", suitability: "good",
      notes: "Cheapest substrate. Higher contam pressure — use only with oysters or beech.",
    },
  },
  {
    key: "grain",
    match: (s) => s.substrates.some((sb) => /grain|rice/i.test(sb)),
    recipe: {
      name: "Grain spawn (rye or brown rice)",
      ingredients: [
        { ingredient: "Whole rye / brown rice", amount: "1.0 kg" },
        { ingredient: "Filtered water", amount: "1.4 L (24h soak)" },
        { ingredient: "Gypsum (optional)", amount: "5 g" },
      ],
      hydrationPct: 55, spawnRatePct: 0, sterilization: "autoclave · 90 min @ 250°F", suitability: "optimal",
      notes: "Used to expand from agar / liquid culture. Shake daily during colonisation.",
    },
  },
];

function deriveRecipes(s: SpeciesEntry): DerivedRecipe[] {
  return RECIPE_BANK.filter((b) => b.match(s)).map((b) => b.recipe);
}

function derivePhotos(s: SpeciesEntry): Array<{ phase: string; caption: string }> {
  return s.phases.map((p) => ({
    phase: p.phase,
    caption: `${p.duration} · ${p.tempF}`,
  }));
}

function PhaseRow({ p }: { p: SpeciesPhase }) {
  return (
    <>
      <tr className="hover:bg-bg-2">
        <td className="border-t border-border-soft px-3.5 py-2.5 align-middle font-body text-text-0">{p.phase}</td>
        <td className="border-t border-border-soft px-3.5 py-2.5 align-middle font-mono text-text-0">{p.tempF}</td>
        <td className="border-t border-border-soft px-3.5 py-2.5 align-middle font-mono text-text-0">{p.humidity}</td>
        <td className="border-t border-border-soft px-3.5 py-2.5 align-middle font-mono text-text-0">{p.co2}</td>
        <td className="border-t border-border-soft px-3.5 py-2.5 align-middle">{p.light}</td>
        <td className="border-t border-border-soft px-3.5 py-2.5 align-middle">{p.fae}</td>
        <td className="border-t border-border-soft px-3.5 py-2.5 align-middle font-mono text-text-0">{p.duration}</td>
      </tr>
      {p.notes && (
        <tr className="hover:bg-bg-2">
          <td colSpan={7} className="border-t border-border-soft px-3.5 pt-0 pb-2 align-middle font-mono text-[12px] text-text-2">
            ↳ {p.notes}
          </td>
        </tr>
      )}
    </>
  );
}
