import type { PiHealth } from "../data/types";

/**
 * The most important element on the Pi top bar (per pi-interface.md):
 * the operator's silent question is "is my cloud dead or my internet
 * dead." Sage = synced, warn = syncing, err = offline.
 */
export function CloudSyncIndicator({ cloud }: { cloud: PiHealth["cloud"] }) {
  if (cloud.state === "synced") {
    return (
      <span className="cloud-sync">
        <span className="live-dot signal" />
        synced
        {cloud.lastSync && <span className="mut">· last {cloud.lastSync}</span>}
      </span>
    );
  }
  if (cloud.state === "syncing") {
    return (
      <span className="cloud-sync warn">
        <span className="live-dot warn" />
        syncing · {cloud.pending} pending
      </span>
    );
  }
  return (
    <span className="cloud-sync err">
      <span className="live-dot err" />
      offline · {cloud.pending} pending
    </span>
  );
}
