"use client";

import type { Actuators, ActuatorKey } from "../data/types";

const ORDER: ActuatorKey[] = ["mister", "fan", "heater", "pump", "light"];
const LABEL: Record<ActuatorKey, string> = {
  mister: "Mister",
  fan: "Fan",
  heater: "Heater",
  pump: "Pump",
  light: "Light",
};

function actuatorValue(on: boolean, sub: string): string {
  if (!on) return "Off";
  if (sub.includes("%")) return sub.split(" · ")[1] ?? "On";
  return "On";
}

export function ActuatorRow({
  actuators,
  /** When true (Pi UI), each actuator gets an "override →" button.
   *  Default false (cloud + mobile show state only). */
  editable = false,
  onOverride,
}: {
  actuators: Actuators;
  editable?: boolean;
  onOverride?: (key: ActuatorKey) => void;
}) {
  return (
    <div className="c-actuators" role="group" aria-label="actuators">
      {ORDER.map((k) => {
        const a = actuators[k];
        const overridden = Boolean(a.override);
        const cls = ["c-act", a.on ? "on" : "", overridden ? "overridden" : ""].filter(Boolean).join(" ");
        return (
          <div key={k} className={cls}>
            <div className="k">{LABEL[k]}</div>
            <div className="v">
              <span className="led" />
              {actuatorValue(a.on, a.sub)}
            </div>
            <div className="sub">{a.sub}</div>
            {editable && (
              <button
                type="button"
                className="override-btn"
                onClick={() => onOverride?.(k)}
              >
                {overridden ? "release →" : "override →"}
              </button>
            )}
          </div>
        );
      })}
    </div>
  );
}
