import { useCallback, useEffect, useMemo, useState } from "react";
import {
  Button,
  CloudSyncIndicator,
  PI_HEALTH,
  PageHeader,
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
  cn,
} from "@sporeprint/design";
import { PiTopBar } from "../components/PiTopBar";
import { apiGet, apiSend } from "../lib/api";
import { fmtClock } from "../lib/chambers";
import type { HardwareNode, SettingsMap } from "../lib/pi-types";

// ── Real Pi API shapes (server/app/vision router) ──────────────────────
interface FrameAnalysis {
  health_assessment?: string;
  confidence?: number;
  summary?: string;
  growth_stage?: string;
  error?: string;
}

interface VisionFrame {
  id: number;
  session_id: number | null;
  node_id: string;
  timestamp: number; // epoch seconds
  resolution: string | null;
  analysis_claude?: FrameAnalysis | null;
}

interface ClaudeCheck {
  state: "idle" | "pending" | "complete" | "failed";
  health?: "healthy" | "warn" | "contam" | "unknown";
  summary?: string;
}

// `.status-pill` base + tone (classmap §10) — self-sufficient tones per
// Binding Lesson 3.
const STATUS_PILL_BASE =
  "inline-flex items-center gap-[7px] rounded-pill border px-3 py-[5px] font-mono text-[12px] font-medium uppercase tracking-widest";
const STATUS_PILL_TONE = {
  accent: "border-accent-line bg-accent-soft text-accent",
  signal: "border-signal/40 bg-signal-soft text-signal",
  warn: "border-warn bg-bg-2 text-warn",
  err: "border-err bg-bg-2 text-err",
} as const;
function statusPill(tone: keyof typeof STATUS_PILL_TONE): string {
  return cn(STATUS_PILL_BASE, STATUS_PILL_TONE[tone]);
}

function isCamera(n: HardwareNode): boolean {
  if (n.node_type === "cam") return true;
  try {
    const roles = n.roles ? (JSON.parse(n.roles) as unknown) : null;
    return Array.isArray(roles) && roles.includes("cam");
  } catch {
    return false;
  }
}

function fmtAgo(epochSec: number): string {
  const s = Math.max(0, Math.floor(Date.now() / 1000 - epochSec));
  if (s < 60) return `${s}s ago`;
  if (s < 3600) return `${Math.floor(s / 60)}m ago`;
  return `${Math.floor(s / 3600)}h ago`;
}

// Map Claude's health_assessment enum → the page's three-tone verdict.
function healthTone(assessment: string | undefined): ClaudeCheck["health"] {
  switch ((assessment ?? "").toLowerCase()) {
    case "healthy":
      return "healthy";
    case "concern":
      return "warn";
    case "contaminated":
      return "contam";
    default:
      return "unknown";
  }
}

const CONTAM_LABELS = [
  "Trichoderma viride",
  "Cobweb (Cladobotryum)",
  "Penicillium",
  "Aspergillus",
  "Bacterial blotch",
];

// Verdict tone → chip styling (replaces two parallel 4-way ternaries).
const HEALTH_STYLE: Record<string, { bg: string; text: string }> = {
  healthy: { bg: "bg-accent-soft", text: "text-accent" },
  warn: { bg: "bg-[rgba(200,150,96,0.12)]", text: "text-warn" },
  contam: { bg: "bg-[rgba(200,90,76,0.12)]", text: "text-err" },
  unknown: { bg: "bg-bg-2", text: "text-text-1" },
};

export function VisionPage() {
  const [cameras, setCameras] = useState<HardwareNode[]>([]);
  const [frames, setFrames] = useState<Record<string, VisionFrame[]>>({});
  const [settings, setSettings] = useState<SettingsMap | null>(null);
  const [loading, setLoading] = useState(true);
  const [loadError, setLoadError] = useState<string | null>(null);

  const [checks, setChecks] = useState<Record<string, ClaudeCheck>>({});
  const [flagged, setFlagged] = useState<Record<string, string>>({});
  const [contamForm, setContamForm] = useState<{ nodeId: string; label: string }>({
    nodeId: "",
    label: CONTAM_LABELS[0]!,
  });
  const [flagBusy, setFlagBusy] = useState(false);
  const [flagError, setFlagError] = useState<string | null>(null);

  const refresh = useCallback(async () => {
    setLoading(true);
    setLoadError(null);
    try {
      const nodes = await apiGet<HardwareNode[]>("/api/hardware/nodes");
      const cams = nodes.filter(isCamera);
      setCameras(cams);
      const frameLists = await Promise.all(
        cams.map((c) =>
          apiGet<VisionFrame[]>(
            `/api/vision/frames?node_id=${encodeURIComponent(c.node_id)}&limit=8`,
          ).catch(() => [] as VisionFrame[]),
        ),
      );
      const byNode: Record<string, VisionFrame[]> = {};
      cams.forEach((c, i) => {
        byNode[c.node_id] = frameLists[i] ?? [];
      });
      setFrames(byNode);
      // BYOK status is read-only here; a failure shouldn't blank the page.
      const s = await apiGet<SettingsMap>("/api/settings").catch(() => null);
      setSettings(s);
    } catch (err) {
      setLoadError(err instanceof Error ? err.message : "fetch failed");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    void refresh();
  }, [refresh]);

  const latestFrame = useCallback(
    (nodeId: string): VisionFrame | undefined => frames[nodeId]?.[0],
    [frames],
  );

  const recentFrames = useMemo(() => {
    const all = Object.values(frames).flat();
    return all.sort((a, b) => b.timestamp - a.timestamp).slice(0, 6);
  }, [frames]);

  async function runClaudeCheck(nodeId: string) {
    const frame = latestFrame(nodeId);
    if (!frame) return;
    setChecks((prev) => ({ ...prev, [nodeId]: { state: "pending" } }));
    try {
      const result = await apiSend<FrameAnalysis>(
        `/api/vision/frames/${frame.id}/analyze`,
        "POST",
      );
      if (result.error) {
        setChecks((prev) => ({
          ...prev,
          [nodeId]: { state: "failed", summary: result.error },
        }));
        return;
      }
      setChecks((prev) => ({
        ...prev,
        [nodeId]: {
          state: "complete",
          health: healthTone(result.health_assessment),
          summary: result.summary ?? result.growth_stage ?? "analysis complete",
        },
      }));
    } catch (err) {
      setChecks((prev) => ({
        ...prev,
        [nodeId]: { state: "failed", summary: err instanceof Error ? err.message : "check failed" },
      }));
    }
  }

  async function flagCamera() {
    const nodeId = contamForm.nodeId;
    const frame = latestFrame(nodeId);
    if (!nodeId || !frame) return;
    setFlagBusy(true);
    setFlagError(null);
    try {
      // Active-learning correction: label the camera's latest frame with the
      // operator's contamination call (correct=false — overriding the CNN).
      await apiSend(`/api/vision/frames/${frame.id}/label`, "POST", {
        label: contamForm.label,
        correct: false,
      });
      setFlagged((prev) => ({ ...prev, [nodeId]: contamForm.label }));
    } catch (err) {
      setFlagError(err instanceof Error ? err.message : "flag failed");
    } finally {
      setFlagBusy(false);
    }
  }

  const byokKey = settings?.claude_api_key;
  const byokSet = !!byokKey && !!byokKey.value;

  return (
    <>
      <PiTopBar
        crumbs={[{ label: "monitor" }, { label: "vision", active: true }]}
        right={<CloudSyncIndicator cloud={PI_HEALTH.cloud} />}
      />

      <PageHeader
        eyebrow="On this Pi"
        title="Camera feed"
        italic={false}
        meta={
          <span>
            {cameras.length} camera{cameras.length === 1 ? "" : "s"} · live frame stream · runs
            against on-Pi BYOK Claude when set
          </span>
        }
        right={
          <Button type="button" variant="solid" onClick={() => void refresh()} disabled={loading}>
            {loading ? "loading…" : "refresh all →"}
          </Button>
        }
      />

      <div className="grid grid-cols-[1fr_400px] gap-[22px] px-7 pt-[22px] pb-7 max-[1180px]:grid-cols-1">
        <main className="flex flex-col gap-3.5">
          {loadError ? (
            <p className="font-mono text-[13px] tracking-[0.05em] text-err">
              Failed to load cameras: {loadError}
            </p>
          ) : loading ? (
            <p className="font-mono text-[13px] tracking-[0.05em] text-text-2">Loading cameras…</p>
          ) : cameras.length === 0 ? (
            <p className="font-body text-[14px] leading-[1.55] text-text-2">
              No camera nodes on this Pi yet. Camera nodes appear here once a cam_node boots and
              sends its first heartbeat over MQTT.
            </p>
          ) : (
            <div className="gallery">
              {cameras.map((c) => {
                const check = checks[c.node_id];
                const mark = flagged[c.node_id];
                const frame = latestFrame(c.node_id);
                const strip = frames[c.node_id] ?? [];
                return (
                  <article key={c.node_id} className="frame">
                    <div className="preview">
                      <span className="relative z-[1]">[live · {c.node_id}]</span>
                    </div>
                    <div className="meta h-auto">
                      <div className="flex items-baseline justify-between gap-3">
                        <span className="id">{c.node_id}</span>
                        <span
                          className={statusPill(
                            c.status === "online" ? "accent" : c.status === "offline" ? "err" : "signal",
                          )}
                        >
                          {c.status}
                        </span>
                      </div>
                      <span className="ts">
                        {frame
                          ? `last frame ${fmtAgo(frame.timestamp)}${frame.resolution ? ` · ${frame.resolution}` : ""}`
                          : "no frames yet"}
                      </span>
                      <div className="mt-1.5 flex flex-wrap items-center gap-1.5">
                        {/* TODO(wire): no capture-trigger endpoint — POST
                            /api/vision/frame is push-only (the cam_node
                            firmware POSTs JPEGs); the Pi cannot ask a camera
                            to grab a frame on demand. */}
                        <Button
                          type="button"
                          variant="ghost"
                          size="sm"
                          disabled
                          title="No capture-trigger endpoint on this Pi — cameras push frames on their own schedule"
                        >
                          capture frame
                        </Button>
                        <Button
                          type="button"
                          variant="solid"
                          size="sm"
                          onClick={() => void runClaudeCheck(c.node_id)}
                          disabled={!frame || check?.state === "pending"}
                        >
                          {check?.state === "pending" ? "claude…" : "claude check"}
                        </Button>
                      </div>
                      {check?.state === "complete" && check.health && (
                        <div
                          className={cn(
                            "mt-1.5 rounded-sm p-2.5",
                            (HEALTH_STYLE[check.health] ?? HEALTH_STYLE.unknown!).bg,
                          )}
                        >
                          <span
                            className={cn(
                              "font-mono text-[12px]",
                              (HEALTH_STYLE[check.health] ?? HEALTH_STYLE.unknown!).text,
                            )}
                          >
                            ↳ {check.summary}
                          </span>
                        </div>
                      )}
                      {check?.state === "failed" && (
                        <div className="mt-1.5 rounded-sm border border-err bg-[rgba(200,90,76,0.12)] px-2.5 py-1.5">
                          <span className="font-mono text-[12px] text-err">↳ {check.summary}</span>
                        </div>
                      )}
                      {mark && (
                        <div className="mt-1.5 rounded-sm border border-err bg-[rgba(200,90,76,0.12)] px-2.5 py-1.5">
                          <span className="font-mono text-[12px] text-err">flagged · {mark}</span>
                        </div>
                      )}
                      <TimelapseStrip frames={strip} />
                    </div>
                  </article>
                );
              })}
            </div>
          )}
        </main>

        <aside className="flex flex-col gap-3.5">
          <section className="flex flex-col gap-[18px] rounded-md border border-border-soft bg-bg-1 p-[26px]">
            <div className="mb-1.5 font-mono text-[15px] font-medium uppercase tracking-[0.16em] text-text-2">Manual contam mark</div>
            <p className="font-body text-[14px] leading-[1.55] text-text-1">
              Override the classifier when you spot something it missed. Applies your label to the
              camera's latest frame as an active-learning correction.
            </p>
            <label className="flex flex-col gap-1.5">
              <span className="font-mono text-[12px] font-medium uppercase tracking-[0.14em] text-text-2">camera</span>
              <Select value={contamForm.nodeId} onValueChange={(v) => setContamForm({ ...contamForm, nodeId: v })}>
                <SelectTrigger className="w-full" aria-label="camera">
                  <span className="min-w-0 flex-1 truncate text-left">
                    <SelectValue placeholder="pick a camera…" />
                  </span>
                </SelectTrigger>
                <SelectContent>
                  {cameras.map((c) => (
                    <SelectItem key={c.node_id} value={c.node_id}>{c.node_id}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </label>
            <label className="flex flex-col gap-1.5">
              <span className="font-mono text-[12px] font-medium uppercase tracking-[0.14em] text-text-2">type</span>
              <Select value={contamForm.label} onValueChange={(v) => setContamForm({ ...contamForm, label: v })}>
                <SelectTrigger className="w-full" aria-label="type">
                  <span className="min-w-0 flex-1 truncate text-left">
                    <SelectValue />
                  </span>
                </SelectTrigger>
                <SelectContent>
                  {CONTAM_LABELS.map((l) => (
                    <SelectItem key={l} value={l}>{l}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </label>
            {contamForm.nodeId && !latestFrame(contamForm.nodeId) && (
              <span className="font-mono text-[12px] text-warn">no frame yet for this camera — nothing to label</span>
            )}
            {flagError && <span className="font-mono text-[12px] text-err">{flagError}</span>}
            <Button
              type="button"
              variant="solid"
              className="self-start"
              disabled={!contamForm.nodeId || !latestFrame(contamForm.nodeId) || flagBusy}
              onClick={() => void flagCamera()}
            >
              {flagBusy ? "flagging…" : "flag chamber →"}
            </Button>
          </section>

          <section className="flex flex-col gap-[18px] rounded-md border border-border-soft bg-bg-1 p-[26px]">
            <div className="mb-1.5 font-mono text-[15px] font-medium uppercase tracking-[0.16em] text-text-2">Recent frames</div>
            {recentFrames.length === 0 ? (
              <p className="font-body text-[14px] leading-[1.55] text-text-2">
                No frames ingested yet · cameras push frames over MQTT as they capture.
              </p>
            ) : (
              <ul className="m-0 flex list-none flex-col gap-1.5 p-0">
                {recentFrames.map((f) => (
                  <li key={f.id} className="flex items-center justify-between gap-3 font-mono text-[12px] text-text-2">
                    <span>{f.node_id}</span>
                    <span className="text-text-2">{fmtClock(f.timestamp)}</span>
                  </li>
                ))}
              </ul>
            )}
          </section>

          <section className="flex flex-col gap-[18px] rounded-md border border-border-soft bg-bg-1 p-[26px]">
            <div className="mb-1.5 font-mono text-[15px] font-medium uppercase tracking-[0.16em] text-text-2">BYOK status</div>
            <div className="flex flex-col gap-2">
              <Row k="claude key" v={byokSet ? `set · ${byokKey!.display_value} (Pi-local)` : "not set"} />
              {/* TODO(wire): the Pi exposes no per-key rate-limit / last-call /
                  cost telemetry endpoint — omitted rather than fabricated. */}
            </div>
            <p className="font-body text-[14px] leading-[1.55] text-text-2">
              When the Pi BYOK key is unset, the Claude check buttons fall back to the local CNN — accuracy
              drops, but no API call leaves the LAN.
            </p>
          </section>
        </aside>
      </div>
    </>
  );
}

function TimelapseStrip({ frames }: { frames: VisionFrame[] }) {
  if (frames.length === 0) return null;
  return (
    <div className="mt-2 flex flex-col gap-1">
      <span className="font-mono text-[12px] font-medium tracking-[0.14em] uppercase text-text-2">
        last {frames.length} frame{frames.length === 1 ? "" : "s"}
      </span>
      <div className="flex gap-1 overflow-x-auto">
        {frames.map((f) => {
          const label = f.analysis_claude?.health_assessment ?? f.analysis_claude?.growth_stage ?? "";
          return (
            <div
              key={f.id}
              title={label ? `${fmtClock(f.timestamp)} · ${label}` : fmtClock(f.timestamp)}
              className="flex h-[42px] w-14 flex-none items-end justify-start rounded-sm border border-border-soft bg-[radial-gradient(circle_at_30%_30%,var(--bg-2),var(--bg-0))] p-[3px]"
            >
              <span className="font-mono text-[12px] text-text-3">{fmtClock(f.timestamp).slice(0, 5)}</span>
            </div>
          );
        })}
      </div>
    </div>
  );
}

function Row({ k, v }: { k: string; v: string }) {
  return (
    <div className="flex items-center justify-between gap-3">
      <span className="font-mono text-[12px] font-medium tracking-[0.14em] uppercase text-text-2">{k}</span>
      <span className="font-mono text-[14px] text-text-1">{v}</span>
    </div>
  );
}
